local function getFootholdLocalization()
	local localization = FH_L10N or FootholdLocalization
	if not localization then
		error("Foothold_Localization.lua must be loaded before using localized Foothold text.", 2)
	end
	return localization
end

local L10N = {
	Get = function(_, ...) return getFootholdLocalization():Get(...) end,
	Format = function(_, ...) return getFootholdLocalization():Format(...) end,
	Text = function(_, ...) return getFootholdLocalization():Text(...) end,
	GetForGroup = function(_, ...) return getFootholdLocalization():GetForGroup(...) end,
	FormatForGroup = function(_, ...) return getFootholdLocalization():FormatForGroup(...) end,
	FormatForLocale = function(_, ...) return getFootholdLocalization():FormatForLocale(...) end,
	ForGroup = function(_, ...) return getFootholdLocalization():ForGroup(...) end,
	BindGroupLocale = function(_, ...) return getFootholdLocalization():BindGroupLocale(...) end,
	SetPlayerLocale = function(_, ...) return getFootholdLocalization():SetPlayerLocale(...) end,
	GetPlayerLocale = function(_, ...) return getFootholdLocalization():GetPlayerLocale(...) end,
	GetGroupLocale = function(_, ...) return getFootholdLocalization():GetGroupLocale(...) end,
	DeferredGet = function(_, ...) return getFootholdLocalization():DeferredGet(...) end,
	DeferredFormat = function(_, ...) return getFootholdLocalization():DeferredFormat(...) end,
	DynamicHeadingLabel = function(_, ...) return getFootholdLocalization():DynamicHeadingLabel(...) end,
	DynamicLegLabel = function(_, ...) return getFootholdLocalization():DynamicLegLabel(...) end,
	DynamicDistanceLabel = function(_, ...) return getFootholdLocalization():DynamicDistanceLabel(...) end,
}

local FootholdLanguageOptions = {
	{ locale = "EN", label = "English" },
	{ locale = "DE", label = "Deutsch" },
	{ locale = "FR", label = "Français" },
	{ locale = "ES", label = "Español" },
	{ locale = "RU", label = "Русский" },
	{ locale = "PT-BR", label = "Português (Brasil)" },
	{ locale = "TR", label = "Türkçe" },
	{ locale = "zh-CN", label = "簡體中文" },
	{ locale = "zh-TW", label = "繁體中文" },
}

local function footholdLanguageLabel(locale)
	local localeKey = string.upper(tostring(locale or ""))
	for _, option in ipairs(FootholdLanguageOptions) do
		if string.upper(tostring(option.locale or "")) == localeKey then
			return option.label
		end
	end
	return localeKey
end

