     env.info("[LZ] stored key: "..n)
end ]]
LandingSpots = {}
local landingSpotPoolByPrefix = {}
local forcedLandingSpotPoolByZone = {}
local cargoDropSubZoneCandidatesByTarget = {}
local cargoDropSubZoneChoicesByLanding = {}

local function _resetLandingSpotPoolCaches()
	landingSpotPoolByPrefix = {}
	forcedLandingSpotPoolByZone = {}
	cargoDropSubZoneCandidatesByTarget = {}
	cargoDropSubZoneChoicesByLanding = {}
end

local function _getLandingSpotPoolForPrefix(prefix)
	if not prefix or prefix == "" then return nil end
	local cached = landingSpotPoolByPrefix[prefix]
	if cached then return cached end

	local pool = {}
	for name, list in pairs(LandingSpots or {}) do
		if name:sub(1, #prefix) == prefix then
			for i = 1, #list do
				local spot = list[i]
				if spot and spot.x and spot.z then
					pool[#pool + 1] = { name = name, x = spot.x, z = spot.z }
				end
			end
		end
	end

	landingSpotPoolByPrefix[prefix] = pool
	return pool
end

local function _getForcedLandingSpotPool(zoneName)
	if not zoneName or zoneName == "" then return nil end
	local cached = forcedLandingSpotPoolByZone[zoneName]
	if cached then return cached end

	local pool = {}
	local idx = 0
	while true do
		local fname = string.format("%s-land-forced-%d", zoneName, idx)
		local fz = getTriggerZone(fname)
		if not fz or not fz.point then break end
		pool[#pool + 1] = { name = fname, x = fz.point.x, z = fz.point.z }
		idx = idx + 1
	end

	forcedLandingSpotPoolByZone[zoneName] = pool
	return pool
end

local function _pickRandomLandingSpot(pool, excludedName)
	if not pool or #pool == 0 then return nil end
	if not excludedName then
		return pool[math.random(#pool)]
	end
	if #pool == 1 and pool[1].name == excludedName then
		return nil
	end

	local maxTries = math.min(#pool, 8)
	for _ = 1, maxTries do
		local cand = pool[math.random(#pool)]
		if cand.name ~= excludedName then
			return cand
		end
	end
	for i = 1, #pool do
		local cand = pool[i]
		if cand.name ~= excludedName then
			return cand
		end
	end
	return nil
end

local function _parseCargoDropTargetFromZoneName(zoneName)
	local base = zoneName:match("^(.-)%-land%-forced%-%d+$")
	if base then return base end
	base = zoneName:match("^(.-)%-land%-%d+$")
	if base then return base end
	return zoneName:match("^(.-)%-%d+$")
end

local function _isCargoDropSubZoneForTarget(targetZoneName, zoneName)
	if not targetZoneName or not zoneName then return false end
	local prefix = targetZoneName .. "-"
	if zoneName:sub(1, #prefix) ~= prefix then return false end
	local suffix = zoneName:sub(#prefix + 1)
	local lowerSuffix = suffix:lower()
	if lowerSuffix:find("sam", 1, true) then return false end
	return suffix:match("^%d+$") ~= nil
		or suffix:match("^land%-%d+$") ~= nil
		or suffix:match("^land%-forced%-%d+$") ~= nil
end

local function _getCargoDropSubZoneCandidates(targetZoneName)
	if not targetZoneName or targetZoneName == "" then return nil end
	local cached = cargoDropSubZoneCandidatesByTarget[targetZoneName]
	if cached then return cached end
	if not zoneByName then buildZoneByName() end

	local candidates = {}
	for zoneName, _ in pairs(zoneByName or {}) do
		if _isCargoDropSubZoneForTarget(targetZoneName, zoneName) then
			local z = getTriggerZone(zoneName)
			if z and z.point then
				candidates[#candidates + 1] = { name = zoneName, x = z.point.x, z = z.point.z }
			end
		end
	end

	table.sort(candidates, function(a, b) return a.name < b.name end)
	cargoDropSubZoneCandidatesByTarget[targetZoneName] = candidates
	return candidates
end

local function _nearestCargoDropSubZoneChoices(targetZoneName, x, z, excludedName, maxChoices)
	local candidates = _getCargoDropSubZoneCandidates(targetZoneName)
	if not candidates or #candidates == 0 or not x or not z then return nil end

	local sorted = {}
	for i = 1, #candidates do
		local candidate = candidates[i]
		if candidate.name ~= excludedName then
			local dx = candidate.x - x
			local dz = candidate.z - z
			sorted[#sorted + 1] = { name = candidate.name, d2 = dx * dx + dz * dz }
		end
	end
	if #sorted == 0 and excludedName then
		for i = 1, #candidates do
			local candidate = candidates[i]
			local dx = candidate.x - x
			local dz = candidate.z - z
			sorted[#sorted + 1] = { name = candidate.name, d2 = dx * dx + dz * dz }
		end
	end
	if #sorted == 0 then return nil end

	table.sort(sorted, function(a, b)
		if a.d2 == b.d2 then return a.name < b.name end
		return a.d2 < b.d2
	end)

	local choices = {}
	local limit = math.min(maxChoices or 2, #sorted)
	for i = 1, limit do
		choices[#choices + 1] = sorted[i].name
	end
	return choices
end

local function _buildCargoDropSubZoneCache()
	cargoDropSubZoneCandidatesByTarget = {}
	cargoDropSubZoneChoicesByLanding = {}
	if not zoneByName then buildZoneByName() end

	local targets = {}
	for zoneName, _ in pairs(zoneByName or {}) do
		local targetName = _parseCargoDropTargetFromZoneName(zoneName)
		if targetName then
			targets[targetName] = true
		end
	end

	for targetName, _ in pairs(targets) do
		_getCargoDropSubZoneCandidates(targetName)
		cargoDropSubZoneChoicesByLanding[targetName] = cargoDropSubZoneChoicesByLanding[targetName] or {}

		local landingPrefix = targetName .. "-land"
		for landingName, spots in pairs(LandingSpots or {}) do
			if landingName == landingPrefix or landingName:sub(1, #landingPrefix + 1) == landingPrefix .. "-" then
				local z = getTriggerZone(landingName)
				local point = z and z.point or nil
				if point then
					cargoDropSubZoneChoicesByLanding[targetName][landingName] = _nearestCargoDropSubZoneChoices(targetName, point.x, point.z, landingName, 2)
				elseif spots and spots[1] then
					cargoDropSubZoneChoicesByLanding[targetName][landingName] = _nearestCargoDropSubZoneChoices(targetName, spots[1].x, spots[1].z, landingName, 2)
				end
			end
		end

		local idx = 0
		while true do
			local forcedName = string.format("%s-land-forced-%d", targetName, idx)
			local forcedZone = getTriggerZone(forcedName)
			if not forcedZone or not forcedZone.point then break end
			cargoDropSubZoneChoicesByLanding[targetName][forcedName] = _nearestCargoDropSubZoneChoices(targetName, forcedZone.point.x, forcedZone.point.z, forcedName, 2)
			idx = idx + 1
		end
	end
end

local function _selectCargoDropSubZoneForLanding(targetZoneName, landingName, landingX, landingZ)
	local choices = landingName
		and cargoDropSubZoneChoicesByLanding[targetZoneName]
		and cargoDropSubZoneChoicesByLanding[targetZoneName][landingName]
		or nil
	if choices and #choices > 0 then
		return choices[math.random(#choices)]
	end

	choices = _nearestCargoDropSubZoneChoices(targetZoneName, landingX, landingZ, landingName, 2)
	if choices and #choices > 0 then
		return choices[math.random(#choices)]
	end

	local candidates = _getCargoDropSubZoneCandidates(targetZoneName)
	if candidates and #candidates > 0 then
		return candidates[math.random(#candidates)].name
	end
	return targetZoneName
end

local NM = 1852
local NEAR_BLUE_METERS = 50 * NM

local headingTrigCache = {}

local function _headingToRad(deg)
  if deg<=180 then return math.rad(deg) else return -math.rad(360-deg) end
end

local function _getHeadingTrig(headingDeg)
  local hdg = headingDeg or 0
  local cached = headingTrigCache[hdg]
  if not cached then
    local h = _headingToRad(hdg)
    cached = { h = h, psi = -h, cos = math.cos(h), sin = math.sin(h) }
    headingTrigCache[hdg] = cached
  end
  return cached
end

local function _surfaceTaskSpawnHeadingDeg(task)
  local route = task and task.params and task.params.route
  local points = route and route.points or nil
  if type(points) ~= "table" or #points < 2 then return nil end
  for i = 1, #points - 1 do
    local a = points[i]
    local b = points[i + 1]
    local ax = a and tonumber(a.x) or nil
    local ay = a and tonumber(a.y) or nil
    local bx = b and tonumber(b.x) or nil
    local by = b and tonumber(b.y) or nil
    if ax and ay and bx and by then
      local dx = bx - ax
      local dy = by - ay
      local distSq = dx * dx + dy * dy
      if distSq > (25 * 25) then
        local headingDeg = math.deg(math.atan2(dy, dx))
        if headingDeg < 0 then headingDeg = headingDeg + 360 end
        return headingDeg
      end
    end
  end
  return nil
end

local function _applyTemplateHeadingDeg(tpl, headingDeg)
  if not tpl or not tpl.units or not headingDeg then return end
  local ht = _getHeadingTrig(headingDeg)
  local h = ht.h
  local psi = ht.psi
  for _, u in ipairs(tpl.units) do
    u.heading = h
    u.psi = psi
  end
end

local function _surfaceTaskEtaMinutes(task)
  local etaSeconds = 0
  local route = task and task.params and task.params.route
  local points = route and route.points or nil
  if type(points) == "table" and #points >= 2 then
    for i = 1, #points - 1 do
      local wpA = points[i]
      local wpB = points[i + 1]
      local ax = wpA and tonumber(wpA.x) or nil
      local ay = wpA and tonumber(wpA.y) or nil
      local bx = wpB and tonumber(wpB.x) or nil
      local by = wpB and tonumber(wpB.y) or nil
      local legSpeed = tonumber((wpB and wpB.speed) or (wpA and wpA.speed)) or (dc.DEFAULT_SPEED or 13.8)
      if ax and ay and bx and by and legSpeed > 0 then
        local dx = bx - ax
        local dy = by - ay
        etaSeconds = etaSeconds + (math.sqrt(dx * dx + dy * dy) / legSpeed)
      end
    end
  end
  return math.floor((etaSeconds / 60) + 0.5)
end

local function _surfaceTaskFreshGroundAttackMessage(groupCommander, task)
  local etaMinutes = _surfaceTaskEtaMinutes(task)
  local origin = groupCommander and groupCommander._freshPlayerGroundAttackDeployOrigin
  local target = groupCommander and groupCommander.targetzone or "target"
  if origin and origin ~= "" then
    return L10N:Format("GROUND_ATTACK_CONVOY_DEPLOYING", origin, target, etaMinutes)
  end
  return L10N:Format("GROUND_ATTACK_CONVOY_EN_ROUTE", target, etaMinutes)
end

local function _bearingDegFromDelta(dx, dy)
  local h = math.deg(math.atan2(dx, dy))
  if h < 0 then h = h + 360 end
  return h
end

function PrecomputeLandingSpots(maxPerZone, attemptsPerZone, maxSlopeDeg)
    maxPerZone = maxPerZone or 5
    attemptsPerZone = attemptsPerZone or 600
    maxSlopeDeg = maxSlopeDeg or 12
	_resetLandingSpotPoolCaches()

    for _, z in ipairs(env.mission.triggers.zones or {}) do
        local zname = z.name
        local lname = zname:lower()
		if lname:sub(-5) == "-land" or lname:match("%-land%-%d+$") then
            local spots = {}
            local allowed = { [land.SurfaceType.LAND]=true, [land.SurfaceType.ROAD]=true }
            for _=1,attemptsPerZone do
                local coord = GetValidCords(zname, allowed, 1)
                if coord then
                    local v = coord:GetVec3()
                    if Utils.getTerrainSlopeAtPoint({x=v.x,z=v.z},20) <= maxSlopeDeg then
                        table.insert(spots, {x=v.x, z=v.z})
                        if #spots >= maxPerZone then break end
                    end
                end
            end
            if #spots > 0 then
                LandingSpots[zname] = spots
            else
                local forced = {}
                local idx = 0
                while true do
                    local fname = string.format("%s-land-forced-%d", zname, idx)
                    local fz = getTriggerZone(fname)
                    if not fz then break end
                    table.insert(forced, {x=fz.point.x, z=fz.point.z})
                    idx = idx + 1
                end
                if #forced > 0 then
                    LandingSpots[zname] = forced
                else
                    trigger.action.outText(L10N:Format("LZ_NO_VALID_LANDING_SPOTS", zname), 10)
                    env.info(string.format("[LZ] Zone %s has no valid landing spots", zname))
                end
            end
        end
    end
	_buildCargoDropSubZoneCache()
end

function getEscortFarpZoneOfUnit(unitName)
    local dcsGroup = Group.getByName(unitName)
    if not dcsGroup or not dcsGroup:isExist() then return nil end
    local leadUnit = dcsGroup:getUnit(1)
    local leadPoint = leadUnit and leadUnit:getPoint() or nil
    local leadCoord = leadPoint and COORDINATE:NewFromVec3(leadPoint) or nil
    if not leadCoord then return nil end
    if not supplyZones then return nil end
    for _, zName in ipairs(supplyZones) do
        if string.find(zName, "Escort Mission FARP") then
            local zObj = getMooseZone(zName)
            local inZone = zObj and zObj:IsCoordinateInZone(leadCoord) or false
            if inZone then
                return {zone = (escortFarpToZone and escortFarpToZone[zName]) or zName,
                    side = dcsGroup:getCoalition()}
            end
        end
    end
end

local function DeepCopy(o, s)
  if type(o)~="table" then return o end
  if s and s[o] then return s[o] end
  local t, s = {}, s or {} ; s[o] = t
  for k,v in pairs(o) do t[DeepCopy(k,s)] = DeepCopy(v,s) end
  return setmetatable(t,getmetatable(o))
end

local gid, uid = 7000, 90000
local function freshIds(t)
  t.groupId = gid ;  gid = gid + 1
  for _,u in ipairs(t.units) do
    u.unitId = uid ; uid = uid + 1
  end
end

local function FixSelfTasks(route, newGrpId, newUnitId)
  if not route or not route.points then return end
  for _,pt in ipairs(route.points) do
    local tasks = (((pt.task or {}).params) or {}).tasks
    if tasks then
      for _,tk in ipairs(tasks) do
        local act = (tk.params or {}).action
        if act and act.id == "EPLRS"          then act.params.groupId = newGrpId end
        if act and act.id == "ActivateBeacon" then act.params.unitId  = newUnitId end
        if act and act.id == "ActivateICLS"   then act.params.unitId  = newUnitId end
      end
    end
  end
end

local CAT={plane="AIRPLANE",helicopter="HELICOPTER",vehicle="GROUND",ship="SHIP",static="STATIC"}


local groupTemplateCache = nil

function buildTemplateCache()
  groupTemplateCache = {}
  for coaName, coa in pairs(env.mission.coalition) do
    if type(coa)=="table" and coa.country then
      for _,country in pairs(coa.country) do
        for cat,catTbl in pairs(country) do
          if type(catTbl)=="table" and catTbl.group then
            for _,g in ipairs(catTbl.group) do
              local t       = DeepCopy(g)
              t.category    = cat
              t.countryId   = country.id
              t.coaSideEnum = coalition.side[string.upper(coaName)]
              groupTemplateCache[g.name] = t
            end
          end
        end
      end
    end
  end
end

local function FetchMETemplate(name)
  if not groupTemplateCache then
    buildTemplateCache()
  end
  local tpl = groupTemplateCache[name]
  if tpl then
    return DeepCopy(tpl)
  end
  return nil
end

local function CopyUnitTypeSlot(slot)
  local out = {}
  if type(slot) ~= "table" then
    return out
  end
  for _, unitType in pairs(slot) do
    if type(unitType) == "string" and unitType ~= "" then
      out[#out + 1] = unitType
    end
  end
  return out
end

local function CopyUnitTypeSnapshot(snapshot)
  local out = {}
  if type(snapshot) ~= "table" then
    return out
  end
  for idx, slot in pairs(snapshot) do
    out[idx] = CopyUnitTypeSlot(slot)
  end
  return out
end

local function IsSavedUnitSlotEmpty(slot)
  if type(slot) ~= "table" then
    return true
  end
  for _, unitType in pairs(slot) do
    if type(unitType) == "string" and unitType ~= "" then
      return false
    end
  end
  return true
end

local function ResolveNamedGroupTemplate(name)
  if not name or name == "" then return nil end

  local grp = GROUP:FindByName(name)
  local tpl = grp and grp:GetTemplate()
  if tpl then
    return (UTILS and UTILS.DeepCopy) and UTILS.DeepCopy(tpl) or tpl
  end

  tpl = FetchMETemplate(name)
  if tpl then
    return tpl
  end

  local db = _DATABASE and _DATABASE.Templates and _DATABASE.Templates.Groups and _DATABASE.Templates.Groups[name]
  if db and db.Template then
    return (UTILS and UTILS.DeepCopy) and UTILS.DeepCopy(db.Template) or db.Template
  end

  return nil
end

local function ShouldTreatSavedZoneAsSuspended(savedZone)
  if type(savedZone) ~= "table" then return false end
  if savedZone.suspended == true then return true end
  if savedZone.suspended ~= nil then return false end
  if savedZone.active ~= true then return false end
  if tonumber(savedZone.side) == 0 then return false end

  local level = math.max(0, math.floor(tonumber(savedZone.level) or 0))
  if level <= 0 then return false end

  local remainingUnits = savedZone.remainingUnits
  if type(remainingUnits) ~= "table" then return false end

  for idx = 1, level do
    local slot = remainingUnits[idx]
    if type(slot) ~= "table" then return false end
    if not IsSavedUnitSlotEmpty(slot) then return false end
  end

  return true
end

local function BuildPersistedSuspendedSnapshot(savedZone)
  local out = {}
  local savedLevel = math.max(0, math.floor(tonumber(savedZone and savedZone.level) or 0))
  for idx = 1, savedLevel do
    local savedSlot = savedZone and savedZone.remainingUnits and savedZone.remainingUnits[idx] or nil
    out[idx] = CopyUnitTypeSlot(savedSlot)
  end

  return out
end

local function ResolveTemplateSide(templateName)
  local tpl = _DATABASE.Templates.Groups[templateName] or nil
  local side = nil
  if tpl then
    local coalitionValue = tpl.Coalition or tpl.coalition
    if type(coalitionValue) == "number" then
      if coalitionValue == coalition.side.RED or coalitionValue == 1 then
        side = 1
      elseif coalitionValue == coalition.side.BLUE or coalitionValue == 2 then
        side = 2
      end
    elseif coalitionValue == "red" or coalitionValue == "RED" then
      side = 1
    elseif coalitionValue == "blue" or coalitionValue == "BLUE" then
      side = 2
    end
    if not side then
      local coalitionId = tpl.CoalitionID or tpl.coalitionId
      if type(coalitionId) == "number" then
        if coalitionId == coalition.side.RED or coalitionId == 1 then
          side = 1
        elseif coalitionId == coalition.side.BLUE or coalitionId == 2 then
          side = 2
        end
      end
    end
  end
  if not side then
    local gr = Group.getByName(templateName)
    if gr then
      local c = gr:getCoalition()
      if c == 1 or c == 2 then
        side = c
      end
    end
  end
  return side
end

