}

local function GetTemplateFirstUnitTypeName(templateName)
	local db = _DATABASE.Templates.Groups[templateName] or nil
	local tpl = db and db.Template or nil
	local firstUnit = tpl and tpl.units and tpl.units[1] or nil
	local typeName = firstUnit and firstUnit.type or nil
	if typeName then return typeName end

	local gr = Group.getByName(templateName)
	local unit = gr and gr:getUnit(1) or nil
	return unit and unit.getTypeName and unit:getTypeName() or nil
end

function Respawn.Group(groupName, uncontrolled)
  local live = Group.getByName(groupName)
  if live and live:isExist() then live:destroy() end

  local tpl = FetchMETemplate(groupName)
  if not tpl then env.error("Respawn: ME template '"..groupName.."' not found") return end

  freshIds(tpl)
  tpl.lateActivation = false

  if uncontrolled and (tpl.category=="plane" or tpl.category=="helicopter") then
    tpl.uncontrolled = true
    local wp1 = tpl.route and tpl.route.points and tpl.route.points[1]
    if wp1 then
      wp1.type   = "TakeOffParking"
      wp1.action = "From Parking Area"
    end
  end

  FixSelfTasks(tpl.route, tpl.groupId, tpl.units[1].unitId)

  local newGrp = coalition.addGroup(tpl.countryId, Group.Category[CAT[tpl.category] or "GROUND"], tpl)
  if not newGrp then
	env.error("Respawn: addGroup failed for group '"..groupName.."'")
	return nil
  end
  return newGrp
end

function Respawn.SpawnAtPoint(grpName, coord, headingDeg, distNm, alt, spd)
  local t0 = timer.getTime()
  local tpl = FetchMETemplate(grpName); if not tpl then return end
  local t1 = timer.getTime()
  
  local ALT = alt and UTILS.FeetToMeters(alt) or tpl.units[1].alt or UTILS.FeetToMeters(25000)

  local cx, cz = coord.x, coord.z
  if coord.GetVec3 then local v = coord:GetVec3(); cx,cz = v.x, v.z end
  local ht = _getHeadingTrig(headingDeg)
  local h = ht.h
  local psi = ht.psi
  local c, s = ht.cos, ht.sin
  local refX, refZ = tpl.units[1].x, tpl.units[1].y
  for _,u in ipairs(tpl.units) do
    local dx, dz = u.x-refX, u.y-refZ
    u.x = cx + dx*c - dz*s
    u.y = cz + dx*s + dz*c
    u.heading = h
    u.psi = psi
    u.alt = ALT
  end
  local d = (distNm or 5)*1852
  local wpX = cx + d*math.cos(h)
  local wpZ = cz + d*math.sin(h)
  if not tpl.route then tpl.route = {points={}} end
  if not tpl.route.points then tpl.route.points = {} end
  tpl.route.points[1] = {type="Turning Point",action="Turning Point",x=tpl.units[1].x,y=tpl.units[1].y,alt=ALT,alt_type="BARO",speed=spd or tpl.units[1].speed or 380,psi=psi,task={id="ComboTask",params={tasks={}}}}
  tpl.route.points[2] = {type="Turning Point",action="Turning Point",x=wpX,y=wpZ,alt=ALT,alt_type="BARO",speed=spd or tpl.route.points[1].speed,psi=psi,task={id="ComboTask",params={tasks={}}}}
  freshIds(tpl)
  tpl.lateActivation = false
  FixSelfTasks(tpl.route, tpl.groupId, tpl.units[1].unitId)
  local t2 = timer.getTime()
  local newGrp = coalition.addGroup(tpl.countryId,Group.Category[CAT[tpl.category] or "GROUND"],tpl)
  local t3 = timer.getTime()
  if not newGrp then env.error("Respawn: addGroup failed - "..tostring(newGrp)) return nil end
  return newGrp
end



local subZoneCache = {}

local function collectSubZones(baseName)
	if subZoneCache[baseName] then return subZoneCache[baseName] end
	local zones = {}
	if not zoneByName then buildZoneByName() end
	local prefix = baseName .. "-"
	for zname,_ in pairs(zoneByName or {}) do
		if zname:sub(1, #prefix) == prefix then
			local suffix = zname:sub(#prefix + 1)
			if suffix:match("^%d+$") then
				zones[#zones + 1] = zname
			end
		end
	end
	table.sort(zones)
	subZoneCache[baseName] = zones
	return zones
end

local zoneCenterCache = {}
	function getZoneCenter(name)
		if zoneCenterCache[name] then return zoneCenterCache[name] end
		local z = getTriggerZone(name)
		if not z or not z.point then return nil end
		local c = { x = z.point.x, y = z.point.z or z.point.y or 0 }
		zoneCenterCache[name] = c
		return c
	end

function StartBomberAuftrag(tag, grpName, tgtList, escortGroup)
	local bomber = Group.getByName(grpName)
	if not bomber or not bomber:isExist() or bomber:getSize() == 0 then return end
	local lead = bomber:getUnit(1)
	if not lead or not lead:isExist() then return end
	local startPos = lead:getPoint()
	local coords = COORDINATE:New(startPos.x, startPos.y or 0, startPos.z)

	if type(tgtList) ~= "table" then tgtList = { tgtList } end
	local choice = nil
	do
		local valid = {}
		for _, v in ipairs(tgtList) do
			local z = bc.indexedZones[v]
			if z and z.side == 2 and not z.suspended then valid[#valid+1] = v end
		end
		local best = math.huge
		for _, v in ipairs(valid) do
			local z = bc.indexedZones[v]
			local zcoord = nil
			local mz = getMooseZone(z.zone or v)
			if mz then
				zcoord = mz:GetCoordinate()
			else
				local c = getZoneCenter(z.zone or v)
				if c then zcoord = COORDINATE:New(c.x,0,c.y) end
			end
			if zcoord then
				local d = coords:Get2DDistance(zcoord)
				if d < best then best = d ; choice = v end
			end
		end
		if not choice and #valid > 0 then choice = valid[math.random(1,#valid)] end
	end
	local zn = choice and bc.indexedZones[choice] or nil
	local altm = UTILS.FeetToMeters(25000)
	local attack = { id = 'ComboTask', params = { tasks = {} } }
	local firstpos = nil
	if zn and zn.built then
		for _, v in pairs(zn.built) do
			local task = bc:getAttackTask(v, AI.Task.WeaponExpend.HALF, altm)
			if task then
				if task.params then task.params.groupAttack = true end
				table.insert(attack.params.tasks, task)
				if not firstpos then
					local p = bc:getTargetPos(v)
					if p then firstpos = p end
				end
			end
		end
	end

	if not firstpos and zn then
		local c = getZoneCenter(zn.zone or choice)
		if c then firstpos = { x = c.x, y = startPos.y, z = c.y } end
	end
	if not firstpos then return bomber, nil, choice end

	local dx = firstpos.x - startPos.x
	local dz = firstpos.z - startPos.z
	local len = math.sqrt(dx * dx + dz * dz)
	if len <= 0 then len = 1 end
	local ux, uz = dx / len, dz / len
	local appPos = {
		x = firstpos.x - ux * UTILS.NMToMeters(25),
		y = startPos.y,
		z = firstpos.z - uz * UTILS.NMToMeters(25)
	}
	local speedKmh = 850
	local destroyAtWp = {
		id = 'WrappedAction',
		params = {
			action = {
				id = 'Script',
				params = {
					command = "local gr = ...\ngr:destroy()"
				}
			}
		}
	}
	local wp = {}
	wp[#wp+1] = COORDINATE:New(appPos.x, altm, appPos.z):WaypointAirTurningPoint("RADIO", speedKmh, { attack }, "Ingress 25 NM")
	--wp[#wp+1] = COORDINATE:New(firstpos.x, altm, firstpos.z):WaypointAirTurningPoint("RADIO", speedKmh, { attack }, "Attack")
	wp[#wp+1] = COORDINATE:New(startPos.x, altm, startPos.z):WaypointAirTurningPoint("RADIO", speedKmh, { destroyAtWp }, "RTB Cleanup")

	local mission = { id = 'Mission', params = { route = { points = wp } } }
	local controller = bomber:getController()
	if controller then controller:setTask(mission) end
	bc:setDefaultAG(bomber)

	if escortGroup then
		timer.scheduleFunction(function()
			local bgr = Group.getByName(grpName)
			local egr = Group.getByName(escortGroup)
			if bgr and egr then
				local c = egr:getController()
				c:setTask({
					id = 'ComboTask',
					params = { tasks = {
						{
							id = 'Escort',
							params = {
								groupId = bgr:getID(),
								pos = { x = -20, y = 2000, z = 50 },
								lastWptIndexFlag = false,
								engagementDistMax = 40*NM,
								targetTypes = { 'plane' }
							}
						}
					}}
				})
			end
		end,{},timer.getTime()+5)
	end
	_G[tag..'Bomber'] = bomber
	_G[tag..'Mission'] = mission
	return bomber, mission, choice
end


CustomZone = {}
do
	function CustomZone:getByName(name)
		local cached = customZoneCache[name]
		if cached ~= nil then
			if cached == false then return nil end
				return cached
		end
			obj = {}
			obj.name = name
			obj.isHidden = name:lower():find("hidden", 1, true) ~= nil
			if not zoneByName then buildZoneByName() end
			local zd = zoneByName[name]
			if not zd then
				customZoneCache[name] = false
				return nil
			end				

			obj.type = zd.type -- 2 == quad, 0 == circle
			if obj.type == 2 then
					obj.vertices = {}
					for _,v in ipairs(zd.verticies) do
			local vertex = {
				x = v.x,
				y = 0,
				z = v.y
			}
			table.insert(obj.vertices, vertex)
		end
	end
	
	obj.radius = zd.radius
	obj.point = {
		x = zd.x,
		y = 0,
		z = zd.y
	}
	
		setmetatable(obj, self)
		self.__index = self
		customZoneCache[name] = obj
		return obj
	end
	
	function CustomZone:isQuad()
		return self.type==2
	end
	
	function CustomZone:isCircle()
		return self.type==0
	end
	
	function CustomZone:isInside(point)
		if self:isCircle() then
			local dist=UTILS.VecDist2D({x=point.x,y=point.z},{x=self.point.x,y=self.point.z})
			return dist<self.radius
		elseif self:isQuad() then
			return UTILS.IsPointInPolygon({x=point.x,y=point.z},self.vertices)
		end
	end
	
	function CustomZone:getZoneBuildings()
		buildingCache                 = buildingCache or {}
		if buildingCache[self.name] then return buildingCache[self.name] end

		local pts, vol = {}, nil
		if self:isCircle() then
			vol = { id = world.VolumeType.SPHERE,
					params = { point = self.point, radius = self.radius } }
		else
			local r = 0
			for _,v in ipairs(self.vertices) do
				local d = UTILS.VecDist2D({x = v.x, y = v.z},
										{x = self.point.x, y = self.point.z})
				if d > r then r = d end
			end
			vol = { id = world.VolumeType.SPHERE,
					params = { point = self.point, radius = r } }
		end

		world.searchObjects(Object.Category.SCENERY, vol, function(o)
			if o then
				local d = o:getDesc()
				if d and d.attributes and d.attributes.Buildings then
					local p = o:getPoint()
					if self:isInside(p) then pts[#pts + 1] = p end
				end
			end
		end)

		buildingCache[self.name] = pts
		return pts
	end

	function CustomZone:draw(id, border, background)

		if not self.name:lower():find("hidden") then
			if self:isCircle() then
				trigger.action.circleToAll(-1, id, self.point, self.radius, border, background, 1)
			elseif self:isQuad() then
				trigger.action.quadToAll(-1, id, self.vertices[4], self.vertices[3], self.vertices[2], self.vertices[1], border, background, 1)
			end
		else
		end
	end

	INVALID_SPAWN_SUB_ZONES = INVALID_SPAWN_SUB_ZONES or {}
	function GetValidCords(zoneName, allowed, attempts)
		local zone = getMooseZone(zoneName); if not zone then return nil end
		attempts = attempts or 100
		local found
		for _=1,attempts do
			local coord = zone:GetRandomCoordinate()
			if coord then
				local st = coord:GetSurfaceType()
				if st ~= land.SurfaceType.RUNWAY and (not allowed or allowed[st]) then found = coord; break end
			end
		end
		if found then return found end
		if not INVALID_SPAWN_SUB_ZONES[zoneName] then
			INVALID_SPAWN_SUB_ZONES[zoneName] = true
			env.info("[ZoneCommander] Blacklisted spawn sub-zone: "..tostring(zoneName))
			local list = {}
			for name,_ in pairs(INVALID_SPAWN_SUB_ZONES) do
				list[#list + 1] = name
			end
			table.sort(list)
			env.info("[ZoneCommander] Blacklisted spawn sub-zones ("..tostring(#list).."): "..table.concat(list, ", "))
		end
		if env.mission.theatre=="GermanyCW" then
			for _=1,attempts do
				local coord = zone:GetRandomCoordinate()
				if coord then return coord end
			end
		end
		env.info("GetValidCords: no valid coord in "..tostring(zoneName))
		return nil
	end

	function CustomZone:getRandomSpawnZone()
		local spawnZones = collectSubZones(self.name)
		if #spawnZones == 0 then return nil end
		local choice = fhRand(1, #spawnZones)
		return spawnZones[choice]
	end

	local function shouldHideSamOnMFD()
		local mode = HideSAMOnMFD
		if mode == true then return true end
		if mode == false then return false end
		if mode == "random" then return fhRand(1, 2) == 1 end
		return true
	end

	local function isSamMfdHiddenGroup(grname)
		return grname and (grname:find("Red SAM") or grname:find("blueHAWK") or grname:find("bluePD") or grname:find("bluePATRIOT"))
	end

	local function zoneNameContainsToken(zoneName, token)
		if not token or token == "" then return false end
		local zoneText = tostring(zoneName or "")
		if zoneText == "" then return false end
		local tokenText = tostring(token)
		if string.find(zoneText, tokenText, 1, true) then return true end
		return string.find(string.lower(zoneText), string.lower(tokenText), 1, true) ~= nil
	end

	function isCarrierZoneName(zoneName)
		if zoneNameContainsToken(zoneName, "carrier") then return true end
		local extraCarrierZoneNames = GlobalSettings.carrierZoneNames
		if type(extraCarrierZoneNames) == "table" then
			for _, token in ipairs(extraCarrierZoneNames) do
				if zoneNameContainsToken(zoneName, token) then
					return true
				end
			end
		end
		return false
	end

function SpawnCustom(grname, zoneName)
	spawnCounter[grname] = (spawnCounter[grname] or 0) + 1
	local alias = string.format("%s # %d", grname, spawnCounter[grname])

	local grp = GROUP:FindByName(grname)
	local tpl = grp and grp:GetTemplate()
	if tpl then
		tpl = (UTILS and UTILS.DeepCopy) and UTILS.DeepCopy(tpl) or tpl
	else
		tpl = ResolveNamedGroupTemplate(grname)
	end
	if grp then grp:Destroy() end
	if not tpl then return nil end

	local isCarrierZone = isCarrierZoneName(zoneName)
	local gr

	if zoneName then
		local allowed = isCarrierZone and {
		[land.SurfaceType.WATER] = true,
		[land.SurfaceType.SHALLOW_WATER] = true
		} or {
		[land.SurfaceType.LAND] = true,
		[land.SurfaceType.ROAD] = true
		}

		local spawn = SPAWN:NewFromTemplate(tpl, grname, alias, true):InitSkill("Excellent")
		if (not grname:find("Red SAM") or grname:find("Dog Ear")) and not grname:find("bluePD") and not grname:find("blueHAWK") and not grname:find("bluePATRIOT") then
		spawn = isCarrierZone and spawn:InitRandomizeUnits(true, 1500, 1000) or spawn:InitRandomizeUnits(true, 100, 30):InitHeading(1, 359)
		end
		if isSamMfdHiddenGroup(grname) and shouldHideSamOnMFD() then
		spawn = spawn:InitHiddenOnMFD()
		end
		if grname:find("IsNotShown") or grname:find("Red EWR") then
		spawn = spawn:InitHiddenOnMap(true)
		end
		local tries = 0
		while tries < 10 and not gr do
			local coord = zoneName and GetValidCords(zoneName, allowed)
			if coord then
			gr = spawn:SpawnFromCoordinate(coord)
			end
			tries = tries + 1
		end
		return gr
		end
	end


	USED_SUB_ZONES = USED_SUB_ZONES or {}

	function CustomZone:getRandomUnusedSpawnZone(markUsed)
		if markUsed == nil then markUsed = true end
		self.usedSpawnZones = self.usedSpawnZones or {}
		local all = {}
		for _, zname in ipairs(collectSubZones(self.name)) do
			if not INVALID_SPAWN_SUB_ZONES[zname] then
				all[#all + 1] = zname
			end
		end
		local unused = {}
		for _, zname in ipairs(all) do
			if not self.usedSpawnZones[zname] and not USED_SUB_ZONES[zname] then
				unused[#unused + 1] = zname
			end
		end
		if #unused == 0 then
			self.usedSpawnZones = {}
			return nil
		end
		local pool = (#unused > 0) and unused or all
		local selected = pool[fhRand(1, #pool)]
		if markUsed then
			self.usedSpawnZones[selected] = true
			USED_SUB_ZONES[selected]      = true
		end
		return selected
	end
	
	spawnCounter = spawnCounter or {}

	local function isStrategicSamGroup(grname)
		if not grname then return false end
		local n = grname:lower()
		return n:find("sa%-2", 1, false) or n:find("sa%-3", 1, false)
			or n:find("sa%-6", 1, false) or n:find("sa%-10", 1, false)
			or n:find("sa%-11", 1, false) or n:find("bluepd", 1, false)
			or n:find("bluehawk", 1, false)
	end

	local function getSamSubZones(zoneName, used)
		local samZones, samUnused = {}, {}
		if not zoneByName then buildZoneByName() end
		local prefix = zoneName:lower() .. "-sam-"
		for zname, _ in pairs(zoneByName or {}) do
			if zname:lower():sub(1, #prefix) == prefix and not INVALID_SPAWN_SUB_ZONES[zname] then
				samZones[#samZones + 1] = zname
				if not (used and used[zname]) and not USED_SUB_ZONES[zname] then
					samUnused[#samUnused + 1] = zname
				end
			end
		end
		return samZones, samUnused
	end

	local function filterOutSamZones(zoneName, zones)
		local filtered = {}
		local prefix = zoneName:lower() .. "-sam-"
		for _, z in ipairs(zones) do
			if not z:lower():find(prefix, 1, true) then
				filtered[#filtered + 1] = z
			end
		end
		return filtered
	end


	function CustomZone:spawnGroup(grname, forceFirst)
	if not grname or type(grname)~="string" then
		trigger.action.outText(L10N:Get("SPAWN_INVALID_GROUP_NAME"),5)
		return nil
	end

	if grname:find("Fixed") then
		local grp = GROUP:FindByName(grname)
		if not grp then
			trigger.action.outText(L10N:Format("SPAWN_MISSING_UPGRADE_GROUP", tostring(grname), tostring(self.name)), 10)
			MISSING_GROUPS[grname] = true
		end
		local tpl = grp and grp:GetTemplate()
		if not tpl then
			local db = _DATABASE.Templates.Groups[grname]
			if not db or not db.Template then
				env.info("Fixed group template missing: "..tostring(grname).." in zone "..tostring(self.name))
				MISSING_GROUPS[grname] = true
				return nil
			end
			tpl = UTILS.DeepCopy(db.Template)
		end
		if grp and grp:IsAlive() then grp:Destroy() end
		local spawn = SPAWN:NewFromTemplate(tpl, grname, nil, true)
		if isSamMfdHiddenGroup(grname) and shouldHideSamOnMFD() then
			spawn = spawn:InitHiddenOnMFD()
		end
		local g = spawn:Spawn()
		return g and { name = g:GetName() } or trigger.action.outText(L10N:Format("SPAWN_FAILED_GROUP_IN_ZONE", grname, self.name),10)
	end

	local all    = {}
	for _, z in ipairs(collectSubZones(self.name)) do
		if not INVALID_SPAWN_SUB_ZONES[z] then
			all[#all + 1] = z
		end
	end
	local unused = {}
	for _, z in ipairs(all) do
			if not INVALID_SPAWN_SUB_ZONES[z] and not (self.usedSpawnZones and self.usedSpawnZones[z]) and not USED_SUB_ZONES[z] then
					unused[#unused + 1] = z
			end
	end
	local zonePool = nil
	if isStrategicSamGroup(grname) then
		local samAll, samUnused = getSamSubZones(self.name, self.usedSpawnZones)
		if #samAll > 0 then
			zonePool = (#samUnused > 0) and samUnused or samAll
		end
	end
	if not zonePool then
		local filteredAll = filterOutSamZones(self.name, all)
		local filteredUnused = filterOutSamZones(self.name, unused)
		zonePool = (#filteredUnused > 0) and filteredUnused or filteredAll
	end
	if #zonePool==0 then zonePool[#zonePool+1]=self.name end

	while #zonePool>0 do
		local idx       = fhRand(1, #zonePool)
		local spawnzone = table.remove(zonePool, idx)
		local g         = SpawnCustom(grname, spawnzone)
		if g then
		self.usedSpawnZones            = self.usedSpawnZones or {}
		self.usedSpawnZones[spawnzone] = true
		USED_SUB_ZONES[spawnzone]      = true
		return { name = g:GetName() }
		end
	end

	trigger.action.outText(L10N:Format("SPAWN_FAILED_GROUP_IN_ZONE", grname, self.name),5)
	env.info("Failed to spawn group: "..grname.." in zone "..self.name)
	return nil
	end

	function CustomZone:clearUsedSpawnZones(zone)
		local prefix = zone or self.name
		for z,_ in pairs(USED_SUB_ZONES) do
			if z:sub(1,#prefix+1) == prefix.."-" then
				USED_SUB_ZONES[z] = nil
			end
		end
	end
end

