	local function _zoneIntelCountLabel(n, singular, plural, translator)
		local T = translator or L10N
		local count = n or 0
		local keySet = _zoneIntelCountLabelKeys[singular] or _zoneIntelCountLabelKeys[plural]
		if keySet then
			return T:Format(count == 1 and keySet.one or keySet.many, count)
		end
		if count == 1 then
			return "1 " .. singular
		end
		return tostring(count) .. " " .. plural
	end

	local function _zoneIntelBuiltEntryName(k, v)
		if type(v) == "string" then return v end
		if type(v) == "table" and type(v.name) == "string" then return v.name end
		if type(k) == "string" then return k end
		return nil
	end

	local function _zoneIntelNormalizeBuiltName(name)
		if type(name) ~= "string" then return "" end
		local clean = name:gsub("%s*#%s*%d+$", "")
		clean = clean:gsub("^%s*[Ff]ixed%s+", "")
		clean = clean:gsub("%s+[Ff]ixed%s+", " ")
		clean = clean:gsub("%s+[Ff]ixed$", "")
		clean = clean:gsub("%s%s+", " ")
		clean = clean:gsub("^%s+", "")
		clean = clean:gsub("%s+$", "")
		return clean
	end

	function _zoneIntelMainZoneFromSubZone(zoneSub)
		if type(zoneSub) ~= "string" then return nil end
		return zoneSub:gsub("%-%d+$", "")
	end

	local function _zoneIntelMatchLongSiteName(lowerName)
		if lowerName:find("red sam sa%-10", 1, false) then return "SA-10" end
		if lowerName:find("red sam sa%-11", 1, false) then return "SA-11" end
		if lowerName:find("red sam sa%-6", 1, false) then return "SA-6" end
		if lowerName:find("red sam sa%-5", 1, false) then return "SA-5" end
		if lowerName:find("red sam sa%-3", 1, false) then return "SA-3" end
		if lowerName:find("red sam sa%-2", 1, false) then return "SA-2" end
		return nil
	end

	local function _zoneIntelMatchShoradName(lowerName)
		if lowerName:find("red sam shorad pantsir", 1, false) then return "Pantsir S1" end
		if lowerName:find("red sam shorad sa%-15", 1, false) then return "SA-15" end
		if lowerName:find("red sam shorad tor m2", 1, false) then return "Tor M2" end
		if lowerName:find("red sam shorad sa%-19", 1, false) then return "SA-19" end
		if lowerName:find("red sam shorad sa%-13", 1, false) then return "SA-13" end
		if lowerName:find("red sam shorad sa%-9", 1, false) then return "SA-9" end
		if lowerName:find("red sam shorad sa%-8", 1, false) then return "SA-8" end
		return nil
	end

	local function _zoneIntelIsArmorGroupName(lowerName)
		return lowerName:find("armour", 1, true) ~= nil
			or lowerName:find("armor", 1, true) ~= nil
	end

	local function _zoneIntelIsAAAGroupName(lowerName)
		return lowerName:find("aaa", 1, true) ~= nil
	end

	local function _zoneIntelIsArtilleryGroupName(lowerName)
		return lowerName:find("artillery", 1, true) ~= nil
			or lowerName:find("arty", 1, true) ~= nil
	end

	local function _zoneIntelIsGroundForcesName(lowerName)
		return lowerName:find("^enemy task forces", 1, false) ~= nil
			or lowerName:find("^enemy ground forces", 1, false) ~= nil
	end

	local function _zoneIntelContactBaseName(name)
		local base = _zoneIntelNormalizeBuiltName(name or "")
		base = base:gsub("[%s_%-]+%d+$", "")
		base = base:gsub("%s%s+", " ")
		base = base:gsub("^%s+", "")
		base = base:gsub("%s+$", "")
		if base == "" then
			base = _zoneIntelNormalizeBuiltName(name or "")
		end
		return base
	end

	local function _zoneIntelResolveStructureContactName(zoneObj, builtName, cleanName, staticObj)
		local fallbackName = _zoneIntelContactBaseName(cleanName)
		if not UseStatics or type(zoneObj) ~= "table" then
			return fallbackName
		end

		if zoneObj._getTrackedStaticBaseName then
			local trackedBaseName = zoneObj:_getTrackedStaticBaseName(builtName) or zoneObj:_getTrackedStaticBaseName(cleanName)
			if trackedBaseName and trackedBaseName ~= "" then
				return _zoneIntelContactBaseName(trackedBaseName)
			end
		end

		if type(zoneObj.newStatics) ~= "table" or not staticObj or not staticObj.getPoint then
			return fallbackName
		end

		local staticPoint = staticObj:getPoint()
		if type(staticPoint) ~= "table" or staticPoint.x == nil or staticPoint.z == nil then
			return fallbackName
		end

		local staticType = staticObj.getTypeName and tostring(staticObj:getTypeName() or ""):lower() or ""
		local bestAnyName, bestTypeName = nil, nil
		local bestAnyDistSq, bestTypeDistSq = nil, nil

		for _, data in ipairs(zoneObj.newStatics) do
			local candidateName = type(data) == "table" and data.name or data
			local candidatePoint = type(data) == "table" and data.point or nil
			if type(candidateName) == "string" and type(candidatePoint) == "table" and candidatePoint.x ~= nil and candidatePoint.z ~= nil then
				local dx = staticPoint.x - candidatePoint.x
				local dz = staticPoint.z - candidatePoint.z
				local distSq = dx * dx + dz * dz
				if not bestAnyDistSq or distSq < bestAnyDistSq then
					bestAnyDistSq = distSq
					bestAnyName = candidateName
				end
				local candidateType = type(data) == "table" and tostring(data.type or ""):lower() or ""
				if staticType ~= "" and candidateType ~= "" and candidateType == staticType then
					if not bestTypeDistSq or distSq < bestTypeDistSq then
						bestTypeDistSq = distSq
						bestTypeName = candidateName
					end
				end
			end
		end

		if bestTypeName and bestTypeDistSq and bestTypeDistSq <= (25 * 25) then
			return _zoneIntelContactBaseName(bestTypeName)
		end
		if bestAnyName and bestAnyDistSq and bestAnyDistSq <= (15 * 15) then
			return _zoneIntelContactBaseName(bestAnyName)
		end
		return fallbackName
	end

	local function _zoneIntelMapInc(mapTable, key, amount)
		if type(mapTable) ~= "table" or type(key) ~= "string" or key == "" then return end
		mapTable[key] = (mapTable[key] or 0) + (amount or 1)
		if mapTable[key] <= 0 then
			mapTable[key] = nil
		end
	end

	local function _zoneIntelSyncBuiltIndex(state, zoneObj)
		if type(state) ~= "table" or type(zoneObj) ~= "table" or type(zoneObj.built) ~= "table" then
			return {}
		end
		state.builtIndex = state.builtIndex or {}
		local index = state.builtIndex
		local seen = {}
		for k, v in pairs(zoneObj.built) do
			local builtName = _zoneIntelBuiltEntryName(k, v)
			if type(builtName) == "string" and builtName ~= "" then
				seen[builtName] = true
				local cleanName = _zoneIntelNormalizeBuiltName(builtName)
				local existing = index[builtName]
				if type(existing) ~= "table" then
					index[builtName] = {
						name = builtName,
						cleanName = cleanName,
						lowerName = cleanName:lower(),
					}
				elseif existing.cleanName ~= cleanName then
					existing.cleanName = cleanName
					existing.lowerName = cleanName:lower()
				end
			end
		end
		for name, _ in pairs(index) do
			if not seen[name] then
				index[name] = nil
			end
		end
		return index
	end

	local function _zoneIntelGroupPoint(grp)
		if not grp or not grp:isExist() then return nil end
		for _, u in ipairs(grp:getUnits() or {}) do
			if u:isExist() and u:getLife() >= 1 then
				return u:getPoint()
			end
		end
		return nil
	end

	local function _zoneIntelGroupHasAliveUnits(grp)
		if not grp or not grp:isExist() then return false end
		for _, u in ipairs(grp:getUnits() or {}) do
			if u:isExist() and u:getLife() >= 1 then
				return true
			end
		end
		return false
	end

	local function _zoneIntelGroupHasAliveTracker(grp, trackerPattern)
		if not grp or not trackerPattern then return false end
		for _, u in ipairs(grp:getUnits() or {}) do
			if u:isExist() and u:getLife() >= 1 then
				local typeName = tostring(u:getTypeName() or ""):lower()
				if typeName:find(trackerPattern, 1, false) or typeName:find(trackerPattern, 1, true) then
					return true
				end
			end
		end
		return false
	end

	local function _zoneIntelGroupHasAliveManpad(grp)
		if not grp then return false end
		for _, u in ipairs(grp:getUnits() or {}) do
			if u:isExist() and u:getLife() >= 1 then
				local typeName = tostring(u:getTypeName() or "")
				local lowerType = typeName:lower()
				if lowerType:find("manpad", 1, true) then
					return true
				end
				local renamed = renameType(typeName)
				if type(renamed) == "string" and renamed:lower():find("manpad", 1, true) then
					return true
				end
			end
		end
		return false
	end

	local function _zoneIntelAnalyzeAAAGroup(grp)
		if not grp then return nil end
		local aliveCount = 0
		local hasAliveShilka = false
		local hasAliveHeavyAAA = false
		local hasAliveFlakGun = false
		local hasAliveZu23AAA = false
		local hasAliveSon9 = false
		local hasAnySon9Seen = false

		for _, u in ipairs(grp:getUnits() or {}) do
			local typeName = tostring(u:getTypeName() or ""):lower()
			local isSon9 = typeName:find("son_9", 1, true) or typeName:find("son%-9", 1, false)
			if isSon9 then
				hasAnySon9Seen = true
			end

			if u:isExist() and u:getLife() >= 1 then
				aliveCount = aliveCount + 1
				if isSon9 then
					hasAliveSon9 = true
				end
				if typeName:find("shilka", 1, true) then
					hasAliveShilka = true
				end
				if typeName:find("zsu_57_2", 1, true) then
					hasAliveHeavyAAA = true
				end
				if typeName:find("zu[%s_%-]?23", 1, false) then
					hasAliveZu23AAA = true
				end
				if typeName:find("ks%-19", 1, false)
					or typeName:find("s%-60", 1, false) then
					hasAliveFlakGun = true
				end
			end
		end

		if aliveCount <= 0 then
			return nil
		end

		local subtype = "Other"
		if hasAliveFlakGun or hasAnySon9Seen then
			subtype = "Flak"
		elseif hasAliveHeavyAAA then
			subtype = "Heavy AAA"
		elseif hasAliveShilka then
			subtype = "Shilka"
		elseif hasAliveZu23AAA then
			subtype = "ZU-23 AAA"
		end

		local radarDestroyed = (subtype == "Flak") and (not hasAliveSon9)
		return { subtype = subtype, radarDestroyed = radarDestroyed }
	end

	local function _zoneIntelCanBroadcast(zoneName)
		if intelActiveZones[zoneName] ~= true then
			return false
		end

		if bc:_hasActiveJtacOnZone(zoneName) then
			return false
		end
		return true
	end

	function _zoneIntelBroadcast(zoneName, message, durationSec, soundFile)
		if type(message) ~= "string" or message == "" then return false end
		if not _zoneIntelCanBroadcast(zoneName) then return false end
		if soundFile then trigger.action.outSoundForCoalition(2, soundFile) end
		trigger.action.outTextForCoalition(2, message,durationSec or 15)
		return true
	end

	local function _zoneIntelCollectSamEntries(snapshot, translator)
		local T = translator or L10N
		local entries = {}
		for _, siteName in ipairs(_zoneIntelLongSiteOrder) do
			local site = snapshot.longSites and snapshot.longSites[siteName]
			if site and site.alive then
				if site.degraded then
					if siteName == "SA-6" then
						entries[#entries + 1] = siteName .. T:Get("INTEL_SAM_STR_DESTROYED_SUFFIX")
					else
						entries[#entries + 1] = siteName .. T:Get("INTEL_SAM_TR_DESTROYED_SUFFIX")
					end
				else
					entries[#entries + 1] = siteName
				end
			end
		end
		for _, shoradName in ipairs(_zoneIntelShoradOrder) do
			if snapshot.shorad and snapshot.shorad[shoradName] then
				entries[#entries + 1] = shoradName
			end
		end
		return entries
	end

	local function _zoneIntelBuildGroundForcesText(snapshot, translator)
		local counts = snapshot.counts or {}
		local ground = counts.ground or 0
		local groundWithManpad = counts.groundWithManpad or 0

		if ground <= 0 then
			return nil
		end
		if groundWithManpad > 0 then
			local groundParts = {}
			groundParts[#groundParts + 1] = _zoneIntelCountLabel(groundWithManpad, "ground forces with MANPAD", "ground forces with MANPAD", translator)
			local plainGround = math.max(0, ground - groundWithManpad)
			if plainGround > 0 then
				groundParts[#groundParts + 1] = _zoneIntelCountLabel(plainGround, "ground forces group", "ground forces groups", translator)
			end
			return table.concat(groundParts, ", ")
		end
		return _zoneIntelCountLabel(ground, "ground forces group", "ground forces groups", translator)
	end

	local function _zoneIntelBuildGroundCategoryLines(snapshot, isRemaining, translator)
		local T = translator or L10N
		local lines = {}
		local counts = snapshot.counts or {}
		local armor = counts.armor or 0
		local artillery = counts.artillery or 0
		local groundText = _zoneIntelBuildGroundForcesText(snapshot, T)

		local armorLineKey = isRemaining and "INTEL_ARMOR_REMAINING_LINE" or "INTEL_ARMOR_LINE"
		local artilleryLineKey = isRemaining and "INTEL_ARTILLERY_REMAINING_LINE" or "INTEL_ARTILLERY_LINE"
		local groundLineKey = isRemaining and "INTEL_GROUND_FORCES_REMAINING_LINE" or "INTEL_GROUND_FORCES_LINE"

		if armor > 0 then
			lines[#lines + 1] = T:Format(armorLineKey, _zoneIntelCountLabel(armor, "armored group", "armored groups", T))
		end
		if artillery > 0 then
			lines[#lines + 1] = T:Format(artilleryLineKey, _zoneIntelCountLabel(artillery, "artillery group", "artillery groups", T))
		end
		if groundText then
			lines[#lines + 1] = T:Format(groundLineKey, groundText)
		elseif #lines == 0 then
			lines[#lines + 1] = T:Format(groundLineKey, T:Get("INTEL_GROUND_FORCES_NONE"))
		end
		return lines
	end

	local function _zoneIntelBuildAAALine(lineKey, snapshot, translator)
		local T = translator or L10N
		local counts = snapshot.counts or {}
		local total = counts.aaaTotal or 0
		local shilka = counts.aaaShilka or 0
		local heavy = counts.aaaHeavy or 0
		local flak = counts.aaaFlak or 0
		local zu23 = counts.aaaZu23 or 0
		local other = counts.aaaOther or 0
		local flakRadarDestroyed = counts.aaaFlakRadarDestroyed or 0

		if total <= 0 then
			return nil
		end

		local sub = {}
		if shilka > 0 then
			sub[#sub + 1] = _zoneIntelCountLabel(shilka, "Shilka group", "Shilka groups", T)
		end
		if heavy > 0 then
			sub[#sub + 1] = _zoneIntelCountLabel(heavy, "heavy AAA group", "heavy AAA groups", T)
		end
		if flak > 0 then
			local flakText = _zoneIntelCountLabel(flak, "Flak group", "Flak groups", T)
			if flakRadarDestroyed > 0 then
				if flakRadarDestroyed >= flak then
					flakText = flakText .. T:Get("INTEL_RADAR_DESTROYED_SUFFIX")
				else
					flakText = flakText .. T:Format("INTEL_RADAR_DESTROYED_COUNT_SUFFIX", flakRadarDestroyed)
				end
			end
			sub[#sub + 1] = flakText
		end
		if zu23 > 0 then
			sub[#sub + 1] = _zoneIntelCountLabel(zu23, "ZU-23 AAA group", "ZU-23 AAA groups", T)
		end
		if other > 0 then
			sub[#sub + 1] = _zoneIntelCountLabel(other, "other AAA group", "other AAA groups", T)
		end

		if #sub > 0 then
			return T:Format(lineKey, table.concat(sub, ", "))
		end
		return T:Format(lineKey, _zoneIntelCountLabel(total, "AAA group", "AAA groups", T))
	end

	local function _zoneIntelSortedCountedNames(countMap)
		local names = {}
		for name, count in pairs(countMap or {}) do
			local n = count or 0
			if n > 0 and type(name) == "string" and name ~= "" then
				if n > 1 then
					names[#names + 1] = name .. " (" .. tostring(n) .. ")"
				else
					names[#names + 1] = name
				end
			end
		end
		table.sort(names)
		return names
	end

	local function _zoneIntelBuildSnapshot(zoneName, state)
		local snapshot = {
			longSites = {},
			shorad = {},
			aaaFlakRadarByGroup = {},
			counts = {
				armor = 0,
				artillery = 0,
				ground = 0,
				groundWithManpad = 0,
				aaaTotal = 0,
				aaaShilka = 0,
				aaaHeavy = 0,
				aaaFlak = 0,
				aaaZu23 = 0,
				aaaOther = 0,
				aaaFlakRadarDestroyed = 0,
			},
			structures = {},
			additionalContacts = {},
		}
		for _, siteName in ipairs(_zoneIntelLongSiteOrder) do
			snapshot.longSites[siteName] = { alive = false, degraded = false, _trackerAlive = false }
		end

		local z = bc:getZoneByName(zoneName) or bc.indexedZones[zoneName]
		if not z or type(z.built) ~= "table" then
			return snapshot
		end

		local owningState = state or {}
		local builtIndex = _zoneIntelSyncBuiltIndex(owningState, z)

		for builtName, idx in pairs(builtIndex) do
			local cleanName = (type(idx) == "table" and idx.cleanName) or _zoneIntelNormalizeBuiltName(builtName)
			local lowerName = (type(idx) == "table" and idx.lowerName) or cleanName:lower()
			local matched = false
			local aliveResolved = false

			local grp = Group.getByName(builtName)
			if grp and grp:isExist() and grp:getSize() > 0 and _zoneIntelGroupHasAliveUnits(grp) then
				aliveResolved = true
				local longSite = _zoneIntelMatchLongSiteName(lowerName)
				local shorad = _zoneIntelMatchShoradName(lowerName)

				if longSite then
					local siteState = snapshot.longSites[longSite]
					if siteState then
						matched = true
						siteState.alive = true
						local trackerPattern = _zoneIntelLongSiteTrackerPattern[longSite]
						if trackerPattern and _zoneIntelGroupHasAliveTracker(grp, trackerPattern) then
							siteState._trackerAlive = true
						end
					end
				end

				if shorad then
					matched = true
					snapshot.shorad[shorad] = true
				end

				if _zoneIntelIsArmorGroupName(lowerName) then
					matched = true
					snapshot.counts.armor = snapshot.counts.armor + 1
				elseif _zoneIntelIsAAAGroupName(lowerName) then
					matched = true
					snapshot.counts.aaaTotal = snapshot.counts.aaaTotal + 1
					local aaaInfo = _zoneIntelAnalyzeAAAGroup(grp)
					if aaaInfo and aaaInfo.subtype == "Shilka" then
						snapshot.counts.aaaShilka = snapshot.counts.aaaShilka + 1
					elseif aaaInfo and aaaInfo.subtype == "Heavy AAA" then
						snapshot.counts.aaaHeavy = snapshot.counts.aaaHeavy + 1
					elseif aaaInfo and aaaInfo.subtype == "Flak" then
						snapshot.counts.aaaFlak = snapshot.counts.aaaFlak + 1
						snapshot.aaaFlakRadarByGroup[builtName] = aaaInfo.radarDestroyed == true
						if aaaInfo.radarDestroyed then
							snapshot.counts.aaaFlakRadarDestroyed = snapshot.counts.aaaFlakRadarDestroyed + 1
						end
					elseif aaaInfo and aaaInfo.subtype == "ZU-23 AAA" then
						snapshot.counts.aaaZu23 = snapshot.counts.aaaZu23 + 1
					else
						snapshot.counts.aaaOther = snapshot.counts.aaaOther + 1
					end
				elseif _zoneIntelIsArtilleryGroupName(lowerName) then
					matched = true
					snapshot.counts.artillery = snapshot.counts.artillery + 1
				elseif _zoneIntelIsGroundForcesName(lowerName) then
					matched = true
					snapshot.counts.ground = snapshot.counts.ground + 1
					if _zoneIntelGroupHasAliveManpad(grp) then
						snapshot.counts.groundWithManpad = snapshot.counts.groundWithManpad + 1
					end
				elseif _zoneIntelGroupHasAliveManpad(grp) then
					matched = true
					snapshot.counts.ground = snapshot.counts.ground + 1
					snapshot.counts.groundWithManpad = snapshot.counts.groundWithManpad + 1
				end
			else
				local st = StaticObject.getByName(builtName)
				if st and st:isExist() and st:getLife() >= 1 then
					aliveResolved = true
					local longSite = _zoneIntelMatchLongSiteName(lowerName)
					local shorad = _zoneIntelMatchShoradName(lowerName)
					if longSite then
						local siteState = snapshot.longSites[longSite]
						if siteState then
							matched = true
							siteState.alive = true
							local trackerPattern = _zoneIntelLongSiteTrackerPattern[longSite]
							if trackerPattern then
								local stTypeName = tostring(st:getTypeName() or ""):lower()
								if stTypeName:find(trackerPattern, 1, false) or stTypeName:find(trackerPattern, 1, true) then
									siteState._trackerAlive = true
								end
							end
						end
					end
					if shorad then
						matched = true
						snapshot.shorad[shorad] = true
					end
					if not matched then
						local structureBase = _zoneIntelResolveStructureContactName(z, builtName, cleanName, st)
						_zoneIntelMapInc(snapshot.structures, structureBase, 1)
						matched = true
					end
				end
			end

			if aliveResolved and not matched and cleanName ~= "" then
				local fallbackName = _zoneIntelContactBaseName(cleanName)
				_zoneIntelMapInc(snapshot.additionalContacts, fallbackName, 1)
			end
		end

		for _, siteName in ipairs(_zoneIntelLongSiteOrder) do
			local siteState = snapshot.longSites[siteName]
			if siteState and siteState.alive then
				siteState.degraded = not siteState._trackerAlive
			else
				siteState.degraded = false
			end
			siteState._trackerAlive = nil
		end
		return snapshot
	end

	local function _zoneIntelBuildStartupMessage(zoneName, snapshot, translator)
		local T = translator or L10N
		local samEntries = _zoneIntelCollectSamEntries(snapshot, T)
		local aaaLine = _zoneIntelBuildAAALine("INTEL_AAA_LINE", snapshot, T)
		local structureContacts = _zoneIntelSortedCountedNames(snapshot.structures)
		local additionalContacts = _zoneIntelSortedCountedNames(snapshot.additionalContacts)
		local groundLines = _zoneIntelBuildGroundCategoryLines(snapshot, false, T)

		local msg = T:Format("INTEL_HEADER", tostring(zoneName))
		if #samEntries > 0 then
			msg = msg .. "\n" .. T:Format("INTEL_IDENTIFIED_SAMS", table.concat(samEntries, ", "))
		end
		for _, line in ipairs(groundLines) do
			msg = msg .. "\n" .. line
		end
		if aaaLine then
			msg = msg .. "\n" .. aaaLine
		end
		if #structureContacts > 0 then
			msg = msg .. "\n" .. T:Format("INTEL_STRUCTURES", table.concat(structureContacts, ", "))
		end
		if #additionalContacts > 0 then
			msg = msg .. "\n" .. T:Format("INTEL_ADDITIONAL_CONTACTS", table.concat(additionalContacts, ", "))
		end
		return msg
	end

	local function _zoneIntelIsZoneActiveForMenu(zoneName, now)
		if intelActiveZones[zoneName] ~= true then return false end
		local tnow = now or timer.getTime()
		local exp = intelExpireTimes[zoneName] or 0
		return exp <= 0 or exp > tnow
	end

	function _zoneIntelGetActiveZoneNamesForMenu(now)
		local names = {}
		local tnow = now or timer.getTime()
		for zoneName in pairs(zoneIntels) do
			if _zoneIntelIsZoneActiveForMenu(zoneName, tnow) then
				names[#names + 1] = zoneName
			end
		end
		table.sort(names)
		return names
	end

	function _zoneIntelBuildCurrentReport(zoneName, translator)
		if not _zoneIntelIsZoneActiveForMenu(zoneName, timer.getTime()) then return nil end
		local state = zoneIntels[zoneName]
		state.builtIndex = state.builtIndex or {}
		local snapshot = _zoneIntelBuildSnapshot(zoneName, state)
		return _zoneIntelBuildStartupMessage(zoneName, snapshot, translator)
	end

	local function _zoneIntelBuildUpdateMessage(zoneName, oldSnapshot, newSnapshot)
		if type(oldSnapshot) ~= "table" or type(newSnapshot) ~= "table" then return nil end
		local updates = {}
		local hasDetectedOrRepaired = false

		for _, siteName in ipairs(_zoneIntelLongSiteOrder) do
			local oldState = (oldSnapshot.longSites and oldSnapshot.longSites[siteName]) or { alive = false, degraded = false }
			local newState = (newSnapshot.longSites and newSnapshot.longSites[siteName]) or { alive = false, degraded = false }

			if oldState.alive and not newState.alive then
				updates[#updates + 1] = L10N:Format("INTEL_SITE_DESTROYED", siteName)
			elseif (not oldState.alive) and newState.alive then
				updates[#updates + 1] = L10N:Format("INTEL_SITE_DETECTED", siteName)
				hasDetectedOrRepaired = true
			end

			if oldState.alive and newState.alive and (oldState.degraded ~= newState.degraded) then
				if newState.degraded then
					if siteName == "SA-6" then
						updates[#updates + 1] = L10N:Format("INTEL_STR_DESTROYED_DEGRADED", siteName)
					else
						updates[#updates + 1] = L10N:Format("INTEL_TR_DESTROYED_DEGRADED", siteName)
					end
				else
					if siteName == "SA-6" then
						updates[#updates + 1] = L10N:Format("INTEL_ENEMY_REPAIRED_STR", siteName)
					else
						updates[#updates + 1] = L10N:Format("INTEL_ENEMY_REPAIRED_TR", siteName)
					end
					hasDetectedOrRepaired = true
				end
			end
		end

		for _, shoradName in ipairs(_zoneIntelShoradOrder) do
			local oldPresent = oldSnapshot.shorad and oldSnapshot.shorad[shoradName] == true
			local newPresent = newSnapshot.shorad and newSnapshot.shorad[shoradName] == true
			if oldPresent and not newPresent then
				updates[#updates + 1] = L10N:Format("INTEL_SITE_DESTROYED", shoradName)
			elseif (not oldPresent) and newPresent then
				updates[#updates + 1] = L10N:Format("INTEL_SITE_DETECTED", shoradName)
				hasDetectedOrRepaired = true
			end
		end

		local oldCounts = oldSnapshot.counts or {}
		local newCounts = newSnapshot.counts or {}

		local function addCountDelta(labelSingular, labelPlural, oldValue, newValue, allowDetected)
			local ov = oldValue or 0
			local nv = newValue or 0
			local delta = nv - ov
			if delta < 0 then
				updates[#updates + 1] = L10N:Format("INTEL_COUNT_DESTROYED", _zoneIntelCountLabel(math.abs(delta), labelSingular, labelPlural))
			elseif delta > 0 and allowDetected ~= false then
				updates[#updates + 1] = L10N:Format("INTEL_COUNT_DETECTED", _zoneIntelCountLabel(delta, labelSingular, labelPlural))
				hasDetectedOrRepaired = true
			end
		end

		addCountDelta("armored group", "armored groups", oldCounts.armor, newCounts.armor, false)
		addCountDelta("Flak group", "Flak groups", oldCounts.aaaFlak, newCounts.aaaFlak, false)
		addCountDelta("heavy AAA group", "heavy AAA groups", oldCounts.aaaHeavy, newCounts.aaaHeavy, false)
		addCountDelta("ZU-23 AAA group", "ZU-23 AAA groups", oldCounts.aaaZu23, newCounts.aaaZu23, false)
		addCountDelta("other AAA group", "other AAA groups", oldCounts.aaaOther, newCounts.aaaOther, false)
		addCountDelta("artillery group", "artillery groups", oldCounts.artillery, newCounts.artillery, false)
		addCountDelta("ground forces group", "ground forces groups", oldCounts.ground, newCounts.ground, false)
		local oldFlakRadarByGroup = oldSnapshot.aaaFlakRadarByGroup or {}
		local newFlakRadarByGroup = newSnapshot.aaaFlakRadarByGroup or {}
		local flakRadarDestroyedDelta = 0
		local flakRadarRepairedDelta = 0
		for groupName, oldDestroyed in pairs(oldFlakRadarByGroup) do
			local newDestroyed = newFlakRadarByGroup[groupName]
			if newDestroyed ~= nil then
				if oldDestroyed and not newDestroyed then
					flakRadarRepairedDelta = flakRadarRepairedDelta + 1
				elseif (not oldDestroyed) and newDestroyed then
					flakRadarDestroyedDelta = flakRadarDestroyedDelta + 1
				end
			end
		end
		if flakRadarDestroyedDelta > 0 then
			updates[#updates + 1] = L10N:Format("INTEL_COUNT_DESTROYED", _zoneIntelCountLabel(flakRadarDestroyedDelta, "Flak radar", "Flak radars"))
		end
		if flakRadarRepairedDelta > 0 then
			updates[#updates + 1] = L10N:Format("INTEL_ENEMY_REPAIRED_COUNT", _zoneIntelCountLabel(flakRadarRepairedDelta, "Flak radar", "Flak radars"))
			hasDetectedOrRepaired = true
		end

		local oldManpad = (oldCounts.groundWithManpad or 0) > 0
		local newManpad = (newCounts.groundWithManpad or 0) > 0
		if oldManpad and not newManpad then
			updates[#updates + 1] = L10N:Get("INTEL_MANPAD_NEUTRALIZED")
		elseif (not oldManpad) and newManpad then
			updates[#updates + 1] = L10N:Get("INTEL_MANPAD_IDENTIFIED")
			hasDetectedOrRepaired = true
		end

		local oldContacts = oldSnapshot.additionalContacts or {}
		local newContacts = newSnapshot.additionalContacts or {}
		local oldStructures = oldSnapshot.structures or {}
		local newStructures = newSnapshot.structures or {}
		local addedContacts = {}
		local removedContacts = {}
		for name, count in pairs(newContacts) do
			local oldCount = oldContacts[name] or 0
			local newCount = count or 0
			if newCount > oldCount then
				addedContacts[#addedContacts + 1] = { name = name, delta = newCount - oldCount }
			end
		end
		for name, count in pairs(oldContacts) do
			local oldCount = count or 0
			local newCount = newContacts[name] or 0
			if oldCount > newCount then
				removedContacts[#removedContacts + 1] = { name = name, delta = oldCount - newCount }
			end
		end
		table.sort(addedContacts, function(a, b) return tostring(a.name) < tostring(b.name) end)
		table.sort(removedContacts, function(a, b) return tostring(a.name) < tostring(b.name) end)
		for _, entry in ipairs(addedContacts) do
			updates[#updates + 1] = L10N:Format("INTEL_CONTACT_DETECTED", _zoneIntelCountLabel(entry.delta, "new contact", "new contacts"), entry.name)
			hasDetectedOrRepaired = true
		end
		for _, entry in ipairs(removedContacts) do
			updates[#updates + 1] = L10N:Format("INTEL_CONTACT_DESTROYED", _zoneIntelCountLabel(entry.delta, "contact", "contacts"), entry.name)
		end

		local addedStructures = {}
		local removedStructures = {}
		for name, count in pairs(newStructures) do
			local oldCount = oldStructures[name] or 0
			local newCount = count or 0
			if newCount > oldCount then
				addedStructures[#addedStructures + 1] = { name = name, delta = newCount - oldCount }
			end
		end
		for name, count in pairs(oldStructures) do
			local oldCount = count or 0
			local newCount = newStructures[name] or 0
			if oldCount > newCount then
				removedStructures[#removedStructures + 1] = { name = name, delta = oldCount - newCount }
			end
		end
		table.sort(addedStructures, function(a, b) return tostring(a.name) < tostring(b.name) end)
		table.sort(removedStructures, function(a, b) return tostring(a.name) < tostring(b.name) end)
		for _, entry in ipairs(addedStructures) do
			updates[#updates + 1] = L10N:Format("INTEL_STRUCTURE_CONTACT_DETECTED", _zoneIntelCountLabel(entry.delta, "structure contact", "structure contacts"), entry.name)
			hasDetectedOrRepaired = true
		end
		for _, entry in ipairs(removedStructures) do
			updates[#updates + 1] = L10N:Format("INTEL_STRUCTURE_DESTROYED", _zoneIntelCountLabel(entry.delta, "structure", "structures"), entry.name)
		end

		if #updates == 0 then
			return nil
		end

		if not hasDetectedOrRepaired then
			local samEntries = _zoneIntelCollectSamEntries(newSnapshot)
			if #samEntries > 0 then
				updates[#updates + 1] = L10N:Format("INTEL_REMAINING_SAMS", table.concat(samEntries, ", "))
			end

			local groundLines = _zoneIntelBuildGroundCategoryLines(newSnapshot, true)
			for _, line in ipairs(groundLines) do
				updates[#updates + 1] = line
			end
			local aaaRemainingLine = _zoneIntelBuildAAALine("INTEL_AAA_REMAINING_LINE", newSnapshot)
			if aaaRemainingLine then
				updates[#updates + 1] = aaaRemainingLine
			end

			local remainingStructures = _zoneIntelSortedCountedNames(newStructures)
			if #remainingStructures > 0 then
				updates[#updates + 1] = L10N:Format("INTEL_STRUCTURES_REMAINING", table.concat(remainingStructures, ", "))
			end

			local remainingContacts = _zoneIntelSortedCountedNames(newContacts)
			if #remainingContacts > 0 then
				updates[#updates + 1] = L10N:Format("INTEL_ADDITIONAL_CONTACTS_REMAINING", table.concat(remainingContacts, ", "))
			end
		end

		return L10N:Format("INTEL_UPDATE_HEADER", tostring(zoneName), table.concat(updates, "\n"))
	end

	local function _zoneIntelRoamGroupLabel(groupName)
		local cleanName = _zoneIntelNormalizeBuiltName(groupName)
		local lowerName = cleanName:lower()

		local longSite = _zoneIntelMatchLongSiteName(lowerName)
		if longSite then return longSite end

		local shorad = _zoneIntelMatchShoradName(lowerName)
		if shorad then return shorad end

		if lowerName:find("^red sam aaa", 1, false) then return "AAA" end
		if _zoneIntelIsArmorGroupName(lowerName) then return "armored group" end
		if _zoneIntelIsArtilleryGroupName(lowerName) then return "artillery group" end
		return nil
	end

	function _zoneIntelMaybeReportRoamMove(zoneName, groupName)
		if type(zoneName) ~= "string" or zoneName == "" then return end
		local label = _zoneIntelRoamGroupLabel(groupName)
		if not label then return end
		if not _zoneIntelCanBroadcast(zoneName) then return end

		local state = zoneIntels[zoneName]
		if type(state) ~= "table" then return end
		state.moveNoticeAtByGroup = state.moveNoticeAtByGroup or {}

		local now = timer.getTime()
		local cooldown = zoneIntelRoamMoveCooldownSec or 120
		local key = tostring(groupName or "")
		local last = state.moveNoticeAtByGroup[key] or 0
		if last > 0 and (now - last) < cooldown then
			return
		end

		state.moveNoticeAtByGroup[key] = now
		_zoneIntelBroadcast(zoneName, L10N:Format("INTEL_ON_MOVE", label, zoneName), 15)
	end

	function _zoneIntelRemoveMark(markId)
		if not markId then return end
		trigger.action.removeMark(markId)
	end

	local function _zoneIntelNewMarker(point, text)
		local coord = COORDINATE:NewFromVec3(point)
		local marker = MARKER:New(coord, tostring(text or ""))
		marker:ReadOnly()
		marker:ToCoalition(2)
		return marker
	end

	function _zoneIntelClearMarkers(state)
		if type(state) ~= "table" then return end
		if type(state.markerByKey) == "table" then
			for _, entry in pairs(state.markerByKey) do
				if type(entry) == "table" and entry.marker and entry.marker.Remove then
					entry.marker:Remove()
				elseif type(entry) == "number" then
					_zoneIntelRemoveMark(entry)
				end
			end
		end
		state.markerByKey = {}
	end

	function _zoneIntelRefreshMarkers(zoneName)
		local state = zoneIntels[zoneName]
		if type(state) ~= "table" then return end
		state.markerByKey = state.markerByKey or {}

		local z = bc:getZoneByName(zoneName) or bc.indexedZones[zoneName]
		if not z or type(z.built) ~= "table" then
			return
		end

		local seen = {}
		for k, v in pairs(z.built) do
			local builtName = _zoneIntelBuiltEntryName(k, v)
			if type(builtName) == "string" and builtName ~= "" then
				local markerKey = nil
				local point = nil

				local grp = Group.getByName(builtName)
				if grp and grp.isExist and grp:isExist() and grp.getSize and grp:getSize() > 0 then
					markerKey = "G:" .. builtName
					point = _zoneIntelGroupPoint(grp)
				else
					local st = StaticObject.getByName(builtName)
					local stLife = (st and st.isExist and st:isExist() and st.getLife and st:getLife()) or 0
					if st and st.getPoint and stLife >= 1 then
						markerKey = "S:" .. builtName
						point = st:getPoint()
					end
				end

				if markerKey and point then
					seen[markerKey] = true
					local entry = state.markerByKey[markerKey]
					if type(entry) ~= "table" then
						entry = { marker = nil, text = nil, x = nil, z = nil }
						state.markerByKey[markerKey] = entry
					end

					if not entry.marker then
						entry.marker = _zoneIntelNewMarker(point, builtName)
					else
						local moved = (entry.x == nil) or (entry.z == nil) or (math.abs((entry.x or 0) - point.x) > 1) or (math.abs((entry.z or 0) - point.z) > 1)
						local renamed = entry.text ~= builtName
						if moved then
							entry.marker:UpdateCoordinate(COORDINATE:NewFromVec3(point))
						end
						if renamed then
							entry.marker:UpdateText(builtName)
						end
					end
					entry.text = builtName
					entry.x = point.x
					entry.z = point.z
				end
			end
		end

		for markerKey, entry in pairs(state.markerByKey) do
			if not seen[markerKey] then
				if type(entry) == "table" and entry.marker and entry.marker.Remove then
					entry.marker:Remove()
				elseif type(entry) == "number" then
					_zoneIntelRemoveMark(entry)
				end
				state.markerByKey[markerKey] = nil
			end
		end
	end

	local function _zoneIntelPruneMoveNotices(state)
		if type(state) ~= "table" then return end
		state.moveNoticeAtByGroup = state.moveNoticeAtByGroup or {}
		local idx = (type(state.builtIndex) == "table") and state.builtIndex or {}
		for groupName, _ in pairs(state.moveNoticeAtByGroup) do
			if not idx[groupName] then
				state.moveNoticeAtByGroup[groupName] = nil
			end
		end
	end

	function _zoneIntelUpdateActiveZones(now)
		if type(zoneIntels) ~= "table" then return end
		local zoneNames = {}
		for zoneName, state in pairs(zoneIntels) do
			if type(zoneName) == "string" and type(state) == "table" then
				zoneNames[#zoneNames + 1] = zoneName
			end
		end
		if #zoneNames == 0 then return end

		local refreshStep = math.max(5, zoneIntelRefreshSec or 20)
		for _, zoneName in ipairs(zoneNames) do
			local state = zoneIntels[zoneName]
			if type(state) == "table" then
				local z = bc.indexedZones[zoneName]
				if not z or z.side ~= 1 then
					stopZoneIntel(zoneName, true)
				elseif intelActiveZones[zoneName] == false then
					stopZoneIntel(zoneName, true)
				else
					local exp = intelExpireTimes[zoneName] or 0
					if exp > 0 and exp <= now then
						stopZoneIntel(zoneName, true)
					else
						state.moveNoticeAtByGroup = state.moveNoticeAtByGroup or {}
						state.builtIndex = state.builtIndex or {}

						if state.startupPending and (state.startupMessageAt or 0) <= now then
							local delayedSnapshot = _zoneIntelBuildSnapshot(zoneName, state)
							state.lastSnapshot = delayedSnapshot
							local delayedMessage = _zoneIntelBuildStartupMessage(zoneName, delayedSnapshot)
							_zoneIntelBroadcast(zoneName, delayedMessage, 20, "Intel.ogg")
							state.startupPending = false
							state.startupMessageAt = nil
							_zoneIntelPruneMoveNotices(state)
						end

						local nextIntelAt = state.nextIntelAt or 0
						if nextIntelAt <= now then
							_zoneIntelRefreshMarkers(zoneName)
							local newSnapshot = _zoneIntelBuildSnapshot(zoneName, state)
							if state.lastSnapshot then
								local updateMessage = _zoneIntelBuildUpdateMessage(zoneName, state.lastSnapshot, newSnapshot)
								if updateMessage then
									_zoneIntelBroadcast(zoneName, updateMessage, 15)
								end
							end
							state.lastSnapshot = newSnapshot
							state.nextIntelAt = now + refreshStep
							_zoneIntelPruneMoveNotices(state)
						end
					end
				end
			end
		end
	end

	function stopZoneIntel(zoneName, silent)
		local state = zoneIntels[zoneName]
		if state then
			_zoneIntelClearMarkers(state)
			zoneIntels[zoneName] = nil
		end

		intelExpireTimes[zoneName] = nil
		intelActiveZones[zoneName] = false
		bc:buildZoneStatusMenuForGroup()
		mc:refreshAllIntelMissionMenus(true)

		local z = bc.indexedZones[zoneName]
		if z then z:updateLabel() end
		if not silent then
			trigger.action.outTextForCoalition(2, L10N:Format("INTEL_EXPIRED_FOR_ZONE", tostring(zoneName)), 10)
		end
	end

	function startZoneIntel(zoneName, durationSec)
		if not zoneName then return end
		local z = bc.indexedZones[zoneName]
		if not z then return end
		if z.side ~= 1 then return end

		local now = timer.getTime()
		local intelDuration = durationSec or (60 * 60)
		local newExpiry = now + intelDuration
		local refreshStep = math.max(5, zoneIntelRefreshSec or 20)
		local startupDelay = math.max(0, zoneIntelStartupMessageDelaySec or 10)

		local state = zoneIntels[zoneName]
		if type(state) ~= "table" then
			state = {
				markerByKey = {},
				moveNoticeAtByGroup = {},
				builtIndex = {},
				lastSnapshot = nil,
				nextIntelAt = 0,
				startupPending = false,
				startupMessageAt = nil,
			}
			zoneIntels[zoneName] = state
		end
		state.moveNoticeAtByGroup = state.moveNoticeAtByGroup or {}
		state.builtIndex = state.builtIndex or {}
		state.markerByKey = state.markerByKey or {}

		local oldExpiry = intelExpireTimes[zoneName] or 0
		if oldExpiry > now then
			newExpiry = math.max(newExpiry, oldExpiry)
		end

		intelExpireTimes[zoneName] = newExpiry
		intelActiveZones[zoneName] = true
		mc:refreshAllIntelMissionMenus(true)

		local hasReconOnZone = false
		if reconMissionTarget == zoneName then
			hasReconOnZone = true
		end
		local missionState = ActiveCurrentMission[zoneName]
		if missionState and missionState["Recon"] then
			hasReconOnZone = true
		end
		if hasReconOnZone then
			stopReconMissionZoneTracker(zoneName)
			if missionState then
				missionState["Recon"] = nil
				if not next(missionState) then
					ActiveCurrentMission[zoneName] = nil
				end
			end
			if reconMissionTarget == zoneName then
				reconMissionTarget = nil
				reconMissionWinner = nil
				reconMissionCompleted = false
				reconMissionCompletedTarget = zoneName
			end
		end

		z:updateLabel()
		_zoneIntelRefreshMarkers(zoneName)
		local startupSnapshot = _zoneIntelBuildSnapshot(zoneName, state)
		state.lastSnapshot = startupSnapshot
		state.startupPending = true
		state.startupMessageAt = now + startupDelay
		state.nextIntelAt = now + refreshStep
		_zoneIntelPruneMoveNotices(state)
	end
	
	function GetNearestCarrierName(coord)
		if not coord then return nil end
		local nearest=nil local number=math.huge
		for _,name in ipairs({"CVN-73","CVN-72","CVN-59","CVN-74","CVN-75"}) do
			if IsGroupActive(name) then
				local unit=UNIT:FindByName(name)
				if unit then
					local distance=coord:Get2DDistance(unit:GetCoordinate())
					if distance<number then number=distance nearest=name end
				end
			end
		end
		if number<200 then return nearest end
	end

	function Utils.allGroupIsLanded(group, ignorespeed)
		for _,unit in ipairs(group:getUnits()) do
			if not Utils.isLanded(unit, ignorespeed) then return false end
		end
		return true
	end

	Group.getByNameBase = Group.getByName

	function Utils.isGroupActive(group)
		if not group or group:getSize()==0 then return false end
		local c=group:getController()
		if c and (not c.hasTask or c:hasTask()) then
			return not Utils.allGroupIsLanded(group,true)
		end
		return false
	end
	
	function Utils.isInAir(unit)
	if not unit then return false end
	if unit.InAir then
		return unit:InAir()
	else
		return unit:inAir()
	end
	end
	
	function Utils.isInZone(unit, zonename)
		local zn = CustomZone:getByName(zonename)
		if zn then
			return zn:isInside(unit:getPosition().p)
		end
		
		return false
	end
	
	function Utils.isCrateSettledInZone(crate, zonename)
		local zn = CustomZone:getByName(zonename)
		if zn and crate then
			return (zn:isInside(crate:getPosition().p) and Utils.getAGL(crate)<1)
		end
		
		return false
	end
	
	function Utils.someOfGroupInZone(group, zonename)
		for i,v in pairs(group:getUnits()) do
			if Utils.isInZone(v, zonename) then
				return true
			end
		end
		
		return false
	end
	
	function Utils.someOfGroupInAir(group)
		for i,v in pairs(group:getUnits()) do
			if Utils.isInAir(v) then
				return true
			end
		end
		
		return false
	end
	
	Utils.canAccessFS = true
	function Utils.saveTable(filename, variablename, data)
		if not Utils.canAccessFS then 
			return
		end
		
		if not io then
			Utils.canAccessFS = false
			trigger.action.outText(L10N:Get("PERSISTENCE_SAVE_DISABLED"), 600)
			return
		end
	
		local str = variablename..' = {}'
		for i,v in pairs(data) do
			if i == 'zones' and type(v) == 'table' then
				str = str..'\n'..variablename..'['..string.format('%q', i)..'] = {}'
				for zoneName, zoneState in pairs(v) do
					str = str..'\n'..variablename..'['..string.format('%q', i)..']['..string.format('%q', zoneName)..'] = '..Utils.serializeValue(zoneState)
				end
			else
				str = str..'\n'..variablename..'['..string.format('%q', i)..'] = '..Utils.serializeValue(v)
			end
		end
	
		File = io.open(filename, "w")
		File:write(str)
		File:close()
	end

	
	function Utils.serializeValue(value, indent, oneLine)
		indent = indent or 0
		local res = ''
		if type(value)=='number' or type(value)=='boolean' then
			res = res..tostring(value)
		elseif type(value)=='string' then
			res = res..string.format('%q', value) -- escape the strings before serializing them (solves the problem with multilines missions descriptions)
		elseif type(value)=='table' then
			local pad = string.rep(' ', indent)
			local pad2 = string.rep(' ', indent + 2)
			local nl = oneLine and '' or '\n'
			res = res..'{'..(oneLine and ' ' or nl)
			for i,v in pairs(value) do
				local k
				if type(i)=='number' then
					k = '['..i..']='
				else
					k = '['..string.format('%q', i)..']='
				end
				res = res..(oneLine and '' or pad2)..k..Utils.serializeValue(v, indent + 2, oneLine)..','..nl
			end
			if not oneLine then
				res = res..pad..'}'
			else
				if res:sub(-1) == ' ' then
					res = res
				end
				if res:sub(-2) == ', ' then
					res = res:sub(1,-3)
				elseif res:sub(-1) == ',' then
					res = res:sub(1,-2)
				end
				res = res..' }'
			end
		end
		return res
	end
	
	function Utils.loadTable(filename)
		if not Utils.canAccessFS then return end
		if not lfs then
			Utils.canAccessFS = false
			trigger.action.outText(L10N:Get("PERSISTENCE_SAVE_DESANITIZE"), 600)
			return
		end
		if not lfs.attributes(filename) then return end

		local chunk = loadfile(filename)
		if chunk then chunk(); return end

		local f = io.open(filename, "r"); if not f then return end
		local lines = {}
		for line in f:lines() do
			local bad = (line:match("%['[^%]]*[\\/]")) or (line:match("%['\\'"))
			if not bad then lines[#lines+1] = line end
		end
		f:close()
		local fixed = table.concat(lines, "\n")
		local chunk = loadstring(fixed)
		if chunk then chunk() end
	end
end


	function Utils.log(func)
		return function(p1,p2,p3,p4,p5,p6,p7,p8,p9,p10)
			local err, msg = pcall(func,p1,p2,p3,p4,p5,p6,p7,p8,p9,p10)
			if not err then
				env.info("ERROR - callFunc\n"..msg)
				env.info('Traceback\n'..debug.traceback())
			end
		end
	end


