		cnt:setCommand({ 
			id = 'SetImmortal', 
			params = { 
				value = true
			} 
		})
        cnt:setCommand({ 
            id = 'SetUnlimitedFuel', 
            params = { 
                value = true
            } 
        })
		cnt:setCommand({ 
			id = 'EPLRS', 
			params = { 
				value = true,
				groupId = GroupID
			} 
