                                point = {x = point.x, y = point.z},
                                altitude = 6000,
                                number = 2
                            }
                        }
                    }
                }
            }

            cnt:setTask(comboTask)
        else
            trigger.action.outText(L10N:Format("JTAC_9LINE_GROUP_NOT_FOUND", self.name), 10)
        end
    end
end

