local function _surfaceIntelApproxGrid(point)
	if not point then return "unknown" end
	local c = COORDINATE:NewFromVec3(point)
	local mgrs = c:ToStringMGRS():gsub("^MGRS%s*", "")
	local gridZone, square, easting, northing = mgrs:match("^(%S+)%s+(%S+)%s+(%d+)%s+(%d+)")
	if gridZone and square and easting and northing then
		return gridZone.." "..square.." "..easting:sub(1, 2).." "..northing:sub(1, 2)
	end
	return mgrs
end

local function _surfaceIntelEntryGrid(point)
	if not point then return "unknown" end
	local c = COORDINATE:NewFromVec3(point)
	local mgrs = c:ToStringMGRS():gsub("^MGRS%s*", "")
	local gridZone, square, easting, northing = mgrs:match("^(%S+)%s+(%S+)%s+(%d+)%s+(%d+)")
	if gridZone and square and easting and northing then
		return gridZone.." "..square.." "..easting:sub(1, 2).."000 "..northing:sub(1, 2).."000"
	end
	return mgrs
end

local function _surfaceIntelVagueGrid(point)
	if not point then return "unknown" end
	local c = COORDINATE:NewFromVec3(point)
	local mgrs = c:ToStringMGRS():gsub("^MGRS%s*", "")
	local _, square, easting, northing = mgrs:match("^(%S+)%s+(%S+)%s+(%d+)%s+(%d+)")
	if square and easting and northing then
		return square..easting:sub(1, 1)..northing:sub(1, 1)
	end
	return mgrs
end

local function _surfaceIntelApproxLatLon(point)
	if not point then return "unknown" end
	local lat, lon = coord.LOtoLL(point)
	local function fmt(value, pos, neg, width)
		local numericValue = value or 0
		local absValue = math.abs(numericValue)
		local degrees = math.floor(absValue)
		local minutes = math.floor(((absValue - degrees) * 60) + 0.5)
		if minutes >= 60 then
			degrees = degrees + 1
			minutes = 0
		end
		return string.format("%s%0"..tostring(width).."d %02d 00", numericValue >= 0 and pos or neg, degrees, minutes)
	end
	return fmt(lat, "N", "S", 2).." "..fmt(lon, "E", "W", 3)
end

local function _surfaceIntelOffsetPoint(point, minMeters, maxMeters)
	if not point then return nil end
	local minOffset = tonumber(minMeters) or 800
	local maxOffset = tonumber(maxMeters) or 1852
	local offsetMeters = math.random(minOffset, maxOffset)
	local angle = math.random() * math.pi * 2
	local x = point.x + math.cos(angle) * offsetMeters
	local z = point.z + math.sin(angle) * offsetMeters
	return { x = x, y = land.getHeight({ x = x, y = z }), z = z }
end

local function _surfaceIntelMissionTime()
	local t = math.floor((timer.getAbsTime() or 0) + 0.5) % 86400
	local h = math.floor(t / 3600)
	local m = math.floor((t % 3600) / 60)
	return string.format("%02d:%02d", h, m)
end

local function _surfaceIntelClearLastKnownMarker(groupKey)
	if type(groupKey) ~= "string" or groupKey == "" then return end
	local markId = SurfaceIntelMarks[groupKey]
	if markId then
		trigger.action.removeMark(markId)
		SurfaceIntelMarks[groupKey] = nil
	end
	markId = MissionMarks[groupKey]
	if markId then
		trigger.action.removeMark(markId)
		MissionMarks[groupKey] = nil
	end
end

local function _surfaceIntelUpdateLastKnownMarker(groupKey, point, label)
	if type(groupKey) ~= "string" or groupKey == "" or not point then return end
	local useMissionMark = MissionGroups[groupKey] ~= nil
	_surfaceIntelClearLastKnownMarker(groupKey)
	local missionMark = MissionMarks[groupKey]
	if missionMark then
		trigger.action.removeMark(missionMark)
		MissionMarks[groupKey] = nil
	end

	missionMarkId = missionMarkId + 1
	trigger.action.markToCoalition(missionMarkId, label, point, 2, false, false)
	if useMissionMark then
		MissionMarks[groupKey] = missionMarkId
	else
		SurfaceIntelMarks[groupKey] = missionMarkId
	end
end

local function rememberMissionFlagMetadata(flagName, setCustomOnComplete)
	if not flagName then return end
	local meta = MissionFlagMetadata[flagName]
	if not meta then
		meta = {}
		MissionFlagMetadata[flagName] = meta
	end
	if setCustomOnComplete == true then
		meta.isStrike = true
	elseif meta.isStrike == nil then
		meta.isStrike = false
	end
end

local function refreshStrikeMenusOnMissionFlag(flagName, setCustomOnComplete)
	if not flagName or setCustomOnComplete ~= true then return end
	mc:refreshAllStrikeMissionMenus(true)
end

function RegisterUnitTarget(uname,reward,stat,flagName,setCustomOnComplete)
    if flagName then
		rememberMissionFlagMetadata(flagName, setCustomOnComplete)
        MissionTargets[uname]={reward=reward,stat=stat,flag=flagName,custom=setCustomOnComplete}
		local wasActive = ActiveMission[flagName] == true
		ActiveMission[flagName] = true
		if not wasActive then
			refreshStrikeMenusOnMissionFlag(flagName, setCustomOnComplete)
		end
    else
        MissionTargets[uname]={reward=reward,stat=stat}
    end
end

function RegisterStaticGroup(groupKey,source,reward,stat,flagName,setCustomOnComplete)
	local list = (source and source.criticalObjects) and source.criticalObjects or source
	if flagName then
		rememberMissionFlagMetadata(flagName, setCustomOnComplete)
	end
	if not list or #list==0 then return end
	local alive = {}
	for i=1,#list do
		local n = list[i]
		local obj = StaticObject.getByName(n)
		if obj and (obj:getLife() or 0) > 1 then alive[#alive+1] = n end
	end
	if #alive==0 then
		if flagName then
			local wasActive = ActiveMission[flagName] == true
			if setCustomOnComplete then CustomFlags[flagName] = true end
			if ActiveMission[flagName] then ActiveMission[flagName] = nil end
			if wasActive then
				refreshStrikeMenusOnMissionFlag(flagName, setCustomOnComplete)
			end
		end
		return
	end
	local tab = {reward = reward, stat = stat, alive = {}, remaining = 0, killers = {}}
	if flagName then tab.flag = flagName end
	tab.custom = setCustomOnComplete
	for i=1,#alive do
		local n = alive[i]
		tab.alive[n] = true
		tab.remaining = tab.remaining + 1
		MissionTargets[n] = {group = groupKey}
		if flagName then MissionTargets[n].flag = flagName end
	end
	MissionGroups[groupKey] = tab
	if flagName then flag = flagName end
	if flagName then
		local wasActive = ActiveMission[flagName] == true
		ActiveMission[flagName] = true
		if not wasActive then
			refreshStrikeMenusOnMissionFlag(flagName, setCustomOnComplete)
		end
	end
	local cnt = #alive
	for i=1,cnt do
		local n = alive[i]
		local obj = StaticObject.getByName(n)
		local p = obj and obj:getPoint()
		if p then
			if i==1 then
				missionMarkId = missionMarkId + 1
				local label = stat and ((cnt>1) and (stat.." "..i) or stat) or groupKey
				trigger.action.markToCoalition(missionMarkId,label,p,2,false,false)
				MissionMarks[groupKey] = missionMarkId
			end
		end
	end
end


function RegisterGroupTarget(groupName,reward,stat,flagName,setCustomOnComplete)
	if flagName then
		rememberMissionFlagMetadata(flagName, setCustomOnComplete)
	end
    local g = Group.getByName(groupName)
    if not g then
	trigger.action.outText(L10N:Format("REGISTER_GROUP_TARGET_FAILED", tostring(groupName)),30)
	return end
    local tab = {reward = reward, stat = stat, alive = {}, remaining = 0, killers = {}}
    if flagName then tab.flag = flagName end
	tab.custom = setCustomOnComplete
    for _,u in ipairs(g:getUnits()) do
        local n = u:getName()
        tab.alive[n] = true
        tab.remaining = tab.remaining + 1
        MissionTargets[n] = {group = groupName}
        if flagName then MissionTargets[n].flag = flagName end
    end
    MissionGroups[groupName] = tab
    if flagName then flag = flagName end
	if flagName then
		local wasActive = ActiveMission[flagName] == true
		ActiveMission[flagName] = true
		if not wasActive then
			refreshStrikeMenusOnMissionFlag(flagName, setCustomOnComplete)
		end
	end
	timer.scheduleFunction(function()
	if not g:isExist() or g:getSize() == 0 then return end
	local gc = bc:_findGroupCommanderByLiveGroupName(groupName)
	if gc and gc._artilleryOnStation == true and gc._artilleryReturnHome ~= true then return end
    local units = g:getUnits()
    local s = getGroupSpeed(g)
	if s and s < 1 then
		local u = units[1]
		if u and u:isExist() then
			local p = u:getPoint()
			_surfaceIntelClearLastKnownMarker(groupName)
			local oldMark = MissionMarks[groupName]
			if oldMark then
				trigger.action.removeMark(oldMark)
				MissionMarks[groupName] = nil
			end
			missionMarkId = missionMarkId + 1
			local label = stat or groupName
			trigger.action.markToCoalition(missionMarkId,label,p,2,false,false)
			MissionMarks[groupName] = missionMarkId
		end
	end
	end, {}, timer.getTime() + 30)
end


function RegisterScoreTarget(flag,obj,reward,stat,setCustomOnComplete)
	rememberMissionFlagMetadata(flag, setCustomOnComplete)
    local st = ScoreTargets[flag]
    if not st then
        st = {objects={},remaining=0,reward=reward,stat=stat,custom=setCustomOnComplete}
        ScoreTargets[flag] = st
    end
    st.objects[#st.objects+1] = obj
    st.remaining = st.remaining + 1
	local wasActive = ActiveMission[flag] == true
	ActiveMission[flag] = true
	if not wasActive then
		refreshStrikeMenusOnMissionFlag(flag, setCustomOnComplete)
	end
end

