			local early = dc.OFFROAD_EXIT_EARLY_METERS or 0
			if early > 0 then
				local dx, dy = anchorSub.x - startV2.x, anchorSub.y - startV2.y
				local d = math.sqrt(dx*dx + dy*dy)
				if d > early and d > 0 then
					local ux, uy = dx/d, dy/d
					aimx = anchorSub.x - ux * early
					aimy = anchorSub.y - uy * early
				end
			end
			local erx, ery = land.getClosestPointOnRoads("roads", aimx, aimy)
			if erx then
				endRoad = { x = erx, y = ery }
			end
		end
		if endRoad then
			local dx, dy = roadStart.x - startV2.x, roadStart.y - startV2.y
			if (dx*dx + dy*dy) > 1 then
				pts[#pts+1] = ground_buildWP(startV2, "Off Road", s_kmh)
				pts[#pts].formation = frm
				pts[#pts+1] = ground_buildWP(roadStart, "on_road", s_kmh)
			else
				pts[#pts+1] = ground_buildWP(startV2, "on_road", s_kmh)
			end
			pts[#pts+1] = ground_buildWP(endRoad,  "on_road", s_kmh)
			pts[#pts+1] = ground_buildWP(anchorSub, "Off Road", s_kmh)
			pts[#pts].formation = frm
			return { id = "Mission", params = { route = { points = pts } } }, startV2
		end
	end
	pts[#pts+1] = ground_buildWP(startV2, "Off Road", s_kmh)
	pts[#pts].formation = frm
	pts[#pts+1] = ground_buildWP(anchorSub, "Off Road", s_kmh)
	pts[#pts].formation = frm
	return { id = "Mission", params = { route = { points = pts } } }, startV2
end

function dc.BuildSupplyConvoyRouteFromPoint(originPoint, targetZoneName, speed, useZoneRoadHooks, routeOptions)
	if not originPoint or not targetZoneName then return nil end

	local formations = {"Off Road","Cone","Diamond","Vee"}
	local startV2 = { x = originPoint.x, y = originPoint.y }
	if not startV2.x or not startV2.y then return nil end
	local opts = type(routeOptions) == "table" and routeOptions or nil
	local useMultiRoadHooks = opts and opts.useMultiRoadHooks == true
	local useOriginMultiRoadHooks = (opts and opts.useOriginMultiRoadHooks == true) or useMultiRoadHooks
	local useTargetMultiRoadHooks = (opts and opts.useTargetMultiRoadHooks == true) or useMultiRoadHooks

	local tSubs = dc.TARGET_SUBZONES and dc.TARGET_SUBZONES[targetZoneName] or {}
	if #tSubs == 0 then
		tSubs = scanTargetSubzones(targetZoneName)
		dc.TARGET_SUBZONES[targetZoneName] = tSubs
		if #tSubs == 0 then
			env.info("DC.BAIL supply_from_point_target_subzones_empty target=" .. tostring(targetZoneName))
			return nil
		end
	end

	local frm = formations[dcrandIndex(#formations)]
	local anchorSub = tSubs[1]
	local originRoadHook = nil
	if opts and opts.originRoadHookZoneName then
		originRoadHook = getZoneRoadHookPoint(opts.originRoadHookZoneName, useOriginMultiRoadHooks and "random" or nil, nil, useOriginMultiRoadHooks)
	elseif useZoneRoadHooks then
		local originZone = bc:getZoneOfPoint({ x = startV2.x, y = land.getHeight({ x = startV2.x, y = startV2.y }), z = startV2.y })
		if originZone and originZone.zone then
			originRoadHook = getZoneRoadHookPoint(originZone.zone, useOriginMultiRoadHooks and "random" or nil, nil, useOriginMultiRoadHooks)
		end
	end
	local roadStart = originRoadHook
	if not roadStart and (not opts or opts.allowNearestRoadStart ~= false) then
		local rx, rz = land.getClosestPointOnRoads("roads", startV2.x, startV2.y)
		roadStart = rx and { x = rx, y = rz } or nil
	end
	local targetRoadHook = ((opts and opts.useTargetRoadHook == true) or useZoneRoadHooks) and getZoneRoadHookPoint(targetZoneName, useTargetMultiRoadHooks and "nearest" or nil, roadStart or startV2, useTargetMultiRoadHooks) or nil
	local s_kmh = math.floor(((speed or dc.DEFAULT_SPEED or 13.8) * 3.6) + 0.5)
	local pts = {}

	if targetRoadHook then
		local ax, ay = targetRoadHook.x, targetRoadHook.y
		local best, bd = anchorSub, math.huge
		for i = 1, #tSubs do
			local v = tSubs[i]
			local dx, dy = v.x - ax, v.y - ay
			local d = dx * dx + dy * dy
			if d < bd then best, bd = v, d end
		end
		anchorSub = best
	elseif roadStart then
		local ax, ay = roadStart.x, roadStart.y
		local best, bd = anchorSub, math.huge
		for i = 1, #tSubs do
			local v = tSubs[i]
			local dx, dy = v.x - ax, v.y - ay
			local d = dx * dx + dy * dy
			if d < bd then best, bd = v, d end
		end
		anchorSub = best
	end

	if roadStart then
		local endRoad = targetRoadHook
		if not endRoad then
			local aimx, aimy = anchorSub.x, anchorSub.y
			local early = dc.OFFROAD_EXIT_EARLY_METERS or 0
			if early > 0 then
				local dx, dy = anchorSub.x - startV2.x, anchorSub.y - startV2.y
				local d = math.sqrt(dx * dx + dy * dy)
				if d > early and d > 0 then
					local ux, uy = dx / d, dy / d
					aimx = anchorSub.x - ux * early
					aimy = anchorSub.y - uy * early
				end
			end
			local erx, ery = land.getClosestPointOnRoads("roads", aimx, aimy)
			if erx then
				endRoad = { x = erx, y = ery }
			end
		end
		if endRoad then
			local dx, dy = roadStart.x - startV2.x, roadStart.y - startV2.y
			if (dx * dx + dy * dy) > 1 then
				pts[#pts + 1] = ground_buildWP(startV2, "Off Road", s_kmh)
				pts[#pts].formation = frm
				pts[#pts + 1] = ground_buildWP(roadStart, "on_road", s_kmh)
			else
				pts[#pts + 1] = ground_buildWP(startV2, "on_road", s_kmh)
			end
			pts[#pts + 1] = ground_buildWP(endRoad, "on_road", s_kmh)
			pts[#pts + 1] = ground_buildWP(anchorSub, "Off Road", s_kmh)
			pts[#pts].formation = frm
			return { id = "Mission", params = { route = { points = pts } } }, startV2
		end
	end

	pts[#pts + 1] = ground_buildWP(startV2, "Off Road", s_kmh)
	pts[#pts].formation = frm
	pts[#pts + 1] = ground_buildWP(anchorSub, "Off Road", s_kmh)
	pts[#pts].formation = frm
	return { id = "Mission", params = { route = { points = pts } } }, startV2
end

function dc.BuildArtilleryRoute(originZoneName, targetZoneName, speed, rangeNm, anchorPoint)
	local formations = {"Off Road","Cone","Diamond","Vee"}
	local aSubs = ZONE_VALID_SUBZONES[originZoneName] or {}
	local targetCenter = getZoneCenter(targetZoneName)
	if not targetCenter then return nil end
	local aimCenter = (anchorPoint and anchorPoint.x and anchorPoint.y) and anchorPoint or targetCenter
	local fireScriptCommand = string.format("local gr = ...\nbc:startFiringAtZone(gr:getName(),%q,10,true)", tostring(targetZoneName))

	if ZONE_DISTANCES and ZONE_DISTANCES[originZoneName] and ZONE_DISTANCES[originZoneName][targetZoneName] then
		local d = ZONE_DISTANCES[originZoneName][targetZoneName] or -1
		--if d > (45*1852) then return nil end
	else
		env.info("DC.INFO no_distance_entry_for_pair")
	end

	local startV2
	if #aSubs > 0 then
		startV2 = pickClosestSubzoneToPoint(aSubs, aimCenter.x or 0, aimCenter.y or 0)
		if not startV2 then env.info("DC.BAIL no_start_from_subzones") return nil end
	else
		local v2c = getZoneCenter(originZoneName)
		if not v2c then return nil end
		startV2 = v2c
	end
	if not startV2 then env.info("DC.BAIL startV2_nil") return nil end

	local firePoint
	if anchorPoint and anchorPoint.x and anchorPoint.y then
		firePoint = { x = anchorPoint.x, y = anchorPoint.y }
	else
		local tZone = getTriggerZone(targetZoneName)
		local targetRadius = tonumber(tZone and tZone.radius) or 0
		if targetRadius < 0 then targetRadius = 0 end
		local effectiveRangeNm = tonumber(rangeNm) or 2
		if effectiveRangeNm <= 0 then effectiveRangeNm = 2 end
		local standoffMeters = targetRadius + (effectiveRangeNm * 1852)

		local dirx = startV2.x - targetCenter.x
		local diry = startV2.y - targetCenter.y
		local dirLen = math.sqrt(dirx*dirx + diry*diry)
		if dirLen < 1 then
			dirx = 1
			diry = 0
			dirLen = 1
		end
		dirx = dirx / dirLen
		diry = diry / dirLen
		firePoint = {
			x = targetCenter.x + dirx * standoffMeters,
			y = targetCenter.y + diry * standoffMeters
		}
	end

	local frm = formations[dcrandIndex(#formations)]
	local routeStartV2 = startV2
	local originRoadHook = getZoneRoadHookPoint(originZoneName, "random", nil, true)
	local rx, rz = land.getClosestPointOnRoads("roads", startV2.x, startV2.y)
	local roadStart = originRoadHook or (rx and { x = rx, y = rz } or nil)
	if roadStart and #aSubs > 0 then
		local roadStartV2 = pickClosestSubzoneToPoint(aSubs, roadStart.x, roadStart.y)
		if roadStartV2 then
			routeStartV2 = roadStartV2
		end
	end
	local s_kmh = math.floor(((speed or dc.DEFAULT_SPEED or 13.8) * 3.6) + 0.5)

	local pts = {}
	if roadStart then
		local aimx, aimy = firePoint.x, firePoint.y
		local early = dc.OFFROAD_EXIT_EARLY_METERS or 0
		if early > 0 then
			local dx, dy = firePoint.x - startV2.x, firePoint.y - startV2.y
			local d = math.sqrt(dx*dx + dy*dy)
			if d > early and d > 0 then
				local ux, uy = dx/d, dy/d
				aimx = firePoint.x - ux * early
				aimy = firePoint.y - uy * early
			end
		end
		local erx, ery = land.getClosestPointOnRoads("roads", aimx, aimy)
		if erx then
			local endRoad = { x = erx, y = ery }
			local dx, dy = roadStart.x - routeStartV2.x, roadStart.y - routeStartV2.y
			if (dx * dx + dy * dy) > 1 then
				pts[#pts+1] = ground_buildWP(routeStartV2, "Off Road", s_kmh)
				pts[#pts].formation = frm
				pts[#pts+1] = ground_buildWP(roadStart, "on_road", s_kmh)
			else
				pts[#pts+1] = ground_buildWP(routeStartV2, "on_road", s_kmh)
			end
			pts[#pts+1] = ground_buildWP(endRoad,  "on_road", s_kmh)
			pts[#pts+1] = ground_buildWP(firePoint, "Off Road", s_kmh)
			pts[#pts].formation = frm
			ground_addScriptTask(pts[#pts], fireScriptCommand)
			return { id = "Mission", params = { route = { points = pts } } }, routeStartV2
		end
	end

	pts[#pts+1] = ground_buildWP(routeStartV2, "Off Road", s_kmh)
	pts[#pts].formation = frm
	pts[#pts+1] = ground_buildWP(firePoint, "Off Road", s_kmh)
	pts[#pts].formation = frm
	ground_addScriptTask(pts[#pts], fireScriptCommand)
	return { id = "Mission", params = { route = { points = pts } } }, routeStartV2
end


function dc.ResolveSurfaceCommanders(list)
	local resolved = {}
	if type(list) == "table" then
		for _, c in ipairs(list) do
			resolved[#resolved+1] = c
		end
		if #resolved == 0 then
			for _, c in pairs(list) do
				resolved[#resolved+1] = c
			end
		end
	end
	if #resolved > 0 then
		return resolved
	end
	for _, zoneObj in ipairs((bc and bc.zones) or {}) do
		for _, c in ipairs(zoneObj.groups or {}) do
			resolved[#resolved+1] = c
		end
	end
	return resolved
end


function dc.CollectZonesFromCommanders(list)
    local seen, out = {}, {}
    for _, c in ipairs(list or {}) do
        if c and c.type == 'surface' and c.template then
            local origin = c.zoneCommander and c.zoneCommander.zone
            local target = c.targetzone
            if origin and not seen[origin] then seen[origin]=true out[#out+1]=origin end
            if target and not seen[target] then seen[target]=true out[#out+1]=target end
        end
    end
    return out
end


dc.KNOWN_ZONES = dc.KNOWN_ZONES or {}

function dc.InitRoadPathCacheFromCommanders(list)
	local commanders = dc.ResolveSurfaceCommanders(list)
    local zones = dc.CollectZonesFromCommanders(commanders)
    dc.KNOWN_ZONES = zones
    for i = 1, #zones do
        for j = 1, #zones do
            if i ~= j then
                local a, b = zones[i], zones[j]
                local key = keyPair(a,b)
                local hookKey = keyPairWithRouteMode(a, b, true, true, false)
                if not dc.ROUTE_CACHE.attack[key] then dc.GetAttackConvoyRoute(a,b) end
                if not dc.ROUTE_CACHE.supply[key] then dc.GetSupplyConvoyRoute(a,b) end
                if not dc.ROUTE_CACHE.attack[hookKey] then dc.GetAttackConvoyRoute(a,b,dc.DEFAULT_SPEED,true,true,false) end
                if not dc.ROUTE_CACHE.supply[hookKey] then dc.GetSupplyConvoyRoute(a,b,dc.DEFAULT_SPEED,true,true,false) end
            end
        end
	end
	for _, c in ipairs(commanders) do
		if c and c.type == 'surface' and c.mission == 'attack' and c.MissionType == 'ARTY' then
			local origin = c.zoneCommander and c.zoneCommander.zone
			local target = c.targetzone
			if origin and target then
				dc.GetArtilleryRoute(origin, target, dc.DEFAULT_SPEED, dc.ResolveArtilleryRangeNm(c))
			end
		end
	end
    return zones
end

function dc.GetAttackConvoyRoute(originZoneName, targetZoneName, speed, useZoneRoadHooks, useMultiRoadHooks, useTargetMultiRoadHooks)
    local key = keyPairWithRouteMode(originZoneName, targetZoneName, useZoneRoadHooks == true, useMultiRoadHooks == true, useTargetMultiRoadHooks == true)
    local cached = dc.ROUTE_CACHE.attack[key]
    if cached then return cached.task, cached.startV2 end
    local task, startV2 = dc.BuildAttackConvoyRoute(originZoneName, targetZoneName, speed, useZoneRoadHooks == true, useMultiRoadHooks == true, useTargetMultiRoadHooks == true)
    if task and startV2 then
        dc.ROUTE_CACHE.attack[key] = { task = task, startV2 = startV2 }
    end
    return task, startV2
end

function dc.GetSupplyConvoyRoute(originZoneName, targetZoneName, speed, useZoneRoadHooks, useMultiRoadHooks, useTargetMultiRoadHooks)
    local key = keyPairWithRouteMode(originZoneName, targetZoneName, useZoneRoadHooks == true, useMultiRoadHooks == true, useTargetMultiRoadHooks == true)
    local cached = dc.ROUTE_CACHE.supply[key]
    if cached then return cached.task, cached.startV2 end
    local task, startV2 = dc.BuildSupplyConvoyRoute(originZoneName, targetZoneName, speed, useZoneRoadHooks == true, useMultiRoadHooks == true, useTargetMultiRoadHooks == true)
    if task and startV2 then
        dc.ROUTE_CACHE.supply[key] = { task = task, startV2 = startV2 }
    end
    return task, startV2
end

function dc.GetArtilleryRoute(originZoneName, targetZoneName, speed, rangeNm)
	local effectiveRangeNm = tonumber(rangeNm) or 2
	if effectiveRangeNm <= 0 then effectiveRangeNm = 2 end
	local anchorName, anchorPoint = dc.ResolveArtilleryAnchor(originZoneName, targetZoneName)
	local key = keyPairWithRange(originZoneName, targetZoneName, effectiveRangeNm, anchorName or "auto")
	local cached = dc.ROUTE_CACHE.artillery[key]
	if cached then return cached.task, cached.startV2 end
	local task, startV2 = dc.BuildArtilleryRoute(originZoneName, targetZoneName, speed, effectiveRangeNm, anchorPoint)
	if task and startV2 then
		dc.ROUTE_CACHE.artillery[key] = { task = task, startV2 = startV2 }
	end
	return task, startV2
end


BattleCommander = {}
do
	BattleCommander.zones = {}
	BattleCommander.indexedZones = {}
	BattleCommander.connections = {}
	BattleCommander.hiddenConnections = {}
	BattleCommander.accounts = { [1]=0, [2]=0} -- 1 = red coalition, 2 = blue coalition
	BattleCommander.shops = {[1]={}, [2]={}}
	BattleCommander.shopItems = {}
	BattleCommander.monitorROE = {}
	BattleCommander.playerContributions = {[1]={}, [2]={}}
	BattleCommander.playerRewardsOn = false
	BattleCommander.rewards = {}
	BattleCommander.creditsCap = nil
	BattleCommander.difficultyModifier = 0
	BattleCommander.lastDiffChange = 0
	BattleCommander.shopSelectorRefreshBudget = 1
	BattleCommander.shopSelectorRefreshInterval = 0.5
	CustomFlags = CustomFlags or {}
	BattleCommander.groupSupportMenus = {}
	ZONE_DISTANCES = {}
	DYNAMIC_FARP_ZONE_DISTANCES = {}

	function BattleCommander:RemoveMenuForCoalition(coalition)
		missionCommands.removeItemForCoalition(coalition, {[1]=L10N:Get("SHOP_MENU_ALL")})
	end
	function BattleCommander:refreshShopMenuForCoalition(coalition)
		missionCommands.removeItemForCoalition(coalition, {[1]=L10N:Get("SHOP_MENU_ALL")})
		
		local shopmenu = missionCommands.addSubMenuForCoalition(coalition, L10N:Get("SHOP_MENU_ALL"))
		local sub1
		local count = 0
		
		local sorted = {}
		for i,v in pairs(self.shops[coalition]) do table.insert(sorted,{i,v}) end
		table.sort(sorted, function(a,b) return self:_localizedShopText(a[2].name) < self:_localizedShopText(b[2].name) end)
		
		for i2,v2 in pairs(sorted) do
			local i = v2[1]
			local v = v2[2]
			local itemName = self:_localizedShopText(v.name)
			count = count +1
			if count<10 then
				missionCommands.addCommandForCoalition(coalition, L10N:Format("SHOP_ITEM_LABEL", v.cost, itemName), shopmenu, self.buyShopItem, self, coalition, i)
			elseif count==10 then
				sub1 = missionCommands.addSubMenuForCoalition(coalition, L10N:Get("MENU_MORE"), shopmenu)
				missionCommands.addCommandForCoalition(coalition, L10N:Format("SHOP_ITEM_LABEL", v.cost, itemName), sub1, self.buyShopItem, self, coalition, i)
			elseif count%9==1 then
				sub1 = missionCommands.addSubMenuForCoalition(coalition, L10N:Get("MENU_MORE"), sub1)
				missionCommands.addCommandForCoalition(coalition, L10N:Format("SHOP_ITEM_LABEL", v.cost, itemName), sub1, self.buyShopItem, self, coalition, i)
			else
				missionCommands.addCommandForCoalition(coalition, L10N:Format("SHOP_ITEM_LABEL", v.cost, itemName), sub1, self.buyShopItem, self, coalition, i)
			end
		end
	end
	

	function BattleCommander:_getLivePlayerGroupsForCoalition(coal)
		local playerUnits = _G.coalition.getPlayers(coal)
		if not playerUnits then
			return {}
		end

		local groups = {}
		local seen = {}
		for _, unitObj in pairs(playerUnits) do
			if unitObj and unitObj:isExist() then
				local groupObj = unitObj:getGroup()
				if groupObj and groupObj:isExist() then
					local groupId = groupObj:getID()
					if not seen[groupId] then
						seen[groupId] = true
						groups[#groups + 1] = {
							groupId = groupId,
							groupObj = groupObj,
						}
					end
				end
			end
		end

		table.sort(groups, function(a, b)
			local aName = self:_getGroupPlayerName(a.groupId, a.groupObj) or a.groupObj:getName() or tostring(a.groupId)
			local bName = self:_getGroupPlayerName(b.groupId, b.groupObj) or b.groupObj:getName() or tostring(b.groupId)
			if aName ~= bName then
				return aName < bName
			end
			return a.groupId < b.groupId
		end)

		return groups
	end

	function BattleCommander:refreshShopMenuForAllGroupsInCoalition(coal)
		local groups = self:_getLivePlayerGroupsForCoalition(coal)
		if #groups == 0 then return end
		for _, entry in ipairs(groups) do
			self:refreshShopMenuForGroup(entry.groupId, entry.groupObj)
		end
	end

	function BattleCommander:_removeTrackedShopHandlesForGroup(groupId, handles)
		if not handles or #handles == 0 then
			return
		end

		local state = self.groupSupportMenus[groupId]
		if not state then
			return
		end

		local removed = {}
		for _, handle in ipairs(handles) do
			if handle then
				removed[handle] = true
				missionCommands.removeItemForGroup(groupId, handle)
			end
		end

		local kept = {}
		for _, handle in ipairs(state.items or {}) do
			if not removed[handle] then
				kept[#kept + 1] = handle
			end
		end
		state.items = kept
	end

	function BattleCommander:_rememberShopHandleForGroup(groupId, handle, selectorChildren)
		if not handle then
			return handle
		end

		local state = self.groupSupportMenus[groupId]
		if not state then
			return handle
		end

		state.items[#state.items + 1] = handle
		if selectorChildren then
			selectorChildren[#selectorChildren + 1] = handle
		end
		return handle
	end

	function BattleCommander:_getGroupPlayerName(groupId, groupObj)
		local pname = (self.playerNames and self.playerNames[groupId]) or nil
		if (not pname) and groupObj and groupObj.isExist and groupObj:isExist() then
			local u = groupObj:getUnit(1)
			if u and u.getPlayerName then
				pname = u:getPlayerName()
			end
		end
		return pname
	end

	function BattleCommander:_resolveShopSelectorItemIds(coalition, itemIdsOrTags)
		local requested = {}
		if type(itemIdsOrTags) == "string" then
			requested[itemIdsOrTags] = true
		elseif type(itemIdsOrTags) == "table" then
			for _, value in ipairs(itemIdsOrTags) do
				if type(value) == "string" and value ~= "" then
					requested[value] = true
				end
			end
			for key, value in pairs(itemIdsOrTags) do
				if value == true and type(key) == "string" and key ~= "" then
					requested[key] = true
				end
			end
		end

		local ids = {}
		local seen = {}
		local shopData = self.shops[coalition] or {}
		for itemId in pairs(shopData) do
			local itemDef = self.shopItems[itemId]
			local selectorSpec = itemDef and itemDef.groupZoneSelector or nil
			if selectorSpec then
				local matched = requested[itemId] == true
				if not matched then
					for _, tag in ipairs(selectorSpec.refreshTags or {}) do
						if requested[tag] == true then
							matched = true
							break
						end
					end
				end
				if matched and not seen[itemId] then
					seen[itemId] = true
					ids[#ids + 1] = itemId
				end
			end
		end

		table.sort(ids)
		return ids
	end

	function BattleCommander:_orderShopSelectorRefreshItemIds(coalitionSide, itemIds)
		local ordered = {}
		local categoryRank = {}
		local categoryOrder = type(ShopCategoryLabels) == "table" and type(ShopCategoryLabels.Order) == "table" and ShopCategoryLabels.Order or nil
		if categoryOrder then
			for idx, category in ipairs(categoryOrder) do
				categoryRank[category] = idx
			end
		end

		local shopData = self.shops[coalitionSide] or {}
		for _, itemId in ipairs(itemIds or {}) do
			local itemData = shopData[itemId] or {}
			local category = itemData.category or ""
			local name = itemData.name or itemId
			ordered[#ordered + 1] = {
				id = itemId,
				category = self:_localizedShopText(category) or "",
				categoryOrder = categoryRank[category] or 999,
				prio = itemData.prio or 999,
				name = self:_localizedShopText(name) or itemId,
			}
		end

		table.sort(ordered, function(a, b)
			if a.categoryOrder ~= b.categoryOrder then
				return a.categoryOrder < b.categoryOrder
			end
			if a.category ~= b.category then
				return a.category < b.category
			end
			if a.prio ~= b.prio then
				return a.prio < b.prio
			end
			if a.name ~= b.name then
				return a.name < b.name
			end
			return a.id < b.id
		end)

		local ids = {}
		for _, entry in ipairs(ordered) do
			ids[#ids + 1] = entry.id
		end
		return ids
	end

	function BattleCommander:refreshShopSelectorItemForGroup(groupId, groupObj, itemId)
		if not groupObj or not groupObj:isExist() then
			return
		end

		local state = self.groupSupportMenus[groupId]
		if not state or not state.menu then
			return
		end

		local node = state.selectorNodes and state.selectorNodes[itemId] or nil
		if not node or not node.menu then
			self:refreshShopMenuForGroup(groupId, groupObj)
			return
		end

		local coalition = groupObj:getCoalition()
		local shopData = self.shops[coalition]
		local itemData = shopData and shopData[itemId] or nil
		local itemDef = self.shopItems[itemId]
		local selectorSpec = itemDef and itemDef.groupZoneSelector or nil
		if not itemData or not selectorSpec then
			self:refreshShopMenuForGroup(groupId, groupObj)
			return
		end

		local myRank = self:getPlayerRank(self:_getGroupPlayerName(groupId, groupObj)) or 0
		local reqRank = itemData.reqRank
		if reqRank and myRank < reqRank then
			self:refreshShopMenuForGroup(groupId, groupObj)
			return
		end

		local oldChildCount = #(node.children or {})
		self:_removeTrackedShopHandlesForGroup(groupId, node.children or {})
		node.children = {}
		self:_populateShopSelectorMenuForGroup(groupId, groupObj, coalition, { id = itemId, data = itemData }, selectorSpec, node.menu, node.children)
	end

	function BattleCommander:refreshShopSelectorItemsForAllGroupsInCoalition(coalition, itemIdsOrTags)
		local itemIds = self:_resolveShopSelectorItemIds(coalition, itemIdsOrTags)
		if #itemIds == 0 then
			return
		end

		local groups = _G.coalition.getGroups(coalition)
		if not groups then
			return
		end

		for _, groupObj in pairs(groups) do
			if groupObj and groupObj:isExist() then
				local groupId = groupObj:getID()
				if self.groupSupportMenus[groupId] then
					for _, itemId in ipairs(itemIds) do
						self:refreshShopSelectorItemForGroup(groupId, groupObj, itemId)
					end
				end
			end
		end
	end

	function BattleCommander:_getGroupRank(groupId, groupObj)
		return self:getPlayerRank(self:_getGroupPlayerName(groupId, groupObj)) or 0
	end

	function BattleCommander:_getTankerRequiredRank(itemId)
		if not RankingSystem then return 0 end
		if type(ShopRankRequirements) == "table" then
			local req = tonumber(ShopRankRequirements[itemId])
			if req then return req end
		end
		return 0
	end

	function BattleCommander:_removeTankerMenuForGroup(groupId)
		self.groupTankerMenus = self.groupTankerMenus or {}
		self.groupTankerSignatures = self.groupTankerSignatures or {}
		local handle = self.groupTankerMenus[groupId]
		if handle then
			missionCommands.removeItemForGroup(groupId, handle)
		end
		self.groupTankerMenus[groupId] = nil
		self.groupTankerSignatures[groupId] = nil
	end

	function BattleCommander:_removeDynamicControlMenuForGroup(groupId)
		self.groupDynamicMenus = self.groupDynamicMenus or {}
		self.groupDynamicSignatures = self.groupDynamicSignatures or {}
		self:_removeTankerMenuForGroup(groupId)
		local handle = self.groupDynamicMenus[groupId]
		if handle then
			missionCommands.removeItemForGroup(groupId, handle)
		end
		self.groupDynamicMenus[groupId] = nil
		self.groupDynamicSignatures[groupId] = nil
	end

	function BattleCommander:_groupHasHumanPlayer(groupObj)
		if not groupObj or not groupObj.isExist or not groupObj:isExist() then return false end
		local sz = groupObj:getSize() or 0
		for i=1,sz do
			local u = groupObj:getUnit(i)
			if u and u.getPlayerName and u:getPlayerName() then
				return true
			end
		end
		return false
	end

	function BattleCommander:_groupIsHelicopter(groupObj)
		if not groupObj or not groupObj.isExist or not groupObj:isExist() then return false end
		local sz = groupObj:getSize() or 0
		for i=1,sz do
			local u = groupObj:getUnit(i)
			if u and (not u.isExist or u:isExist()) and u.getDesc then
				local desc = u:getDesc()
				local category = desc and desc.category
				if category ~= nil and Unit and Unit.Category and Unit.Category.HELICOPTER ~= nil then
					return category == Unit.Category.HELICOPTER
				end
				if desc and desc.attributes then
					if desc.attributes.Helicopters or desc.attributes.Helicopter then
						return true
					else
						return false
					end
				end
			end
		end
		return false
	end

	function BattleCommander:refreshDynamicControlMenusForBlue(force)
		self.groupDynamicMenus = self.groupDynamicMenus or {}
		self.groupDynamicSignatures = self.groupDynamicSignatures or {}
		local seen = {}
		local groups = coalition.getGroups(2) or {}
		for _, g in pairs(groups) do
			if g and g:isExist() then
				local gid = g:getID()
				seen[gid] = true
				self:refreshDynamicControlMenuForGroup(gid, g, force)
			end
		end
		for gid, _ in pairs(self.groupDynamicMenus) do
			if not seen[gid] then
				self:_removeDynamicControlMenuForGroup(gid)
				self:_removeTankerMenuForGroup(gid)
			end
		end
	end

	function BattleCommander:refreshDynamicControlMenuForGroup(groupId, groupObj, force)
		self.groupDynamicMenus = self.groupDynamicMenus or {}
		self.groupDynamicSignatures = self.groupDynamicSignatures or {}

		if not groupObj or not groupObj.isExist or not groupObj:isExist() then
			self:_removeDynamicControlMenuForGroup(groupId)
			self:_removeTankerMenuForGroup(groupId)
			return
		end
		if groupObj:getCoalition() ~= 2 then
			self:_removeDynamicControlMenuForGroup(groupId)
			self:_removeTankerMenuForGroup(groupId)
			return
		end
		if not self:_groupHasHumanPlayer(groupObj) then
			self:_removeDynamicControlMenuForGroup(groupId)
			self:_removeTankerMenuForGroup(groupId)
			return
		end

		local hasNonTankerDynamic = capActive or casActive or seadActive or decoyActive or bomberActive or StructureActive
		local isHeloGroup = (self._groupIsHelicopter and self:_groupIsHelicopter(groupObj)) or false
		local hasEligibleTankerController = false
		local rank = (self._getGroupRank and self:_getGroupRank(groupId, groupObj)) or 0
		local reqArco = (self._getTankerRequiredRank and self:_getTankerRequiredRank("dynamicarco")) or 0
		local reqTexaco = (self._getTankerRequiredRank and self:_getTankerRequiredRank("dynamictexaco")) or 0
		if (ArcoActive or TexacoActive) and not isHeloGroup then
			hasEligibleTankerController = (ArcoActive and rank >= reqArco) or (TexacoActive and rank >= reqTexaco)
		end

		if not (hasNonTankerDynamic or hasEligibleTankerController) then
			self:_removeDynamicControlMenuForGroup(groupId)
			self:_removeTankerMenuForGroup(groupId)
			return
		end

		local signature = table.concat({
			tostring(capActive), tostring(casActive), tostring(seadActive),
			tostring(decoyActive), tostring(bomberActive), tostring(StructureActive),
			tostring(ArcoActive), tostring(TexacoActive),
			tostring(isHeloGroup), tostring(rank),
			tostring(reqArco), tostring(reqTexaco),
			tostring(hasEligibleTankerController),
		}, "|")

		if not force and self.groupDynamicMenus[groupId] and self.groupDynamicSignatures[groupId] == signature then
			self:refreshTankerControlMenuForGroup(groupId, groupObj, false, self.groupDynamicMenus[groupId])
			return
		end

		self:_removeDynamicControlMenuForGroup(groupId)
		local T = L10N:ForGroup(groupId)
		local rootMenu = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_DYNAMIC_CONTROL"))
		self.groupDynamicMenus[groupId] = rootMenu
		self.groupDynamicSignatures[groupId] = signature
		self:refreshTankerControlMenuForGroup(groupId, groupObj, true, rootMenu)


		local function orderedCapZonesForGroup()
			local zones = (self.getZones and self:getZones()) or {}
			local c = {}
			for _, v in ipairs(zones) do
				if v.active
				and ((v.side == 2) or (v.side == 0 and (not v.NeutralAtStart or v.firstCaptureByRed)))
				and (not v.isHidden)
				and (not v.suspended) then
					local suf = WaypointList and WaypointList[v.zone]
					local wp = suf and tonumber(tostring(suf):match("%d+"))
					c[#c+1] = { z = v, wp = wp, disp = (wp and (v.zone .. suf) or v.zone) }
				end
			end
			table.sort(c, function(a, b)
				if a.wp and b.wp then return a.wp > b.wp end
				if a.wp then return true end
				if b.wp then return false end
				return a.z.zone < b.z.zone
			end)
			return c
		end

		if capActive then
			local capSubMenu = missionCommands.addSubMenuForGroup(groupId, T:Get("DYNAMIC_CAP_CONTROL"), rootMenu)

			local zoneMenu = missionCommands.addSubMenuForGroup(groupId, T:Get("DYNAMIC_CAP_REPOSITION_BY_ZONE"), capSubMenu)
			local count = 0
			local sub1
			for _, wrap in ipairs(orderedCapZonesForGroup()) do
				local v = wrap.z
				local zoneSubMenu
				count = count + 1
				if count < 10 then
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, zoneMenu)
				elseif count == 10 then
					sub1 = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_MORE"), zoneMenu)
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, sub1)
				elseif count % 9 == 1 then
					sub1 = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_MORE"), sub1)
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, sub1)
				else
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, sub1)
				end
				for _, headingName in ipairs({"Orbit","Hot 360","Hot 045","Hot 090","Hot 135","Hot 180","Hot 225","Hot 270","Hot 315"}) do
					local headingLabel = localizedDynamicHeadingLabel(headingName, T)
					if headingName == "Orbit" then
						missionCommands.addCommandForGroup(groupId, headingLabel, zoneSubMenu, function()
							local zone = ZONE:FindByName(v.zone)
							if not zone then return end
							local coord = zone:GetCoordinate()
							setCapRacetrack(coord, 045, 0, v.zone)
							MESSAGE:New(L10N:Format("DYNAMIC_CAP_EN_ROUTE_TO_ZONE", v.zone), 20):ToAll()
						end)
					else
						local headingVal = capHeadings[headingName]
						local headingMenu = missionCommands.addSubMenuForGroup(groupId, headingLabel, zoneSubMenu)
						for _, legName in ipairs({"Orbit","10 NM Leg","20 NM Leg","30 NM Leg","40 NM Leg","50 NM Leg"}) do
							local legVal = capLegs[legName]
							local legLabel = localizedDynamicLegLabel(legName, T)
							missionCommands.addCommandForGroup(groupId, legLabel, headingMenu, function()
								local zone = ZONE:FindByName(v.zone)
								if not zone then return end
								local coord = zone:GetCoordinate()
								setCapRacetrack(coord, headingVal, legVal)
								MESSAGE:New(L10N:Format("DYNAMIC_CAP_REPOSITIONING_ZONE", v.zone, headingVal, legVal), 20):ToAll()
							end)
						end
					end
				end
			end

			local posMenu = missionCommands.addSubMenuForGroup(groupId, T:Get("DYNAMIC_CAP_REPOSITION_BY_POSITION"), capSubMenu)
			for _, dirName in ipairs({"Reposition 360", "Reposition 045", "Reposition 090", "Reposition 135", "Reposition 180", "Reposition 225", "Reposition 270", "Reposition 315"}) do
				local dirVal = capPositionDirections[dirName]
				local dirLabel = localizedDynamicHeadingLabel(dirName, T)
				local dirMessageLabel = localizedDynamicHeadingLabel(dirName)
				local dirMenu = missionCommands.addSubMenuForGroup(groupId, dirLabel, posMenu)
				for _, distName in ipairs({"0 NM", "10 NM", "20 NM", "30 NM", "40 NM", "50 NM", "60 NM", "70 NM", "80 NM", "90 NM", "100 NM"}) do
					local distVal = capPositionDistances[distName]
					local distLabel = localizedDynamicDistanceLabel(distName, T)
					local distMessageLabel = localizedDynamicDistanceLabel(distName)
					local distMenu = missionCommands.addSubMenuForGroup(groupId, distLabel, dirMenu)
					for _, headingName in ipairs({"Orbit","Hot 360","Hot 045","Hot 090","Hot 135","Hot 180","Hot 225","Hot 270","Hot 315"}) do
						local headingLabel = localizedDynamicHeadingLabel(headingName, T)
						if headingName == "Orbit" then
							missionCommands.addCommandForGroup(groupId, headingLabel, distMenu, function()
								if capGroup then
									local offsetCoord = capGroup:GetCoordinate():Translate(UTILS.NMToMeters(distVal), dirVal, true)
									setCapRacetrack(offsetCoord, 045, 0)
									MESSAGE:New(L10N:Format("DYNAMIC_CAP_REPOSITIONING_ORBIT", dirMessageLabel, distMessageLabel), 20):ToAll()
								end
							end)
						else
							local headingVal = capHeadings[headingName]
							local headingMenu = missionCommands.addSubMenuForGroup(groupId, headingLabel, distMenu)
							for _, legName in ipairs({"Orbit", "10 NM Leg", "20 NM Leg", "30 NM Leg", "40 NM Leg", "50 NM Leg"}) do
								local legVal = capLegs[legName]
								local legLabel = localizedDynamicLegLabel(legName, T)
								missionCommands.addCommandForGroup(groupId, legLabel, headingMenu, function()
									if capGroup then
										local offsetCoord = capGroup:GetCoordinate():Translate(UTILS.NMToMeters(distVal), dirVal, true)
										setCapRacetrack(offsetCoord, headingVal, legVal)
										MESSAGE:New(L10N:Format("DYNAMIC_CAP_REPOSITIONING_POSITION", dirMessageLabel, distMessageLabel, headingVal, legVal), 20):ToAll()
									end
								end)
							end
						end
					end
				end
			end
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_CAP_HOLD_RACETRACK"), capSubMenu, function()
				if capGroup then
					capGroup:SwitchROE(2)
				end
				MESSAGE:New(L10N:Get("DYNAMIC_CAP_ENGAGE_IF_ENGAGED"), 15):ToAll()
			end)
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_CAP_FLIGHTSWEEP"), capSubMenu, function()
				if capGroup then
					capGroup:SwitchROE(1)
				end
				MESSAGE:New(L10N:Get("DYNAMIC_CAP_ENGAGE_ALL"), 15):ToAll()
			end)
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_CAP_DESTROY"), capSubMenu, despawnCap)
		end
		if casActive then
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_CAS_DESTROY"), rootMenu, despawnCas)
		end
		if bomberActive then
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_BOMBER_DESTROY"), rootMenu, despawnBomber)
		end
		if seadActive then
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_SEAD_DESTROY"), rootMenu, despawnSead)
		end
		if decoyActive then
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_DECOY_DESTROY"), rootMenu, despawnDecoy)
		end
		if StructureActive then
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_BUILDING_STRIKE_DESTROY"), rootMenu, despawnStructure)
		end
	end

	function BattleCommander:refreshTankerControlMenusForBlue(force)
		self.groupTankerMenus = self.groupTankerMenus or {}
		self.groupTankerSignatures = self.groupTankerSignatures or {}
		self.groupDynamicMenus = self.groupDynamicMenus or {}
		local seen = {}
		local groups = coalition.getGroups(2) or {}
		for _, g in pairs(groups) do
			if g and g:isExist() then
				local gid = g:getID()
				seen[gid] = true
				self:refreshTankerControlMenuForGroup(gid, g, force, self.groupDynamicMenus[gid])
			end
		end
		for gid, _ in pairs(self.groupTankerMenus) do
			if not seen[gid] then
				self:_removeTankerMenuForGroup(gid)
			end
		end
	end

	function BattleCommander:refreshTankerControlMenuForGroup(groupId, groupObj, force, parentMenu)
		self.groupTankerMenus = self.groupTankerMenus or {}
		self.groupTankerSignatures = self.groupTankerSignatures or {}
		self.groupDynamicMenus = self.groupDynamicMenus or {}

		if not groupObj or not groupObj.isExist or not groupObj:isExist() then
			self:_removeTankerMenuForGroup(groupId)
			return
		end
		if groupObj:getCoalition() ~= 2 then
			self:_removeTankerMenuForGroup(groupId)
			return
		end
		if not self:_groupHasHumanPlayer(groupObj) then
			self:_removeTankerMenuForGroup(groupId)
			return
		end
		if self._groupIsHelicopter and self:_groupIsHelicopter(groupObj) then
			self:_removeTankerMenuForGroup(groupId)
			return
		end

		local rank = self:_getGroupRank(groupId, groupObj)
		local reqArco = self:_getTankerRequiredRank("dynamicarco")
		local reqTexaco = self:_getTankerRequiredRank("dynamictexaco")

			local arcoUnlocked = _getTankerState("arco").unlocked == true
			local texacoUnlocked = _getTankerState("texaco").unlocked == true
			local arcoAltCurrent = _getTankerCurrentAltitude("arco")
			local texacoAltCurrent = _getTankerCurrentAltitude("texaco")
			local arcoSpeedCurrent = _getTankerCurrentSpeed("arco")
			local texacoSpeedCurrent = _getTankerCurrentSpeed("texaco")

		local arcoEligible = (rank >= reqArco) and ArcoActive
		local texacoEligible = (rank >= reqTexaco) and TexacoActive
		if not (arcoEligible or texacoEligible) then
			self:_removeTankerMenuForGroup(groupId)
			return
		end

			local signature = table.concat({
				tostring(rank),
				tostring(reqArco), tostring(reqTexaco),
				tostring(arcoUnlocked), tostring(texacoUnlocked),
				tostring(ArcoActive), tostring(TexacoActive),
				tostring(arcoAltCurrent), tostring(texacoAltCurrent),
				tostring(arcoSpeedCurrent),
				tostring(texacoSpeedCurrent),
			}, "|")
		if not force and self.groupTankerMenus[groupId] and self.groupTankerSignatures[groupId] == signature then
			return
		end

		self:_removeTankerMenuForGroup(groupId)
		local rootMenu = parentMenu or self.groupDynamicMenus[groupId]
		if not rootMenu then
			return
		end

		local T = L10N:ForGroup(groupId)
		local tankersMenu = missionCommands.addSubMenuForGroup(groupId, T:Get("DYNAMIC_TANKERS_CONTROL"), rootMenu)
		self.groupTankerMenus[groupId] = tankersMenu
		self.groupTankerSignatures[groupId] = signature

		local orbitAndHeadings = {"Orbit","Hot 360","Hot 045","Hot 090","Hot 135","Hot 180","Hot 225","Hot 270","Hot 315"}
		local legs = {"Orbit","10 NM Leg","20 NM Leg","30 NM Leg","40 NM Leg","50 NM Leg"}
		local posDirs = {"Reposition 360", "Reposition 045", "Reposition 090", "Reposition 135", "Reposition 180", "Reposition 225", "Reposition 270", "Reposition 315"}
		local posDists = {"0 NM", "10 NM", "20 NM", "30 NM", "40 NM", "50 NM", "60 NM", "70 NM", "80 NM", "90 NM", "100 NM"}
		local spawnLegs = {"10 NM Leg", "20 NM Leg", "30 NM Leg", "40 NM Leg", "50 NM Leg"}
		local function orderedBlueZones()
			local zones = self:getZones() or {}
			local c = {}
			for _, v in ipairs(zones) do
				if v.active and v.side == 2 and (not v.isHidden) then
					local suf = WaypointList and WaypointList[v.zone]
					local wp = suf and tonumber(tostring(suf):match("%d+"))
					c[#c+1] = { z = v, wp = wp, disp = (wp and (v.zone .. suf) or v.zone) }
				end
			end
			table.sort(c, function(a, b)
				if a.wp and b.wp then return a.wp > b.wp end
				if a.wp then return true end
				if b.wp then return false end
				return a.z.zone < b.z.zone
			end)
			return c
		end

		local function addSpawnByZoneForGroup(title, spawnFn)
			local root = missionCommands.addSubMenuForGroup(groupId, title, tankersMenu)
			local count = 0
			local sub1
			for _, wrap in ipairs(orderedBlueZones()) do
				local v = wrap.z
				local zoneName = v.zone
				local zoneDisplayName = wrap.disp
				local zoneMenu
				count = count + 1
				if count < 10 then
					zoneMenu = missionCommands.addSubMenuForGroup(groupId, zoneDisplayName, root)
				elseif count == 10 then
					sub1 = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_MORE"), root)
					zoneMenu = missionCommands.addSubMenuForGroup(groupId, zoneDisplayName, sub1)
				elseif count % 9 == 1 then
					sub1 = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_MORE"), sub1)
					zoneMenu = missionCommands.addSubMenuForGroup(groupId, zoneDisplayName, sub1)
				else
					zoneMenu = missionCommands.addSubMenuForGroup(groupId, zoneDisplayName, sub1)
				end
				for _, headingName in ipairs(orbitAndHeadings) do
					local headingLabel = localizedDynamicHeadingLabel(headingName, T)
					if headingName == "Orbit" then
						missionCommands.addCommandForGroup(groupId, headingLabel, zoneMenu, function()
							spawnFn(zoneName, 45, 0)
						end)
					else
						local headingVal = capHeadings[headingName]
						local headingMenu = missionCommands.addSubMenuForGroup(groupId, headingLabel, zoneMenu)
						for _, legName in ipairs(spawnLegs) do
							local legVal = capLegs[legName]
							local legLabel = localizedDynamicLegLabel(legName, T)
							missionCommands.addCommandForGroup(groupId, legLabel, headingMenu, function()
								spawnFn(zoneName, headingVal, legVal)
							end)
						end
					end
				end
			end
		end

		local function addRepositionMenusForGroup(prefix, zoneTitle, posTitle, groupGetter, setFn)
			local zoneMenu = missionCommands.addSubMenuForGroup(groupId, zoneTitle, tankersMenu)
			local count = 0
			local sub1
			for _, wrap in ipairs(orderedBlueZones()) do
				local v = wrap.z
				local zoneName = v.zone
				local zoneSubMenu
				count = count + 1
				if count < 10 then
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, zoneMenu)
				elseif count == 10 then
					sub1 = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_MORE"), zoneMenu)
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, sub1)
				elseif count % 9 == 1 then
					sub1 = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_MORE"), sub1)
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, sub1)
				else
					zoneSubMenu = missionCommands.addSubMenuForGroup(groupId, wrap.disp, sub1)
				end
				for _, headingName in ipairs(orbitAndHeadings) do
					local headingLabel = localizedDynamicHeadingLabel(headingName, T)
					if headingName == "Orbit" then
						missionCommands.addCommandForGroup(groupId, headingLabel, zoneSubMenu, function()
							local zone = ZONE:FindByName(zoneName)
							if not zone then return end
							local coord = zone:GetCoordinate()
							if setFn(coord, 45, 0, zoneName) then
								MESSAGE:New(L10N:Format("DYNAMIC_TANKER_EN_ROUTE_TO_ZONE", prefix, zoneName), 20):ToAll()
							end
						end)
					else
						local headingVal = capHeadings[headingName]
						local headingMenu = missionCommands.addSubMenuForGroup(groupId, headingLabel, zoneSubMenu)
						for _, legName in ipairs(legs) do
							local legVal = capLegs[legName]
							local legLabel = localizedDynamicLegLabel(legName, T)
							missionCommands.addCommandForGroup(groupId, legLabel, headingMenu, function()
								local zone = ZONE:FindByName(zoneName)
								if not zone then return end
								local coord = zone:GetCoordinate()
								if setFn(coord, headingVal, legVal) then
									MESSAGE:New(L10N:Format("DYNAMIC_TANKER_REPOSITIONING_ZONE", prefix, zoneName, headingVal, legVal), 20):ToAll()
								end
							end)
						end
					end
				end
			end

			local posMenu = missionCommands.addSubMenuForGroup(groupId, posTitle, tankersMenu)
			for _, dirName in ipairs(posDirs) do
				local dirVal = capPositionDirections[dirName]
				local dirLabel = localizedDynamicHeadingLabel(dirName, T)
				local dirMessageLabel = localizedDynamicHeadingLabel(dirName)
				local dirMenu = missionCommands.addSubMenuForGroup(groupId, dirLabel, posMenu)
				for _, distName in ipairs(posDists) do
					local distVal = capPositionDistances[distName]
					local distLabel = localizedDynamicDistanceLabel(distName, T)
					local distMessageLabel = localizedDynamicDistanceLabel(distName)
					local distMenu = missionCommands.addSubMenuForGroup(groupId, distLabel, dirMenu)
					for _, headingName in ipairs(orbitAndHeadings) do
						local headingLabel = localizedDynamicHeadingLabel(headingName, T)
						if headingName == "Orbit" then
							missionCommands.addCommandForGroup(groupId, headingLabel, distMenu, function()
								local g = groupGetter()
								if g then
									local baseCoord = nil
									if g.GetCoordinate then
										baseCoord = g:GetCoordinate()
									elseif g.getUnit then
										local gu = g:getUnit(1)
										local gp = gu and gu:getPoint() or nil
										if gp then
											baseCoord = COORDINATE:New(gp.x, gp.y, gp.z)
										end
									end
									if baseCoord then
										local offsetCoord = baseCoord:Translate(UTILS.NMToMeters(distVal), dirVal, true)
										if setFn(offsetCoord, 45, 0) then
											MESSAGE:New(L10N:Format("DYNAMIC_TANKER_REPOSITIONING_ORBIT", prefix, dirMessageLabel, distMessageLabel), 20):ToAll()
										end
									end
								end
							end)
						else
							local headingVal = capHeadings[headingName]
							local headingMenu = missionCommands.addSubMenuForGroup(groupId, headingLabel, distMenu)
							for _, legName in ipairs(legs) do
								local legVal = capLegs[legName]
								local legLabel = localizedDynamicLegLabel(legName, T)
								missionCommands.addCommandForGroup(groupId, legLabel, headingMenu, function()
									local g = groupGetter()
									if g then
										local baseCoord = nil
										if g.GetCoordinate then
											baseCoord = g:GetCoordinate()
										elseif g.getUnit then
											local gu = g:getUnit(1)
											local gp = gu and gu:getPoint() or nil
											if gp then
												baseCoord = COORDINATE:New(gp.x, gp.y, gp.z)
											end
										end
										if baseCoord then
											local offsetCoord = baseCoord:Translate(UTILS.NMToMeters(distVal), dirVal, true)
											if setFn(offsetCoord, headingVal, legVal) then
												MESSAGE:New(L10N:Format("DYNAMIC_TANKER_REPOSITIONING_POS", prefix, dirMessageLabel, distMessageLabel, headingVal, legVal), 20):ToAll()
											end
										end
									end
								end)
							end
						end
					end
				end
			end
		end

			local function addAltitudeMenuForGroup(prefix, title, kind, applyFn)
				local altMenu = missionCommands.addSubMenuForGroup(groupId, title, tankersMenu)
				local currentAlt = tonumber(_getTankerCurrentAltitude(kind)) or _getTankerDefaultAltitude(kind)
				for _, altFt in ipairs(_getTankerAltitudeOptions(kind)) do
					local label = _formatFeetMenuLabel(altFt)
				if altFt == currentAlt then
					label = label .. " (current)"
				end
				missionCommands.addCommandForGroup(groupId, label, altMenu, function()
					local ok = applyFn(altFt)
					if ok and self.refreshTankerControlMenusForBlue then
						self:refreshTankerControlMenusForBlue(true)
					end
					end)
				end
			end

			local function addSpeedMenuForGroup(prefix, title, kind, applyFn)
				local speedMenu = missionCommands.addSubMenuForGroup(groupId, title, tankersMenu)
				local currentSpeed = _getTankerCurrentSpeed(kind) or _getTankerDefaultSpeed(kind)
				for _, speedKt in ipairs(_getTankerSpeedOptions(kind) or {}) do
					local label = tostring(speedKt) .. " kt"
					if speedKt == currentSpeed then
						label = label .. " (current)"
					end
					missionCommands.addCommandForGroup(groupId, label, speedMenu, function()
						local ok = applyFn(speedKt)
						if ok and self.refreshTankerControlMenusForBlue then
							self:refreshTankerControlMenusForBlue(true)
						end
					end)
				end
			end

		if arcoEligible then
			if ArcoActive then
				addRepositionMenusForGroup("Arco", T:Get("DYNAMIC_TANKER_ARCO_MOVE_TO_ZONE"), T:Get("DYNAMIC_TANKER_ARCO_MOVE_BY_POS"), function() return ArcoGroup end, ArcoRepositionCheckAndSet)
				addAltitudeMenuForGroup("Arco", T:Get("DYNAMIC_TANKER_ARCO_ALTITUDE"), "arco", ArcoAltitudeCheckAndSet)
				addSpeedMenuForGroup("Arco", T:Get("DYNAMIC_TANKER_ARCO_SPEED"), "arco", ArcoSpeedCheckAndSet)
			end
		end

			if texacoEligible then
				if TexacoActive then
					addRepositionMenusForGroup("Texaco", T:Get("DYNAMIC_TANKER_TEXACO_MOVE_TO_ZONE"), T:Get("DYNAMIC_TANKER_TEXACO_MOVE_BY_POS"), function() return TexacoGroup end, TexacoRepositionCheckAndSet)
					addAltitudeMenuForGroup("Texaco", T:Get("DYNAMIC_TANKER_TEXACO_ALTITUDE"), "texaco", TexacoAltitudeCheckAndSet)
					addSpeedMenuForGroup("Texaco", T:Get("DYNAMIC_TANKER_TEXACO_SPEED"), "texaco", TexacoSpeedCheckAndSet)
				end
			end

		local tankerInfoLines = {}
		if arcoEligible and ArcoActive then
			local arcoAlt = _formatFeetMenuLabel(_getTankerCurrentAltitude("arco"))
			tankerInfoLines[#tankerInfoLines + 1] = T:Format("DYNAMIC_TANKER_ARCO_INFO", arcoAlt)
		end
		if texacoEligible and TexacoActive then
			local texacoAlt = _formatFeetMenuLabel(_getTankerCurrentAltitude("texaco"))
			tankerInfoLines[#tankerInfoLines + 1] = T:Format("DYNAMIC_TANKER_TEXACO_INFO", texacoAlt)
		end
		if #tankerInfoLines > 0 then
			missionCommands.addCommandForGroup(groupId, T:Get("DYNAMIC_TANKER_INFO"), tankersMenu, function()
				trigger.action.outTextForGroup(groupId, table.concat(tankerInfoLines, "\n"), 15)
			end)
		end
	end
	
function BattleCommander:new(savepath, updateFrequency, saveFrequency, difficulty) -- difficulty = {start = 1.4, min = -0.5, max = 0.5, escalation = 0.1, fade = 0.1, fadeTime = 30*60, coalition=1} --coalition 1:red 2:blue
		local obj = {}
		obj.saveFile = 'zoneCommander.lua'
		if savepath then
			obj.saveFile = savepath
		end
		
		if not updateFrequency then updateFrequency = 10 end
		if not saveFrequency then saveFrequency = 60 end
		
		obj.difficulty = difficulty
		obj.updateFrequency = updateFrequency
		obj.saveFrequency = saveFrequency
		obj.spawnEvalEnabled = true
		obj.spawnEvalTickSec = 0.5
		obj.spawnEvalJitterSec = 0.15
		obj.spawnEvalBudgetBase = 8
		obj.spawnEvalBudgetHigh = 18
		obj.spawnEvalHighWater = 70
		obj.spawnEvalCacheTtlSec = 60
		obj._fsmFilterGeneration = 1
		obj._reindexCombatFilterGeneration = 1
		obj._supplyCacheGeneration = 1
		obj._reindexCombatCacheGeneration = 0
		obj.hiddenConnections = {}
		obj.connectionMap = {}
		obj.connectionMapHybridSuspend = {}
		obj._connectionTopologyDirty = true
		obj._connectionBlueByZone = {}
		obj._connectionNearBlueCount = {}
		obj._connectionNearBlueCandidates = nil
		obj._connectionNearBlueThreshold = nil
		obj._enemyTerritoryOverlayZones = {}
		obj._friendlyTerritoryOverlayZones = {}
		obj._neutralTerritoryOverlayZones = {}
		obj._territoryOverlayZoneCache = {}
		obj._territoryOverlayZoneStates = {}
		obj._territoryOverlayNeighborOrder = {}
		obj._territoryOverlayAffectedBy = {}
		obj._territoryOverlaySiteMap = {}
		obj._territoryOverlayActiveNames = {}
		obj._territoryOverlayActiveNameSet = {}
		obj._territoryOverlayBoundsInfo = nil
		obj._territoryOverlayConfigKey = nil
		obj._territoryOverlaySideCounts = {[0] = 0, [1] = 0, [2] = 0, total = 0}
		obj._territoryOverlayDrawSeq = 0
		obj._territoryOverlayStateKey = nil
		obj._redDifficultyZoneState = {}
		obj._redDifficultyEligibleTotal = 0
		obj._redDifficultyEligibleBlue = 0
		obj._redDifficultyDirty = true
		obj._zoneStatusMenuRefreshPendingGroups = {}
		obj._zoneStatusMenuRefreshAll = false
		obj._zoneStatusMenuRefreshScheduler = nil
		obj._frontlineRefreshDirty = false
		obj._frontlineRefreshScheduler = nil
		obj._fsmCrashLastTickStartAbs = 0
		obj._fsmCrashLastTickDoneAbs = 0
		obj._fsmCrashPhase = 'init'
		obj._fsmCrashCurrentZone = '<none>'
		obj._fsmCrashCurrentGroup = '<none>'
		obj._fsmCrashReported = false
		obj._fsmCrashVersion = FootholdSaveBaseName

		obj.rankThresholds = obj.rankThresholds or {0,3000,5000,8000,12000,16000,22000,30000,45000,65000,90000}
		obj.rankNames      = obj.rankNames      or {"Recruit","Aviator","Airman","Senior Airman","Staff Sergeant","Technical Sergeant","Master Sergeant","Senior Master Sergeant","Chief Master Sergeant","Second Lieutenant","First Lieutenant"}
		obj.jointMenuOwnersByGroup = obj.jointMenuOwnersByGroup or {}
		obj.jointMenuOwnersBySide = obj.jointMenuOwnersBySide or { [1] = {}, [2] = {} }
		obj.jointGroupByPlayerBySide = obj.jointGroupByPlayerBySide or { [1] = {}, [2] = {} }
		obj.jointRequests = obj.jointRequests or { [1] = {}, [2] = {} }
		obj.jointMenusByGroup = obj.jointMenusByGroup or {}
		
		
		setmetatable(obj, self)
		self.__index = self
		return obj
	end

	function BattleCommander:markFsmGroupFilterDirty()
		self._fsmFilterGeneration = self._fsmFilterGeneration + 1
	end

	function BattleCommander:markReindexCombatFilterDirty()
		self._reindexCombatFilterGeneration = self._reindexCombatFilterGeneration + 1
	end

	function BattleCommander:markRedDifficultyDirty()
		self._redDifficultyDirty = true
	end

	function BattleCommander:markSupplyCacheDirty()
		self._supplyCacheGeneration = (self._supplyCacheGeneration or 0) + 1
	end

	function BattleCommander:_flushZoneStatusMenuRefreshQueue()
		self._zoneStatusMenuRefreshScheduler = nil
		local refreshAll = self._zoneStatusMenuRefreshAll
		local pendingGroups = self._zoneStatusMenuRefreshPendingGroups
		self._zoneStatusMenuRefreshAll = false
		self._zoneStatusMenuRefreshPendingGroups = {}

		if refreshAll then
			self:buildZoneStatusMenuForGroup()
			return
		end

		for groupId in pairs(pendingGroups) do
			self:buildZoneStatusMenuForGroup(groupId)
		end
	end

	function BattleCommander:requestZoneStatusMenuRefresh(groupId)
		if groupId == nil then
			self._zoneStatusMenuRefreshAll = true
		elseif not self._zoneStatusMenuRefreshAll then
			self._zoneStatusMenuRefreshPendingGroups[groupId] = true
		end

		if self._zoneStatusMenuRefreshScheduler then
			return
		end

		self._zoneStatusMenuRefreshScheduler = SCHEDULER:New(nil, function(bcRef)
			bcRef:_flushZoneStatusMenuRefreshQueue()
		end, {self}, 0.15, 0)
	end

	function BattleCommander:_flushShopSelectorRefreshQueue()
		self._shopSelectorRefreshScheduler = nil
		local pending = self._shopSelectorRefreshPendingByCoalition or {}
		self._shopSelectorRefreshPendingByCoalition = {}

		for coalitionSide, tokens in pairs(pending) do
			local itemIds = self:_resolveShopSelectorItemIds(coalitionSide, tokens)
			if #itemIds > 0 then
				self:_queueShopSelectorRefreshItemsForCoalition(coalitionSide, itemIds)
			end
		end
		self:_startShopSelectorRefreshWorker()
	end

	function BattleCommander:requestShopSelectorRefreshForCoalition(coalitionSide, tagsOrItemIds)
		self._shopSelectorRefreshPendingByCoalition = self._shopSelectorRefreshPendingByCoalition or {}
		local pending = self._shopSelectorRefreshPendingByCoalition[coalitionSide]
		if not pending then
			pending = {}
			self._shopSelectorRefreshPendingByCoalition[coalitionSide] = pending
		end

		if type(tagsOrItemIds) == "string" then
			pending[tagsOrItemIds] = true
		elseif type(tagsOrItemIds) == "table" then
			for _, value in ipairs(tagsOrItemIds) do
				if type(value) == "string" and value ~= "" then
					pending[value] = true
				end
			end
			for key, value in pairs(tagsOrItemIds) do
				if value == true and type(key) == "string" and key ~= "" then
					pending[key] = true
				end
			end
		end

		if self._shopSelectorRefreshScheduler then
			return
		end

		self._shopSelectorRefreshScheduler = SCHEDULER:New(nil, function(bcRef)
			bcRef:_flushShopSelectorRefreshQueue()
		end, {self}, 0.15, 0)
	end

	function BattleCommander:requestDelayedSupplyMenuRefresh()
		self._supplyMenuRefreshToken = (self._supplyMenuRefreshToken or 0) + 1
		local token = self._supplyMenuRefreshToken
		SCHEDULER:New(nil, function(bcRef, expectedToken)
			if bcRef._supplyMenuRefreshToken ~= expectedToken then return end
			bcRef:requestShopSelectorRefreshForCoalition(2, { 'supplies2', 'supplies' })
		end, {self, token}, 5, 0)
	end

	function BattleCommander:_queueShopSelectorRefreshItemsForCoalition(coalitionSide, itemIds)
		if not itemIds or #itemIds == 0 then
			return
		end

		self._shopSelectorRefreshWorkQueue = self._shopSelectorRefreshWorkQueue or {}
		self._shopSelectorRefreshWorkSeen = self._shopSelectorRefreshWorkSeen or {}
		self._shopSelectorRefreshWorkHead = self._shopSelectorRefreshWorkHead or 1

		local groups = self:_getLivePlayerGroupsForCoalition(coalitionSide)
		if #groups == 0 then
			return
		end

		itemIds = self:_orderShopSelectorRefreshItemIds(coalitionSide, itemIds)

		for _, itemId in ipairs(itemIds) do
			for _, entry in ipairs(groups) do
				local groupId = entry.groupId
				local groupObj = entry.groupObj
				if self.groupSupportMenus[groupId] then
					local workKey = tostring(coalitionSide) .. "|" .. tostring(groupId) .. "|" .. tostring(itemId)
					if not self._shopSelectorRefreshWorkSeen[workKey] then
						self._shopSelectorRefreshWorkSeen[workKey] = true
						self._shopSelectorRefreshWorkQueue[#self._shopSelectorRefreshWorkQueue + 1] = {
							coalition = coalitionSide,
							groupId = groupId,
							groupObj = groupObj,
							itemId = itemId,
							workKey = workKey,
						}
					end
				end
			end
		end
	end

	function BattleCommander:_startShopSelectorRefreshWorker()
		local queue = self._shopSelectorRefreshWorkQueue or {}
		local head = self._shopSelectorRefreshWorkHead or 1
		if head > #queue then
			return
		end
		if self._shopSelectorRefreshWorkerScheduler then
			return
		end

		local delay = self.shopSelectorRefreshInterval or 0.5
		self._shopSelectorRefreshWorkerScheduler = SCHEDULER:New(nil, function(bcRef)
			bcRef:_runShopSelectorRefreshWorkerTick()
		end, {self}, delay, 0)
	end

	function BattleCommander:_runShopSelectorRefreshWorkerTick()
		self._shopSelectorRefreshWorkerScheduler = nil
		local queue = self._shopSelectorRefreshWorkQueue or {}
		local head = self._shopSelectorRefreshWorkHead or 1
		local queueCount = #queue
		local budget = self.shopSelectorRefreshBudget or 8
		local processed = 0

		while processed < budget and head <= queueCount do
			local job = queue[head]
			head = head + 1
			processed = processed + 1

			if job then
				if self._shopSelectorRefreshWorkSeen then
					self._shopSelectorRefreshWorkSeen[job.workKey] = nil
				end
				self:refreshShopSelectorItemForGroup(job.groupId, job.groupObj, job.itemId)
			end
		end

		if head > queueCount then
			self._shopSelectorRefreshWorkQueue = {}
			self._shopSelectorRefreshWorkHead = 1
			self._shopSelectorRefreshWorkSeen = {}
		else
			self._shopSelectorRefreshWorkHead = head
			self:_startShopSelectorRefreshWorker()
		end
	end

	function BattleCommander:_flushFrontlineRefresh()
		self._frontlineRefreshScheduler = nil
		if not self._frontlineRefreshDirty then
			return
		end
		self._frontlineRefreshDirty = false
		Frontline.BuildFromZones(self.indexedZones or self.zones)
		Frontline.ReindexZoneCalcs()
	end

	function BattleCommander:requestFrontlineRefresh()
		self._frontlineRefreshDirty = true
		if self._frontlineRefreshScheduler then
			return
		end

		self._frontlineRefreshScheduler = SCHEDULER:New(nil, function(bcRef)
			bcRef:_flushFrontlineRefresh()
		end, {self}, 0.15, 0)
	end

	function BattleCommander:_recordFsmFilterRebuildSummary(zoneName, removedPatrol, removedAttack, fsmFiltered, reindexCached)
		if not GlobalSettings.FilterLog then
			return
		end
		local filtered = fsmFiltered or {}
		local cached = reindexCached or {}
		local fsmLeftAll = #filtered
		local fsmLeftCombat = 0
		local fsmLeftSupply = 0
		for i = 1, #filtered do
			local gc = filtered[i]
			local mission = gc and gc.mission
			if mission == 'attack' or mission == 'patrol' then
				if gc and gc.targetzone then
					fsmLeftCombat = fsmLeftCombat + 1
				end
			elseif mission == 'supply' then
				fsmLeftSupply = fsmLeftSupply + 1
			end
		end
		local reindexLeft = #cached
		local detailed = GlobalSettings.FilterLogDetailed == true
		local fsmGen = self._fsmFilterGeneration or 0
		local reindexGen = self._reindexCombatFilterGeneration or 0
		local key = tostring(fsmGen) .. "|" .. tostring(reindexGen)
		local s = self._fsmFilterSummary
		if not s or s.key ~= key then
			local staleOthers = 0
			for _, z in ipairs(self.zones) do
				if z._fsmFilterGeneration ~= fsmGen or z._reindexCombatCacheGeneration ~= reindexGen then
					staleOthers = staleOthers + 1
				end
			end
			s = {
				key = key,
				expected = staleOthers + 1, -- include the caller zone rebuilt right now
				processed = 0,
				zones = 0,
				removedPatrol = 0,
				removedAttack = 0,
				total = 0,
				fsmLeftAll = 0,
				fsmLeftCombat = 0,
				fsmLeftSupply = 0,
				reindexLeft = 0,
				detailed = detailed,
				fsmCombatByZone = detailed and {} or nil,
				fsmSupplyByZone = detailed and {} or nil,
				reindexByZone = detailed and {} or nil,
			}
			self._fsmFilterSummary = s
		end
		if detailed and not s.fsmCombatByZone then
			s.fsmCombatByZone = {}
			s.fsmSupplyByZone = {}
			s.reindexByZone = {}
			s.detailed = true
		end

		s.processed = s.processed + 1
		s.zones = s.zones + 1
		s.removedPatrol = s.removedPatrol + (removedPatrol or 0)
		s.removedAttack = s.removedAttack + (removedAttack or 0)
		s.total = s.total + (removedPatrol or 0) + (removedAttack or 0)
		s.fsmLeftAll = s.fsmLeftAll + (fsmLeftAll or 0)
		s.fsmLeftCombat = s.fsmLeftCombat + (fsmLeftCombat or 0)
		s.fsmLeftSupply = s.fsmLeftSupply + (fsmLeftSupply or 0)
		s.reindexLeft = s.reindexLeft + (reindexLeft or 0)
		if s.detailed then
			local zn = tostring(zoneName or "unknown")
			local fsmCombatNames = {}
			local fsmSupplyNames = {}
			for i = 1, #filtered do
				local gc = filtered[i]
				if gc and gc.name then
					local mission = gc.mission
					if mission == 'attack' or mission == 'patrol' then
						if gc.targetzone then
							fsmCombatNames[#fsmCombatNames + 1] = gc.name
						end
					elseif mission == 'supply' then
						fsmSupplyNames[#fsmSupplyNames + 1] = gc.name
					end
				end
			end
			if #fsmCombatNames > 0 then
				s.fsmCombatByZone[zn] = fsmCombatNames
			end
			if #fsmSupplyNames > 0 then
				s.fsmSupplyByZone[zn] = fsmSupplyNames
			end

			local reindexNames = {}
			for i = 1, #cached do
				local row = cached[i]
				local gc = row and row.groupRef
				if gc and gc.name then
					reindexNames[#reindexNames + 1] = gc.name
				end
			end
			if #reindexNames > 0 then
				s.reindexByZone[zn] = reindexNames
			end
		end
		if s.processed >= s.expected then
			env.info(string.format("[FSM-FILTER] summary zones=%d filteredOut patrol=%d attack=%d total=%d leftFSM=%d leftReindexCache=%d leftFSupply=%d leftFSMAll=%d", s.zones, s.removedPatrol, s.removedAttack, s.total, s.fsmLeftCombat, s.reindexLeft, s.fsmLeftSupply, s.fsmLeftAll))
			if s.detailed then
				local function _logDetailedByZone(tag, map)
					local zones = {}
					for zn, _ in pairs(map or {}) do
						zones[#zones + 1] = zn
					end
					table.sort(zones)
					if #zones == 0 then
						env.info("[FSM-FILTER] detailed " .. tag .. " zone=<none> groups=<none>")
						return
					end
					for i = 1, #zones do
						local zn = zones[i]
						local names = map[zn] or {}
						table.sort(names)
						env.info(string.format("[FSM-FILTER] detailed %s zone=%s groups=%s", tag, zn, table.concat(names, ",")))
					end
				end
				_logDetailedByZone("leftFSM", s.fsmCombatByZone)
				_logDetailedByZone("leftFSupply", s.fsmSupplyByZone)
				_logDetailedByZone("leftReindexCache", s.reindexByZone)
			end
			self._fsmFilterSummary = nil
		end
	end

	function BattleCommander:_rebuildReindexCombatCache()
		local zones = self.zones
		for i = 1, #zones do
			local zone = zones[i]
			local cached = {}
			local groups = zone and zone.groups
			if groups then
				for j = 1, #groups do
					local gc = groups[j]
					local isRetired = gc and self:_dynamicHybridIsRetiredGroup(gc)
					if gc and not isRetired then
						local reason = zone:_fsmExcludeReason(gc)
						local mission = gc.mission
						if not reason and gc._artilleryReturnHome ~= true and (mission == 'attack' or mission == 'patrol') then
							local targetName = gc.targetzone
							if targetName then
								cached[#cached + 1] = {
									groupRef = gc,
									targetZoneName = targetName,
								}
							end
						end
					end
				end
			end
			if zone then
				zone._reindexCombatCache = cached
				zone._reindexCombatCacheGeneration = self._reindexCombatFilterGeneration
			end
		end
		self._reindexCombatCacheGeneration = self._reindexCombatFilterGeneration
	end

	function BattleCommander:_initSpawnEvalDispatcher()
		if self._spawnEvalInit then return end

		self._spawnEvalOrder = {
			'cap_patrol',
			'cap_attack',
			'cas',
			'sead',
			'runway',
			'antiship',
			'supply',
			'attack',
		}
		self._spawnEvalQueues = {}
		for _, key in ipairs(self._spawnEvalOrder) do
			self._spawnEvalQueues[key] = {}
		end
		self._spawnEvalQueued = {}
		self._spawnEvalCursor = 1
		self._spawnEvalInit = true
	end

	function BattleCommander:_spawnEvalGroupKey(gc)
		local zn = gc and gc.zoneCommander and gc.zoneCommander.zone or ""
		local gn = gc and gc.name or ""
		local mt = gc and gc.MissionType or ""
		local mz = gc and gc.targetzone or ""
		return tostring(gn) .. "|" .. tostring(mt) .. "|" .. tostring(mz) .. "|" .. tostring(zn)
	end

	function BattleCommander:_queueShouldSpawnEval(gc, triggerState, ignore)
		if not gc or not triggerState then return end
		if self.spawnEvalEnabled == false then return end
		self:_initSpawnEvalDispatcher()

		local key = self:_spawnEvalGroupKey(gc)
		if self._spawnEvalQueued[key] then return end

		local bucket = 'other'
		local missionType = gc.MissionType
		local mission = gc.mission
		if missionType == 'CAP' then
			bucket = (mission == 'attack') and 'cap_attack' or 'cap_patrol'
		elseif missionType == 'CAS' then
			bucket = 'cas'
		elseif missionType == 'SEAD' then
			bucket = 'sead'
		elseif missionType == 'RUNWAYSTRIKE' then
			bucket = 'runway'
		elseif missionType == 'ANTISHIP' then
			bucket = 'antiship'
		elseif mission == 'supply' then
			bucket = 'supply'
		elseif mission == 'attack' then
			bucket = 'attack'
		elseif mission == 'patrol' then
			bucket = 'patrol'
		end

		local queue = self._spawnEvalQueues[bucket]
		if not queue then
			queue = {}
			self._spawnEvalQueues[bucket] = queue
			self._spawnEvalOrder[#self._spawnEvalOrder + 1] = bucket
		end
		queue[#queue + 1] = {
			gc = gc,
			state = triggerState,
			ignore = ignore == true,
		}
		self._spawnEvalQueued[key] = true
	end

	function BattleCommander:_consumeShouldSpawnEval(gc, triggerState, ignore)
		local cache = gc and gc._spawnEvalCache
		if not cache then return nil end
		local ttl = self.spawnEvalCacheTtlSec or 90
		local at = cache.at or 0
		if timer.getAbsTime() - at > ttl then
			gc._spawnEvalCache = nil
			return nil
		end
		if cache.state ~= triggerState then return nil end
		if cache.ignore ~= (ignore == true) then return nil end
		local value = cache.value == true
		gc._spawnEvalCache = nil
		return value
	end

	function BattleCommander:_isSpawnableCached(gc, ttlSec)
		local cache = gc and (gc._spawnEvalLast or gc._spawnEvalCache)
		if not cache then return false end
		local ttl = ttlSec or self.spawnEvalCacheTtlSec or 90
		if timer.getAbsTime() - (cache.at or 0) > ttl then
			return false
		end
		return cache.value == true
	end

	function BattleCommander:_runShouldSpawnEvalTick()
		if self.spawnEvalEnabled == false then return end
		self:_initSpawnEvalDispatcher()

		local total = 0
		for _, key in ipairs(self._spawnEvalOrder) do
			local q = self._spawnEvalQueues[key]
			total = total + ((q and #q) or 0)
		end
		if total <= 0 then return end

		local budget = (total > self.spawnEvalHighWater) and self.spawnEvalBudgetHigh or self.spawnEvalBudgetBase
		local processed = 0
		local emptyTurns = 0
		local idx = self._spawnEvalCursor or 1
		local orderCount = #self._spawnEvalOrder

		while processed < budget and total > 0 and emptyTurns < orderCount do
			if idx > orderCount then idx = 1 end
			local key = self._spawnEvalOrder[idx]
			local q = self._spawnEvalQueues[key]
			if q and #q > 0 then
				local entry = table.remove(q, 1)
				total = total - 1
				processed = processed + 1
				emptyTurns = 0

				if entry and entry.gc then
					local gc = entry.gc
					self._spawnEvalQueued[self:_spawnEvalGroupKey(gc)] = nil
					local st = gc.state
					if st == entry.state and (st == 'inhangar' or st == 'preparing' or st == 'dead') then
						local decision = gc:shouldSpawn(entry.ignore)
						gc._spawnEvalCache = {
							value = decision == true,
							state = entry.state,
							ignore = entry.ignore == true,
							at = timer.getAbsTime(),
						}
						gc._spawnEvalLast = gc._spawnEvalCache
					end
				end
			else
				emptyTurns = emptyTurns + 1
			end
			idx = idx + 1
		end

		if idx > orderCount then idx = 1 end
		self._spawnEvalCursor = idx
	end
	
	function BattleCommander:_jointIsSharing(p)
		return self.jointPairs and self.jointPairs[p] ~= nil
	end

	function BattleCommander:_jointPartner(p)
		return self.jointPairs and self.jointPairs[p] or nil
	end

	function BattleCommander:_jointEnd(p)
		local q = self.jointPairs and self.jointPairs[p]
		if q then
			self.jointPairs[q] = nil
			self.jointPairs[p] = nil
		end
	end

	function BattleCommander:_jointPartnerAlive(p)
		local pls = coalition.getPlayers(1)
		for _, u in pairs(pls) do
			if u and u:isExist() and u:getLife() > 0 and u:getPlayerName() == p then
				return true
			end
		end
		pls = coalition.getPlayers(2)
		for _, u in pairs(pls) do
			if u and u:isExist() and u:getLife() > 0 and u:getPlayerName() == p then
				return true
			end
		end
	end

	function BattleCommander:_jointLeave(groupid)
		self.playerNames = self.playerNames or {}
		local a = self.playerNames[groupid]
		if not a then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_NO_PLAYER_FOR_GROUP"), 10)
			return
		end
		local b = self.jointPairs and self.jointPairs[a]
		if b then
			self.jointPairs[b] = nil
			self.jointPairs[a] = nil
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_LEFT"), 15)
			local gid2 = self.groupByPlayer and self.groupByPlayer[b]
			if gid2 then
				trigger.action.outTextForGroup(gid2, L10N:FormatForGroup(gid2, "JOINT_PLAYER_LEFT", a), 15)
			end
			local owner = self.jointMenuOwnersByGroup and self.jointMenuOwnersByGroup[groupid]
			if owner then
				self:refreshJointMenusForSide(owner.side)
			end
		else
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_ALREADY_ALONE"), 10)
		end
	end

	function BattleCommander:_jointGenCode(groupid, side)
		self.jointCodes = self.jointCodes or {}
		for code, data in pairs(self.jointCodes) do
			if data.gid == groupid and data.side == side then
				trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_CODE", code), 30)
				return
			end
		end
		local c
		repeat
			c = tostring(math.random(1000, 9999))
		until not self.jointCodes[c]
		self.jointCodes[c] = { gid = groupid, side = side }
		trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_CODE", c), 30)
	end

	function BattleCommander:_jointAcceptCode(groupid, code, side)
		self.jointPairs = self.jointPairs or {}
		self.playerNames = self.playerNames or {}
		local host = self.jointCodes and self.jointCodes[tostring(code)]
		if not host then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_INVALID_CODE"), 15)
			return
		end
		if host.side ~= side then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_SAME_COALITION"), 10)
			return
		end
		local a = self.playerNames[host.gid]
		local b = self.playerNames[groupid]
		if not a or not b then
			return
		end
		if a == b then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_CANT_JOIN_OWN"), 15)
			return
		end
		if self.jointPairs[a] or self.jointPairs[b] then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_ALREADY_SHARING"), 15)
			return
		end
		self.jointPairs[a] = b
		self.jointPairs[b] = a
		self.jointCodes[tostring(code)] = nil
		trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_JOINED", a), 20)
		if host.gid then
			trigger.action.outTextForGroup(host.gid, L10N:FormatForGroup(host.gid, "JOINT_PLAYER_JOINED", b), 20)
		end
	end

	function BattleCommander:_jointEnsureMenuState()
		self.jointMenuOwnersByGroup = self.jointMenuOwnersByGroup or {}
		self.jointMenuOwnersBySide = self.jointMenuOwnersBySide or { [1] = {}, [2] = {} }
		self.jointGroupByPlayerBySide = self.jointGroupByPlayerBySide or { [1] = {}, [2] = {} }
		self.jointRequests = self.jointRequests or { [1] = {}, [2] = {} }
		self.jointMenusByGroup = self.jointMenusByGroup or {}
	end

	function BattleCommander:_jointRemoveMenuForGroup(groupid)
		self:_jointEnsureMenuState()
		local state = self.jointMenusByGroup[groupid]
		if state then
			local handle = type(state) == "table" and state.root or state
			if handle then
				missionCommands.removeItemForGroup(groupid, handle)
			end
		end
		self.jointMenusByGroup[groupid] = nil
	end

	function BattleCommander:_jointClearTrackedMenuItems(groupid, items)
		for _, handle in ipairs(items or {}) do
			missionCommands.removeItemForGroup(groupid, handle)
		end
	end

	function BattleCommander:_jointRegisterMenuOwner(groupid, groupname, player, side)
		self:_jointEnsureMenuState()
		local oldOwner = self.jointMenuOwnersByGroup[groupid]
		if oldOwner then
			self.jointMenuOwnersBySide[oldOwner.side][groupid] = nil
			if self.jointGroupByPlayerBySide[oldOwner.side][oldOwner.player] == groupid then
				self.jointGroupByPlayerBySide[oldOwner.side][oldOwner.player] = nil
			end
		end
		self.jointMenuOwnersBySide[side] = self.jointMenuOwnersBySide[side] or {}
		self.jointGroupByPlayerBySide[side] = self.jointGroupByPlayerBySide[side] or {}
		self.jointMenuOwnersByGroup[groupid] = { player = player, groupName = groupname, side = side }
		self.jointMenuOwnersBySide[side][groupid] = true
		self.jointGroupByPlayerBySide[side][player] = groupid
	end

	function BattleCommander:_jointClearRequestsForPlayer(player)
		self:_jointEnsureMenuState()
		if not player then return end
		for side, targets in pairs(self.jointRequests) do
			for targetPlayer, requesters in pairs(targets) do
				if targetPlayer == player then
					targets[targetPlayer] = nil
				else
					requesters[player] = nil
					if next(requesters) == nil then
						targets[targetPlayer] = nil
					end
				end
			end
		end
	end

	function BattleCommander:_jointPruneGroup(groupid)
		self:_jointEnsureMenuState()
		local owner = self.jointMenuOwnersByGroup[groupid]
		local side = owner and owner.side or nil
		local player = owner and owner.player or (self.playerNames and self.playerNames[groupid] or nil)
		local partner = player and self.jointPairs and self.jointPairs[player] or nil
		if partner then
			local partnerGroupId = self.groupByPlayer and self.groupByPlayer[partner] or nil
			local partnerOwner = partnerGroupId and self.jointMenuOwnersByGroup[partnerGroupId] or nil
			side = side or (partnerOwner and partnerOwner.side)
			self:_jointEnd(player)
			if partnerGroupId then
				trigger.action.outTextForGroup(partnerGroupId, L10N:FormatForGroup(partnerGroupId, "JOINT_PLAYER_LEFT", player), 15)
			end
		end
		self:_jointRemoveMenuForGroup(groupid)
		if owner then
			self.jointMenuOwnersBySide[owner.side][groupid] = nil
			if self.jointGroupByPlayerBySide[owner.side][owner.player] == groupid then
				self.jointGroupByPlayerBySide[owner.side][owner.player] = nil
			end
			self.jointMenuOwnersByGroup[groupid] = nil
		end
		self:_jointClearRequestsForPlayer(player)
		return side
	end

	function BattleCommander:_jointGetActiveIncomingRequests(side, targetPlayer)
		self:_jointEnsureMenuState()
		local entries = {}
		local targetRequests = self.jointRequests[side] and self.jointRequests[side][targetPlayer] or nil
		if not targetRequests then return entries end
		local now = timer.getTime()
		for requester, request in pairs(targetRequests) do
			if now < (request.expiresAt or 0) then
				entries[#entries + 1] = { player = requester, request = request }
			end
		end
		table.sort(entries, function(a, b) return a.player < b.player end)
		return entries
	end

	function BattleCommander:_jointEnsureMenuForGroup(groupid, parent)
		self:_jointEnsureMenuState()
		local T = L10N:ForGroup(groupid)
		local state = self.jointMenusByGroup[groupid]
		if type(state) ~= "table" or not state.root then
			if state then
				missionCommands.removeItemForGroup(groupid, state)
			end
			local jm = missionCommands.addSubMenuForGroup(groupid, T:Get("JOINT_MENU_ROOT"), parent)
			state = {
				root = jm,
				requestItems = {},
				pendingItems = {},
			}
			state.requestMenu = missionCommands.addSubMenuForGroup(groupid, T:Get("JOINT_MENU_REQUEST_PLAYER"), jm)
			state.pendingMenu = missionCommands.addSubMenuForGroup(groupid, T:Get("JOINT_MENU_PENDING_REQUESTS"), jm)
			state.leaveItem = missionCommands.addCommandForGroup(groupid, T:Get("JOINT_MENU_LEAVE"), jm, self._jointLeave, self, groupid)
			state.statusItem = missionCommands.addCommandForGroup(groupid, T:Get("JOINT_MENU_STATUS"), jm, function()
				local pname = self.playerNames and self.playerNames[groupid]
				local jp = pname and self.jointPairs and self.jointPairs[pname]
				if jp and self:_jointPartnerAlive(pname) and self:_jointPartnerAlive(jp) then
					trigger.action.outTextForGroup(groupid, T:Format("JOINT_STATUS_WITH", jp), 15)
				else
					trigger.action.outTextForGroup(groupid, T:Get("JOINT_STATUS_ALONE"), 15)
				end
			end)
			state.helpItem = missionCommands.addCommandForGroup(groupid, T:Get("JOINT_MENU_HELP"), jm, function()
				trigger.action.outTextForGroup(groupid, T:Get("JOINT_HELP_REQUESTS"), 30)
			end)
			self.jointMenusByGroup[groupid] = state
		end
		return state
	end

	function BattleCommander:refreshJointRequestPlayerChildrenForGroup(groupid, parent, side)
		local state = self:_jointEnsureMenuForGroup(groupid, parent)
		self:_jointClearTrackedMenuItems(groupid, state.requestItems)
		state.requestItems = {}
		local T = L10N:ForGroup(groupid)
		local owner = self.jointMenuOwnersByGroup[groupid]
		local player = owner and owner.player or (self.playerNames and self.playerNames[groupid] or nil)
		local coalitionSide = side or owner.side

		local function addPaged(entries, root, trackedItems, addEntry)
			local count = 0
			local sub1 = nil
			for _, entry in ipairs(entries) do
				count = count + 1
				local target = root
				local trackEntry = false
				if count < 10 then
					target = root
					trackEntry = true
				elseif count == 10 then
					sub1 = missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MORE"), root)
					trackedItems[#trackedItems + 1] = sub1
					target = sub1
				elseif count % 9 == 1 then
					sub1 = missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MORE"), sub1)
					target = sub1
				else
					target = sub1
				end
				local handle = addEntry(entry, target)
				if trackEntry and handle then
					trackedItems[#trackedItems + 1] = handle
				end
			end
		end

		local candidates = {}
		if player and not (self.jointPairs and self.jointPairs[player]) then
			for candidateGroupId in pairs(self.jointMenuOwnersBySide[coalitionSide] or {}) do
				local candidate = self.jointMenuOwnersByGroup[candidateGroupId]
				if candidate
					and candidateGroupId ~= groupid
					and candidate.player ~= player
					and not (self.jointPairs and self.jointPairs[candidate.player])
					and MissionsRootMenus[candidateGroupId]
				then
					candidates[#candidates + 1] = candidate
				end
			end
		end
		table.sort(candidates, function(a, b) return a.player < b.player end)
		if #candidates == 0 then
			state.requestItems[#state.requestItems + 1] = missionCommands.addCommandForGroup(groupid, T:Get("JOINT_MENU_NO_PLAYERS"), state.requestMenu, trigger.action.outTextForGroup, groupid, T:Get("JOINT_MENU_NO_PLAYERS"), 10)
		else
			addPaged(candidates, state.requestMenu, state.requestItems, function(candidate, target)
				return missionCommands.addCommandForGroup(groupid, candidate.player, target, self._jointRequestPlayer, self, groupid, candidate.player, coalitionSide)
			end)
		end
	end

	function BattleCommander:refreshJointPendingRequestChildrenForGroup(groupid, parent, side)
		local state = self:_jointEnsureMenuForGroup(groupid, parent)
		self:_jointClearTrackedMenuItems(groupid, state.pendingItems)
		state.pendingItems = {}
		local T = L10N:ForGroup(groupid)
		local owner = self.jointMenuOwnersByGroup[groupid]
		local player = owner and owner.player or (self.playerNames and self.playerNames[groupid] or nil)
		local coalitionSide = side or owner.side

		local function addPaged(entries, root, trackedItems, addEntry)
			local count = 0
			local sub1 = nil
			for _, entry in ipairs(entries) do
				count = count + 1
				local target = root
				local trackEntry = false
				if count < 10 then
					target = root
					trackEntry = true
				elseif count == 10 then
					sub1 = missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MORE"), root)
					trackedItems[#trackedItems + 1] = sub1
					target = sub1
				elseif count % 9 == 1 then
					sub1 = missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MORE"), sub1)
					target = sub1
				else
					target = sub1
				end
				local handle = addEntry(entry, target)
				if trackEntry and handle then
					trackedItems[#trackedItems + 1] = handle
				end
			end
		end

		local pending = player and self:_jointGetActiveIncomingRequests(coalitionSide, player) or {}
		if #pending == 0 then
			state.pendingItems[#state.pendingItems + 1] = missionCommands.addCommandForGroup(groupid, T:Get("JOINT_MENU_NO_PENDING_REQUESTS"), state.pendingMenu, trigger.action.outTextForGroup, groupid, T:Get("JOINT_MENU_NO_PENDING_REQUESTS"), 10)
		else
			addPaged(pending, state.pendingMenu, state.pendingItems, function(entry, target)
				local requestMenu = missionCommands.addSubMenuForGroup(groupid, T:Format("JOINT_MENU_REQUEST_FROM", entry.player), target)
				missionCommands.addCommandForGroup(groupid, T:Get("JOINT_MENU_ACCEPT_REQUEST"), requestMenu, self._jointAcceptRequest, self, groupid, entry.player)
				missionCommands.addCommandForGroup(groupid, T:Get("JOINT_MENU_DENY_REQUEST"), requestMenu, self._jointDenyRequest, self, groupid, entry.player)
				return requestMenu
			end)
		end
	end

	function BattleCommander:refreshJointMenuForGroup(groupid, parent, side)
		self:refreshJointRequestPlayerChildrenForGroup(groupid, parent, side)
		self:refreshJointPendingRequestChildrenForGroup(groupid, parent, side)
	end

	function BattleCommander:refreshJointMenusForSide(side)
		self:_jointEnsureMenuState()
		local groupIds = {}
		for groupid in pairs(self.jointMenuOwnersBySide[side] or {}) do
			if MissionsRootMenus[groupid] then
				groupIds[#groupIds + 1] = groupid
			end
		end
		table.sort(groupIds)
		for _, groupid in ipairs(groupIds) do
			self:refreshJointMenuForGroup(groupid, MissionsRootMenus[groupid], side)
		end
	end

	function BattleCommander:_jointRefreshPlayerMenu(side, player)
		local groupid = self.jointGroupByPlayerBySide and self.jointGroupByPlayerBySide[side] and self.jointGroupByPlayerBySide[side][player] or nil
		if groupid and MissionsRootMenus[groupid] then
			self:refreshJointMenuForGroup(groupid, MissionsRootMenus[groupid], side)
		end
	end

	function BattleCommander:_jointRefreshPlayerPendingMenu(side, player)
		local groupid = self.jointGroupByPlayerBySide and self.jointGroupByPlayerBySide[side] and self.jointGroupByPlayerBySide[side][player] or nil
		if groupid and MissionsRootMenus[groupid] then
			self:refreshJointPendingRequestChildrenForGroup(groupid, MissionsRootMenus[groupid], side)
		end
	end

	function BattleCommander:_jointRequestPlayer(groupid, targetPlayer, side)
		self:_jointEnsureMenuState()
		self.jointPairs = self.jointPairs or {}
		self.playerNames = self.playerNames or {}
		local requester = self.playerNames[groupid]
		if not requester then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_NO_PLAYER_FOR_GROUP"), 10)
			return
		end
		if requester == targetPlayer then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_CANT_JOIN_OWN"), 15)
			return
		end
		if self.jointPairs[requester] then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_REQUEST_REQUESTER_BUSY"), 15)
			return
		end
		local targetGroupId = self.jointGroupByPlayerBySide[side] and self.jointGroupByPlayerBySide[side][targetPlayer] or nil
		if not targetGroupId or not self.jointMenuOwnersByGroup[targetGroupId] then
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_REQUEST_NOT_AVAILABLE"), 15)
			return
		end
		if self.jointPairs[targetPlayer] then
			trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_REQUEST_TARGET_BUSY", targetPlayer), 15)
			return
		end
		self.jointRequests[side] = self.jointRequests[side] or {}
		self.jointRequests[side][targetPlayer] = self.jointRequests[side][targetPlayer] or {}
		local now = timer.getTime()
		local request = self.jointRequests[side][targetPlayer][requester]
		if request and now < (request.expiresAt or 0) then
			local remaining = math.max(1, math.ceil((request.expiresAt or now) - now))
			trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_REQUEST_ALREADY_SENT", targetPlayer, remaining), 15)
			return
		end
		local expiresAt = now + 120
		local newRequest = {
			requesterGroupId = groupid,
			targetGroupId = targetGroupId,
			side = side,
			expiresAt = expiresAt,
		}
		self.jointRequests[side][targetPlayer][requester] = newRequest
		timer.scheduleFunction(function(args, _)
			local bcObj = args.context
			local targetRequests = bcObj.jointRequests[args.side] and bcObj.jointRequests[args.side][args.targetPlayer] or nil
			local request = targetRequests and targetRequests[args.requester] or nil
			if request ~= args.request then return end
			targetRequests[args.requester] = nil
			if next(targetRequests) == nil then
				bcObj.jointRequests[args.side][args.targetPlayer] = nil
			end
			local targetGroup = bcObj.jointMenuOwnersByGroup[args.targetGroupId]
			if targetGroup and MissionsRootMenus[args.targetGroupId] then
				trigger.action.outTextForGroup(args.targetGroupId, L10N:GetForGroup(args.targetGroupId, "JOINT_REQUEST_EXPIRED"), 15)
				bcObj:refreshJointPendingRequestChildrenForGroup(args.targetGroupId, MissionsRootMenus[args.targetGroupId], args.side)
			end
			local requesterGroup = bcObj.jointMenuOwnersByGroup[args.requesterGroupId]
			if requesterGroup and MissionsRootMenus[args.requesterGroupId] then
				trigger.action.outTextForGroup(args.requesterGroupId, L10N:GetForGroup(args.requesterGroupId, "JOINT_REQUEST_EXPIRED"), 15)
			end
		end, {
			context = self,
			side = side,
			targetPlayer = targetPlayer,
			requester = requester,
			request = newRequest,
			targetGroupId = targetGroupId,
			requesterGroupId = groupid,
		}, expiresAt)
		trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_REQUEST_SENT", targetPlayer), 15)
		trigger.action.outTextForGroup(targetGroupId, L10N:FormatForGroup(targetGroupId, "JOINT_REQUEST_RECEIVED", requester), 30)
		self:_jointRefreshPlayerPendingMenu(side, targetPlayer)
	end

	function BattleCommander:_jointAcceptRequest(groupid, requester)
		self:_jointEnsureMenuState()
		self.jointPairs = self.jointPairs or {}
		self.playerNames = self.playerNames or {}
		local owner = self.jointMenuOwnersByGroup[groupid]
		local side = owner.side
		local target = self.playerNames[groupid]
		local targetRequests = target and self.jointRequests[side] and self.jointRequests[side][target] or nil
		local request = targetRequests and targetRequests[requester] or nil
		if not request or timer.getTime() >= (request.expiresAt or 0) then
			if targetRequests then targetRequests[requester] = nil end
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_REQUEST_EXPIRED"), 15)
			if request then
				local requesterGroupId = self.jointGroupByPlayerBySide[side] and self.jointGroupByPlayerBySide[side][requester] or request.requesterGroupId
				if requesterGroupId and self.jointMenuOwnersByGroup[requesterGroupId] and MissionsRootMenus[requesterGroupId] then
					trigger.action.outTextForGroup(requesterGroupId, L10N:GetForGroup(requesterGroupId, "JOINT_REQUEST_EXPIRED"), 15)
				end
			end
			self:refreshJointPendingRequestChildrenForGroup(groupid, MissionsRootMenus[groupid], side)
			return
		end
		local requesterGroupId = self.jointGroupByPlayerBySide[side] and self.jointGroupByPlayerBySide[side][requester] or request.requesterGroupId
		if not target or not requesterGroupId or not self.jointMenuOwnersByGroup[requesterGroupId] then
			targetRequests[requester] = nil
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_REQUEST_NOT_AVAILABLE"), 15)
			self:refreshJointPendingRequestChildrenForGroup(groupid, MissionsRootMenus[groupid], side)
			return
		end
		if target == requester then
			targetRequests[requester] = nil
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_CANT_JOIN_OWN"), 15)
			self:refreshJointPendingRequestChildrenForGroup(groupid, MissionsRootMenus[groupid], side)
			return
		end
		if self.jointPairs[target] or self.jointPairs[requester] then
			targetRequests[requester] = nil
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_ALREADY_SHARING"), 15)
			self:refreshJointMenuForGroup(groupid, MissionsRootMenus[groupid], side)
			self:_jointRefreshPlayerMenu(side, requester)
			return
		end
		self.jointPairs[target] = requester
		self.jointPairs[requester] = target
		targetRequests[requester] = nil
		if next(targetRequests) == nil then
			self.jointRequests[side][target] = nil
		end
		trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_JOINED", requester), 20)
		trigger.action.outTextForGroup(requesterGroupId, L10N:FormatForGroup(requesterGroupId, "JOINT_PLAYER_JOINED", target), 20)
		self:refreshJointMenusForSide(side)
	end

	function BattleCommander:_jointDenyRequest(groupid, requester)
		self:_jointEnsureMenuState()
		self.playerNames = self.playerNames or {}
		local owner = self.jointMenuOwnersByGroup[groupid]
		local side = owner.side
		local target = self.playerNames[groupid]
		local targetRequests = target and self.jointRequests[side] and self.jointRequests[side][target] or nil
		local request = targetRequests and targetRequests[requester] or nil
		if request and timer.getTime() >= (request.expiresAt or 0) then
			targetRequests[requester] = nil
			if next(targetRequests) == nil then
				self.jointRequests[side][target] = nil
			end
			trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "JOINT_REQUEST_EXPIRED"), 15)
			local requesterGroupId = self.jointGroupByPlayerBySide[side] and self.jointGroupByPlayerBySide[side][requester] or request.requesterGroupId
			if requesterGroupId and self.jointMenuOwnersByGroup[requesterGroupId] and MissionsRootMenus[requesterGroupId] then
				trigger.action.outTextForGroup(requesterGroupId, L10N:GetForGroup(requesterGroupId, "JOINT_REQUEST_EXPIRED"), 15)
			end
		elseif request then
			targetRequests[requester] = nil
			if next(targetRequests) == nil then
				self.jointRequests[side][target] = nil
			end
			trigger.action.outTextForGroup(groupid, L10N:FormatForGroup(groupid, "JOINT_REQUEST_DENIED", requester), 15)
			local requesterGroupId = self.jointGroupByPlayerBySide[side] and self.jointGroupByPlayerBySide[side][requester] or request.requesterGroupId
			if requesterGroupId then
				trigger.action.outTextForGroup(requesterGroupId, L10N:FormatForGroup(requesterGroupId, "JOINT_REQUEST_DENIED_BY", target), 15)
			end
		end
		self:refreshJointPendingRequestChildrenForGroup(groupid, MissionsRootMenus[groupid], side)
	end
	

	function BattleCommander:increaseDifficulty()
		self.difficultyModifier = math.max(self.difficultyModifier-self.difficulty.escalation, self.difficulty.min)
		GlobalSettings.setDifficultyScaling(self.difficulty.start + self.difficultyModifier, self.difficulty.coalition)
		self.lastDiffChange = timer.getAbsTime()
		env.info('increasing diff: '..self.difficultyModifier)
	end
	
	function BattleCommander:decreaseDifficulty()
		self.difficultyModifier = math.min(self.difficultyModifier+self.difficulty.fade, self.difficulty.max)
		GlobalSettings.setDifficultyScaling(self.difficulty.start + self.difficultyModifier,self.difficulty.coalition)
		self.lastDiffChange = timer.getAbsTime()
		env.info('decreasing diff: '..self.difficultyModifier)
	end
	
	--end difficulty scaling
	
