	function ZoneCommander:_builtHas(name)
		for i,v in pairs(self.built) do
			if v == name then return true end
		end
		return false
	end

function ZoneCommander:suspend()
		local previousState = {
			active = self.active,
			suspended = self.suspended,
			side = self.side,
			isHidden = self.isHidden,
			NeutralAtStart = self.NeutralAtStart,
			firstCaptureByRed = self.firstCaptureByRed,
			airbaseName = self.airbaseName,
			LogisticCenter = self.LogisticCenter,
		}
		self._suspendedLiveFsm = nil
		for _, gc in ipairs(self.groups or {}) do
			if self:_gcIsLiveForFsm(gc) or gc._supplyReturnHome == true then
				self._suspendedLiveFsm = self._suspendedLiveFsm or {}
				self._suspendedLiveFsm[gc.name] = gc
			end
		end
		self.suspended = true
		self.battleCommander:markRedDifficultyDirty()
		env.info("[SUSPEND] "..self.zone)
		self._hibernated = self._hibernated or {}
		self._persistedHibernated = nil
		if not self.remainingUnitsSnapshot then
			local snap = {}
			for i2,v2 in pairs(self.built) do
				snap[i2] = {}
				local gr = Group.getByName(v2)
				if gr then
					local units = gr:getUnits()
					if units and #units > 0 then
						for _,u in ipairs(units) do
							table.insert(snap[i2], u:getDesc().typeName)
						end
					end
				end
			end
			self.remainingUnitsSnapshot = snap
		end
		for _, gName in pairs(self.built) do
			local g = Group.getByName(gName)
			if g and g:isExist() and g:getSize() > 0 then
				self._hibernated[gName] = true
				g:destroy()
			end
		end
		self.battleCommander:_applyZoneShopSelectorDelta(self, previousState)
		local selectorRefreshTags = self.battleCommander:_getZoneSelectorRefreshTags(self, previousState)
		if #selectorRefreshTags > 0 then
			self.battleCommander:requestShopSelectorRefreshForCoalition(2, selectorRefreshTags)
		end
	end

	function ZoneCommander:resume(internal)
		local previousState = {
			active = self.active,
			suspended = self.suspended,
			side = self.side,
			isHidden = self.isHidden,
			NeutralAtStart = self.NeutralAtStart,
			firstCaptureByRed = self.firstCaptureByRed,
			airbaseName = self.airbaseName,
			LogisticCenter = self.LogisticCenter,
		}
		if self._resuming and not internal then return end
		self._resuming = true
		local cz = CustomZone:getByName(self.zone)
		if cz then cz:clearUsedSpawnZones(self.zone) end
		local pending = {}
		for gName,_ in pairs(self._hibernated or {}) do
			local persistedTemplate = self._persistedHibernated and self._persistedHibernated[gName] == true
			if (not persistedTemplate) and Group.getByName(gName) then
				if not self:_builtHas(gName) then pending[gName] = true end
			else
				local ok = false
				if cz and cz.spawnGroup then
					local r = cz:spawnGroup(gName, false)
					if r and r.name then
						for i,v in pairs(self.built) do if v == gName then self.built[i] = r.name break end end
						if Group.getByName(r.name) then ok = true end
					end
				end
				if not ok then env.info("Spawn failed: "..gName.." in zone "..self.zone); pending[gName] = true end
			end
			if self._persistedHibernated and not pending[gName] then
				self._persistedHibernated[gName] = nil
			end
		end
		self._hibernated = pending
		if self._persistedHibernated and not next(self._persistedHibernated) then
			self._persistedHibernated = nil
		end
		if next(self._hibernated) then
			SCHEDULER:New(nil, function(z) z:resume(true) end, {self}, 2, 0)
		else
			self.suspended = false
			self._suspendedLiveFsm = nil
			self.battleCommander:markRedDifficultyDirty()
			self.remainingUnitsSnapshot = nil
			self._persistedHibernated = nil
			self._resuming = nil
			self.battleCommander:_applyZoneShopSelectorDelta(self, previousState)
			local selectorRefreshTags = self.battleCommander:_getZoneSelectorRefreshTags(self, previousState)
			if #selectorRefreshTags > 0 then
				self.battleCommander:requestShopSelectorRefreshForCoalition(2, selectorRefreshTags)
			end
		end
	end

	
	function ZoneCommander:getUpgradesUsed(side)
		local s = side or self.side
		if s == 1 then
			return self.upgradesUsedRed or 0
		elseif s == 2 then
			return self.upgradesUsedBlue or 0
		end
		return self.upgradesUsed or 0
	end

	function ZoneCommander:_setUpgradesUsed(side, val)
		if side == 1 then
			self.upgradesUsedRed = val
		elseif side == 2 then
			self.upgradesUsedBlue = val
		end
		if side == self.side then
			self.upgradesUsed = val
		end
	end

	function ZoneCommander:_syncUpgradesUsed()
		self.upgradesUsed = self:getUpgradesUsed(self.side)
	end

	function ZoneCommander:addExtraSlot(groupName)
		local max = 1 + (bc.globalExtraUnlock and 1 or 0)
		local cur = self:getUpgradesUsed(self.side)
		if cur >= max then return false end

		self:_setUpgradesUsed(self.side, cur + 1)
		self.level        = self.level + 1

		self.extraUpgrade = self.extraUpgrade or {}
		table.insert(self.extraUpgrade, { side = self.side, name = groupName })

		if self.side == 2 then
			table.insert(self.upgrades.blue, groupName)
			self.battleCommander:requestShopSelectorRefreshForCoalition(2, { 'zinf', 'zsam', 'zhimars', 'zarm', 'zpat' })
			if self:_refreshSupplyMenuCache() then
				self.battleCommander:requestDelayedSupplyMenuRefresh()
			end
		elseif self.side == 1 then
			table.insert(self.upgrades.red , groupName)
		end

		return true
	end

	function ZoneCommander:_cacheUpgradeStatics()
		if not self.upgrades then return end

		self.newStatics = self.newStatics or {}

		local seen = {}
		for _, data in ipairs(self.newStatics) do
			if data and data.name then
				seen[data.name] = true
			end
		end

		local allUpgrades = {}
		for _, name in ipairs(self._configuredStaticUpgrades or {}) do
			if name then allUpgrades[name] = true end
		end
		local function collectUpgradeNames(source)
			if not source then return end
			if source.red then
				for _, entry in pairs(source.red) do
					local name = getUpgradeEntryName(entry)
					if name then allUpgrades[name] = true end
				end
			end
			if source.blue then
				for _, entry in pairs(source.blue) do
					local name = getUpgradeEntryName(entry)
					if name then allUpgrades[name] = true end
				end
			end
		end
		collectUpgradeNames(self.upgrades)

		for name, _ in pairs(allUpgrades) do
			if not seen[name] then
				local staticObj = STATIC:FindByName(name, false)
				if staticObj then
					local point = staticObj:GetPointVec3()
					local desc = staticObj:GetDesc()
					local shapeName = desc and desc.shapeName
					local typeName  = staticObj:GetTypeName()
					if typeName == ".Command Center" then
						shapeName = shapeName or "ComCenter"
					end
					if typeName == ".Ammunition depot" then
						shapeName = shapeName or "SkladC"
					end
					table.insert(self.newStatics, {
						name = name,
						point = point,
						type = typeName,
						heading = staticObj:GetHeading(),
						country = staticObj:GetCoalition(),
						shapeName = shapeName,
					})
					seen[name] = true
				end
			end
		end

		if next(self.newStatics) == nil then
			self.newStatics = nil
		end
	end

	function ZoneCommander:_getTrackedStaticBaseName(name)
		local baseName = _normalizeBuiltName(name)
		if not baseName or baseName == "" then
			return nil
		end
		for _, data in ipairs(self.newStatics or {}) do
			local staticName = type(data) == "table" and data.name or data
			if _normalizeBuiltName(staticName) == baseName then
				return baseName
			end
		end
		return nil
	end

	function ZoneCommander:_applyRetiredStaticUpgrades(opts)
		opts = opts or {}
		local retiredSet = _copyRetiredStaticSet(self.retiredStaticUpgrades)
		if not next(retiredSet) then
			self.retiredStaticUpgrades = nil
			return false
		end

		self.retiredStaticUpgrades = retiredSet

		local remapSlots = opts.remapSlots ~= false
		local currentList = nil
		if self.side == 1 then
			currentList = self.upgrades and self.upgrades.red
		elseif self.side == 2 then
			currentList = self.upgrades and self.upgrades.blue
		end
		local remap = _buildUpgradeIndexRemap(currentList, retiredSet)
		local remapChanged = remapSlots and _hasIndexRemapChange(remap) or false
		local changed = false

		if self.upgrades then
			local pruned = false
			self.upgrades.red, pruned = _compactUpgradeListForRetiredStatics(self.upgrades.red, retiredSet)
			changed = changed or pruned
			self.upgrades.blue, pruned = _compactUpgradeListForRetiredStatics(self.upgrades.blue, retiredSet)
			changed = changed or pruned
		end

		if self.randomUpgradesRed then
			local pruned = false
			self.randomUpgradesRed, pruned = _compactUpgradeListForRetiredStatics(self.randomUpgradesRed, retiredSet)
			changed = changed or pruned
		end
		if self.randomUpgradesBlue then
			local pruned = false
			self.randomUpgradesBlue, pruned = _compactUpgradeListForRetiredStatics(self.randomUpgradesBlue, retiredSet)
			changed = changed or pruned
		end

		if remapChanged then
			self.built = _remapIndexedSlots(self.built, remap)
			if self.remainingUnits then
				self.remainingUnits = _remapIndexedSlots(self.remainingUnits, remap)
			end
			if self.remainingUnitsSnapshot then
				self.remainingUnitsSnapshot = _remapIndexedSlots(self.remainingUnitsSnapshot, remap)
			end
		end

		return changed or remapChanged
	end


function ZoneCommander:getFilteredUpgrades()
		local upgrades
		if self.side == 1 then
			upgrades = self.upgrades.red
		elseif self.side == 2 then
			upgrades = self.upgrades.blue
		else
			upgrades = {}
		end

		if not UseStatics then
			self:_cacheUpgradeStatics()
		end

		if self.suspended and self.remainingUnitsSnapshot then
			local res = {}
			for idx,_ in pairs(self.remainingUnitsSnapshot) do
				local entry = upgrades[idx]
				local name = getUpgradeEntryName(entry)
				if name then res[idx] = name end
			end
			return res
		end

		if UseStatics then
			-- Always return resolved names (upgrade lists may contain table entries).
			local res = {}
			for idx, entry in pairs(upgrades) do
				local name = getUpgradeEntryName(entry)
				if name then res[idx] = name end
			end
			return res
		end

		local res = {}
		local statics = {}
		for _, data in ipairs(self.newStatics or {}) do
			if data and data.name then
				statics[data.name] = true
			end
		end
		for idx, entry in pairs(upgrades) do
			local name = getUpgradeEntryName(entry)
			local isStatic = statics[name] == true
			if isStatic then
				local st = StaticObject.getByName(name)
				if st and st:isExist() then st:destroy() end
			else
				res[idx] = name
			end
		end
		return res
	end

-- Randomized upgrade helpers (shared across missions)
RandomGroundGroups = RandomGroundGroups or true
RandomBlueGroups = RandomBlueGroups or true

local function _fhAdvanceSeed(min, max)
	FH_RNG_SEED = FH_RNG_SEED or 1234567
	FH_RNG_SEED = (1103515245 * FH_RNG_SEED + 12345) % 2147483648
	local r = FH_RNG_SEED / 2147483648
	if min == nil then return r end
	if max == nil then return math.floor(r * min) + 1 end
	return math.floor(r * (max - min + 1)) + min
end

function fhRand(min, max)
	if FH_RNG_SEED ~= nil then
		return _fhAdvanceSeed(min, max)
	end
	if math and math.randomseed then
		if min == nil then return math.random() end
		if max == nil then return math.random(min) end
		return math.random(min, max)
	end
	return _fhAdvanceSeed(min, max)
end

local function _fhMixSeed(seed, value)
	local mixed = math.floor(tonumber(seed) or 0) % 2147483648
	local text = tostring(value or "")
	for i = 1, #text do
		mixed = (mixed * 1103515245 + text:byte(i) + 12345) % 2147483648
	end
	return mixed
end

local function _fhEnsureCampaignSeed()
	if FH_RNG_CAMPAIGN_SEED ~= nil then
		return FH_RNG_CAMPAIGN_SEED
	end
	if socket and socket.gettime then
		FH_RNG_CAMPAIGN_SEED = math.floor(socket.gettime() * 1e6)
		env.info("[Foothold RNG] seed source=socket.gettime seed=" .. tostring(FH_RNG_CAMPAIGN_SEED))
	else
		local d = env.mission.date or {}
		FH_RNG_CAMPAIGN_SEED = (((tonumber(d.Year) or 0) * 100 + (tonumber(d.Month) or 0)) * 100 + (tonumber(d.Day) or 0)) * 100000 + math.floor(tonumber(env.mission.start_time) or 0)
		env.info("[Foothold RNG] seed source=mission_date seed=" .. tostring(FH_RNG_CAMPAIGN_SEED))
	end
	return FH_RNG_CAMPAIGN_SEED
end

local function _fhSeedZone(zoneObj, sideTag)
	local seed = _fhEnsureCampaignSeed()
	seed = _fhMixSeed(seed, sideTag)
	seed = _fhMixSeed(seed, getZoneSize(zoneObj))
	seed = _fhMixSeed(seed, zoneObj and zoneObj.zone or "")
	FH_RNG_SEED = seed
	return seed
end

function resolveCount(v)
	if type(v) == "table" then
		local a, b = v[1], v[2]
		if a and b then
			return fhRand(a, b)
		end
	end
	return tonumber(v) or 0
end

function resolveTemplate(t)
	return {
		sam = resolveCount(t.sam),
		shorad = resolveCount(t.shorad),
		aaa = resolveCount(t.aaa),
		ground = resolveCount(t.ground),
		armor = resolveCount(t.armor),
		arty = resolveCount(t.arty),
		total = resolveCount(t.total),
	}
end


function resolveTemplateBlue(t)
	return {
		sam = resolveCount(t.sam),
		ground = resolveCount(t.ground),
		armor = resolveCount(t.armor),
		total = resolveCount(t.total),
	}
end

function getZoneSize(zoneObj)
	if not zoneObj then return "none" end
	return zoneObj.size or "none"
end

function classifyUpgradeName(name)
	if not name then return "other" end
	local n = name:lower()

	local function hasAny(list)
		for i = 1, #list do
			if n:find(list[i], 1, true) then return true end
		end
		return false
	end

	if hasAny({ "aaa" }) then
		return "aaa"
	elseif hasAny({ "shorad", "pantsir", "tor", "sa-8", "sa 8", "sa-13", "sa 13", "sa-15", "sa 15", "sa-19", "sa 19", "dog ear" }) then
		return "shorad"
	elseif hasAny({ "sa-2", "sa 2", "sa-3", "sa 3", "sa-6", "sa 6", "sa-10", "sa 10", "sa-11", "sa 11" }) then
		return "sam"
	elseif hasAny({ "arty", "artillery", "mlrs", "grad", "smerch", "uragan", "bm-21" }) then
		return "arty"
	elseif hasAny({ "armour", "armor" }) then
		return "armor"
	elseif hasAny({ "enemy ground", "enemy task", "enemy forces" }) then
		return "ground"
	elseif hasAny({ "sam" }) then
		return "sam"
	end
	return "other"
end

function classifyBlueUpgradeName(name)
	if not name then return "other" end
	local n = name:lower()
	if n:find("infantry", 1, true) then
		return "ground"
	elseif n:find("armor", 1, true) then
		return "armor"
	elseif n:find("sam", 1, true) or n:find("pd", 1, true) then
		return "sam"
	end
	return "other"
end

function isFixedName(name)
	if not name then return false end
	local n = name:lower()
	return n:find("fixed", 1, true) ~= nil or n:find("(p)", 1, true) ~= nil
end

-- Upgrade entries can be either a string group/static name, or a table like:
--   { n = "Group Name", p = true }  -- p=true means "pinned": never random-picked/replaced
function getUpgradeEntryName(entry)
	if type(entry) == "table" then
		return entry.n or entry.name or entry[1]
	end
	return entry
end

function isPinnedUpgradeEntry(entry)
	return type(entry) == "table" and entry.p == true
end

function hasGroupTemplate(name)
	if not name then return false end
	if _DATABASE.Templates.Groups[name] then return true end
	local gr = Group.getByName(name)
	if gr then return true end
	return false
end

function isStaticUpgrade(name)
	if not name then return false end
	return StaticObject.getByName(name) ~= nil
end

function isLongRangeSam(name)
	if not name then return false end
	local n = name:lower()
	return n:find("sa-2", 1, true) or n:find("sa 2", 1, true)
		or n:find("sa-10", 1, true) or n:find("sa 10", 1, true)
		or n:find("sa-11", 1, true) or n:find("sa 11", 1, true)
end

function isExcludedBySize(name, zoneObj, zoneSize)
	if not name or not zoneSize then return false end
	local list = ZoneSizeExclusions[zoneSize]
	if list then
		local n = name:lower()
		for i = 1, #list do
			local pat = list[i]
			if pat and n:find(pat, 1, true) then
				return true
			end
		end
	end
	if zoneObj and zoneObj.noLongRangeSam and isLongRangeSam(name) then
		return true
	end
	return false
end

function buildGlobalRedPool()
	if RandomRedPool and #RandomRedPool > 0 then
		return RandomRedPool
	end
	if type(upgrades) ~= "table" then return {} end
	local pool = {}
	local seen = {}
	for key, def in pairs(upgrades) do
		if type(def) == "table" then
			local k = tostring(key):lower()
			if not isCarrierZoneName(key) and not k:find("hidden", 1, true) then
				local red = def.red
				if type(red) == "table" then
					for _, entry in ipairs(red) do
						local name = getUpgradeEntryName(entry)
						if name and not isPinnedUpgradeEntry(entry) and not isFixedName(name) and not isStaticUpgrade(name) and not seen[name] and hasGroupTemplate(name) then
							seen[name] = true
							pool[#pool+1] = name
						end
					end
				end
			end
		end
	end
	return pool
end

function getGlobalRedPool()
	if not GlobalRedPool or #GlobalRedPool == 0 then
		GlobalRedPool = buildGlobalRedPool()
	end
	return GlobalRedPool
end

GlobalRedPool = GlobalRedPool or buildGlobalRedPool()

function buildGlobalBluePool()
	if RandomBluePool and #RandomBluePool > 0 then
		return RandomBluePool
	end
	if type(upgrades) ~= "table" then return {} end
	local pool = {}
	local seen = {}
	for _, def in pairs(upgrades) do
		if type(def) == "table" then
			local blue = def.blue
			if type(blue) == "table" then
				for _, entry in ipairs(blue) do
					local name = getUpgradeEntryName(entry)
					if name and not isPinnedUpgradeEntry(entry) and name ~= "bluePATRIOT" and not isFixedName(name) and not isStaticUpgrade(name) and not seen[name] and hasGroupTemplate(name) then
						seen[name] = true
						pool[#pool+1] = name
					end
				end
			end
		end
	end
	return pool
end

function getGlobalBluePool()
	if not GlobalBluePool or #GlobalBluePool == 0 then
		GlobalBluePool = buildGlobalBluePool()
	end
	return GlobalBluePool
end

GlobalBluePool = GlobalBluePool or buildGlobalBluePool()

function fillPoolsFrom(source, pools, zoneObj, zoneSize)
	local poolSeen = {}
	local count = 0
	for _, entry in ipairs(source or {}) do
		local name = getUpgradeEntryName(entry)
		if name and not isPinnedUpgradeEntry(entry) and not isFixedName(name) and not isStaticUpgrade(name) and not isExcludedBySize(name, zoneObj, zoneSize) and hasGroupTemplate(name) then
			if not poolSeen[name] then
				poolSeen[name] = true
				local cat = classifyUpgradeName(name)
				pools[cat] = pools[cat] or {}
				pools[cat][#pools[cat]+1] = name
				count = count + 1
			end
		end
	end
	return count
end

function fillPoolsFromBlue(source, pools)
	local poolSeen = {}
	local count = 0
	for _, entry in ipairs(source or {}) do
		local name = getUpgradeEntryName(entry)
		if name and not isPinnedUpgradeEntry(entry) and name ~= "bluePATRIOT" and not isFixedName(name) and not isStaticUpgrade(name) and hasGroupTemplate(name) then
			if not poolSeen[name] then
				poolSeen[name] = true
				local cat = classifyBlueUpgradeName(name)
				pools[cat] = pools[cat] or {}
				pools[cat][#pools[cat]+1] = name
				count = count + 1
			end
		end
	end
	return count
end

function pickFromPool(pool, count)
	local picks = {}
	for i = 1, count do
		local n = #pool
		if n == 0 then break end
		local idx = fhRand(1, n)
		picks[#picks+1] = pool[idx]
		pool[idx] = pool[n]
		pool[n] = nil
	end
	return picks
end

function pickFromPoolAllowRepeats(pool, count)
	local picks = {}
	if type(pool) ~= "table" or count <= 0 then return picks end

	local uniquePool = {}
	for i = 1, #pool do
		uniquePool[i] = pool[i]
	end

	local uniquePicks = pickFromPool(uniquePool, count)
	for _, name in ipairs(uniquePicks) do
		picks[#picks+1] = name
	end

	local missing = count - #uniquePicks
	if missing > 0 and #pool > 0 then
		for _ = 1, missing do
			picks[#picks+1] = pool[fhRand(1, #pool)]
		end
	end

	return picks
end

function buildRandomRedUpgrades(zoneObj)
	if not (zoneObj and zoneObj.upgrades and zoneObj.upgrades.red) then return nil end
	local zoneSize = getZoneSize(zoneObj)
	_fhSeedZone(zoneObj, "red")
	local templateDef = RandomUpgradeTemplates and RandomUpgradeTemplates[zoneSize]
	if not templateDef then return nil end
	local template = resolveTemplate(templateDef)

	local extraForced = {}
	if zoneObj.extraUpgrade then
		for _, grp in ipairs(zoneObj.extraUpgrade) do
			if type(grp) == "table" then
				local n = grp.name
				if n and (grp.side == 1 or (grp.side == nil and zoneObj.side == 1)) then
					extraForced[n] = true
				end
			end
		end
	end

	local fixedList = {}
	local staticList = {}
	local fixedCounts = { sam = 0, shorad = 0, aaa = 0, ground = 0, armor = 0, arty = 0, other = 0 }
	local fixedUnknown = 0
	local totalFixed = 0
	local pools = { sam = {}, shorad = {}, aaa = {}, ground = {}, armor = {}, arty = {}, other = {} }

	for _, entry in ipairs(zoneObj.upgrades.red) do
		local name = getUpgradeEntryName(entry)
		if name then
			if isStaticUpgrade(name) then
				staticList[#staticList+1] = name
			elseif isFixedName(name) or extraForced[name] or isPinnedUpgradeEntry(entry) then
				fixedList[#fixedList+1] = name
				totalFixed = totalFixed + 1
				local cat = classifyUpgradeName(name)
				if fixedCounts[cat] ~= nil then
					fixedCounts[cat] = fixedCounts[cat] + 1
				else
					fixedUnknown = fixedUnknown + 1
				end
			end
		end
	end
	if fixedUnknown > 0 then
		totalFixed = totalFixed + fixedUnknown
	end

	local poolCount = 0
	if RandomGroundGroups then
		poolCount = fillPoolsFrom(getGlobalRedPool(), pools, zoneObj, zoneSize)
	else
		poolCount = fillPoolsFrom(zoneObj.upgrades.red, pools, zoneObj, zoneSize)
		if poolCount == 0 then
			pools = { sam = {}, shorad = {}, aaa = {}, ground = {}, armor = {}, arty = {}, other = {} }
			poolCount = fillPoolsFrom(getGlobalRedPool(), pools, zoneObj, zoneSize)
		end
	end
	if next(extraForced) ~= nil then
		for _, cat in ipairs({"sam","shorad","aaa","ground","armor","arty","other"}) do
			local list = pools[cat]
			if list and #list > 0 then
				local filtered = {}
				for i = 1, #list do
					local n = list[i]
					if n and not extraForced[n] then
						filtered[#filtered+1] = n
					end
				end
				pools[cat] = filtered
			end
		end
	end

	local targetTotal = template.total
	if not targetTotal or targetTotal <= 0 then
		targetTotal = (template.sam or 0) + (template.shorad or 0) + (template.aaa or 0) + (template.ground or 0) + (template.armor or 0) + (template.arty or 0)
	end
	local needed = {
		sam = math.max(0, (template.sam or 0) - fixedCounts.sam),
		shorad = math.max(0, (template.shorad or 0) - fixedCounts.shorad),
		aaa = math.max(0, (template.aaa or 0) - fixedCounts.aaa),
		ground = math.max(0, (template.ground or 0) - fixedCounts.ground),
		armor = math.max(0, (template.armor or 0) - fixedCounts.armor),
		arty = math.max(0, (template.arty or 0) - fixedCounts.arty),
	}
	local cats = {"sam","shorad","aaa","ground","armor","arty"}
	local function getMinCount(defVal)
		if type(defVal) == "table" then
			local a = tonumber(defVal[1]) or 0
			local b = tonumber(defVal[2]) or a
			if b < a then a, b = b, a end
			return a
		end
		return tonumber(defVal) or 0
	end
	local function getMaxCount(defVal)
		if type(defVal) == "table" then
			local a = tonumber(defVal[1]) or 0
			local b = tonumber(defVal[2]) or a
			if b < a then a, b = b, a end
			return b
		end
		return tonumber(defVal) or 0
	end
	local minNeeded = {}
	local sumNeeded = 0
	local sumMinNeeded = 0
	local currentCounts = {
		sam = fixedCounts.sam or 0,
		shorad = fixedCounts.shorad or 0,
		aaa = fixedCounts.aaa or 0,
		ground = fixedCounts.ground or 0,
		armor = fixedCounts.armor or 0,
		arty = fixedCounts.arty or 0,
	}
	for _, cat in ipairs(cats) do
		local mn = math.max(0, getMinCount(templateDef[cat]) - (fixedCounts[cat] or 0))
		minNeeded[cat] = mn
		sumNeeded = sumNeeded + (needed[cat] or 0)
		sumMinNeeded = sumMinNeeded + mn
	end
	-- Never allow rolled total below category minimums.
	if targetTotal < (totalFixed + sumMinNeeded) then
		targetTotal = totalFixed + sumMinNeeded
	end
	local remainingTotal = math.max(0, targetTotal - totalFixed)
	if sumNeeded > remainingTotal then
		local cut = sumNeeded - remainingTotal
		for _, cat in ipairs(cats) do
			if cut <= 0 then break end
			if type(templateDef[cat]) == "table" then
				local canReduce = math.max(0, (needed[cat] or 0) - (minNeeded[cat] or 0))
				if canReduce > 0 then
					local delta = math.min(canReduce, cut)
					needed[cat] = (needed[cat] or 0) - delta
					cut = cut - delta
				end
			end
		end
	end

	local result = {}
	if UseStatics then
		for _, name in ipairs(staticList) do
			result[#result+1] = name
		end
	end
	for _, name in ipairs(fixedList) do
		result[#result+1] = name
	end

	for _, cat in ipairs({"sam","shorad","aaa","ground","armor","arty"}) do
		if remainingTotal <= 0 then break end
		local want = math.min(needed[cat] or 0, remainingTotal)
		if want > 0 then
			local picks = pickFromPoolAllowRepeats(pools[cat] or {}, want)
			for _, name in ipairs(picks) do
				result[#result+1] = name
			end
			local got = #picks
			needed[cat] = math.max(0, (needed[cat] or 0) - got)
			currentCounts[cat] = (currentCounts[cat] or 0) + got
			remainingTotal = remainingTotal - got
		end
	end

	if remainingTotal > 0 then
		while remainingTotal > 0 do
			local anyPool = {}
			local poolCats = {}
			for _, cat in ipairs(cats) do
				local room = math.max(0, getMaxCount(templateDef[cat]) - (currentCounts[cat] or 0))
				if room > 0 then
					for _, name in ipairs(pools[cat] or {}) do
						anyPool[#anyPool+1] = name
						poolCats[#poolCats+1] = cat
					end
				end
			end
			if #anyPool == 0 then
				for _, name in ipairs(pools.other or {}) do
					anyPool[#anyPool+1] = name
				end
			end
			if #anyPool == 0 then break end
			local idx = fhRand(1, #anyPool)
			result[#result+1] = anyPool[idx]
			local pickedCat = poolCats[idx]
			if pickedCat and currentCounts[pickedCat] ~= nil then
				currentCounts[pickedCat] = currentCounts[pickedCat] + 1
			end
			remainingTotal = remainingTotal - 1
		end
	end

	return result
end

function buildRandomBlueUpgrades(zoneObj)
	if not (zoneObj and zoneObj.upgrades and zoneObj.upgrades.blue) then return nil end
	local zoneSize = getZoneSize(zoneObj)
	_fhSeedZone(zoneObj, "blue")
	local template = RandomUpgradeTemplatesBlue and RandomUpgradeTemplatesBlue[zoneSize]
	if not template then return nil end
	template = resolveTemplateBlue(template)

	local extraForced = {}
	if zoneObj.extraUpgrade then
		for _, grp in ipairs(zoneObj.extraUpgrade) do
			if type(grp) == "table" then
				local n = grp.name
				if n and (grp.side == 2 or (grp.side == nil and zoneObj.side == 2)) then
					extraForced[n] = true
				end
			elseif type(grp) == "string" and zoneObj.side == 2 then
				extraForced[grp] = true
			end
		end
	end

	local fixedList = {}
	local staticList = {}
	local fixedCounts = { sam = 0, ground = 0, armor = 0, other = 0 }
	local fixedUnknown = 0
	local totalFixed = 0
	local pools = { sam = {}, ground = {}, armor = {}, other = {} }

	for _, entry in ipairs(zoneObj.upgrades.blue) do
		local name = getUpgradeEntryName(entry)
		if name then
			if isStaticUpgrade(name) then
				staticList[#staticList+1] = name
			elseif isFixedName(name) or extraForced[name] or isPinnedUpgradeEntry(entry) then
				fixedList[#fixedList+1] = name
				totalFixed = totalFixed + 1
				local cat = classifyBlueUpgradeName(name)
				if fixedCounts[cat] ~= nil then
					fixedCounts[cat] = fixedCounts[cat] + 1
				else
					fixedUnknown = fixedUnknown + 1
				end
			end
		end
	end
	if fixedUnknown > 0 then
		totalFixed = totalFixed + fixedUnknown
	end

	local poolCount = 0
	if RandomBlueGroups then
		poolCount = fillPoolsFromBlue(getGlobalBluePool(), pools)
	else
		poolCount = fillPoolsFromBlue(zoneObj.upgrades.blue, pools)
		if poolCount == 0 then
			pools = { sam = {}, ground = {}, armor = {}, other = {} }
			poolCount = fillPoolsFromBlue(getGlobalBluePool(), pools)
		end
	end
	if next(extraForced) ~= nil then
		for _, cat in ipairs({"sam","ground","armor","other"}) do
			local list = pools[cat]
			if list and #list > 0 then
				local filtered = {}
				for i = 1, #list do
					local n = list[i]
					if n and not extraForced[n] then
						filtered[#filtered+1] = n
					end
				end
				pools[cat] = filtered
			end
		end
	end

	local targetTotal = template.total
	if not targetTotal or targetTotal <= 0 then
		targetTotal = (template.sam or 0) + (template.ground or 0) + (template.armor or 0)
	end
	local remainingTotal = math.max(0, targetTotal - totalFixed)
	local needed = {
		sam = math.max(0, (template.sam or 0) - fixedCounts.sam),
		ground = math.max(0, (template.ground or 0) - fixedCounts.ground),
		armor = math.max(0, (template.armor or 0) - fixedCounts.armor),
	}

	local result = {}
	if UseStatics then
		for _, name in ipairs(staticList) do
			result[#result+1] = name
		end
	end
	for _, name in ipairs(fixedList) do
		result[#result+1] = name
	end

	for _, cat in ipairs({"sam","ground","armor"}) do
		if remainingTotal <= 0 then break end
		local want = math.min(needed[cat] or 0, remainingTotal)
		if want > 0 then
			local picks = pickFromPool(pools[cat] or {}, want)
			for _, name in ipairs(picks) do
				result[#result+1] = name
			end
			local got = #picks
			needed[cat] = math.max(0, (needed[cat] or 0) - got)
			remainingTotal = remainingTotal - got
		end
	end

	if remainingTotal > 0 then
		local anyPool = {}
		local allowCat = {}
		for _, cat in ipairs({"sam","ground","armor"}) do
			if (needed[cat] or 0) > 0 then
				allowCat[cat] = true
			end
		end
		for _, cat in ipairs({"sam","ground","armor","other"}) do
			if cat == "other" or allowCat[cat] then
				for _, name in ipairs(pools[cat] or {}) do
					anyPool[#anyPool+1] = name
				end
			end
		end
		local picks = pickFromPool(anyPool, remainingTotal)
		for _, name in ipairs(picks) do
			result[#result+1] = name
		end
	end

	return result
end

function applyRandomRedUpgrades()
	for _, z in pairs(zones or {}) do
		if z and z.isHidden and not z.Popup then
		elseif z and z.zone and isCarrierZoneName(z.zone) then
		else
			local list = buildRandomRedUpgrades(z)
			if list and #list > 0 then
				local base = {}
				for i, v in ipairs(list) do base[i] = v end
				z.randomUpgradesRed = base
				z.upgrades.red = {}
				for i, v in ipairs(base) do z.upgrades.red[i] = v end
			end
		end
	end
end

function applyRandomBlueUpgrades()
	for _, z in pairs(zones or {}) do
		if z and z.isHidden and not z.Popup then
		elseif z and z.zone and isCarrierZoneName(z.zone) then
		else
			local list = buildRandomBlueUpgrades(z)
			if list and #list > 0 then
				local base = {}
				for i, v in ipairs(list) do base[i] = v end
				z.randomUpgradesBlue = base
				z.upgrades.blue = {}
				for i, v in ipairs(base) do z.upgrades.blue[i] = v end
			end
		end
	end
end

function applyRandomUpgradesForNewZonesOnly()
    local savedZones = zonePersistance.zones

    for _, z in pairs(zones) do
        local saved = savedZones[z.zone]
        local shouldSeed = (saved == nil) or (saved.randomUpgradesRed == nil and saved.randomUpgradesBlue == nil)

        local skipForHidden = z.isHidden and not z.Popup
		if shouldSeed and not skipForHidden and not isCarrierZoneName(z.zone) then
			local seeded = false

            local red = buildRandomRedUpgrades(z)
            if red and #red > 0 then
                local base = {}
                for i, v in ipairs(red) do base[i] = v end
                z.randomUpgradesRed = base
                z.upgrades.red = {}
                for i, v in ipairs(base) do z.upgrades.red[i] = v end
                seeded = true
            end

            local blue = buildRandomBlueUpgrades(z)
            if blue and #blue > 0 then
                local base = {}
                for i, v in ipairs(blue) do base[i] = v end
                z.randomUpgradesBlue = base
                z.upgrades.blue = {}
                for i, v in ipairs(base) do z.upgrades.blue[i] = v end
                seeded = true
            end

            if seeded then
                z.remainingUnits = nil
                z._refreshRandomUpgrades = true
            end
        end
    end
end

function pickReplacementUpgrade(zoneObj, missingName, upgradesList, targetSide)
	if not zoneObj or not missingName then return nil end
	local used = {}
	local side = targetSide or zoneObj.side
	if upgradesList then
		for _, entry in pairs(upgradesList) do
			local n = getUpgradeEntryName(entry)
			if n then used[n] = true end
		end
	end
	used[missingName] = true

	if side == 1 then
		local zoneSize = getZoneSize(zoneObj)
		local pools = { sam = {}, shorad = {}, aaa = {}, ground = {}, armor = {}, arty = {}, other = {} }
		local source = (RandomGroundGroups and getGlobalRedPool()) or (zoneObj.upgrades and zoneObj.upgrades.red) or {}
		fillPoolsFrom(source, pools, zoneObj, zoneSize)
		local cat = classifyUpgradeName(missingName)

		local function pickFrom(list)
			local filtered = {}
			for i = 1, #list do
				local n = list[i]
				if n and not used[n] then
					filtered[#filtered + 1] = n
				end
			end
			if #filtered == 0 then return nil end
			return filtered[fhRand(1, #filtered)]
		end

		local choice = pickFrom(pools[cat] or {})
		if not choice then
			local any = {}
			for _, c in ipairs({ "sam", "shorad", "aaa", "ground", "armor", "arty", "other" }) do
				local list = pools[c]
				if list then
					for i = 1, #list do
						local n = list[i]
						if n and not used[n] then
							any[#any + 1] = n
						end
					end
				end
			end
			if #any > 0 then
				choice = any[fhRand(1, #any)]
			end
		end
		return choice
	elseif side == 2 then
		local pools = { sam = {}, ground = {}, armor = {}, other = {} }
		local source = (RandomBlueGroups and getGlobalBluePool()) or (zoneObj.upgrades and zoneObj.upgrades.blue) or {}
		fillPoolsFromBlue(source, pools)
		local cat = classifyBlueUpgradeName(missingName)

		local function pickFrom(list)
			local filtered = {}
			for i = 1, #list do
				local n = list[i]
				if n and not used[n] then
					filtered[#filtered + 1] = n
				end
			end
			if #filtered == 0 then return nil end
			return filtered[fhRand(1, #filtered)]
		end

		local choice = pickFrom(pools[cat] or {})
		if not choice then
			local any = {}
			for _, c in ipairs({ "sam", "ground", "armor", "other" }) do
				local list = pools[c]
				if list then
					for i = 1, #list do
						local n = list[i]
						if n and not used[n] then
							any[#any + 1] = n
						end
					end
				end
			end
			if #any > 0 then
				choice = any[fhRand(1, #any)]
			end
		end
		return choice
	end

	return nil
end



	function ZoneCommander:addRestrictedPlayerGroup(groupinfo)
		table.insert(self.restrictedGroups, groupinfo)
	end
	
	function ZoneCommander:markWithSmoke(requestingCoalition)
		if requestingCoalition and (self.side ~= requestingCoalition and self.side ~= 0) then
			return
		end
	
		local zone = CustomZone:getByName(self.zone)
		local p = Utils.getPointOnSurface(zone.point)
		trigger.action.smoke(p, 0)
	end
	
	--if all critical onjects are lost in a zone, that zone turns neutral and can never be recaptured
	function ZoneCommander:addCriticalObject(staticname)
		table.insert(self.criticalObjects, staticname)
	end

	function ZoneCommander:activateScoreTargetsForCritical(flag, reward, stat)
		if self._critScoreActive or CustomFlags[flag] then return end
		local list = self.criticalObjects or {}
		local alive = 0
		for i=1,#list do
			local obj = StaticObject.getByName(list[i])
			if obj and (obj:getLife() or 0) > 1 then alive = alive + 1 end
		end
		if alive == 0 and #list > 0 then
			CustomFlags[flag] = true
			ActiveMission[flag] = nil
			self._critScoreActive = true
			return
		end
		for i=1,#list do
			local obj = StaticObject.getByName(list[i])
			if obj then RegisterScoreTarget(flag, obj, reward, stat) end
		end
		ActiveMission[flag] = true
		self._critScoreActive = true
	end

	
	function ZoneCommander:getDestroyedCriticalObjects()
		local destroyed = {}
		for i,v in ipairs(self.criticalObjects) do
			local st = StaticObject.getByName(v)
			if not st or st:getLife()<1 then
				table.insert(destroyed, v)
			end
		end
		
		return destroyed
	end
	
	--zone triggers 
	-- trigger types= captured, upgraded, repaired, lost, destroyed
	function ZoneCommander:registerTrigger(eventType, action, id, timesToRun)
		table.insert(self.triggers, {eventType = eventType, action = action, id = id, timesToRun = timesToRun, hasRun=0})
	end
	
	--return true from eventhandler to end event after run
	function ZoneCommander:runTriggers(eventType)
		for i,v in ipairs(self.triggers) do
			if v.eventType == eventType then
				if not v.timesToRun or v.hasRun < v.timesToRun then
					v.action(v,self)
					v.hasRun = v.hasRun + 1
				end
			end
		end
	end
	--end zone triggers
	-------------------------------------------------------- DISABLE FRIENDLY ZONE ---------------------------------------------------------------------------

	function ZoneCommander:disableFriendlyZone(force)
		if not force then	
			if not self.active or not self.wasBlue then return false end
		end
		if (self.active and self.side == 2) or force then
			local wasVisible = self.isHidden ~= true
			self.battleCommander:markRedDifficultyDirty()
			self.battleCommander:markFsmGroupFilterDirty()
			self.battleCommander:markReindexCombatFilterDirty()
			self.wasBlue = true
			print("Zone was blue before disabling: " .. self.zone)

			for i, v in pairs(self.built) do
				local gr = Group.getByName(v)
				if gr and gr:getSize() > 0 then
					gr:destroy()
				elseif gr and gr:getSize() == 0 then
					gr:destroy()
				end

				if not gr then
					local st = StaticObject.getByName(v)
					if st and st:getLife() < 1 then
						st:destroy()
					end
				end

				self.built[i] = nil    
			end

			self.side = 0
			self.active = false
			
			if self.airbaseName and self.airbaseName ~= 'CVN-72' and self.airbaseName ~= 'CVN-73' and self.airbaseName ~= 'CVN-74' and self.airbaseName ~= 'CVN-75' then
				env.info("Disabling airbase " .. self.airbaseName)
				local ab = getDcsAirbaseByName(self.airbaseName)
				if ab then
					if self.wasBlue and not self.active then
						if ab:autoCaptureIsOn() then ab:autoCapture(false) end
						ab:setCoalition(2)
						if RespawnStaticsForAirbase then
							RespawnStaticsForAirbase(self.airbaseName, 2)
						end
					end
				else
					env.info("Airbase " .. self.airbaseName .. " is not found ask leka")
					trigger.action.outText(L10N:Format("ZONE_AIRBASE_NOT_FOUND", self.airbaseName), 10)
				end
			end
			if self.wasBlue and not self.active then
				trigger.action.setMarkupColor(2000 + self.index, {0, 0, 0.7, 1})
				trigger.action.setMarkupColorFill(self.index, {0, 0, 1, 0.3})
				trigger.action.setMarkupColor(self.index, {0, 0, 1, 0.3})
				
				if self.isHeloSpawn then
					trigger.action.setMarkupTypeLine(self.index, 2)
					trigger.action.setMarkupColor(self.index, {0, 1, 0, 1})
				end
			end
			
			self:runTriggers('FriendlyDestroyed')
            self:updateLabel()
			self.battleCommander:RefreshTerritoryOverlayZone(self.zone)
			if wasVisible then
				self.battleCommander:requestZoneStatusMenuRefresh()
			end
			self.battleCommander:requestFrontlineRefresh()
			SCHEDULER:New(bc, bc.abortSupplyToOpposite, {self.zone, 0}, 10, 0)

		end
	end

	function ZoneCommander:DestroyHiddenZone()
	if not self.active or not self.side == 1 then return false end
		print("Destroying Hidden zone" .. self.zone)

		for i, v in pairs(self.built) do
			local gr = Group.getByName(v)
			if gr and gr:getSize() > 0 then
				gr:destroy()
			elseif gr and gr:getSize() == 0 then
				gr:destroy()
			end

			if not gr then
				local st = StaticObject.getByName(v)
				if st and st:getLife() < 1 then
					st:destroy()
				end
			end

			self.built[i] = nil    
		end

		self.side = 0
		self.active = false
		self.battleCommander:markRedDifficultyDirty()
		self.battleCommander:markFsmGroupFilterDirty()
		self.battleCommander:markReindexCombatFilterDirty()
		self.battleCommander:requestFrontlineRefresh()
	end

	function ZoneCommander:disableZone(Silent)
    if self.active then
		local wasVisible = self.isHidden ~= true
		local previousSide = self.side

		for i, v in pairs(self.built) do
			local gr = Group.getByName(v)
			if gr then
				gr:destroy()
			else
				local st = StaticObject.getByName(v)
				if st then
					st:destroy()
				end
			end
			self.built[i] = nil
		end

        self.side = 0
		self.battleCommander:markRedDifficultyDirty()
		self.battleCommander:markFsmGroupFilterDirty()
		self.battleCommander:markReindexCombatFilterDirty()
		if CheckJtacStatus then
			CheckJtacStatus()
		end
        self.active = false
		self.wasBlue = false
		
		if SpawnFriendlyAssets then
		
			SCHEDULER:New(nil,SpawnFriendlyAssets,{},2)
		end
        if not Silent then
            trigger.action.outText(L10N:Format("ZONE_DESTROYED", self.zone), 5)
			if trigger.misc.getUserFlag(180) == 0 then
				trigger.action.outSoundForCoalition(2, "ding.ogg")
			end
		end
		if trigger.misc.getUserFlag(180) == 0 then
			trigger.action.outSoundForCoalition(2, "ding.ogg")
		end
		if not self.active then
			trigger.action.setMarkupColor(2000 + self.index, {0.1,0.1,0.1,1})
			trigger.action.setMarkupColorFill(self.index, {0.1,0.1,0.1,0.3})
			trigger.action.setMarkupColor(self.index, {0.1,0.1,0.1,0.3})
		end
		self:runTriggers('destroyed')
		bc:buildConnectionMap(self.zone, previousSide)
		bc:_buildHunterBaseList()
        self:updateLabel()
		self.battleCommander:RefreshTerritoryOverlayZone(self.zone)
		self.battleCommander:RefreshConnectionsLines(self.zone)
		if wasVisible then
			self.battleCommander:requestZoneStatusMenuRefresh()
		end
		self.battleCommander:requestFrontlineRefresh()
													  
													 
    end
end
	


function ZoneCommander:displayStatus(grouptoshow, messagetimeout, overrideIntel)
    local upgrades=0
    local sidename=L10N:Get("ZONE_SIDE_NEUTRAL")
    if self.side==1 then
        sidename=L10N:Get("ZONE_SIDE_RED")
        upgrades = Utils.getTableSize(self:getFilteredUpgrades())
    elseif self.side==2 then
        sidename=L10N:Get("ZONE_SIDE_BLUE")
        upgrades = Utils.getTableSize(self:getFilteredUpgrades())
    end
    if not self.active then
        sidename=L10N:Get("ZONE_SIDE_NONE")
    end
    if not self.active and self.wasBlue then
        sidename=L10N:Get("ZONE_SIDE_BLUE")
    end
    local count=0
    if self.built then
        count=Utils.getTableSize(self.built)
    end
    local count = 0
    if self.built then
        count = Utils.getTableSize(self.built)
    end

    local intelTime  = ""
    local intelActive = (intelActiveZones[self.zone] == true)
    local jtacActive  = (jtacIntelActive and jtacIntelActive[self.zone] == true)

    if intelActive and intelExpireTimes[self.zone] then
        local r = math.max(0, math.floor((intelExpireTimes[self.zone] - timer.getTime()) / 60))
        intelTime = "\n" .. L10N:Format("ZONE_INTEL_MIN_REMAINING", r)
    end

    status = L10N:Format("ZONE_STATUS_TITLE", self.zone) .. "\n" .. L10N:Format("ZONE_CONTROLLED_BY", sidename) .. intelTime
	local function cleanName(s) return (s:gsub("%s*#%s*%d+",""):gsub("%s+Fixed",""):gsub("%s%s+"," "):gsub("^%s+",""):gsub("%s+$","")) end

    local isEnemy     = (self.side == 1)
    local canSeeEnemy = intelActive or jtacActive
    if overrideIntel and isEnemy then
        canSeeEnemy = true
    end
    if isEnemy and bc.shops and bc.shops[2] and bc.shops[2].intel then
        if canSeeEnemy and self.built and count>0 then
            status=status.."\n"..L10N:Format("ZONE_UPGRADES_LINE", count, upgrades)
            status=status.."\n"..L10N:Get("ZONE_GROUPS_HEADER")
            if self.suspended and self.remainingUnitsSnapshot then
                for idx,_ in pairs(self.remainingUnitsSnapshot) do
                    local v = self.built[idx]
                    if v then
                        status=status.."\n"..L10N:Format("ZONE_GROUP_HEALTH", cleanName(v), 100)
                    end
                end
            else
                local anyResolved=false
                local unresolved={}
                for i,v in pairs(self.built) do
                    local gr=Group.getByName(v)
                    if gr then
                        anyResolved=true
                        local grhealth=math.ceil((gr:getSize()/gr:getInitialSize())*100)
                        grhealth=math.min(grhealth,100)
                        grhealth=math.max(grhealth,1)
                        status=status.."\n"..L10N:Format("ZONE_GROUP_HEALTH", cleanName(v), grhealth)
                    else
                        local st=StaticObject.getByName(v)
                        if st then
                            anyResolved=true
                            status=status.."\n"..L10N:Format("ZONE_GROUP_HEALTH", cleanName(v), 100)
                        else
                            unresolved[#unresolved+1]=cleanName(v)
                        end
                    end
                end
                if overrideIntel and not self.suspended and not anyResolved then
                    if #unresolved>0 then
                        status=status.."\n"..L10N:Format("ZONE_UNRESOLVED_BUILT", table.concat(unresolved, ", "))
                    else
                        local up=self:getFilteredUpgrades() or {}
                        if #up>0 then
                            local want={}
                            for _,nm in pairs(up) do want[#want+1]=cleanName(nm) end
                            status=status.."\n"..L10N:Format("ZONE_EXPECTED_UPGRADES", table.concat(want, ", "))
                        else
                            status=status.."\n"..L10N:Get("ZONE_NO_BUILT_OR_UPGRADES")
                        end
                    end
                end
            end
        else
            status=status.."\n\n"..L10N:Get("ZONE_BUY_INTEL_OR_JTAC")
        end
    else
        if self.built and count>0 then
            status=status.."\n"..L10N:Format("ZONE_UPGRADES_LINE", count, upgrades)
            status=status.."\n"..L10N:Get("ZONE_GROUPS_HEADER")
            if self.suspended and self.remainingUnitsSnapshot then
                for idx,_ in pairs(self.remainingUnitsSnapshot) do
                    local v = self.built[idx]
                    if v then
                        status=status.."\n"..L10N:Format("ZONE_GROUP_HEALTH", v, 100)
                    end
                end
            else
                local anyResolved=false
                local unresolved={}
                for i,v in pairs(self.built) do
                    local gr=Group.getByName(v)
                    if gr then
                        anyResolved=true
                        local grhealth=math.ceil((gr:getSize()/gr:getInitialSize())*100)
                        grhealth=math.min(grhealth,100)
                        grhealth=math.max(grhealth,1)
                        status=status.."\n"..L10N:Format("ZONE_GROUP_HEALTH", v, grhealth)
                    else
                        local st=StaticObject.getByName(v)
                        if st then
                            anyResolved=true
                            status=status.."\n"..L10N:Format("ZONE_GROUP_HEALTH", v, 100)
                        else
                            unresolved[#unresolved+1]=tostring(v)
                        end
                    end
                end
                if overrideIntel and not self.suspended and not anyResolved then
                    if #unresolved>0 then
                        status=status.."\n"..L10N:Format("ZONE_UNRESOLVED_BUILT", table.concat(unresolved, ", "))
                    else
                        local up=self:getFilteredUpgrades() or {}
                        if #up>0 then
                            local want={}
                            for _,nm in pairs(up) do want[#want+1]=cleanName(nm) end
                            status=status.."\n"..L10N:Format("ZONE_EXPECTED_UPGRADES", table.concat(want, ", "))
                        else
                            status=status.."\n"..L10N:Get("ZONE_NO_BUILT_OR_UPGRADES")
                        end
                    end
                end
            end
        end
    end
    if self.flavorText and self.active then
        status=status.."\n\n"..self.flavorText
    end
    if not self.active and not self.wasBlue then
        status=status.."\n\n "..L10N:Get("ZONE_IRREPARABLY_DAMAGED")
    end
    if not self.active and self.wasBlue then
        status=status.."\n\n"..L10N:Get("ZONE_FRIENDLY_REPOSITIONED")
        if self.isHeloSpawn then
            status=status.."\n\n"..L10N:Get("ZONE_FARP_AIRFIELD_OPERATIONAL")
        end
    end
    local zn=CustomZone:getByName(self.zone)
	if zn then
		local pnt      = zn.point
		local c        = COORDINATE:NewFromVec3(pnt)
		local lat, lon = coord.LOtoLL(pnt)

		local function ddm(v,h)
			local d = math.floor(math.abs(v))
			local m = (math.abs(v) - d) * 60
			return string.format("[%s %02d %06.3f']", h, d, m)
		end
		local function dms(v,h)
			local av = math.abs(v)
			local d  = math.floor(av)
			local m  = math.floor((av - d) * 60)
			local s  = ((av - d) * 60 - m) * 60
			return string.format("[%s %02d %02d' %05.2f\"]", h, d, m, s)
		end

		local ddmStr = ddm(lat, lat >= 0 and "N" or "S") .. "⇢ " .. ddm(lon, lon >= 0 and "E" or "W")
		local dmsStr = dms(lat, lat >= 0 and "N" or "S") .. "⇢ " .. dms(lon, lon >= 0 and "E" or "W")
		local mgrs   = c:ToStringMGRS():gsub("^MGRS%s*", "")
		local alt    = c:GetLandHeight()

		status = status
			.. "\n\n" .. L10N:Format("ZONE_COORD_DDM", ddmStr)
			.. "\n" .. L10N:Format("ZONE_COORD_DMS", dmsStr)
			.. "\n" .. L10N:Format("ZONE_COORD_MGRS", mgrs)
			.. "\n\n" .. L10N:Format("ZONE_COORD_ALT", math.floor(alt), math.floor(alt * 3.280839895))
	end
	local timeout = messagetimeout or 15
	if grouptoshow then
		trigger.action.outTextForGroup(grouptoshow, status, timeout)
	else
		trigger.action.outText(status, timeout)
	end
end


---------------------- Capture a zone on command BLUE ---------------------------------

function ZoneCommander:MakeZoneBlue()
	if not self.active or self.wasBlue then return
	end
    if self.active and not self.wasBlue then
        BASE:I("Making this zone Blue: " .. self.zone)
        local unitsInZone = coalition.getGroups(1)
        for _, group in ipairs(unitsInZone) do
            local groupUnits = group:getUnits()
            for _, unit in ipairs(groupUnits) do
                if Utils.isInZone(unit, self.zone) then
                    unit:destroy()
                end
            end
        end
        timer.scheduleFunction(function()
            self:capture(2,true)
            BASE:I("Zone captured by Blue: " .. self.zone)
			self.wasBlue = true
        end, nil, timer.getTime() + 12)
    else
        BASE:I("Zone is either inactive or not controlled by the blue side, no action taken.")
    end
end

function ZoneCommander:MakeZoneRed()
    if self.active and self.side == 0 and self.NeutralAtStart and not self.firstCaptureByRed then
        BASE:I("Making this zone Red: " .. self.zone)

        timer.scheduleFunction(function()
            self:capture(1, true)
            BASE:I("Zone captured by Red: " .. self.zone)
        end, {}, timer.getTime() + 2)
    else
        BASE:I("Zone is either inactive or not eligible for red capture, no action taken.")
    end
end
---------------------- Capture a zone on command RED ---------------------------------      
local function ScheduleZoneUpgradeUntilComplete(ZoneCommanderObject, LogPrefixText, EmitProgressLogs)
	local UpgradeDefinitions = ZoneCommanderObject:getFilteredUpgrades()
	local TotalUpgrades = Utils.getTableSize(UpgradeDefinitions)
	local function UpgradeZoneStep()
		local BuiltCount = Utils.getTableSize(ZoneCommanderObject.built)
		if BuiltCount < TotalUpgrades then
			ZoneCommanderObject:upgrade(true)
			if EmitProgressLogs then
				BuiltCount = Utils.getTableSize(ZoneCommanderObject.built)
				BASE:I(LogPrefixText .. " upgraded " .. BuiltCount .. "/" .. TotalUpgrades .. " for Red: " .. ZoneCommanderObject.zone)
			end
			timer.scheduleFunction(UpgradeZoneStep, {}, timer.getTime() + 2)
		elseif EmitProgressLogs then
			BASE:I(LogPrefixText .. " fully upgraded for Red: " .. ZoneCommanderObject.zone)
		end
	end
	timer.scheduleFunction(UpgradeZoneStep, {}, timer.getTime() + 1)
end

function ZoneCommander:MakeZoneRedAndUpgrade()
	if self.active and self.side == 0 and self.NeutralAtStart and not self.firstCaptureByRed then
		self:capture(1, true)
		ScheduleZoneUpgradeUntilComplete(self, "Zone", false)
	else
		BASE:I("Zone " .. self.zone .. " is either inactive or not eligible for red capture and upgrade, no action taken.")
	end
end

local function GetZoneMarkupPoint(ZoneObject)
	local zone = CustomZone:getByName(ZoneObject.zone)
	local point = zone.point
	if zone:isCircle() then
		point = { x = zone.point.x, y = zone.point.y, z = zone.point.z + zone.radius }
	elseif zone:isQuad() then
		local largestZ = zone.vertices[1].z
		local largestX = zone.vertices[1].x
		for i = 2, 4 do
			if zone.vertices[i].z > largestZ then
				largestZ = zone.vertices[i].z
				largestX = zone.vertices[i].x
			end
		end
		point = { x = largestX, y = zone.point.y, z = largestZ }
	end
	return zone, point
end

function ZoneCommander:AwakenZone()
	if not self.active then
		BASE:I("Zone " .. self.zone .. " is inactive and cannot be awakened.")
		return
	end

	local previousState = {
		active = self.active,
		suspended = self.suspended,
		side = self.side,
		isHidden = self.isHidden,
		NeutralAtStart = self.NeutralAtStart,
		firstCaptureByRed = self.firstCaptureByRed,
		airbaseName = self.airbaseName,
		LogisticCenter = self.LogisticCenter,
	}
	local wasHidden = self.isHidden == true
	if not self.isHidden then
		if self.Popup == true then
			self.isAwaken = true
			normalizePopupAwakenState(self)
		end
		self:updateLabel()
		return
	end

	if self.Popup == true then
		self.isAwaken = true
		normalizePopupAwakenState(self)
	else
		self.isHidden = false
		self.battleCommander:markRedDifficultyDirty()
	end
	self.battleCommander.zonesDetails_cache = nil

	local color = {0.7, 0.7, 0.7, 0.3}
	local textColor = {0.3, 0.3, 0.3, 1}
	if self.side == 1 then
		color = {1, 0, 0, 0.3}
		textColor = {0.7, 0, 0, 0.8}
	elseif self.side == 2 then
		color = {0, 0, 1, 0.3}
		textColor = {0, 0, 0.7, 0.8}
	elseif self.side == 0 and self.wasBlue then
		color = {0, 0, 1, 0.3}
		textColor = {0, 0, 0.7, 1}
	end

	local zone, point = GetZoneMarkupPoint(self)
	zone:draw(self.index, color, color)
	local backgroundColor = {0.7, 0.7, 0.7, 0.8}
	trigger.action.textToAll(-1, 2000 + self.index, point, textColor, backgroundColor, 17, true, " " .. self.zone)
	self:updateLabel()
	bc:buildConnectionMap(self.zone, self.side)
	self.battleCommander:RefreshTerritoryOverlayZone(self.zone)
	self.battleCommander:RefreshConnectionsLines(self.zone)
	if wasHidden and not self.isHidden then
		if self.Popup == true then
			bc:_applyZoneShopSelectorDelta(self, previousState)
			local selectorRefreshTags = bc:_getZoneSelectorRefreshTags(self, previousState)
			if #selectorRefreshTags > 0 then
				bc:requestShopSelectorRefreshForCoalition(2, selectorRefreshTags)
			end
		end
		self.battleCommander:requestZoneStatusMenuRefresh()
		self.battleCommander:requestFrontlineRefresh()
	end
													 
													
end

function ZoneCommander:AwakenZoneAndUpgrade()
	if self.side == 0 and self.NeutralAtStart and not self.firstCaptureByRed then
		self:MakeZoneRedAndUpgrade()
	elseif self.side == 1 then
		ScheduleZoneUpgradeUntilComplete(self, "Zone", false)
	end
	self:AwakenZone()
end

function ZoneCommander:MakeZoneRedAndUpgraded() -- for disabledfriendlyzone to make them go red and suspend
	if self.side == 0 and self.NeutralAtStart and not self.firstCaptureByRed then
		self:capture(1, true)
		ScheduleZoneUpgradeUntilComplete(self, "Zone", false)
	end
end

function ZoneCommander:MakeZoneredandupgradednow() -- for disabledfriendlyzone to make them go red and suspend
	if self.active and self.side ~= 2 then
		self:capture(1, true)
		ScheduleZoneUpgradeUntilComplete(self, "Zone", false)
	end
end

------------------------ UPGRADE RED ZONE ON COMMAND ------------------------------------

function ZoneCommander:MakeRedZoneUpgraded()
	if self.active and self.side == 1 then
		ScheduleZoneUpgradeUntilComplete(self, "Zone", true)
	else
		BASE:I("Zone is either inactive or not Red, no action taken.")
	end
end
---------------------- End of Capture a zone on command ---------------------------------

local function GetZoneRepairTargetName(ZoneObject)
	for _, BuiltName in pairs(ZoneObject.built or {}) do
		if not string.find(BuiltName, "dismounted") then
			local BaseName = string.gsub(BuiltName, "#%d+$", "")
			local IsStatic = false
			for _, StaticData in ipairs(ZoneObject.newStatics or {}) do
				if StaticData.name == BaseName then
					IsStatic = true
					break
				end
			end
			if IsStatic then
				local StaticReference = StaticObject.getByName(BuiltName) or StaticObject.getByName(BaseName)
				if not StaticReference or (StaticReference.isExist and not StaticReference:isExist()) then
					return BuiltName
				end
			else
				local GroupReference = GROUP:FindByName(BuiltName)
				if GroupReference and GroupReference:IsAlive() then
					local CurrentSize = GroupReference:GetSize()
					local InitialSize = GroupReference:GetInitialSize()
					if (InitialSize and CurrentSize and CurrentSize < InitialSize) or (not InitialSize) then
						return BuiltName
					end
				else
					return BuiltName
				end
			end
		end
	end
	return nil
end

local function ZoneNeedsRepair(ZoneObject)
	return GetZoneRepairTargetName(ZoneObject) ~= nil
end

local function RespawnZoneRepairTarget(ZoneObject, RepairTargetName, LogPrefixText)
	local TargetGroup = GROUP:FindByName(RepairTargetName)
	if TargetGroup and TargetGroup:GetSize() and TargetGroup:GetInitialSize() and TargetGroup:GetSize() < TargetGroup:GetInitialSize() then
		CustomRespawn(RepairTargetName)
		return
	end

	local ZoneSpawner = CustomZone:getByName(ZoneObject.zone)
	if not ZoneSpawner or not ZoneSpawner.spawnGroup then
		BASE:E(LogPrefixText .. ": spawnGroup missing for zone " .. tostring(ZoneObject.zone) .. " target=" .. tostring(RepairTargetName))
		return
	end

	BASE:I(LogPrefixText .. ": respawning target " .. tostring(RepairTargetName) .. " in zone " .. tostring(ZoneObject.zone))
	local BaseTargetName = string.gsub(RepairTargetName, "#%d+$", "")
	local IsStatic = false
	local StaticDefinition = nil
	for _, StaticData in ipairs(ZoneObject.newStatics or {}) do
		if StaticData.name == BaseTargetName then
			IsStatic = true
			StaticDefinition = StaticData
			break
		end
	end

	if IsStatic and StaticDefinition then
		if StaticDefinition.country == 1 then
			StaticDefinition.country = country.id.RUSSIA
		else
			StaticDefinition.country = country.id.USA
		end
		local SpawnTemplate = {
			name = StaticDefinition.name,
			type = StaticDefinition.type,
			country = StaticDefinition.country,
			shape_name = StaticDefinition.shapeName,
			heading = math.rad(StaticDefinition.heading),
			position = StaticDefinition.point
		}
		local StaticSpawner = SPAWNSTATIC:NewFromTemplate(SpawnTemplate, StaticDefinition.country)
		local SpawnedObject = StaticSpawner:SpawnFromCoordinate(COORDINATE:NewFromVec3(StaticDefinition.point))
		if SpawnedObject then
			ZoneObject.built = ZoneObject.built or {}
			for BuiltIndex, BuiltName in pairs(ZoneObject.built) do
				local BaseBuiltName = string.gsub(BuiltName, "#%d+$", "")
				if BuiltName == RepairTargetName or BaseBuiltName == BaseTargetName then
					ZoneObject.built[BuiltIndex] = SpawnedObject:GetName()
					break
				end
			end
		end
	else
		local SpawnedGroup = ZoneSpawner:spawnGroup(RepairTargetName, false)
		if SpawnedGroup and SpawnedGroup.name then
			ZoneObject.built = ZoneObject.built or {}
			for BuiltIndex, BuiltName in pairs(ZoneObject.built) do
				if BuiltName == RepairTargetName then
					ZoneObject.built[BuiltIndex] = SpawnedGroup.name
					break
				end
			end
		end
	end
end

function ZoneCommander:UpgradeUntilComplete(OnCompleteFunction, DelaySeconds)
	local TotalUpgrades = Utils.getTableSize(self:getFilteredUpgrades() or {})
	local Delay = DelaySeconds or 2

	local function HasPendingWork()
		return GetZoneRepairTargetName(self) ~= nil or Utils.getTableSize(self.built or {}) < TotalUpgrades
	end

	if not HasPendingWork() then
		return false
	end

	local function UpgradeZoneStep()
		local RepairTarget = GetZoneRepairTargetName(self)
		if RepairTarget then
			RespawnZoneRepairTarget(self, RepairTarget, "UpgradeUntilComplete")
		else
			local CurrentBuiltCount = Utils.getTableSize(self.built or {})
			if TotalUpgrades > 0 and CurrentBuiltCount < TotalUpgrades then
				self:upgrade(true)
			end
		end

		if HasPendingWork() then
			timer.scheduleFunction(UpgradeZoneStep, {}, timer.getTime() + Delay)
		elseif OnCompleteFunction then
			OnCompleteFunction(self)
		end
	end

	timer.scheduleFunction(UpgradeZoneStep, {}, timer.getTime() + 1)
	return true
end

local function CollectUpgradeableZoneNamesBySide(TargetSide, LogPrefixText)
	local ZoneNames = {}
	local ZoneList = bc:getZones()
	for _, ZoneEntry in ipairs(ZoneList) do
		if not ZoneEntry.isHidden and ZoneEntry.side == TargetSide and not ZoneEntry.suspended then
			local ZoneObject = bc.indexedZones[ZoneEntry.zone]
			if ZoneObject and ZoneObject.side == TargetSide then
				local UpgradeDefinitions = ZoneObject:getFilteredUpgrades()
				local TotalUpgrades = Utils.getTableSize(UpgradeDefinitions)
				local BuiltCount = Utils.getTableSize(ZoneObject.built or {})
				if ZoneNeedsRepair(ZoneObject) or (TotalUpgrades > 0 and BuiltCount < TotalUpgrades) then
					BASE:I(LogPrefixText .. ": candidate " .. tostring(ZoneEntry.zone))
					table.insert(ZoneNames, ZoneEntry.zone)
				end
			end
		end
	end
	return ZoneNames
end

local function ProcessZoneUpgradeQueueBySide(TargetSide, CandidateZoneNames, LogPrefixText, OnCompleteFunction)
	local SideTitle = (TargetSide == 1) and "Red" or "Blue"
	local SideTitleLower = string.lower(SideTitle)

	local function ProcessIndex(ZoneIndex)
		local ZoneName = CandidateZoneNames[ZoneIndex]
		if ZoneName then
			local ZoneObject = bc.indexedZones[ZoneName]
			if ZoneObject and ZoneObject.side == TargetSide then
				local UpgradeDefinitions = ZoneObject:getFilteredUpgrades()
				local TotalUpgrades = Utils.getTableSize(UpgradeDefinitions)
				local BuiltCount = Utils.getTableSize(ZoneObject.built or {})
				local RepairTargetName = GetZoneRepairTargetName(ZoneObject)
				if RepairTargetName or (TotalUpgrades > 0 and BuiltCount < TotalUpgrades) then
					BASE:I("Upgrading " .. SideTitle .. " zone: " .. ZoneObject.zone .. " (" .. BuiltCount .. "/" .. TotalUpgrades .. ")")
					local function UpgradeZoneStep()
						local RepairTarget = GetZoneRepairTargetName(ZoneObject)
						if RepairTarget then
							RespawnZoneRepairTarget(ZoneObject, RepairTarget, LogPrefixText)
							timer.scheduleFunction(UpgradeZoneStep, {}, timer.getTime() + 2)
						else
							local CurrentBuiltCount = Utils.getTableSize(ZoneObject.built or {})
							if TotalUpgrades > 0 and CurrentBuiltCount < TotalUpgrades then
								ZoneObject:upgrade(true)
								timer.scheduleFunction(UpgradeZoneStep, {}, timer.getTime() + 2)
							else
								BASE:I("Zone fully upgraded for " .. SideTitle .. ": " .. ZoneObject.zone)
							end
						end
					end
					timer.scheduleFunction(UpgradeZoneStep, {}, timer.getTime() + 1)
				else
					BASE:I("Zone already fully upgraded for " .. SideTitle .. ": " .. ZoneObject.zone)
				end
			end
			timer.scheduleFunction(function()
				ProcessIndex(ZoneIndex + 1)
			end, {}, timer.getTime() + 10)
		else
			BASE:I("All " .. SideTitleLower .. " zones are now fully upgraded.")
			trigger.action.outText(L10N:Format("ZONE_ALL_SIDE_FULLY_UPGRADED", SideTitleLower), 15)
			if OnCompleteFunction then
				OnCompleteFunction()
			end
		end
	end

	ProcessIndex(1)
end

----------------------- upgrade all red zones --------------------------

function upgradeRedZones()
	if upgradeRedZonesBusy then
		trigger.action.outText(L10N:Get("ZONE_UPGRADE_PROCESS_RUNNING"), 15)
		return
	end
	upgradeRedZonesBusy = true

	local RedZones = CollectUpgradeableZoneNamesBySide(1, "upgradeRedZones")
	if #RedZones == 0 then
		BASE:I("All red zones are now fully upgraded.")
		trigger.action.outText(L10N:Get("ZONE_ALL_RED_FULLY_UPGRADED"), 15)
		upgradeRedZonesBusy = false
		return
	end

	trigger.action.outText(L10N:Get("ZONE_COMMAND_ACCEPTED_PENDING"), 20)
	ProcessZoneUpgradeQueueBySide(1, RedZones, "upgradeRedZones", function()
		upgradeRedZonesBusy = false
	end)
end

