function upgradeBlueZones()
	if upgradeBlueZonesBusy then
		trigger.action.outText(L10N:Get("ZONE_UPGRADE_PROCESS_RUNNING"), 15)
		return
	end
	upgradeBlueZonesBusy = true

	local BlueZones = CollectUpgradeableZoneNamesBySide(2, "upgradeBlueZones")
	if #BlueZones == 0 then
		BASE:I("All blue zones are now fully upgraded.")
		trigger.action.outText(L10N:Get("ZONE_ALL_BLUE_FULLY_UPGRADED"), 15)
		upgradeBlueZonesBusy = false
		return
	end

	trigger.action.outText(L10N:Get("ZONE_COMMAND_ACCEPTED_PENDING"), 20)
	ProcessZoneUpgradeQueueBySide(2, BlueZones, "upgradeBlueZones", function()
		upgradeBlueZonesBusy = false
	end)
end

function ZoneCommander:MakeZoneNeutralAgain()
    if not self.active or self.wasBlue then
        return
    end

	self:killAll()

    timer.scheduleFunction(function()
        self.firstCaptureByRed = false
        BASE:I("Zone " .. self.zone .. " has been reset to neutral.")
    end, nil, timer.getTime() + 5)
end
