function BattleCommander:addWarehouseItemsAtZone(zoneObj, coalition, amountPerItem)
    if not zoneObj then
        return false, "[Warehouse] No zone at this point."
    end

    local rocketSet = nil
    if WEAPONSLIST and WEAPONSLIST.GetItems then
        rocketSet = {}
        for _, itemName in ipairs(WEAPONSLIST.GetItems("AG_ROCKETS") or {}) do
            if itemName then rocketSet[itemName] = true end
        end
    end

    local zoneName = zoneObj.zone
    local abName = zoneObj.airbaseName or zoneObj.baseName or zoneName
    if not abName or abName == "" then
        return false, string.format("[Warehouse] %s has no airbase.", tostring(zoneName or "Zone"))
    end

    if not WarehouseLogistics then
        return false, "[Warehouse] WarehouseLogistics is disabled."
    end

    local storage = STORAGE:FindByName(abName) or nil
    if not storage and zoneName and abName ~= zoneName then
        storage = STORAGE:FindByName(zoneName) or nil
        if storage then
            abName = zoneName
        end
    end
    if not storage then
        return false, string.format("[Warehouse] No storage found for airbase: %s", tostring(abName))
    end

    local amount = tonumber(amountPerItem) or 50
    amount = math.max(1, math.floor(amount))

    local items = WEAPONSLIST.GetAllItems()
    local added = 0

	local forbiddenWeaponsInAllEraSet = {}
	for _, forbiddenWeapon in ipairs(ForbiddWeaponsInAllEra or {}) do
		forbiddenWeaponsInAllEraSet[forbiddenWeapon] = true
	end

	for _, item in ipairs(items) do
		if not forbiddenWeaponsInAllEraSet[item] then
			if not (Era == "Coldwar" and WEAPONSLIST.IsRestricted(item)) then
				local addAmount = amount
				if rocketSet and rocketSet[item] then addAmount = addAmount * 3 end
				addAmount = _getWarehouseRefillAmount(item, addAmount)
				if addAmount > 0 then
					storage:AddItem(item, addAmount)
					added = added + 1
				end
			end
		end
	end

    return true, string.format("[Warehouse] Added %d item types x%d to %s (zone: %s).",added, amount, tostring(abName), tostring(zoneName or "unknown"))
end

local function _autoRestockFriendlyAirbases()
	if WarehouseLogistics ~= true then return end

	for _, zoneObj in ipairs(bc.zones) do
		if zoneObj and zoneObj.side == 2 and not zoneObj.suspended and zoneObj.airbaseName then
			local amount = AutoFillResources or 5
			bc:addWarehouseItemsAtZone(zoneObj, 2, amount)
		end
	end
end

if WarehouseLogistics == true and AutoFillResources > 0 then
	SCHEDULER:New(nil, function()
		_autoRestockFriendlyAirbases()
	end, {}, 900, 900)
end

local _resourceMapCache = nil
local function _getWarehouseResourceMap()
	if _resourceMapCache ~= nil then
		return _resourceMapCache or nil
	end
	if Warehouse and Warehouse.getResourceMap then
		_resourceMapCache = Warehouse.getResourceMap()
	else
		_resourceMapCache = false
	end
	return _resourceMapCache or nil
end

local function _prefillLogisticCenterFromResourceMap(airbaseName, fillAmount)
    if WarehouseLogistics ~= true then return end
    if not airbaseName then return end
    local resMap = _getWarehouseResourceMap()
    if not resMap then return end
    local storage = STORAGE:FindByName(airbaseName) or nil
    if not storage then return end

    local fill = tonumber(fillAmount) or 1000
    if fill < 1 then fill = 1 end

    -- Build known set from WEAPONSLIST.Items
    local known = {}
    for _, list in pairs(WEAPONSLIST.Items or {}) do
        for _, name in ipairs(list) do
            known[name] = true
        end
    end

    -- Build mods set
    local mods = {}
    for _, name in ipairs(WEAPONSLIST_MODS_ITEMS or {}) do
        mods[name] = true
    end

    local allowModFill = (Era == "Modern" and AllowMods == true)
    local addedCount = 0
    local forbiddenWeaponsInAllEraSet = {}
    for _, forbiddenWeapon in ipairs(ForbiddWeaponsInAllEra or {}) do
        forbiddenWeaponsInAllEraSet[forbiddenWeapon] = true
    end

    for itemName, ws in pairs(resMap) do
        if type(ws) == "table" and ws[1] == 4 then
            if not (restrictedWeaponSet and restrictedWeaponSet[itemName]) then
                if not known[itemName] and not forbiddenWeaponsInAllEraSet[itemName] then
                    -- If mods are not allowed (Coldwar or AllowMods false), skip mod items
                    if allowModFill or not mods[itemName] then
                        local amt = storage:GetItemAmount(itemName)
                        if not amt or amt == 0 then
                            storage:SetItem(itemName, fill)
                            addedCount = addedCount + 1
							--env.info(string.format("[Warehouse] Pre-filling %s with %d of %s based on resource map." ,tostring(airbaseName), fill, tostring(itemName)))
                        end
                    end
                end
            end
        end
    end

    if addedCount > 0 then
        env.info(string.format("[Warehouse] Prefill %s: added %d item(s) at %d each", tostring(airbaseName), addedCount, fill))
    end
end



