function ZoneCommander:MakeZoneSideAndUpgraded()
    if self.active and self.side~=0 and not self.suspended then
        self:capture(self.side, true)
		local upgrades=self:getFilteredUpgrades()
        local totalUpgrades=Utils.getTableSize(upgrades)
        local sideText=(self.side==1) and "Red" or "Blue"
        BASE:I("Zone captured by "..sideText..": "..self.zone.." ("..Utils.getTableSize(self.built).."/"..totalUpgrades..")")
        local function upgradeZone()
            local builtNow=Utils.getTableSize(self.built)
            if builtNow<totalUpgrades then
                self:upgrade(true)
                builtNow=Utils.getTableSize(self.built)
                timer.scheduleFunction(upgradeZone,{},timer.getTime()+2)
            else
                BASE:I("Zone fully upgraded for "..sideText..": "..self.zone)
            end
        end
        timer.scheduleFunction(upgradeZone,{},timer.getTime()+1)
    end
end

function ZoneCommander:init()
	if self.destroyOnInit then
		for i,v in pairs(self.destroyOnInit) do
			local st = StaticObject.getByName(v)
			if st then
				--trigger.action.explosion(st:getPosition().p, st:getLife())
				st:destroy()
			end
		end
	end
	local zone = CustomZone:getByName(self.zone)
	if not zone then
		trigger.action.outText(L10N:Format("ZONE_ERROR_NOT_FOUND_IN_MISSION", self.zone), 60)
		env.info('ERROR: zone ['..self.zone..'] cannot be found in the mission')
	end
	normalizePopupAwakenState(self)

	local color = {0.7, 0.7, 0.7, 0.3}
	local textColor = {0.3, 0.3, 0.3, 1}
	if self.side == 1 then
		color = {1, 0, 0, 0.3}
		textColor = {0.7, 0, 0, 0.8}
	elseif self.side == 2 then
		color = {0, 0, 1, 0.3}
		textColor = {0, 0, 0.7, 0.8}
		self.wasBlue = true
	elseif self.side == 0 and self.wasBlue then
		color = {0, 0, 1, 0.3}
		textColor = {0, 0, 0.7, 1}
	end

	if not self.active then
		if self.wasBlue then
			color = {0, 0, 1, 0.3}
			textColor = {0, 0, 0.7, 0.8}
		else
			color = {0.1, 0.1, 0.1, 0.3}
			textColor = {0.1, 0.1, 0.1, 1}
		end
	end

	if self.side ~= 0 and self.NeutralAtStart == true then
		self.NeutralAtStart = false
	end

	if self.active and not self.isHidden then
		zone:draw(self.index, color, color)
	else
		trigger.action.removeMark(self.index)
		trigger.action.removeMark(2000 + self.index)
	end

	local point = zone.point
	if zone:isCircle() then
		point = { x = zone.point.x, y = zone.point.y, z = zone.point.z + zone.radius }
	elseif zone:isQuad() then
		local largestZ = zone.vertices[1].z
		local largestX = zone.vertices[1].x
		for i = 2, 4 do
			if zone.vertices[i].z > largestZ then
				largestZ = zone.vertices[i].z
				largestX = zone.vertices[i].x
			end
		end
		point = { x = largestX, y = zone.point.y, z = largestZ }
	end

	if self.airbaseName and self.airbaseName ~= 'CVN-72' and self.airbaseName ~= 'CVN-73' and self.airbaseName ~= 'CVN-74' and self.airbaseName ~= 'CVN-75' then

		--timer.scheduleFunction(function()
			local ab = getDcsAirbaseByName(self.airbaseName)
			if ab then
				if ab:autoCaptureIsOn() then ab:autoCapture(false) end
 				if self.side == 2 and self.LogisticCenter and WarehouseLogistics == true then
					_prefillLogisticCenterFromResourceMap(self.airbaseName, 1000)
				end

				if self.side == 0 or (not self.active and not self.wasBlue) then
				  timer.scheduleFunction(function()
					if RespawnStaticsForAirbase then
						RespawnStaticsForAirbase(self.airbaseName, 0)						
					end
				  end, {}, timer.getTime() +1)	
					ab:setCoalition(1)
					if WarehouseLogistics == true and not self.LogisticCenter then
						WEAPONSLIST.ClearWeaponsAtAirbase(self.airbaseName)
					end					
				end
				if self.side == 1 then
				  timer.scheduleFunction(function()
					if RespawnStaticsForAirbase then
						RespawnStaticsForAirbase(self.airbaseName, 1)
						if self.LogisticCenter then self.LogisticCenter = false
						end
					end
				  end, {}, timer.getTime() +1)	
					ab:setCoalition(1)
				end
				if self.side == 2 then
					timer.scheduleFunction(function()
					if RespawnStaticsForAirbase then

						RespawnStaticsForAirbase(self.airbaseName, 2)
					end
				  end, {}, timer.getTime() +1)
						ab:setCoalition(2)
					if WarehouseLogistics == true and not self.LogisticCenter then
						WEAPONSLIST.ClearWeaponsAtAirbase(self.airbaseName)
					end
				end
			else
				env.info("Airbase " .. self.airbaseName .. " not found")
			end
		--end, {}, timer.getTime() +1)
	end

	self:_cacheUpgradeStatics()
	local upgrades = self:getFilteredUpgrades()
	local persistedSuspended = self.suspended and self._persistedSuspended == true

	if persistedSuspended then
		self.built = {}
		self._hibernated = {}
		self._persistedHibernated = {}
		for i, v in pairs(upgrades) do
			if i <= self.level then
				local staticObj = (not Group.getByName(v)) and StaticObject.getByName(v) or nil
				if staticObj then
					if UseStatics then
						self.built[i] = v
					end
				elseif not tostring(v):find("dismounted") then
					self.built[i] = v
					self._hibernated[v] = true
					self._persistedHibernated[v] = true
				end
			end
		end
		if not next(self._persistedHibernated) then
			self._persistedHibernated = nil
		end
		self.remainingUnits = nil
	end

	if not persistedSuspended then
		for i, v in pairs(self.built) do
			local gr = Group.getByName(v)
			local st = StaticObject.getByName(v)
			if not gr and not st then self.built[i] = nil end
		end
	end

		if not self._validatedUpgrades then
		for i, v in pairs(upgrades) do
			if v and not tostring(v):find("dismounted") then
				local gr = Group.getByName(v)
				local st = (not gr) and StaticObject.getByName(v) or nil
				local hasTpl = _DATABASE.Templates.Groups[v]
				if not gr and not st and not hasTpl then
					MISSING_GROUPS[v] = true
					local msg = L10N:Format("ZONE_INIT_MISSING_UPGRADE_GROUP", tostring(v), tostring(self.zone), tostring(i))
					env.info(msg)
					trigger.action.outText(msg, 10)
				end
			end
		end
		self._validatedUpgrades = true
	end

	local forceRefresh = self._refreshRandomUpgrades == true
	if forceRefresh then
		self.remainingUnits = nil
	end

	if not persistedSuspended and self.remainingUnits then
		for i, v in pairs(self.remainingUnits) do
			if not self.built[i] then
				local upg = upgrades[i]
				if not upg then
				else
					local staticObj = (not Group.getByName(upg)) and StaticObject.getByName(upg) or nil
					if staticObj then
						if UseStatics then
							self.built[i] = upg
						end
					else
						if not tostring(upg):find("dismounted") then
							local gr = zone:spawnGroup(upg, false)
							if gr then
								self.built[i] = gr.name
								else
								MISSING_GROUPS[upg] = true
								trigger.action.outText(L10N:Format("ZONE_UPGRADE_GROUP_MISSING_SKIPPED", tostring(upg)),10)
								env.info('zoneCommander ERROR: spawnGroup returned nil for zone ['..self.zone..'] extra upgrade index '..tostring(i)..' name='..(upg or 'nil'))
							end							
						end
					end
				end
			end
		end
	elseif not persistedSuspended then
		if forceRefresh or Utils.getTableSize(self.built) < self.level then
			for i, v in pairs(upgrades) do
				if not self.built[i] and i <= self.level then
					local staticObj = (not Group.getByName(v)) and StaticObject.getByName(v) or nil
					if staticObj then
						if UseStatics then
							self.built[i] = v
						end
					else
						if not tostring(v):find("dismounted") then
							local gr = zone:spawnGroup(v, false)
							if not gr then
								MISSING_GROUPS = MISSING_GROUPS or {}
								MISSING_GROUPS[v] = true
								local replacement = pickReplacementUpgrade(self, v, upgrades)
								if replacement then
									upgrades[i] = replacement
									if self.side == 1 and self.upgrades and self.upgrades.red then
										local cur = self.upgrades.red[i]
										if getUpgradeEntryName(cur) == v then
											-- If the original entry was pinned, replacement implicitly unpins it.
											self.upgrades.red[i] = replacement
										end
									elseif self.side == 2 and self.upgrades and self.upgrades.blue then
										local cur = self.upgrades.blue[i]
										if getUpgradeEntryName(cur) == v then
											self.upgrades.blue[i] = replacement
										end
									end
									if self.randomUpgradesRed and self.randomUpgradesRed[i] == v then
										self.randomUpgradesRed[i] = replacement
									end
									if self.randomUpgradesBlue and self.randomUpgradesBlue[i] == v then
										self.randomUpgradesBlue[i] = replacement
									end
									local gr2 = zone:spawnGroup(replacement, false)
									if gr2 then
										self.built[i] = gr2.name
									else
										MISSING_GROUPS[replacement] = true
										trigger.action.outText(L10N:Format("ZONE_FAILED_SPAWN_REPLACEMENT_GROUP", replacement or "nil"), 10)
										env.info("zoneCommander DEBUG: spawnGroup returned nil for zone ["..self.zone.."] replacement index "..tostring(i).." name="..(replacement or "nil"))
									end
								else
									trigger.action.outText(L10N:Format("ZONE_FAILED_SPAWN_GROUP_FOR_UPGRADE", v or "nil"), 10)
									env.info("zoneCommander DEBUG: spawnGroup returned nil for zone ["..self.zone.."] upgrade index "..tostring(i).." name="..(v or "nil"))
								end
							else
								self.built[i] = gr.name
							end
						end
					end
				end
			end
		end
	end
	if forceRefresh then
		self._refreshRandomUpgrades = nil
	end
	if not self.isHidden and self.active then
		local waypointLabel = WaypointList and WaypointList[self.zone] or ""
		local msg = " " .. self.zone .. "" .. waypointLabel
		if missions then
			local mission = getFirstMatchingZoneMission(self.zone, function(candidate)
				local tz = bc.indexedZones[candidate.TargetZone]
				return tz and self.side == 2 and tz.side == 1
			end)
			if mission then
				msg = msg .. "\n " .. L10N:Get("ZONE_LABEL_MISSION")
			end
		end
		if self.side == 2 then
			if self.LogisticCenter then
				msg = msg .. "\n [WH]"
			end
			local upgrades = self:getFilteredUpgrades()
			local builtCount = 0
			for _ in pairs(self.built) do builtCount = builtCount + 1 end
			local total = Utils.getTableSize(upgrades)
			if builtCount ~= total then
				msg = msg .. "\n " .. builtCount .. "/" .. total
			end
		end
		local backgroundColor = {0.7, 0.7, 0.7, 0.8}
		trigger.action.textToAll(-1, 2000 + self.index, point, textColor, backgroundColor, 17, true, msg)
		trigger.action.setMarkupText(2000 + self.index, msg)
	end


	if self.side == 2 and self.isHeloSpawn then
		trigger.action.setMarkupTypeLine(self.index, 2)
		trigger.action.setMarkupColor(self.index, {0,1,0,1})
	end
	if self.wasBlue and not self.active and self.isHeloSpawn then
		trigger.action.setMarkupTypeLine(self.index, 2)
		trigger.action.setMarkupColor(self.index, {0,1,0,1})
	end
	self:weedOutRemainingUnits({ skipUnitTrim = persistedSuspended })
	for i, v in ipairs(self.restrictedGroups) do
		trigger.action.setUserFlag(v.name, v.side ~= self.side)
	end
	for i, v in ipairs(self.groups) do
		v:init()
	end
	self:_refreshSupplyMenuCache()
	self._persistedSuspended = nil
	self._fsmFilterGeneration = -1
	self._reindexCombatCacheGeneration = -1
	self._supplyCacheGeneration = -1
end

if WarehouseLogistics == true then 
	env.info("ZoneCommander: WarehouseLogistics is enabled")

end

	function ZoneCommander:weedOutRemainingUnits(opts)
		opts = opts or {}
		local skipUnitTrim = opts.skipUnitTrim == true
		local destroyPersistedUnits = function(context)
			if (not skipUnitTrim) and context.remainingUnits then
				for i2, v2 in pairs(context.built) do
					local bgr = Group.getByName(v2)
					if bgr then
						local ru = context.remainingUnits[i2]
						if ru and #ru > 0 then
							local need = {}
							for _, t in ipairs(ru) do
								need[t] = (need[t] or 0) + 1
							end
							for i3, v3 in ipairs(bgr:getUnits()) do
								local budesc = v3:getDesc()
								if need[budesc.typeName] and need[budesc.typeName] > 0 then
									need[budesc.typeName] = need[budesc.typeName] - 1
								else
									v3:destroy()
								end
							end
						end
					end
				end
			end
			if context.newStatics then
				for _, v4 in ipairs(context.newStatics) do
					local staticName = type(v4) == "table" and v4.name or v4
					local st = StaticObject.getByName(staticName)
					if st and st:isExist() then
						local foundInBuilt = false
						for _, builtName in pairs(context.built) do
							if builtName == staticName then
								foundInBuilt = true
								break
							end
						end
						if not foundInBuilt then
							st:destroy()
						end
					end
				end
			end
		end
		
		SCHEDULER:New(nil,destroyPersistedUnits,{self},2,0)
		SCHEDULER:New(nil, destroyPersistedUnits, {self},4,0)
	end


	function ZoneCommander:checkCriticalObjects()
		if not self.active then
			return
		end
		
		local stillactive = false
		if self.criticalObjects and #self.criticalObjects > 0 then
			for i,v in ipairs(self.criticalObjects) do
				local st = StaticObject.getByName(v)
				if st and st:getLife()>1 then
					stillactive = true
				end
				
				--clean up statics that still exist for some reason even though they're dead
				if st and st:getLife()<1 then
					st:destroy()
				end
			end
		else
			stillactive = true
		end
		
		if not stillactive then
			self:disableZone()
		end
	end

	function ZoneCommander:_gcIsLiveForFsm(gc)
		local st = gc.state
		return st == 'takeoff' or st == 'inair' or st == 'landed' or st == 'enroute' or st == 'atdestination'
	end

	function ZoneCommander:_forceIncludeRestoreLiveGc(gc)
		if not gc or not gc.name then
			return
		end
		self._fsmRestoreLiveOverrides = self._fsmRestoreLiveOverrides or {}
		self._fsmRestoreLiveOverrides[gc.name] = true

		local filtered = self._fsmFilteredGroups
		if not filtered then
			return
		end
		for i = 1, #filtered do
			if filtered[i] == gc then
				return
			end
		end
		filtered[#filtered + 1] = gc
	end

	function ZoneCommander:_fsmExcludeReason(gc)
		if gc and gc._dynamicHybridRetired == true then
			return "dynamic_hybrid_retired"
		end
		local mission = gc.mission
		if not self.active then
			return "source_inactive"
		end
		if gc.template and self.side ~= 0 and not gc:_templateSupportsSide(self.side) then
			return "template_side_unavailable"
		end
		if mission == 'supply' then
			if self:_gcIsLiveForFsm(gc) or gc._supplyReturnHome == true then
				return nil
			end
			if self.suspended then
				if gc._allowSuspendedShopSupplySpawn == true
					and gc.ShopLaunchOnly == true
					and gc.side == 2
				then
					return nil
				end
				return "supply_source_suspended"
			end
			local targetNameSupply = gc.targetzone
			if not targetNameSupply then
				return nil
			end
			local tzSupply = self.battleCommander:getZoneByName(targetNameSupply)
			if not tzSupply then
				return nil
			end
			if not tzSupply.active then
				return "supply_target_inactive"
			end
			if tzSupply.suspended then
				return "supply_target_suspended"
			end
			if tzSupply.side ~= self.side and tzSupply.side ~= 0 then
				return "supply_target_side_mismatch"
			end
			return nil
		end
		if mission ~= 'patrol' and mission ~= 'attack' then
			return nil
		end
		if self:_gcIsLiveForFsm(gc) then
			return nil
		end
		local targetName = gc.targetzone
		if not targetName then
			return nil
		end

		local tz = self.battleCommander:getZoneByName(targetName)
		if not tz then
			return nil
		end
		local srcSide = self.side
		local isDynh = string.sub(gc.name or "", 1, 5) == "DYNH-"

--[[ 	if (mission == 'patrol' or mission == 'attack') then
			if self.suspended then
				return "dynh_source_suspended"
			end
			if tz.suspended then
				return "dynh_target_suspended"
			end
		end ]]
		if mission == 'patrol' then
			if tz.side ~= srcSide then
				return "patrol_target_side_mismatch"
			end
			return nil
		end
		if not tz.active then
			return "target_inactive"
		end
		if tz.side == srcSide then
			return "attack_target_friendly"
		end
		if tz.side == 0 then
			return "attack_target_neutral"
		end
		return nil
	end

	function ZoneCommander:_shouldIncludeGcInFsm(gc)
		return self:_fsmExcludeReason(gc) == nil
	end

	function ZoneCommander:_rebuildSupplyCache()
		local cached = {}
		local groups = self.groups
		for i = 1, #groups do
			local gc = groups[i]
			if gc.mission == 'supply' and not self.battleCommander:_dynamicHybridIsRetiredGroup(gc) then
				cached[#cached + 1] = gc
			end
		end
		self._supplyCache = cached
		self._supplyCacheGeneration = (self.battleCommander and self.battleCommander._supplyCacheGeneration) or 0
	end

	function ZoneCommander:_getSupplyCache()
		local gen = (self.battleCommander and self.battleCommander._supplyCacheGeneration) or 0
		if self._supplyCacheGeneration ~= gen then
			self:_rebuildSupplyCache()
		end
		return self._supplyCache or {}
	end

	function ZoneCommander:_rebuildCombatPoolsOnce()
		local filtered = {}
		local combatCached = {}
		local removed = 0
		local keptPatrol = 0
		local keptAttack = 0
		local removedPatrol = 0
		local removedAttack = 0
		local restoreOverrides = self._fsmRestoreLiveOverrides
		local seenRestoreOverrides = restoreOverrides and {} or nil

		for i, gc in ipairs(self.groups) do
			local isRetired = self.battleCommander:_dynamicHybridIsRetiredGroup(gc)
			local forceIncludeRestoreLive = false
			if restoreOverrides and gc and gc.name and restoreOverrides[gc.name] then
				seenRestoreOverrides[gc.name] = true
				if not isRetired and self:_gcIsLiveForFsm(gc) then
					forceIncludeRestoreLive = true
				else
					restoreOverrides[gc.name] = nil
				end
			end
			local reason = nil
			if not forceIncludeRestoreLive then
				reason = isRetired and "dynamic_hybrid_retired" or self:_fsmExcludeReason(gc)
			end
			if not reason then
				filtered[#filtered + 1] = gc
				local mission = gc.mission
				if mission == 'patrol' then
					keptPatrol = keptPatrol + 1
				elseif mission == 'attack' then
					keptAttack = keptAttack + 1
				end
				if gc._artilleryReturnHome ~= true and (mission == 'attack' or mission == 'patrol') then
					local targetName = gc.targetzone
					if targetName then
						combatCached[#combatCached + 1] = {
							groupRef = gc,
							targetZoneName = targetName,
						}
					end
				end
			else
				removed = removed + 1
				if gc.mission == 'patrol' then
					removedPatrol = removedPatrol + 1
				elseif gc.mission == 'attack' then
					removedAttack = removedAttack + 1
				end
			end
		end
		if restoreOverrides then
			for name, _ in pairs(restoreOverrides) do
				if not seenRestoreOverrides[name] then
					restoreOverrides[name] = nil
				end
			end
			if not next(restoreOverrides) then
				self._fsmRestoreLiveOverrides = nil
			end
		end

		local stats = self.battleCommander._fsmFilterPassStats
		if stats then
			stats.zones = stats.zones + 1
			stats.total = stats.total + #self.groups
			stats.kept = stats.kept + #filtered
			stats.keptPatrol = stats.keptPatrol + keptPatrol
			stats.keptAttack = stats.keptAttack + keptAttack
			stats.removed = stats.removed + removed
			stats.removedPatrol = stats.removedPatrol + removedPatrol
			stats.removedAttack = stats.removedAttack + removedAttack
		end
		self._fsmFilteredGroups = filtered
		self._reindexCombatCache = combatCached
		self._fsmFilterGeneration = self.battleCommander._fsmFilterGeneration
		self._reindexCombatCacheGeneration = self.battleCommander._reindexCombatFilterGeneration
		if GlobalSettings.FilterLog then
			self.battleCommander:_recordFsmFilterRebuildSummary(self.zone, removedPatrol, removedAttack, filtered, combatCached)
		end
	end

	function ZoneCommander:_ensureCombatPoolsFresh()
		if self._fsmFilterGeneration ~= self.battleCommander._fsmFilterGeneration
			or self._reindexCombatCacheGeneration ~= self.battleCommander._reindexCombatFilterGeneration then
			self:_rebuildCombatPoolsOnce()
		end
	end

	function ZoneCommander:_getFsmFilteredGroups()
		self:_ensureCombatPoolsFresh()
		return self._fsmFilteredGroups
	end

	function ZoneCommander:_getReindexCombatCache()
		-- Reindex path consumes the latest cache built during the update-cycle refresh.
		return self._reindexCombatCache or {}
	end
	
	function ZoneCommander:update()
		if not self.active then return end
		self.battleCommander._fsmCrashCurrentZone = self.zone
		self.battleCommander._fsmCrashCurrentGroup = '<none>'
		if self.income and self.side ~= 0 then
			if self.redIncomeOnly then
				if self.side == 1 then
					self.battleCommander:addFunds(self.side, self.income)
				end
			else
				self.battleCommander:addFunds(self.side, self.income)
			end
		end
		local allowSpawnWhileSuspended = self._suspendAllowSpawn == true
		if self.suspended then
			if allowSpawnWhileSuspended then
				local fsmGroups = self:_getFsmFilteredGroups()
				for i, v in ipairs(fsmGroups) do
					v:update()
				end
			else
				for _, v in pairs(self._suspendedLiveFsm or {}) do
					v:update()
				end
			end
			self.battleCommander._fsmCrashPhase = 'zones'
			self.battleCommander._fsmCrashCurrentGroup = '<none>'
			return
		end
		if not self.suspended then
			self:checkCriticalObjects()

			local toRemove = {}
			local marked   = {}

			for i,v in pairs(self.built) do
				local gr = Group.getByName(v)
				local st = StaticObject.getByName(v)

				if gr and not gr:isExist() then
					gr = nil
				end

				if st and st:isExist() == false then
					st = nil
				end

				if gr and gr:getSize() == 0 then
					gr:destroy()
					if not marked[i] then marked[i]=true; toRemove[#toRemove+1]={key=i,name=v} end
				end

				if gr and gr:getSize() > 0 and not marked[i] then
					local anyAlive = false
					local unitCount = gr:getSize()
					for uidx=1,unitCount do
						local u = gr:getUnit(uidx)
						local life = (u and u:isExist() and u.getLife and u:getLife()) or 0
						if life >= 1 then anyAlive = true; break end
					end
					if not anyAlive then
						gr:destroy()
						if not marked[i] then marked[i] = true; toRemove[#toRemove+1] = { key = i, name = v } end
					end
				end
				
				if not gr and not marked[i] then
					local stLife = (st and st.getLife and st:getLife()) or 0
					if st and stLife < 1 then
						st:destroy()
						if not marked[i] then marked[i] = true; toRemove[#toRemove+1] = { key = i, name = v } end
					end
				end

				if not gr and not st then
					if not marked[i] then marked[i] = true; toRemove[#toRemove+1] = { key = i, name = v } end
				end
			end

				local anyRemoved = false
				local retiredStaticNames = {}
				for _,rem in ipairs(toRemove) do
					self.built[rem.key] = nil
					anyRemoved = true
					if UseStatics then
						local retiredBaseName = self:_getTrackedStaticBaseName(rem.name)
						if retiredBaseName then
							retiredStaticNames[retiredBaseName] = true
						end
					end
					if GlobalSettings.messages.grouplost then trigger.action.outText(L10N:Format("ZONE_LOST_GROUP", self.zone, rem.name), 5) end
				end
				local retiredStaticsChanged = false
				if next(retiredStaticNames) then
					local retiredSet = _copyRetiredStaticSet(self.retiredStaticUpgrades)
					local added = false
					for retiredBaseName in pairs(retiredStaticNames) do
						if not retiredSet[retiredBaseName] then
							retiredSet[retiredBaseName] = true
							added = true
						end
					end
					if added then
						self.retiredStaticUpgrades = retiredSet
						retiredStaticsChanged = self:_applyRetiredStaticUpgrades() or true
					end
				end
				if anyRemoved or retiredStaticsChanged then
					self:updateLabel()
					if self.side == 2 and self:_refreshSupplyMenuCache() then
						bc:requestDelayedSupplyMenuRefresh()
					end
			end

			local empty = (next(self.built) == nil)

			if empty and self.side ~= 0 and self.active then


			if self.battleCommander.difficulty and self.side == self.battleCommander.difficulty.coalition then
				self.battleCommander:increaseDifficulty()      
			end
			local previousState = {
				active = self.active,
				suspended = self.suspended,
				side = self.side,
				isHidden = self.isHidden,
				NeutralAtStart = self.NeutralAtStart,
				firstCaptureByRed = self.firstCaptureByRed,
				airbaseName = self.airbaseName,
				LogisticCenter = self.LogisticCenter,
			}
			local previousSide = self.side
			self.side = 0
			if intelActiveZones[self.zone] == true then
				stopZoneIntel(self.zone, true)
			end
			bc:markFsmGroupFilterDirty()
			bc:markReindexCombatFilterDirty()
			bc:markSupplyCacheDirty()
			if self:_refreshSupplyMenuCache(false) then
				bc:requestDelayedSupplyMenuRefresh()
			end
			self.wasBlue = false
			self:runTriggers('lost')
			bc:buildConnectionMap(self.zone, previousSide)
			buildCapControlMenu()
			bc.huntBases = nil
			bc:_buildHunterBaseList()
			self.battleCommander:requestZoneStatusMenuRefresh()
			self.battleCommander:requestFrontlineRefresh()
									 
									
				 
			self.battleCommander:RefreshTerritoryOverlayZone(self.zone)
			self.battleCommander:RefreshConnectionsLines(self.zone)


			local cz = CustomZone:getByName(self.zone)
			if cz then cz:clearUsedSpawnZones(self.zone) end
			if self.airbaseName and self.airbaseName ~= 'CVN-72' and self.airbaseName ~= 'CVN-73' and self.airbaseName ~= 'CVN-74' and self.airbaseName ~= 'CVN-75' then

				local ab = getDcsAirbaseByName(self.airbaseName)
				if ab then
					local currentCoalition = ab:getCoalition()
					--if currentCoalition ~= coalition.side.RED then
						if RespawnStaticsForAirbase then
						RespawnStaticsForAirbase(self.airbaseName, coalition.side.NEUTRAL)
						end
						ab:setCoalition(0)
						if WarehouseLogistics == true and not self.LogisticCenter then
							WEAPONSLIST.ClearWeaponsAtAirbase(self.airbaseName)
						end
					--end
				end
			end	
			self:syncColdwarAllowedPlanesAtAirbase()
			if self.active and GlobalSettings.messages.zonelost and not self.isHidden then
				local zoneLostMessage = previousSide == 2 and "ZONE_LOST_BY_BLUE" or "ZONE_NOW_NEUTRAL"
				trigger.action.outText(L10N:Format(zoneLostMessage, self.zone), 15)
				if trigger.misc.getUserFlag(180) == 0 then
					trigger.action.outSoundForCoalition(2, "ding.ogg")
				end
            if WarehouseLogistics then
                local zn = tostring(self.zone or "")
                if isCarrierZoneName(zn) then
                    if not self._carrierAutoRecapScheduled then
                        self._carrierAutoRecapScheduled = true
                        local zc = self
                        timer.scheduleFunction(function()
                            if not zc then return end
                            zc._carrierAutoRecapScheduled = false
                            -- only if it’s still neutral when the timer fires
                            if zc.active and zc.side == 0 then
                                if map == "Syria" then
                                    local sz = zc.battleCommander:getZoneByName('Silkworm Site')
                                    if sz and sz.active then return end
								elseif map == "PersianGulf" then
								if not CustomFlags['StartNormalFalse'] and (zones.lavan.side == 1 or zones.kish.side == 1 or zones.bandarabbas.side == 1 or zones.sirri.side == 1
									or zones.abumusa.side == 1 or zones.tunbisland.side == 1 or zones.qeshmisland.side == 1 or 
									zones.moradi.side == 1) then return end
								end
                                zc:capture(2)
                            end
                        end, nil, timer.getTime() + 5)
                    end
                end
            end
        end
			if self.active then   
				trigger.action.setMarkupColor(2000 + self.index, {0.3, 0.3, 0.3, 1})
				trigger.action.setMarkupColorFill(self.index, {0.7, 0.7, 0.7, 0.3})
				trigger.action.setMarkupColor(self.index, {0.7, 0.7, 0.7, 0.3})
				self:updateLabel()
				if missions then
					for _, m in pairs(missions) do
						if m.TargetZone == self.zone then
							local src = bc.indexedZones[m.zone]
							if src then src:updateLabel() end
						end
					end
				end
			end
			
			if CaptureZoneIfNeutral then
				CaptureZoneIfNeutral()
			end
			if CheckJtacStatus then
				CheckJtacStatus()
			end

			bc:_applyZoneShopSelectorDelta(self, previousState)
			local selectorRefreshTags = bc:_getZoneSelectorRefreshTags(self, previousState)
			if #selectorRefreshTags > 0 then
				bc:requestShopSelectorRefreshForCoalition(2, selectorRefreshTags)
			end
		
			if addCTLDZonesForBlueControlled then
				addCTLDZonesForBlueControlled(self.zone)
			end
			if SpawnFriendlyAssets then
				SCHEDULER:New(nil,SpawnFriendlyAssets,{},2)
			end

			SCHEDULER:New(nil, function() bc:buildCapSpawnBuckets() end, {}, 5)


			self.battleCommander:_rebalanceRedDifficulty(self.zone, {
				active = true,
				suspended = self.suspended,
				side = previousSide,
				isHidden = self.isHidden
			})
		end

		end

		local fsmGroups = self:_getFsmFilteredGroups()
		for i, v in ipairs(fsmGroups) do
			v:update()
		end
		self.battleCommander._fsmCrashPhase = 'zones'
		self.battleCommander._fsmCrashCurrentGroup = '<none>'

		if not self.suspended then
			if self.crates then
				for i, v in ipairs(self.crates) do
					local crate = StaticObject.getByName(v)
					if crate and Utils.isCrateSettledInZone(crate, self.zone) then
						if self.side == 0 then
							self:capture(crate:getCoalition())
							if self.battleCommander.playerRewardsOn then
								self.battleCommander:addFunds(self.side, self.battleCommander.rewards.crate)
								trigger.action.outTextForCoalition(self.side, L10N:Format("LOGISTICS_CAPTURE_CREDITS", tostring(self.battleCommander.rewards.crate)), 5)
							end
						elseif self.side == crate:getCoalition() then
							if self.battleCommander.playerRewardsOn then
								if self:canRecieveSupply() then
									self.battleCommander:addFunds(self.side, self.battleCommander.rewards.crate)
									trigger.action.outTextForCoalition(self.side, L10N:Format("LOGISTICS_RESUPPLY_CREDITS", tostring(self.battleCommander.rewards.crate)), 5)
								else
									local reward = self.battleCommander.rewards.crate * 0.25
									self.battleCommander:addFunds(self.side, reward)
									trigger.action.outTextForCoalition(self.side, L10N:Format("LOGISTICS_RESUPPLY_NO_DEMAND", tostring(reward)), 5)
								end
							end
							self:upgrade()
						end

						crate:destroy()
					end
				end
			end

			for i, v in ipairs(self.restrictedGroups) do
				trigger.action.setUserFlag(v.name, v.side ~= self.side)
			end
		end
	end

	function ZoneCommander:_refreshSupplyMenuCache(canReceive)
		local oldNeedsSupplyForMenu = self._needsSupplyForMenu == true
		local oldUpgradeCount = tonumber(self._supplyMenuUpgradeCount) or 0
		local oldTotalUpgrades = tonumber(self._supplyMenuTotalUpgrades) or 0

		local newNeedsSupplyForMenu = false
		local newUpgradeCount = 0
		local newTotalUpgrades = 0

		if self.active and self.side == 2 and not self.suspended then
			newTotalUpgrades = Utils.getTableSize(self:getFilteredUpgrades())
			for _, builtUnit in pairs(self.built or {}) do
				local gr = Group.getByName(builtUnit)
				if gr and gr:getCoalition() == 2 and gr:getSize() == gr:getInitialSize() then
					newUpgradeCount = newUpgradeCount + 1
				end
			end
			if canReceive == nil then
				newNeedsSupplyForMenu = self:canRecieveSupply() == true
			else
				newNeedsSupplyForMenu = canReceive == true
			end
		end

		self._needsSupplyForMenu = newNeedsSupplyForMenu
		self._supplyMenuUpgradeCount = newUpgradeCount
		self._supplyMenuTotalUpgrades = newTotalUpgrades

		return oldNeedsSupplyForMenu ~= newNeedsSupplyForMenu
			or oldUpgradeCount ~= newUpgradeCount
			or oldTotalUpgrades ~= newTotalUpgrades
	end

	function ZoneCommander:updateLabel()
		if self.isHidden then return end
		if not self.active then
			trigger.action.removeMark(self.index)
			trigger.action.removeMark(2000 + self.index)
			trigger.action.setMarkupText(2000 + self.index, "")
			return
		end
		local waypointLabel = (self.active and WaypointList and WaypointList[self.zone]) or ""
		local msg = " " .. self.zone .. "" .. waypointLabel
		if missions then
			local mission = getFirstMatchingZoneMission(self.zone, function(candidate)
				local ownZone = bc.indexedZones[candidate.zone]
				local targetZone = bc.indexedZones[candidate.TargetZone]
				return ownZone and targetZone and self.side == 2 and targetZone.side == 1
			end)
			if mission then
				msg = msg .. "\n " .. L10N:Get("ZONE_LABEL_MISSION")
			end
		end
		if self.LogisticCenter then
			msg = msg .. "\n [WH]"
		end
		if self.side == 2 and WarehouseLowSupplies and WarehouseLowSupplies[self.zone] and not self.LogisticCenter then
			local supply = WarehouseLowSupplies[self.zone]
			local avg = supply.avg
			local entries = supply.entries
			if (type(entries) == "number" and entries < 500) or (type(avg) == "number" and avg < 10) then
				msg = msg .. "\n Empty warehouse!"
			elseif type(avg) == "number" and avg < 50 then
				msg = msg .. "\n Low warehouse!"
			end
		end
		if ActiveCurrentMission[self.zone] then
			local cur = ActiveCurrentMission[self.zone]
			if type(cur) == "table" then
				for k in pairs(cur) do
					msg = msg .. "\n " .. getZoneMissionTagLabel(k) .. "!"
				end
			else
				msg = msg .. "\n " .. getZoneMissionTagLabel(cur) .. "!"
			end
		end
		local intelActive = (intelActiveZones[self.zone] == true)
		if (self.side == 2 and not self.suspended) or intelActive then
			local upgrades = self:getFilteredUpgrades()
			local builtCount = 0
			if self.built then for _ in pairs(self.built) do builtCount = builtCount + 1 end end
			local total = Utils.getTableSize(upgrades)
			if total > 0 then
				local showWhenFullyUpgraded = (self.side == 1 and intelActive)
				if showWhenFullyUpgraded or (total ~= builtCount) then
					msg = msg .. "\n " .. builtCount .. "/" .. total
				end
			end
		end
		trigger.action.setMarkupText(2000 + self.index, msg)
	end


	
	function ZoneCommander:addGroup(group)
		table.insert(self.groups, group)
		group.zoneCommander = self
		self._fsmFilterGeneration = -1
		self._reindexCombatCacheGeneration = -1
		self._supplyCacheGeneration = -1
		local bcRef = self.battleCommander
		if bcRef and bcRef._reindexCombatFilterGeneration then
			bcRef:markReindexCombatFilterDirty()
			bcRef:markSupplyCacheDirty()
		end
	end
	
	function ZoneCommander:addGroups(groups)
		for i,v in ipairs(groups) do
			table.insert(self.groups, v)
			v.zoneCommander = self
			
		end
		self._fsmFilterGeneration = -1
		self._reindexCombatCacheGeneration = -1
		self._supplyCacheGeneration = -1
		local bcRef = self.battleCommander
		if bcRef and bcRef._reindexCombatFilterGeneration then
			bcRef:markReindexCombatFilterDirty()
			bcRef:markSupplyCacheDirty()
		end
	end
	
	function ZoneCommander:validateTargetzones()
		for i,v in ipairs(self.groups or {}) do
			if v.targetzone then
				local tz = self.battleCommander and self.battleCommander:getZoneByName(v.targetzone)
				if not tz then
					trigger.action.outText(L10N:Format("ZONE_WARNING_UNKNOWN_TARGETZONE", tostring(v.targetzone), tostring(v.name), tostring(self.zone)), 15)
					env.info(string.format("[WARN] unknown targetzone=%s in group=%s zone=%s", tostring(v.targetzone), tostring(v.name), tostring(self.zone)))
				end
			end
		end
	end

SCHEDULER:New(nil,function() for i,v in pairs(bc.zones or {}) do v:validateTargetzones() end end,{},1,0)

	function ZoneCommander:killAll()
		for i,v in pairs(self.built) do
			local gr = GROUP:FindByName(v)
			if gr then
				gr:Destroy()
			else
				local st = StaticObject.getByName(v)
				if st then
					st:destroy()
				end
			end
		end
	end

	function ZoneCommander:syncColdwarAllowedPlanesAtAirbase()
		if Era ~= "Coldwar" then return end
		if not self.airbaseName then return end
		local storage = STORAGE:FindByName(self.airbaseName)
		if not storage then return end
		local planeList = (self.side == 2) and (allowedPlanes or {}) or (allowedPlanesRed or allowedPlanes or {})
		if not storage.GetInventory then return end
		local ac = storage:GetInventory()
		for name, _ in pairs(ac or {}) do
			storage:SetItem(name, 0)
		end
		for i = 1, #(planeList or {}) do
			storage:SetItem(planeList[i], 1073741823)
		end
	end
	

	
function ZoneCommander:capture(newside,silent)
    if self.active and self.side == 0 and newside ~= 0 then
        local previousState = {
			active = self.active,
			suspended = self.suspended,
			side = self.side,
			isHidden = self.isHidden,
			NeutralAtStart = self.NeutralAtStart,
			firstCaptureByRed = self.firstCaptureByRed,
			airbaseName = self.airbaseName,
			LogisticCenter = self.LogisticCenter,
		}
        local previousSide = self.side
        self.side = newside
        bc:markFsmGroupFilterDirty()
        bc:markReindexCombatFilterDirty()
        bc:markSupplyCacheDirty()
        if self:_refreshSupplyMenuCache() then
            bc:requestDelayedSupplyMenuRefresh()
        end
        bc._redReactiveBlueCaptureAt = bc._redReactiveBlueCaptureAt or {}
        if newside == 2 then
            bc._redReactiveBlueCaptureAt[self.zone] = timer.getTime()
        else
            bc._redReactiveBlueCaptureAt[self.zone] = nil
        end
        self:_syncUpgradesUsed()
		self.battleCommander:requestZoneStatusMenuRefresh()
        local sidename = ''
        local color = {0.7,0.7,0.7,0.3}
        local textcolor = {0.7,0.7,0.7,0.3}
        self.wasBlue = false
		self.NeutralAtStart = false
		
        trigger.action.setMarkupColor(2000 + self.index, textcolor)

        if self.side == 1 then
            sidename = 'RED'
            color = {1,0,0,0.3}
            textcolor = {0.7,0,0,0.8}
            self.wasBlue = false
			
            if self.NeutralAtStart and not self.firstCaptureByRed then
                self.firstCaptureByRed = true														 
            end

        elseif self.side == 2 then
            sidename = 'BLUE'
            color = {0,0,1,0.3}
            textcolor = {0,0,0.7,0.8}
            self.wasBlue = true
	end
		
		if SpawnFriendlyAssets then
			SCHEDULER:New(nil,SpawnFriendlyAssets,{},2)	
		end
		if addCTLDZonesForBlueControlled then
			addCTLDZonesForBlueControlled(self.zone)
		end
        trigger.action.setMarkupColor(2000 + self.index, textcolor)
        trigger.action.setMarkupColorFill(self.index, color)
        trigger.action.setMarkupColor(self.index, color)
        self:runTriggers('captured')
		if newside == 2 and self.battleCommander.logisticCommander then
			self.battleCommander.logisticCommander:_processCsarHomeZoneCaptured(self.zone)
		end
        bc:buildConnectionMap(self.zone, previousSide)
		bc.huntBases = nil
        bc:_buildHunterBaseList()
		bc:_applyZoneShopSelectorDelta(self, previousState)
        self.battleCommander:_rebalanceRedDifficulty(self.zone, {
			active = self.active,
			suspended = self.suspended,
			side = previousSide,
			isHidden = self.isHidden
		})
		self.battleCommander:RefreshTerritoryOverlayZone(self.zone)
		self.battleCommander:RefreshConnectionsLines(self.zone)

        SCHEDULER:New(bc, bc.abortSupplyToOpposite, {self.zone, self.side}, 10, 0)
        if _awacsRepositionSched then _awacsRepositionSched:Stop() end
        _awacsRepositionSched = SCHEDULER:New(nil, RepositionAwacsToFront, {}, 15)
		
		self.battleCommander:requestFrontlineRefresh()

		if checkAndDisableFriendlyZones then
			checkAndDisableFriendlyZones()
		end

		local selectorRefreshTags = bc:_getZoneSelectorRefreshTags(self, previousState)
		if #selectorRefreshTags > 0 then
			bc:requestShopSelectorRefreshForCoalition(2, selectorRefreshTags)
		end

		if not silent then
			if GlobalSettings.messages.captured and self.active then 
                trigger.action.outText(L10N:Format("ZONE_CAPTURED_BY", self.zone, sidename), 20)
        	elseif GlobalSettings.messages.captured and not self.active and self.wasBlue then 
                trigger.action.outText(L10N:Format("ZONE_CAPTURED_BLUE_PROGRESS_DISABLED", self.zone), 20)
			end
		end
		
		if self.active then
			if not silent then
				self:upgrade()
			else
				self:upgrade(true)
			end
			if CaptureZoneIfNeutral then CaptureZoneIfNeutral() end
		end
		if previousSide == 0 and newside == 2 then
			SCHEDULER:New(nil, function(zoneObj)
				local excludeUnitName = nil
				local pending = zoneSupplyLandingOnce and zoneSupplyLandingOnce.pending
				if pending and pending.zoneName == zoneObj.zone and pending.unit and pending.unit:isExist() then
					excludeUnitName = pending.unit:getName()
				end
				local seenUnits = {}
				local blueUnits = coalition.getPlayers(coalition.side.BLUE) or {}
				for _, unitCap in ipairs(blueUnits) do
					if unitCap and unitCap:isExist() then
						local pnameCap = unitCap:getPlayerName()
						local unitName = unitCap:getName()
						if pnameCap and AnyBluePlayers[pnameCap] and unitName ~= excludeUnitName and not seenUnits[unitName] and Utils.isLanded(unitCap, true) then
							local zoneData = bc:getZoneOfPoint(unitCap:getPoint())
							local pendingContribution = (bc.playerContributions[2] and bc.playerContributions[2][pnameCap]) or 0
							if zoneData and zoneData.zone == zoneObj.zone and zoneData.side == 2 and pendingContribution > 0 then
								seenUnits[unitName] = true
								world.onEvent({
									id = world.event.S_EVENT_LAND,
									time = timer.getAbsTime(),
									initiator = unitCap,
									initiatorPilotName = pnameCap,
									initiator_unit_type = unitCap:getTypeName(),
									initiator_coalition = 2,
									skipRewardMsg = true,
								})
							end
						end
					end
				end
			end, {self}, 1, 0)
		end
		
        if self.wasBlue and self.isHeloSpawn then
            trigger.action.setMarkupTypeLine(self.index, 2)
            trigger.action.setMarkupColor(self.index, {0, 1, 0, 1})
        end  
			if self.airbaseName and self.airbaseName ~= 'CVN-72' and self.airbaseName ~= 'CVN-73' and self.airbaseName ~= 'CVN-74' and self.airbaseName ~= 'CVN-75' then
				local ab = Airbase.getByName(self.airbaseName)
				if ab then
					if self.wasBlue then
						self.side = 2
					end
					ab:setCoalition(self.side)
					if RespawnStaticsForAirbase then
					RespawnStaticsForAirbase(self.airbaseName, self.side)
					end
					local baseCaptureEvent = {
						id = world.event.S_EVENT_BASE_CAPTURED,
						initiator = ab,
						place = ab,
						coalition = self.side,
					}
					world.onEvent(baseCaptureEvent)
				end
				bc.huntBases = nil
				
			end
		self:syncColdwarAllowedPlanesAtAirbase()
		local isUrgent = type(self.urgent) == "function" and self.urgent() or self.urgent
		
        for _, v in ipairs(self.groups) do
		if v.state == 'inhangar' or v.state == 'dead' then
			 if isUrgent then
					v.lastStateTime = timer.getAbsTime() + 30
				else
					v.lastStateTime = timer.getAbsTime() + math.random(60, GlobalSettings.initialDelayVariance * 60) 
				end
			end
		end
		bc:buildCapSpawnBuckets()
		if buildCapControlMenu then
			buildCapControlMenu()
		end

        if self.battleCommander.difficulty and newside == self.battleCommander.difficulty.coalition then
            self.battleCommander:decreaseDifficulty()
        end
    end
	if not silent then		
		if not self.active and not self.wasBlue then
			if GlobalSettings.messages.disabled then
				trigger.action.outText(L10N:Format("ZONE_DESTROYED_NO_CAPTURE", self.zone), 5)
				SCHEDULER:New(nil,function()
					trigger.action.setMarkupColor(2000 + self.index, {0.1, 0.1, 0.1, 1})
				end,{},0.5,0)
			end
		end
	end
	self:updateLabel()
	if missions then
		for _, m in pairs(missions) do
			if m.TargetZone == self.zone then
				local src = bc.indexedZones[m.zone]
				if src then src:updateLabel() end
			end
		end
	end
end

	
	function ZoneCommander:canRecieveSupply()
		if not self.active then
			return false
		end

		if self.suspended then
			return false
		end

		if self.side == 0 then 
			return true
		end
		local upgrades = self:getFilteredUpgrades()

		for i, v in pairs(self.built) do
			if not string.find(v, "dismounted") then
				local gr = Group.getByName(v)
				if gr and gr:getSize() < gr:getInitialSize() then
					return true
				end
			end
		end

		if Utils.getTableSize(self.built) < Utils.getTableSize(upgrades) then
			return true
		end

		return false
	end

	function ZoneCommander:clearWreckage()
		 local zn = getTriggerZone(self.zone)
		 local pos =  {
		x = zn.point.x, 
		y = land.getHeight({x = zn.point.x, y = zn.point.z}), 
		z= zn.point.z
		}
		local radius = zn.radius
		world.removeJunk({id = world.VolumeType.SPHERE,params = {point = pos ,radius = radius}})
	end
	
function ZoneCommander:upgrade(silent)
	if self.active and self.side ~= 0 then
		local zone = CustomZone:getByName(self.zone)
		local upgrades       = self:getFilteredUpgrades()
		local totalUpgrades  = Utils.getTableSize(upgrades)
		local function calculateUpgradeCount()
			local fullyRepairedGroups = {}
			for i,v in pairs(self.built) do
				success = false
				local gr = Group.getByName(v)
				if gr then
					local allUnitsRepaired = true
					for _,u in ipairs(gr:getUnits()) do
						if u and u:isExist() then
							if u:getLife() < u:getLife0() then
								allUnitsRepaired = false
								break
							end
						end
					end
					if allUnitsRepaired and gr:getSize() == gr:getInitialSize() then
						table.insert(fullyRepairedGroups,gr)
					end
				end
			end
			return #fullyRepairedGroups
		end
		local upgradeCount = calculateUpgradeCount()
		local repaired     = false
		local success    = false
		for i,v in pairs(self.built) do
			if not string.find(v,"dismounted") then
				local gr = GROUP:FindByName(v)
				if gr then	
					if gr:GetSize() and gr:GetInitialSize() then
						if gr:GetSize() < gr:GetInitialSize() then
							CustomRespawn(v)
							success = true
						end
					else
						zone:spawnGroup(v,false)
						success = true
					end
				end
			if success then
				if not silent then
					if GlobalSettings.messages.repaired then
						if self.side == 1 then
							trigger.action.outText(L10N:Format("ZONE_REPAIRED", self.zone),10)
						else
							trigger.action.outText(L10N:Format("ZONE_GROUP_REPAIRED", v, self.zone),10)
						end
					end
				end
				self:runTriggers('repaired')
				self:clearWreckage()
				self.battleCommander:RefreshConnectionsLines(self.zone)
				repaired = true
                self:updateLabel()
				if self.side == 2 and self:_refreshSupplyMenuCache() then
					self.battleCommander:requestDelayedSupplyMenuRefresh()
				end
				break
			end
		 end
		end
		if not repaired and upgradeCount == totalUpgrades then
			if self.side == 2 and not silent then
				trigger.action.outText(L10N:Format("ZONE_ALREADY_FULLY_UPGRADED", self.zone),10)
			end
			return false
		end
		if not repaired and Utils.getTableSize(self.built) < Utils.getTableSize(upgrades) then
			local zone = CustomZone:getByName(self.zone)
			for i,v in pairs(upgrades) do
				if not self.built[i] then
					local isStatic = false
					local stData   = nil
					for _,data in ipairs(self.newStatics or {}) do
						if data.name == v then
							isStatic = true
							stData   = data
							break
						end
					end
					if isStatic and stData then
						if stData.country == 1 then
							stData.country = country.id.RUSSIA
						else
							stData.country = country.id.USA
						end
						local spawnTemplate = {
							name       = stData.name,
							type       = stData.type,
							country    = stData.country,
							shape_name = stData.shapeName,
							heading    = math.rad(stData.heading),
							position   = stData.point
						}
						local spawnStatic = SPAWNSTATIC:NewFromTemplate(spawnTemplate,stData.country)
						local spawnedObject = spawnStatic:SpawnFromCoordinate(COORDINATE:NewFromVec3(stData.point))
						self.built[i] = spawnedObject:GetName()
					else
						local gr   = zone:spawnGroup(v,false)
						if gr then
							self.built[i] = gr.name
						else
							env.info("spawnGroup FAILED for "..tostring(v))
							trigger.action.outText(L10N:Format("ZONE_SPAWNGROUP_FAILED", tostring(v)), 30)
						end
					end
					SCHEDULER:New(nil,function()
						upgradeCount = calculateUpgradeCount()
						if self.side == 2 then
							if GlobalSettings.messages.upgraded and not silent then
								trigger.action.outText(L10N:Format("ZONE_UPGRADED_COUNT", self.zone, upgradeCount, totalUpgrades),10)
							end
						else
							if not silent then
								if GlobalSettings.messages.upgraded then
									trigger.action.outText(L10N:Format("ZONE_DEFENSES_UPGRADED", self.zone),10)
								end
							end
						end
					end,{},1,0)
					self:runTriggers('upgraded')
					self:clearWreckage()
                    self:updateLabel()
					if self.side == 2 and self:_refreshSupplyMenuCache() then
						self.battleCommander:requestDelayedSupplyMenuRefresh()
					end
					break
				end
			end
		end
		return true
	end
	if not self.active then
		if GlobalSettings.messages.disabled and not silent then
			trigger.action.outText(L10N:Format("ZONE_DESTROYED_NO_UPGRADE", self.zone),10)
		end
	end
	return false
end
end
GroupCommander = {}
do
	--{ name='groupname', mission=['patrol', 'supply', 'attack'], targetzone='zonename', type=['air','carrier_air','surface'] }
function GroupCommander:new(obj)
    obj = obj or {}
    
	obj.diceChance = obj.diceChance or 0
	
    if not obj.type then
        obj.type = 'air'
    end
	obj.Era = obj.Era

    obj.state = 'inhangar'
    obj.lastStateTime = timer.getAbsTime()
    obj.zoneCommander = {}
    obj.landsatcarrier = obj.type == 'carrier_air'
    obj.side = 0
    
    obj.urgent = obj.urgent or false

    setmetatable(obj, self)
    self.__index = self
    return obj
end
function GroupCommander:_applyHangarDelay(isInitial)
    local now = timer.getAbsTime()
    local urgent = type(self.urgent) == "function" and self.urgent() or self.urgent

    local delay = 0
    if urgent then
        if isInitial then
            delay = 20
        end
    else
        local variance = 25
        local maxSeconds = math.max(math.floor(variance * 60), 0)
        if maxSeconds > 0 then
            local minDelay = isInitial and 60 or 0
            if maxSeconds < minDelay then
                delay = maxSeconds
            else
                delay = math.random(minDelay, maxSeconds)
            end
        end
    end

    self.lastStateTime = now + delay
end

function GroupCommander:_removeFromSuspendedLiveFsm()
    local tracked = self.zoneCommander and self.zoneCommander._suspendedLiveFsm
    if tracked then
        tracked[self.name] = nil
        if not next(tracked) then
            self.zoneCommander._suspendedLiveFsm = nil
        end
    end
end

function GroupCommander:_destroyLogiCargo()
    local cargoByGroup = self._logiCargoByGroup
    if not cargoByGroup then return end

    local cname = cargoByGroup[self.name]
    if cname then
        local cargo = StaticObject.getByName(cname)
        if cargo and cargo:isExist() then cargo:destroy() end
        cargoByGroup[self.name] = nil
    end
end

function GroupCommander:_clearSupplyLaunchState(opts)
    opts = opts or {}
    if opts.keepPendingFarp ~= true then
        self._pendingSupplyFarpLaunch = nil
    end
    if opts.keepActiveFarp ~= true then
        self._activeSupplyLaunchSourceZone = nil
        self._activeSupplyFarpLaunch = nil
    end
    if opts.keepCtldFarpTakeoff ~= true then
        self._supplyCtldFarpTakeoff = nil
        self._supplyCtldFarpTakeoffCheckAt = nil
        self._supplyCtldFarpExistenceCheckAt = nil
    end
end

function GroupCommander:_resetAirPingState()
    self._zonePinged = nil
    self.pinged = false
end

function GroupCommander:_resetSupplyHeloToPreparing(originZone, opts)
    opts = opts or {}
    local now = opts.now or timer.getAbsTime()

    if opts.destroyCargo ~= false then
        self:_destroyLogiCargo()
    end

    self:_clearSupplyLaunchState(opts.clearLaunchState)
    if opts.pendingFarpLaunch then
        self._pendingSupplyFarpLaunch = opts.pendingFarpLaunch
    end
    if opts.retryNoCargo == true then
        self._supplyRetryNoCargo = true
    end
    if opts.skipBlockedHelo == true then
        self._supplyRetrySkipBlockedHelo = true
    end

    if opts.message ~= false then
        self._pendingSupplyLaunchMessage = opts.message or ('A friendly helicopter is scrambling from '..originZone..' to '..self.targetzone)
    end
    self.spawnedName = nil
    self.state = 'preparing'
    self.lastStateTime = now - 999999
    self:_resetAirPingState()
end

function GroupCommander:_enterHangar(isInitial)
	self:_removeFromSuspendedLiveFsm()
	self.state = 'inhangar'
	local bc = self.zoneCommander and self.zoneCommander.battleCommander or nil
	if bc then
		bc:_failPendingShopPurchase(self, "LOGISTICS_NO_AVAILABLE_PILOTS")
	end
	self._pendingSurfaceRestore = nil
    self._pendingRestoreHeloRoutePlan = nil
    self._pendingRestorePlaneRoutePlan = nil
    self._restoreSavedSide = nil
    self._restoreSupplyReturnHome = nil
    self._allowSuspendedShopSupplySpawn = nil
    self._sortieSide = nil
    self._paidSupplyParallelLaunch = nil
    self._shopLaunchRequested = nil
    self._supplyRetryNoCargo = nil
    self._supplyEarlyDeathRetried = nil
    self._supplyRetrySkipBlockedHelo = nil
    self:_clearSupplyLaunchState({ keepPendingFarp = true, keepActiveFarp = true })
    _surfaceIntelClearLastKnownMarker(self.name)
    self._surfaceIntelRouteToken = (self._surfaceIntelRouteToken or 0) + 1
    self._surfaceIntelRouteReportsSent = nil
    self._artilleryOnStation = nil
    self._artilleryReturnHome = nil
    self._surfaceIsArtillery = nil
    self._artilleryFireTargetZone = nil
    self._artilleryFireStartedAt = nil
    self._artilleryFiringIntelToken = (self._artilleryFiringIntelToken or 0) + 1
    self._artilleryFiringIntelScheduled = nil
    self._artilleryFiringIntelSent = nil
    self._artilleryStillFiringIntelSent = nil
    self._currentCapHoldingPoint = nil
    self._currentCapOrbitDistanceNm = nil
    self._currentCapBufferNm = nil
    self._capAssistRetaskedThisSortie = nil
    self._capAssistRetaskedTargetzone = nil
    self._capAssistCheckedOnAirborne = nil
    self._capAssistPendingTargetzone = nil
    self._capAssistPendingToken = nil
    self:_applyHangarDelay(isInitial)
end

function GroupCommander:_retirePlayerGroundAttack()
	local bc = self.zoneCommander.battleCommander
	_surfaceIntelClearLastKnownMarker(self.name)
	self._surfaceIntelRouteToken = (self._surfaceIntelRouteToken or 0) + 1
	self._surfaceIntelRouteReportsSent = nil
	local removed = bc:_dynamicHybridRemoveTrackedGroup(self.name)
	if removed then
		return
	end

	self._dynamicHybridRetired = true
	self._dynamicHybridRetiredAt = timer.getAbsTime()
	self:_removeFromSuspendedLiveFsm()
	self.state = 'dead'
	self.lastStateTime = timer.getAbsTime()
	bc:markFsmGroupFilterDirty()
	bc:markReindexCombatFilterDirty()
	bc:markSupplyCacheDirty()
end

function GroupCommander:_getSpawnAlias()
	if self._retasked then
		local tgt = tostring(self.targetzone or "none"):gsub("%s+", "_")
		return string.format("%s_retasked_%s", self.name, tgt)
	end
	return self.name
end

function GroupCommander:forceSpawnNow(targetZoneName)
	local oldTarget = self.targetzone

	if targetZoneName then
		self.targetzone = targetZoneName
	end

	if self._baseTargetzone == nil then
		self._baseTargetzone = oldTarget or self.targetzone
	end

	self._retasked = (self.targetzone ~= self._baseTargetzone)

	self.forceSpawn = true
	self.diceRolled = false
	self.Spawned = false
	self.state = 'preparing'
	self.lastStateTime = timer.getAbsTime() - 3600
	self:update()
	self.forceSpawn = nil
end

function GroupCommander:init()
    self.state = 'inhangar'
    if type(self.spawnDelayFactor)=='function' then self.spawnDelayFactor=self.spawnDelayFactor(self) end
    self:_applyHangarDelay(true)

	self._baseTargetzone = self._baseTargetzone or self.targetzone
	self._retasked = self._retasked or false

	local templateName = self.template or self.name
	self:_ensureTemplateCache()
	local list = self._tplAll
	local resolved = (#list>0) and nil or templateName

	if list and #list>0 then
		self._tplBySide = { [1]={}, [2]={} }
		local filtered = {}
		for i=1,#list do
			local tn = list[i]
			local gr = Group.getByName(tn)
			local tpl = _DATABASE.Templates.Groups[tn] or nil
			local hasTpl = tpl or gr
			if gr and hasTpl then
				local Side = ResolveTemplateSide(tn) or gr:getCoalition()
				if Side==1 then self._tplBySide[1][#self._tplBySide[1]+1]=tn elseif Side==2 then self._tplBySide[2][#self._tplBySide[2]+1]=tn end
				filtered[#filtered+1] = tn
				if self.side == 0 then self.side = Side end
				if not self.unitCategory then local u = gr:getUnit(1); if u then self.unitCategory = u:getDesc().category end end
				if (self.type == 'air' or self.type == 'carrier_air') then local us=gr:getUnits(); local cnt=us and #us or 0; if not self.AirCount or cnt>self.AirCount then self.AirCount=cnt end end
				if self.type ~= 'air' then local uu=gr:getUnit(1); local cat=uu and uu:getDesc().category or nil; if not (cat==Unit.Category.AIRPLANE or cat==Unit.Category.HELICOPTER) then gr:destroy() end end
			elseif hasTpl then
				local Side = ResolveTemplateSide(tn)
				if Side==1 then self._tplBySide[1][#self._tplBySide[1]+1]=tn elseif Side==2 then self._tplBySide[2][#self._tplBySide[2]+1]=tn end
				filtered[#filtered+1] = tn
				if self.side == 0 and Side then self.side = Side end
			else
				trigger.action.outText(L10N:Format("ZONE_ERROR_GROUP_TEMPLATE_MISSING", tostring(tn)), 30)
				env.info('ERROR: group ['..tostring(tn)..'] template missing')
			end
		end
		self._tplAll = filtered
		self:_updateTemplateSideSupport()
		if self.side == 0 and #filtered>0 then
			local gfirst = Group.getByName(filtered[1])
			if gfirst then self.side = gfirst:getCoalition() if self.type ~= 'air' then 
			local uu=gfirst:getUnit(1); local cat=uu and uu:getDesc().category or nil; if not (cat==Unit.Category.AIRPLANE or cat==Unit.Category.HELICOPTER) then gfirst:destroy() end end end

		end
        if self.side == 0 then
            trigger.action.outText(L10N:Format("ZONE_ERROR_DYNAMIC_SET_COALITION", templateName), 20)
            env.info('ERROR: could not resolve coalition for dynamic set ['..templateName..']')
        end
        self._tplCache = true
   else
        if not self.template then
            local gr = Group.getByName(self.name)
            if gr then
                self.side = gr:getCoalition()
                local u = gr:getUnit(1)
                if u then
                    local cat = u:getDesc().category
                    self.unitCategory = cat
                    if (self.type == 'air' or self.type == 'carrier_air') then local us=gr:getUnits(); self.AirCount=(us and #us) or 0 end
                else
                    env.info('ERROR: group ['..self.name..'] has no units')
                end
                if self.type ~= 'air' then local uu=gr:getUnit(1); local cat=uu and uu:getDesc().category or nil; if not (cat==Unit.Category.AIRPLANE or cat==Unit.Category.HELICOPTER) then gr:destroy() end end
            else
                trigger.action.outText(L10N:Format("ZONE_ERROR_GROUP_NOT_FOUND_MISSION", self.name), 60)
                env.info('ERROR: group ['..self.name..'] can not be found in the mission')
            end
        else
            trigger.action.outText(L10N:Format("ZONE_ERROR_TEMPLATE_NO_VALID_GROUPS", templateName), 60)
            env.info('ERROR: template ['..templateName..'] has no valid group entries')
        end
    end
end


function GroupCommander:_findFlatLZ(originZoneName, attempts, maxSlope)
    local zn = originZoneName and ZONE:FindByName(originZoneName)
    if not zn then return nil end
    attempts = attempts or 100
    maxSlope = maxSlope or 0.06
    for i=1,attempts do
        local c = zn:GetRandomCoordinate()
        if c then
            local v = c:GetVec3()
            local function H(x,z) return land.getHeight({x=x,y=z}) end
            local dx,dy = 8,8
            local hx1,hx2 = H(v.x+dx,v.z), H(v.x-dx,v.z)
            local hy1,hy2 = H(v.x,v.z+dy), H(v.x,v.z-dy)
            local sx = (hx1 - hx2)/(2*dx)
            local sy = (hy1 - hy2)/(2*dy)
            local slope = math.sqrt(sx*sx + sy*sy)
            if slope <= maxSlope then
                return { x = v.x, z = v.z }
            end
        end
    end
    return nil
end

function GroupCommander:_resolveParkingWithBelonging()
    if self.unitCategory ~= Unit.Category.AIRPLANE then return nil end
    local zc = self.zoneCommander
    local abName = zc and zc.airbaseName
    if not abName or abName=="" then return nil end
    local chain = { abName }
    local bel = (AirbaseBelonging and AirbaseBelonging[abName]) or nil
    if bel then for i=1,#bel do chain[#chain+1]=bel[i] end end
    local need = math.max(self.AirCount or 2, 1)
    local termType = self.terminalType or AIRBASE.TerminalType.OpenMedOrBig
    for ni=1,#chain do
        local candidateName = chain[ni]
        local candidateZone = nil
        local allowCandidate = true
        if ni > 1 then
            for _, zref in ipairs(bc:getZones() or {}) do
                local z = bc.indexedZones[zref.zone]
                if z and z.airbaseName == candidateName then
                    candidateZone = z
                    break
                end
            end
        end

        if ni > 1 and candidateZone then
            if candidateZone.side ~= self.side or candidateZone.active ~= true or candidateZone.suspended == true then
                allowCandidate = false
            end
        elseif ni > 1 then
            local dcsAirbase = getDcsAirbaseByName(candidateName)
            if dcsAirbase then
                if dcsAirbase.autoCaptureIsOn and dcsAirbase:autoCaptureIsOn() then
                    dcsAirbase:autoCapture(false)
                end
                dcsAirbase:setCoalition(self.side)
            end
        end

        if allowCandidate then
            local ab = getAirbaseByName(candidateName)
            local co = (ab and ab.GetCoalition) and ab:GetCoalition() or nil
            local sideOk = (self.side == 1 and co == coalition.side.RED) or (self.side == 2 and co == coalition.side.BLUE)
            if ab and ab:IsAirdrome() and sideOk then
                local free = (ab and ab.GetFreeParkingSpotsTable) and ab:GetFreeParkingSpotsTable(termType, false) or {}
                if type(free) ~= 'table' then free = {} end
                if #free >= need then
                    local ids = _pickCachedParkingIds(ab, termType, free, need)
                    return { kind='parking', airbase=ab, spots=ids }
                end
            end
        end
    end
    return nil
end

function GroupCommander:_assignPlaneRoute(grName, zoneName, altitude,ownZone, ownside,skipWarehouseAdjust)
    local gr = Group.getByName(grName); if not gr or not gr:isExist() or gr:getSize() == 0 then return false end
    local un = gr:getUnit(1); if not un or not un:isExist() then return false end
    local sp = un:getPoint()
    if not sp then
        env.info("[AirPersistence] _assignPlaneRoute missing point for "..tostring(grName))
        return nil
    end
    local group = GROUP:FindByName(grName); if not group or not group:IsAlive() then return false end
    local plan = self._pendingRestorePlaneRoutePlan
    if not plan or plan.zoneName ~= zoneName then
        plan = self:_resolvePlaneRoutePlan(zoneName, sp.x, sp.z, altitude)
    end
    self._pendingRestorePlaneRoutePlan = nil
    if not plan then return nil end

    local wp = {}
    wp[#wp+1] = { type=AI.Task.WaypointType.TAKEOFF, x=sp.x, y=sp.z, speed=0, action=AI.Task.TurnMethod.FIN_POINT, alt=0, alt_type=AI.Task.AltitudeType.RADIO }
    wp[#wp+1] = COORDINATE:New(plan.apx, plan.cruiseAlt, plan.apy):WaypointAirTurningPoint(UTILS.MpsToKmph(50), plan.cruiseAlt, AI.Task.AltitudeType.BARO, "Approach")
    wp[#wp+1] = plan.airbase:GetCoordinate():WaypointAirLanding(UTILS.MpsToKmph(50), plan.airbase, {}, "RTB Land (Airbase)")
    group:Route(wp, 1)
	if not skipWarehouseAdjust then
		self:_adjustWarehouseStock(ownZone, -50)
	end
	if self._pendingSupplyLaunchMessage then
		trigger.action.outTextForCoalition(2, self._pendingSupplyLaunchMessage, 10)
		self._pendingSupplyLaunchMessage = nil
	end
	self.zoneCommander.battleCommander:_completePendingShopPurchase(self)
	return true
end

local function _buildMooseWaypointAirLike(coord, altType, wpType, wpAction, speedKmh, speedLocked, airbase, dcsTasks, description, timeReFuAr)
	altType = altType or "RADIO"
	if speedLocked == nil then speedLocked = true end
	speedKmh = speedKmh or 500

	local RoutePoint = {}
	RoutePoint.x = coord.x
	RoutePoint.y = coord.z
	RoutePoint.alt = coord.y
	RoutePoint.alt_type = altType
	RoutePoint.type = wpType
	RoutePoint.action = wpAction
	RoutePoint.speed = speedKmh / 3.6
	RoutePoint.speed_locked = speedLocked
	RoutePoint.ETA = 0
	RoutePoint.ETA_locked = false
	RoutePoint.name = description

	if airbase then
		local AirbaseID = airbase:GetID()
		local AirbaseCategory = airbase:GetAirbaseCategory()
		if AirbaseCategory == Airbase.Category.SHIP or AirbaseCategory == Airbase.Category.HELIPAD then
			RoutePoint.linkUnit = AirbaseID
			RoutePoint.helipadId = AirbaseID
			RoutePoint.airdromeId = airbase:IsAirdrome() and AirbaseID or nil
		elseif AirbaseCategory == Airbase.Category.AIRDROME then
			RoutePoint.airdromeId = AirbaseID
		else
			env.info("[Route] ERROR: Unknown airbase category in _buildMooseWaypointAirLike")
		end
	end

	if wpType == "LandingReFuAr" then
		RoutePoint.timeReFuAr = timeReFuAr or 10
	end

	RoutePoint.task = { id = "ComboTask", params = { tasks = dcsTasks or {} } }
	return RoutePoint
end

-- Small MOOSE-style helper: build a DCS CargoTransportation task that can be placed into a waypoint ComboTask.
-- This allows doing helo logistics with GROUP:Route() without using AUFTRAG.
function COORDINATE:TaskCargoTransportation(cargoGroupId, dropZoneId)
	return { number = 1, auto = false, id = 'CargoTransportation', params = { groupId = cargoGroupId, zoneId = dropZoneId } }
end


function GroupCommander:_assignHeloLogisticsRoute(groupName, targetZoneName, ownZone, side, farpLaunch)
	local staticType = "container_cargo"
	local staticCategory = "Cargos"
	local cargoMassKg = 600
	local cargoCountryId = side == 1 and country.id.RUSSIA or country.id.USA

	local gr = Group.getByName(groupName); if not gr then env.info("No group found for name " .. groupName) return false end
	local c = gr:getController(); if not c then env.info("No controller found for group " .. groupName) return false end
	local un = gr:getUnit(1); if not un then env.info("No unit found for group " .. groupName) return false end
	local pos = un:getPoint()
	local destx, desty
	local landingPickName = nil
	local useAirbase = false
	local pickName, dropZone, dropx, dropy

	-- Old random cargo-drop block. Re-enable this and remove the warmed landing-nearest block below if needed.
--[[ 	local sub = collectSubZones(targetZoneName)
	pickName = (#sub > 0) and sub[math.random(#sub)] or targetZoneName
	dropZone = getMooseZone(pickName)
	if not dropZone or not dropZone.ZoneID then return nil end
	local fz = getTriggerZone(pickName)
	if not fz or not fz.point then return nil end
	dropx, dropy = fz.point.x, fz.point.z ]]


	local spawnCoord = nil
	if farpLaunch and farpLaunch.x and farpLaunch.z then
		local bc = self.zoneCommander.battleCommander
		bc._farpCargoSpawnState = bc._farpCargoSpawnState or {}
		local farpCargoArc = {
			{ distance = 115, bearing = 300 },
			{ distance = 115, bearing = 270 },
			{ distance = 115, bearing = 240 },
			{ distance = 115, bearing = 210 },
			{ distance = 115, bearing = 180 },
			{ distance = 115, bearing = 150 },
		}
		local farpCargoState = bc._farpCargoSpawnState[farpLaunch.name] or { index = 0 }
		farpCargoState.index = ((tonumber(farpCargoState.index) or 0) % #farpCargoArc) + 1
		farpCargoState.time = timer.getAbsTime()
		bc._farpCargoSpawnState[farpLaunch.name] = farpCargoState

		local farpCoord = COORDINATE:New(farpLaunch.x, land.getHeight({ x = farpLaunch.x, y = farpLaunch.z }), farpLaunch.z)
		local cargoOffset = farpCargoArc[farpCargoState.index]
		local cargoCoord = farpCoord:Translate(cargoOffset.distance, cargoOffset.bearing)
		spawnCoord = COORDINATE:New(cargoCoord.x, land.getHeight({ x = cargoCoord.x, y = cargoCoord.z }), cargoCoord.z)
	end
	if not spawnCoord then
		local prefix = ownZone and (ownZone .. "-land") or nil
		local pooledLand = prefix and _getLandingSpotPoolForPrefix(prefix) or nil
		if ownZone and (not pooledLand or #pooledLand == 0) then
			pooledLand = _getForcedLandingSpotPool(ownZone)
		end
		local lastSpawn = self._lastGroundSpawnSpot and self._lastGroundSpawnSpot.zone or nil
		if pooledLand and #pooledLand > 0 then
			local pick = _pickRandomLandingSpot(pooledLand, lastSpawn)
			if pick then
				spawnCoord = COORDINATE:New(pick.x, 0, pick.z)
			end
		else
			local unitType = un and un.getTypeName and un:getTypeName() or nil
			local caps =  CTLD.UnitTypeCapabilities and unitType and CTLD.UnitTypeCapabilities[unitType] or nil
			local spawnDist = ((caps and caps.length) or 20) + 2
			local heading = un and un.getHeading and un:getHeading() or 0
			local azDeg = math.deg(heading)
			spawnCoord = COORDINATE:New(pos.x, pos.y, pos.z):Translate(spawnDist, azDeg)
		end
	end
	if not spawnCoord then
		local heading = un and un.getHeading and un:getHeading() or 0
		local azDeg = math.deg(heading)
		spawnCoord = COORDINATE:New(pos.x, pos.y, pos.z):Translate(20, azDeg)
	end

	local tag = self.name .. "_LOGI"
	local cargoName = string.format("%s_CARGO_%d", tostring(tag), math.random(100000,999999))
	
	--local sp = SPAWNSTATIC:NewFromStatic("AI Cargo", cargoCountryId)
	
	local sp = SPAWNSTATIC:NewFromType(staticType, staticCategory, cargoCountryId)
	sp:InitCoordinate(spawnCoord)
	sp:InitCargo(true)
	sp:InitCargoMass(cargoMassKg)
	local cargo = sp:Spawn(0, cargoName)
	if not cargo then return nil end
	self._logiCargoByGroup = self._logiCargoByGroup or {}
	self._logiCargoByGroup[self.name] = cargoName
	if AIDeliveryamount == nil then AIDeliveryamount = 20 end
	if AIDeliveryamount > 0 then
	self:_adjustWarehouseStock(ownZone, -AIDeliveryamount)
	end

	local prefix2 = targetZoneName and (targetZoneName .. "-land") or nil
	local pooledLand2 = prefix2 and _getLandingSpotPoolForPrefix(prefix2) or nil
	if pooledLand2 and #pooledLand2 > 0 then
		local pick = pooledLand2[math.random(#pooledLand2)]
		env.info('Landing spot for ' .. targetZoneName .. ' found, picking')
		destx, desty = pick.x, pick.z
		landingPickName = pick.name
	end

	if not destx then
		local pooledForced = _getForcedLandingSpotPool(targetZoneName)
		if pooledForced and #pooledForced > 0 then
			local pick = pooledForced[math.random(#pooledForced)]
			destx, desty = pick.x, pick.z
			landingPickName = pick.name
		end
	end

	if not destx then
		local tz = self.zoneCommander.battleCommander:getZoneByName(targetZoneName)
		local abn = tz and tz.airbaseName
		if abn then
			local ab = AIRBASE:FindByName(abn)
			if ab and ab:GetCoalition()==gr:getCoalition() then
				useAirbase = true
			end
		end
	end

	if not destx and not useAirbase then
		local lz = self:_findFlatLZ(targetZoneName.."-", 200, math.tan(math.rad(12)))
		if not lz then lz = self:_findFlatLZ(targetZoneName, 200, math.tan(math.rad(12))) end
		if lz then destx, desty = lz.x, lz.z end
	end
	if not destx and not useAirbase then return nil end

	if useAirbase then
		local tz = self.zoneCommander.battleCommander:getZoneByName(targetZoneName)
		local abn = tz and tz.airbaseName
		local airb = abn and AIRBASE:FindByName(abn) or nil
		if airb and airb.GetCoordinate then
			local cc = airb:GetCoordinate(); if cc and cc.GetVec2 then local v=cc:GetVec2(); destx, desty = v.x, v.y end
		end
	end
	if not destx or not desty then return nil end

	-- New warmed cargo-drop block. Picks one of the closest two valid drop subzones to the selected landing point.
	pickName = _selectCargoDropSubZoneForLanding(targetZoneName, landingPickName, destx, desty)
	dropZone = getMooseZone(pickName)
	if not dropZone or not dropZone.ZoneID then
		pickName = targetZoneName
		dropZone = getMooseZone(pickName)
	end
	if not dropZone or not dropZone.ZoneID then return nil end

	local fz = getTriggerZone(pickName)
	if not fz or not fz.point then return nil end
	dropx, dropy = fz.point.x, fz.point.z

	local kmh = 289
	local spd = kmh / 3.6
	local alt = UTILS.FeetToMeters(1500)
	local alt2 = UTILS.FeetToMeters(500)

	-- Use MOOSE route engine end-to-end (this also gives the 1s delayed SetTask that Route(...,1) uses).
	local gmoose = GROUP:FindByName(groupName)
	if not gmoose or not gmoose:IsAlive() then return false end

	local route = {}
	-- WP1 at cargo location: execute CargoTransportation (pick up here, deliver to dropZone.ZoneID).
	local cargoTask = COORDINATE:TaskCargoTransportation(cargo:GetID(), dropZone.ZoneID)
	local pickupCoord = COORDINATE:New(spawnCoord.x, spawnCoord.y, spawnCoord.z):SetAltitude(alt)
	route[#route + 1] = pickupCoord:WaypointAirTurningPoint("RADIO", kmh, { cargoTask }, "Cargo")

	-- WP2 at drop point, low enough to start landing without climbing again.
	route[#route + 1] = COORDINATE:New(dropx, alt2, dropy):WaypointAirTurningPoint("RADIO", kmh)

	-- WP3 landing: if airbase, pin to airbase; else land at coordinate.
	if useAirbase then
		local tz = self.zoneCommander.battleCommander:getZoneByName(targetZoneName)
		local abn = tz and tz.airbaseName
		local airb = abn and AIRBASE:FindByName(abn) or nil
		if not airb then return end
		route[#route + 1] = airb:GetCoordinate():WaypointAirLanding(kmh, airb, {}, "Landing")
	else
		local landTask = gmoose:TaskLandAtVec2({ x = destx, y = desty }, 20, side == 2, nil)
		route[#route + 1] = COORDINATE:New(dropx, alt2, dropy):WaypointAirTurningPoint("RADIO", kmh, { landTask }, "Landing")
	end
	gmoose:Route(route, 1)
	if side == 1 and c then
		c:setOption(AI.Option.Air.id.REACTION_ON_THREAT, AI.Option.Air.val.REACTION_ON_THREAT.ALLOW_ABORT_MISSION)
	end
	if self._pendingSupplyLaunchMessage then
		trigger.action.outTextForCoalition(2, self._pendingSupplyLaunchMessage, 10)
		self._pendingSupplyLaunchMessage = nil
	end
	self.zoneCommander.battleCommander:_completePendingShopPurchase(self)
	return true
end

function ManualAdjustWarehouse(zoneName, deltaPerItem)
    if type(zoneName) ~= "string" then
        env.info("[ManualAdjustWarehouse] Missing zone name")
        return
    end
    local proxy = setmetatable({
        name = "ManualAdjust",
        side = 2,
        zoneCommander = { battleCommander = bc },
    }, { __index = GroupCommander })

    proxy:_adjustWarehouseStock(zoneName, deltaPerItem)
end

-- Example:
-- ManualAdjustWarehouse("Naumburg FARP", -10)

function GroupCommander:_adjustWarehouseStock(zoneName, deltaPerItem)
	if WarehouseLogistics ~= true then return end
	if type(deltaPerItem) ~= "number" or deltaPerItem == 0 then return end
	if not zoneName then return end
	if self.side ~= 2 then return end

	local originZone = self.zoneCommander.battleCommander:getZoneByName(zoneName) or zoneName
	local abName = originZone and originZone.airbaseName or zoneName
	if not abName then return end

	local storage = STORAGE:FindByName(abName)
	if not storage then return end

	local items = WEAPONSLIST.GetAllItems() or {}
	local forbiddenWeaponsInAllEraSet = {}
	for _, forbiddenWeapon in ipairs(ForbiddWeaponsInAllEra or {}) do
		forbiddenWeaponsInAllEraSet[forbiddenWeapon] = true
	end

	for _, item in ipairs(items) do
		if not forbiddenWeaponsInAllEraSet[item] then
			local current = 0
			local amt = storage:GetItemAmount(item)
			if type(amt) == "number" then
				current = amt
			end
			local target = current + deltaPerItem
			if target < 0 then target = 0 end
			pcall(function() storage:SetItem(item, target) end)
		end
	end
	env.info(string.format("Group [%s] adjusted warehouse [%s] by %+d per item (zone=%s)", tostring(self.name), tostring(abName), deltaPerItem, tostring(zoneName)))
end

function GroupCommander:_resolveHeloRoutePlan(zoneName, fromX, fromZ, coalitionSide)
	local plan = { zoneName = zoneName, spd = 79, useAirbase = false, airbase = nil, destx = nil, desty = nil, apx = nil, apy = nil, back = nil }
	local destx, desty
	local useAirbase = false

	local prefix = zoneName and (zoneName .. "-land") or nil
	local pooledLand = prefix and _getLandingSpotPoolForPrefix(prefix) or nil
	if pooledLand and #pooledLand > 0 then
		local pick = pooledLand[math.random(#pooledLand)]
		destx, desty = pick.x, pick.z
	end

	if not destx then
		local pooledForced = _getForcedLandingSpotPool(zoneName)
		if pooledForced and #pooledForced > 0 then
			local pick = pooledForced[math.random(#pooledForced)]
			destx, desty = pick.x, pick.z
		end
	end

	local tz = self.zoneCommander.battleCommander:getZoneByName(zoneName)
	local abn = tz and tz.airbaseName
	local airb = abn and AIRBASE:FindByName(abn) or nil
	if not destx and airb and airb:GetCoalition() == coalitionSide then
		useAirbase = true
	end

	if not destx and not useAirbase then
		local lz = self:_findFlatLZ(zoneName.."-", 200, math.tan(math.rad(15)))
		if not lz then lz = self:_findFlatLZ(zoneName, 200, math.tan(math.rad(15))) end
		if lz then destx, desty = lz.x, lz.z end
	end
	if not destx and not useAirbase then return nil end

	if useAirbase then
		local tvx, tvy = destx, desty
		if (not tvx or not tvy) and airb and airb.GetCoordinate then
			local coord = airb:GetCoordinate()
			if coord and coord.GetVec2 then
				local v = coord:GetVec2()
				tvx, tvy = v.x, v.y
			end
		end
		destx, desty = tvx or fromX, tvy or fromZ
		plan.useAirbase = true
		plan.airbase = airb
		plan.back = 3 * 1852
	else
		plan.back = 2 * 1852
	end

	local dx, dz = destx - fromX, desty - fromZ
	local L = math.sqrt(dx * dx + dz * dz)
	local apx = (L > 10) and (destx - dx / L * plan.back) or destx
	local apy = (L > 10) and (desty - dz / L * plan.back) or desty

	plan.destx = destx
	plan.desty = desty
	plan.apx = apx
	plan.apy = apy
	return plan
end

function GroupCommander:_resolvePlaneRoutePlan(zoneName, fromX, fromZ, altitude)
	local tz = self.zoneCommander.battleCommander:getZoneByName(zoneName); if not tz then return nil end
	local abn = tz.airbaseName; if not abn then return nil end
	local ab = getAirbaseByName(abn)
	if ab and ab:GetCoalition() ~= tz.side then
		ab:SetCoalition(0)
	end
	if not ab then return nil end

	local abC = ab:GetCoordinate()
	local abV = abC:GetVec2()
	local cruiseAlt = altitude or UTILS.FeetToMeters(10000)
	local back = 20 * 1852
	local dx, dz = fromX - abV.x, fromZ - abV.y
	local L = math.sqrt(dx * dx + dz * dz)
	local apx = (L > 10) and (abV.x + dx / L * back) or abV.x
	local apy = (L > 10) and (abV.y + dz / L * back) or abV.y

	return {
		zoneName = zoneName,
		airbase = ab,
		cruiseAlt = cruiseAlt,
		destx = abV.x,
		desty = abV.y,
		apx = apx,
		apy = apy,
		back = back
	}
end

function GroupCommander:_getRestoreHeloSupplySpawnPoint(savedX, savedZ, zoneName, approachX, approachZ)
	local plan = self:_resolveHeloRoutePlan(zoneName, approachX or savedX, approachZ or savedZ, self.side)
	if not plan then return savedX, savedZ end
	self._pendingRestoreHeloRoutePlan = plan

	local dx, dz = plan.destx - savedX, plan.desty - savedZ
	local L = math.sqrt(dx * dx + dz * dz)
	if L <= plan.back and L > 10 then
		local ax, az = plan.apx - plan.destx, plan.apy - plan.desty
		local AL = math.sqrt(ax * ax + az * az)
		local ux, uz = (AL > 10) and (ax / AL) or (-dx / L), (AL > 10) and (az / AL) or (-dz / L)
		local spawnBack = plan.back + (1 * 1852)
		return plan.destx + ux * spawnBack, plan.desty + uz * spawnBack
	end

	return savedX, savedZ
end

function GroupCommander:_getRestorePlaneSupplySpawnPoint(savedX, savedZ, zoneName, altitude, approachX, approachZ)
	local plan = self:_resolvePlaneRoutePlan(zoneName, approachX or savedX, approachZ or savedZ, altitude)
	if not plan then return savedX, savedZ, nil end
	self._pendingRestorePlaneRoutePlan = plan

	local dx, dz = plan.destx - savedX, plan.desty - savedZ
	local L = math.sqrt(dx * dx + dz * dz)
	if L <= plan.back and L > 10 then
		local ax, az = plan.apx - plan.destx, plan.apy - plan.desty
		local AL = math.sqrt(ax * ax + az * az)
		local ux, uz = (AL > 10) and (ax / AL) or (-dx / L), (AL > 10) and (az / AL) or (-dz / L)
		local spawnBack = plan.back + (1 * 1852)
		local spawnX = plan.destx + ux * spawnBack
		local spawnZ = plan.desty + uz * spawnBack
		local groundY = land.getHeight({ x = spawnX, y = spawnZ })
		local restoreAlt = groundY + UTILS.FeetToMeters(6000)
		plan.cruiseAlt = restoreAlt
		return spawnX, spawnZ, restoreAlt
	end

	return savedX, savedZ, nil
end

function GroupCommander:_assignHeloRoute(grName, zoneName)
    local gr = Group.getByName(grName); if not gr then env.info("No group found for name " .. grName) return false end
    local c = gr:getController(); if not c then env.info("No controller found for group " .. grName) return false end
    local un = gr:getUnit(1); if not un then env.info("No unit found for group " .. grName) return false end
    local pos = un:getPoint()
    local plan = self._pendingRestoreHeloRoutePlan
    if not plan or plan.zoneName ~= zoneName then
        plan = self:_resolveHeloRoutePlan(zoneName, pos.x, pos.z, gr:getCoalition())
    end
    self._pendingRestoreHeloRoutePlan = nil
    if not plan then return nil end

    local spd = plan.spd
    if plan.useAirbase then
        local gmoose = GROUP:FindByName(grName); if not gmoose or not gmoose:IsAlive() then return false end
        local kmh = math.floor((spd or 280) * 3.6)

        local route = {}
        route[#route+1] = COORDINATE:New(plan.apx, UTILS.FeetToMeters(1500), plan.apy):WaypointAirFlyOverPoint("RADIO", kmh)
        route[#route+1] = COORDINATE:New(plan.destx, 0, plan.desty):WaypointAirLanding(kmh, plan.airbase)

        gmoose:Route(route, 1)
    else
        local gmoose = GROUP:FindByName(grName); if not gmoose or not gmoose:IsAlive() then return false end
        local kmh = math.floor((spd or 280) * 3.6)
        local alt = UTILS.FeetToMeters(1000)
        local alt2 = UTILS.FeetToMeters(500)
        local landTask = gmoose:TaskLandAtVec2({ x = plan.destx, y = plan.desty }, 20, self.side == 2, nil)

        local route = {}
        route[#route + 1] = COORDINATE:New(pos.x, pos.y, pos.z):SetAltitude(alt):WaypointAirTurningPoint("RADIO", kmh, {}, "Current")
        route[#route + 1] = COORDINATE:New(plan.apx, alt, plan.apy):WaypointAirTurningPoint("RADIO", kmh)
        route[#route + 1] = COORDINATE:New(plan.apx, alt2, plan.apy):WaypointAirTurningPoint("RADIO", kmh, { landTask }, "Landing")

        gmoose:Route(route, 1)
    end
	if self._pendingSupplyLaunchMessage then
		trigger.action.outTextForCoalition(2, self._pendingSupplyLaunchMessage, 10)
		self._pendingSupplyLaunchMessage = nil
	end
	self.zoneCommander.battleCommander:_completePendingShopPurchase(self)
	return true
end


function BattleCommander:abortSupplyToOpposite(zoneName, newSide)
	for _, oz in ipairs(self.zones) do
		for _, gc in ipairs(oz:_getSupplyCache() or {}) do
			if gc
				and gc.mission == 'supply'
				and gc.targetzone == zoneName
				and (newSide == 0 or gc.side ~= newSide)
			then
				if gc.unitCategory == Unit.Category.HELICOPTER or gc.unitCategory == Unit.Category.AIRPLANE then
					if gc.state == 'inair' then
						gc._supplyReturnHome = true
						if gc.unitCategory == Unit.Category.HELICOPTER then
							gc:_assignHeloRoute(gc.name, gc.zoneCommander.zone)
						else
							gc:_assignPlaneRoute(gc.name, gc.zoneCommander.zone, gc.Altitude, gc.zoneCommander.zone, gc.side, true)
						end
					elseif gc.state == 'takeoff' then
						local g = Group.getByName(gc.name)
						if g then g:destroy() end
						gc._supplyReturnHome = nil
						gc:_enterHangar(false)
					end
				elseif gc.type == 'surface' and gc.state == 'enroute' then
					local liveGroup = gc:_getDcsGroupCached()
					local lead = liveGroup and liveGroup:isExist() and liveGroup:getSize() > 0 and liveGroup:getUnit(1) or nil
					local pos = lead and lead:isExist() and lead:getPoint() or nil
					local ctrl = liveGroup and liveGroup:isExist() and liveGroup:getController() or nil
					if pos and ctrl then
						local task = select(1, dc.BuildSupplyConvoyRouteFromPoint({ x = pos.x, y = pos.z }, gc.zoneCommander.zone, dc.DEFAULT_SPEED))
						if task then
							gc._supplyReturnHome = true
							ctrl:popTask()
							SCHEDULER:New(nil, function()
								local freshGroup = gc:_getDcsGroupCached()
								if not freshGroup or not freshGroup:isExist() then return end
								local freshCtrl = freshGroup:getController()
								if not freshCtrl then return end
								freshCtrl:pushTask(task)
							end, {}, 1)
						end
					end
				end
			end
		end
	end
end


function GroupCommander:_ensureTemplateCache()
	if self._tplCache then return end
	local templateKey = self.template or self.name
	local set = nil
	local gset = _G[templateKey]
	if type(gset)=="table" and #gset>0 and type(gset[1])=="string" then
		set = gset
	elseif dc and dc.SETS then
		local dset = dc.SETS[templateKey]
		if type(dset)=="table" and #dset>0 and type(dset[1])=="string" then
			set = dset
		end
	end
	self._tplAll = set or {}
	self._tplBySide = { [1]={}, [2]={} }
	self._tplUnitTypeByName = {}
	if set and #set>0 then
		for i=1,#set do
			local tn = set[i]
			self._tplUnitTypeByName[tn] = GetTemplateFirstUnitTypeName(tn) or false
			local cnum = ResolveTemplateSide(tn)
			if cnum==1 then self._tplBySide[1][#self._tplBySide[1]+1]=tn elseif cnum==2 then self._tplBySide[2][#self._tplBySide[2]+1]=tn end
		end
	elseif self.template then
		self._tplUnitTypeByName[templateKey] = GetTemplateFirstUnitTypeName(templateKey) or false
		local cnum = ResolveTemplateSide(templateKey)
		if cnum==1 then self._tplBySide[1][#self._tplBySide[1]+1]=templateKey elseif cnum==2 then self._tplBySide[2][#self._tplBySide[2]+1]=templateKey end
	end
	self:_updateTemplateSideSupport()
	self._tplCache = true
end

function GroupCommander:_updateTemplateSideSupport()
	local bySide = self._tplBySide or {}
	self._tplHasSide = {
		[1] = (type(bySide[1])=="table" and #bySide[1] > 0) and true or false,
		[2] = (type(bySide[2])=="table" and #bySide[2] > 0) and true or false,
	}
end

function GroupCommander:_templateSupportsSide(side)
	if side ~= 1 and side ~= 2 then return true end
	if not self.template then return true end
	self:_ensureTemplateCache()
	if not self._tplHasSide then
		self:_updateTemplateSideSupport()
	end
	return self._tplHasSide[side] == true
end

function GroupCommander:_getTemplateUnitTypeName(templateName)
	if not templateName then return nil end
	self._tplUnitTypeByName = self._tplUnitTypeByName or {}
	if self._tplUnitTypeByName[templateName] ~= nil then
		return self._tplUnitTypeByName[templateName] or nil
	end
	local typeName = GetTemplateFirstUnitTypeName(templateName)
	self._tplUnitTypeByName[templateName] = typeName or false
	return typeName
end

function GroupCommander:_isCtldFarpBlockedHeloTemplate(templateName)
	local typeName = self:_getTemplateUnitTypeName(templateName)
	return typeName and CtldFarpBlockedHeloTypes[typeName] == true or false
end

function GroupCommander:_resolveCtldFarpTemplateName()
	self:_ensureTemplateCache()
	if not self.template then
		if self:_isCtldFarpBlockedHeloTemplate(self.name) then
			return nil, self.name
		end
		return self.name, nil
	end

	local side = self.side
	if side ~= 0 then
		local list = self._tplBySide[side]
		if list and #list > 0 then
			local allowed = {}
			local blocked = nil
			for i = 1, #list do
				local templateName = list[i]
				if self:_isCtldFarpBlockedHeloTemplate(templateName) then
					blocked = blocked or templateName
				else
					allowed[#allowed + 1] = templateName
				end
			end
			if #allowed > 0 then
				return allowed[math.random(1, #allowed)], blocked
			end
			return nil, blocked
		end
	end
	return nil, nil
end

function GroupCommander:_isGroupInCtldFarpLaunchZone(gr, farpLaunch)
	if not gr or not gr:isExist() or not farpLaunch then return false end
	local farpZone = farpLaunch.name and getMooseZone(farpLaunch.name) or nil
	local units = gr:getUnits() or {}
	if farpZone then
		for _, unit in ipairs(units) do
			if unit and unit:isExist() and farpZone:IsVec3InZone(unit:getPoint()) then
				return true
			end
		end
	end
	if farpLaunch.x and farpLaunch.z then
		local farpRadiusMeters = 120
		for _, unit in ipairs(units) do
			local pos = unit and unit:isExist() and unit:getPoint() or nil
			if pos then
				local dx = pos.x - farpLaunch.x
				local dz = pos.z - farpLaunch.z
				if (dx * dx + dz * dz) <= (farpRadiusMeters * farpRadiusMeters) then
					return true
				end
			end
		end
	end
	return false
end


function GroupCommander:_getTemplateSet(templateKey)
	local g = _G[templateKey]
	if type(g) == "table" and #g>0 and type(g[1])=="string" then return g end
	if dc and dc.SETS then
		local s = dc.SETS[templateKey]
		if type(s) == "table" and #s>0 and type(s[1])=="string" then return s end
	end
	return nil
end

function GroupCommander:_resolveTemplateName()
	self:_ensureTemplateCache()
	if not self.template then return self.name end
	local side = self.side
	if side~=0 then
		local list = self._tplBySide[side]
		if list and #list>0 then return list[math.random(1,#list)] else return nil end
	end
	return nil
end

function GroupCommander:_resolveSpawn()
    local zc = self.zoneCommander
    local abName = zc.airbaseName
    if type(abName) == "table" then
        abName = abName[zc.side]
    end
    local need = self.AirCount
    local termType = self.terminalType or AIRBASE.TerminalType.OpenMedOrBig
    local helipadId

    -- if abName then
	-- 	local ab = AIRBASE:FindByName(abName)

    if abName and not abName:find("^H%s*FRG") and not abName:find("^H%s*GDR") then
        local ab = AIRBASE:FindByName(abName)
        if ab then
            if self.unitCategory == Unit.Category.AIRPLANE and not (ab:IsAirdrome() or ab:IsShip()) then
                ab = nil
            end
            if self.unitCategory == Unit.Category.HELICOPTER and not (ab:IsAirdrome() or ab:IsHelipad() or ab:IsShip()) then
                ab = nil
            end
            if ab then
                if self.unitCategory == Unit.Category.HELICOPTER and (ab:IsHelipad() or ab:IsShip()) and ab.GetID then
                    helipadId = ab:GetID()
                end
				if ab.IsShip and ab:IsShip() and not IsGroupActive(ab:GetName()) then
                    return nil
                end
                local ttype = (self.unitCategory == Unit.Category.HELICOPTER) and AIRBASE.TerminalType.HelicopterUsable or termType
                local free = ab:GetFreeParkingSpotsTable(ttype, false)
                if #free < need then
                    local free2 = ab:GetFreeParkingSpotsTable(ttype, true)
                    if #free2 > #free then free = free2 end
                end
                if #free >= need then
                    local ids = _pickCachedParkingIds(ab, ttype, free, need)
                    return { kind='parking', airbase=ab, spots=ids, helipadId=helipadId, airbaseId=(ab and ab.GetID) and ab:GetID() or nil, isShip=(ab and ab.IsShip and ab:IsShip()) or false }
                end
            end
        end
    end
    return nil
end

