			return 3
		elseif numPlayers <= 9 then
			return 4
		else
			return 5
		end
	else
		if numPlayers <= 1 then
			return 1
		elseif numPlayers <= 3 then
			return 2
		elseif numPlayers == 4 then
			return 3
		else
			return 4
		end
	end
end

function getRedAntiShipLimit(numPlayers)
	numPlayers = numPlayers or getRedCasPlayersCount()
	local diff = string.lower(tostring(AntiShipDifficulty or CasSeadDifficulty or 'medium'))
	local stagesByDiff = RedAntiShipLimitStages or RedCasLimitStages
	local stages = stagesByDiff and (stagesByDiff[diff] or stagesByDiff.medium or stagesByDiff.easy or stagesByDiff.hard)
	if stages then
		local v = _limitFromStages(numPlayers, stages)
		if v ~= nil then return v end
	end
	if diff == 'easy' then
		if numPlayers == 0 then
			return 0
		elseif numPlayers <= 2 then
			return 1
		elseif numPlayers <= 4 then
			return 2
		else
			return 3
		end
	elseif diff == 'hard' then
		if numPlayers == 0 then
			return 1
		elseif numPlayers <= 2 then
			return 2
		elseif numPlayers == 3 then
			return 3
		elseif numPlayers <= 9 then
			return 4
		else
			return 5
		end
	else
		if numPlayers <= 1 then
			return 1
		elseif numPlayers <= 3 then
			return 2
		elseif numPlayers == 4 then
			return 3
		else
			return 4
		end
	end
end

function getBlueCapLimit(numPlayers)
    numPlayers = numPlayers or getBluePlayersCount()
	local diff = string.lower(tostring(FriendlyCapSupport or 'medium'))
	local stagesByDiff = BlueCapSupportStages
	local stages = stagesByDiff and (stagesByDiff[diff] or stagesByDiff.medium or stagesByDiff.easy or stagesByDiff.hard)
	if stages then
		local v = _limitFromStages(numPlayers, stages)
		if v ~= nil then return v end
	end
    if diff == 'easy' then
        if numPlayers <= 0 then
            return 2
        elseif numPlayers == 1 then
            return 2
        else
            return 1
        end
    elseif diff == 'hard' then
        return 0
    else
        if numPlayers <= 0 then
            return 1
        elseif numPlayers == 1 then
            return 1
        else
            return 0
        end
    end
end

