function BattleCommander:buildNonCapSpawnBuckets()
	self._activeSupplyCount = { [1]={}, [2]={} }
	self._activeCasSeadCount = { [1]={_all=0}, [2]={_all=0} }
	self._activeStrikeCount = { [1]={}, [2]={} }
	self._nonCapBucketsBuilt = true
	for _,zc in ipairs(self.zones) do
		for _,gc in ipairs(zc.groups or {}) do
			if gc then
				gc._nonCapSupplySide=nil
				gc._nonCapSupplyZone=nil
				gc._nonCapCasSeadSide=nil
				gc._nonCapCasSeadMission=nil
				gc._nonCapStrikeSide=nil
				gc._nonCapStrikeMission=nil
				gc._nonCapStrikeRole=nil
				gc._nonCapStrikeUnitCategory=nil
				self:_syncNonCapSpawnBucketsForGroup(gc)
			end
		end
	end
end

function BattleCommander:buildCapActiveBuckets()
	self._activeCapCount = {
		[1] = { _all = 0, patrol = 0, attack = 0 },
		[2] = { _all = 0, patrol = 0, attack = 0 }
	}
	self._airborneBlueCapByName = {}
	self._airborneBluePatrolByTargetzone = {}
	self._hasAirborneBlueCap = false
	self._capAssistPendingByTargetzone = self._capAssistPendingByTargetzone or {}
	self._capAssistCooldownByTargetzone = self._capAssistCooldownByTargetzone or {}
	self._capBucketsBuilt = true
	for _,zc in ipairs(self.zones) do
		for _,gc in ipairs(zc.groups or {}) do
			if gc then
				gc._capActiveSide = nil
				gc._capActiveMission = nil
				gc._capAssistBlueAirborneTracked = nil
				gc._capAssistBluePatrolTrackedTargetzone = nil
				self:_syncCapSpawnBucketsForGroup(gc)
			end
		end
	end
end

function BattleCommander:_capDelta(side, missionType, delta)
	if side ~= 1 and side ~= 2 then return end
	local bySide = self._activeCapCount and self._activeCapCount[side]
	if not bySide then
		bySide = { _all = 0, patrol = 0, attack = 0 }
		self._activeCapCount = self._activeCapCount or {}
		self._activeCapCount[side] = bySide
	end
	local total = (bySide._all or 0) + delta
	if total < 0 then total = 0 end
	bySide._all = total
	if missionType then
		local n = (bySide[missionType] or 0) + delta
		if n < 0 then n = 0 end
		bySide[missionType] = n
	end
end

function BattleCommander:_ensureCapAssistRuntime()
	self._airborneBlueCapByName = self._airborneBlueCapByName or {}
	self._airborneBluePatrolByTargetzone = self._airborneBluePatrolByTargetzone or {}
	self._capAssistPendingByTargetzone = self._capAssistPendingByTargetzone or {}
	self._capAssistCooldownByTargetzone = self._capAssistCooldownByTargetzone or {}
	if self._hasAirborneBlueCap == nil then
		self._hasAirborneBlueCap = false
	end
end

function BattleCommander:_capAssistIsBlueCapActiveState(groupState)
	return groupState == 'takeoff' or groupState == 'inair'
end

function BattleCommander:_capAssistUntrackBluePatrol(groupCommander)
	local previousTargetzone = groupCommander and groupCommander._capAssistBluePatrolTrackedTargetzone
	if not previousTargetzone then return end
	local targetzoneMap = self._airborneBluePatrolByTargetzone and self._airborneBluePatrolByTargetzone[previousTargetzone]
	if targetzoneMap then
		targetzoneMap[groupCommander.name] = nil
		if not next(targetzoneMap) then
			self._airborneBluePatrolByTargetzone[previousTargetzone] = nil
		end
	end
	groupCommander._capAssistBluePatrolTrackedTargetzone = nil
end

function BattleCommander:_capAssistTrackBlueAirborne(groupCommander, shouldTrack)
	self:_ensureCapAssistRuntime()
	if not groupCommander or not groupCommander.name then return end

	local groupName = groupCommander.name
	if shouldTrack then
		self._airborneBlueCapByName[groupName] = groupCommander
		groupCommander._capAssistBlueAirborneTracked = true

		local patrolTargetzone = nil
		if groupCommander.mission == 'patrol' and groupCommander.targetzone then
			patrolTargetzone = groupCommander.targetzone
		elseif groupCommander._capAssistRetaskedTargetzone then
			patrolTargetzone = groupCommander._capAssistRetaskedTargetzone
		end
		local previousTargetzone = groupCommander._capAssistBluePatrolTrackedTargetzone
		if previousTargetzone and previousTargetzone ~= patrolTargetzone then
			self:_capAssistUntrackBluePatrol(groupCommander)
		end
		if patrolTargetzone then
			local targetzoneMap = self._airborneBluePatrolByTargetzone[patrolTargetzone]
			if not targetzoneMap then
				targetzoneMap = {}
				self._airborneBluePatrolByTargetzone[patrolTargetzone] = targetzoneMap
			end
			targetzoneMap[groupName] = groupCommander
			groupCommander._capAssistBluePatrolTrackedTargetzone = patrolTargetzone
		else
			self:_capAssistUntrackBluePatrol(groupCommander)
		end
	else
		if groupCommander._capAssistBlueAirborneTracked then
			self._airborneBlueCapByName[groupName] = nil
			groupCommander._capAssistBlueAirborneTracked = nil
		end
		self:_capAssistUntrackBluePatrol(groupCommander)
	end

	self._hasAirborneBlueCap = next(self._airborneBlueCapByName) ~= nil
end

function BattleCommander:_capAssistDistanceNm(pointA, pointB)
	if not pointA or not pointB then return nil end
	local pointAX = pointA.x
	local pointAZ = pointA.z or pointA.y
	local pointBX = pointB.x
	local pointBZ = pointB.z or pointB.y
	if not pointAX or not pointAZ or not pointBX or not pointBZ then return nil end
	local deltaX = pointAX - pointBX
	local deltaZ = pointAZ - pointBZ
	return math.sqrt(deltaX * deltaX + deltaZ * deltaZ) / NM
end

function BattleCommander:_capAssistResolveBlueRetaskMode(targetZoneName)
	if not targetZoneName then return 'patrol' end
	local targetZone = self:getZoneByName(targetZoneName)
	if targetZone and targetZone.side == 2 then
		return 'patrol'
	end
	return 'attack'
end

function BattleCommander:_capAssistGetBlueOriginZoneName(groupCommander)
	if not groupCommander or not groupCommander.zoneCommander then return nil end
	return groupCommander.zoneCommander.zone
end

function BattleCommander:_capAssistBuildBluePatrolStation(targetZoneName)
	if not targetZoneName then return nil, nil, nil end
	local towardEnemyNm = 35
	local offsetNm = -towardEnemyNm
	local safeDistanceNm = 30
	local patrolStation = Frontline.PickStationNearZone(targetZoneName, 2, offsetNm, 0, 0, 0, safeDistanceNm)
	if not patrolStation then return nil, nil, nil end
	local stationPoint = { x = patrolStation.x, z = patrolStation.y }
	return patrolStation, stationPoint, safeDistanceNm
end

function BattleCommander:_capAssistBuildBlueAttackStation(originZoneName, targetZoneName)
	if not originZoneName or not targetZoneName then return nil, nil, nil end
	local attackOffsetNm = 25
	local attackStation = Frontline.PickCapStationFromOrigin(originZoneName, targetZoneName, 2, 100, attackOffsetNm)
	if not attackStation then return nil, nil, nil end
	local stationPoint = { x = attackStation.x, z = attackStation.y }
	return attackStation, stationPoint, attackOffsetNm
end

function BattleCommander:_capAssistHasBluePatrolCoverage(targetZoneName, desiredStationPoint, coverageDistanceNm)
	self:_ensureCapAssistRuntime()
	local patrolGroups = self._airborneBluePatrolByTargetzone[targetZoneName]
	if not patrolGroups then return false, nil, nil end

	local nearestCommander = nil
	local nearestDistanceNm = nil
	for patrolGroupName, patrolCommander in pairs(patrolGroups) do
		if patrolCommander and self:_capAssistIsBlueCapActiveState(patrolCommander.state) then
			local holdingPoint = patrolCommander._currentCapHoldingPoint
			local distanceNm = self:_capAssistDistanceNm(holdingPoint, desiredStationPoint)
			if distanceNm then
				if (not nearestDistanceNm) or distanceNm < nearestDistanceNm then
					nearestDistanceNm = distanceNm
					nearestCommander = patrolCommander
				end
				if distanceNm <= coverageDistanceNm then
					return true, patrolCommander, distanceNm
				end
			end
		end
	end
	return false, nearestCommander, nearestDistanceNm
end

function BattleCommander:_capAssistHasBlueAttackCoverage(targetZoneName, coverageDistanceNm)
	self:_ensureCapAssistRuntime()
	if not targetZoneName then return false, nil, nil end

	local nearestCommander = nil
	local nearestDistanceNm = nil
	for candidateGroupName, candidateCommander in pairs(self._airborneBlueCapByName) do
		if candidateCommander
		and self:_capAssistIsBlueCapActiveState(candidateCommander.state)
		and candidateCommander.MissionType == 'CAP'
		and (candidateCommander.targetzone == targetZoneName or candidateCommander._capAssistRetaskedTargetzone == targetZoneName) then
			local originZoneName = self:_capAssistGetBlueOriginZoneName(candidateCommander)
			local attackStation, stationPoint = self:_capAssistBuildBlueAttackStation(originZoneName, targetZoneName)
			if attackStation and stationPoint then
				local holdingPoint = candidateCommander._currentCapHoldingPoint
				local distanceNm = self:_capAssistDistanceNm(holdingPoint, stationPoint)
				if distanceNm then
					if (not nearestDistanceNm) or distanceNm < nearestDistanceNm then
						nearestDistanceNm = distanceNm
						nearestCommander = candidateCommander
					end
					if distanceNm <= coverageDistanceNm then
						return true, candidateCommander, distanceNm
					end
				end
			end
		end
	end
	return false, nearestCommander, nearestDistanceNm
end

function BattleCommander:_capAssistSelectBluePatrolCandidate(desiredStationPoint)
	self:_ensureCapAssistRuntime()
	local nearestCommander = nil
	local nearestDistanceNm = nil
	for candidateGroupName, candidateCommander in pairs(self._airborneBlueCapByName) do
		if candidateCommander
		and self:_capAssistIsBlueCapActiveState(candidateCommander.state)
		and candidateCommander.MissionType == 'CAP'
		and candidateCommander._capAssistRetaskedThisSortie ~= true then
			local holdingPoint = candidateCommander._currentCapHoldingPoint
			local distanceNm = self:_capAssistDistanceNm(holdingPoint, desiredStationPoint)
			if distanceNm and ((not nearestDistanceNm) or distanceNm < nearestDistanceNm) then
				nearestDistanceNm = distanceNm
				nearestCommander = candidateCommander
			end
		end
	end
	return nearestCommander, nearestDistanceNm
end

function BattleCommander:_capAssistSelectBlueAttackCandidate(targetZoneName)
	self:_ensureCapAssistRuntime()
	local nearestCommander = nil
	local nearestDistanceNm = nil
	local nearestAttackStation = nil
	local nearestAttackOffsetNm = nil
	for candidateGroupName, candidateCommander in pairs(self._airborneBlueCapByName) do
		if candidateCommander
		and self:_capAssistIsBlueCapActiveState(candidateCommander.state)
		and candidateCommander.MissionType == 'CAP'
		and candidateCommander._capAssistRetaskedThisSortie ~= true then
			local originZoneName = self:_capAssistGetBlueOriginZoneName(candidateCommander)
			local attackStation, stationPoint, attackOffsetNm = self:_capAssistBuildBlueAttackStation(originZoneName, targetZoneName)
			if attackStation and stationPoint then
				local holdingPoint = candidateCommander._currentCapHoldingPoint
				local distanceNm = self:_capAssistDistanceNm(holdingPoint, stationPoint)
				if distanceNm and ((not nearestDistanceNm) or distanceNm < nearestDistanceNm) then
					nearestDistanceNm = distanceNm
					nearestCommander = candidateCommander
					nearestAttackStation = attackStation
					nearestAttackOffsetNm = attackOffsetNm
				end
			end
		end
	end
	return nearestCommander, nearestDistanceNm, nearestAttackStation, nearestAttackOffsetNm
end

function BattleCommander:_capAssistHasActiveRedCapForTargetzone(targetZoneName)
	if not targetZoneName then return false end
	for zoneIndex, zoneCommander in ipairs(self.zones or {}) do
		for groupIndex, groupCommander in ipairs(zoneCommander.groups or {}) do
			if groupCommander
			and groupCommander.side == 1
			and groupCommander.MissionType == 'CAP'
			and groupCommander.state == 'inair'
			and groupCommander.targetzone == targetZoneName then
				return true
			end
		end
	end
	return false
end

function BattleCommander:_executeBlueCapAssistForTargetzone(targetZoneName, pendingToken)
	if GlobalSettings.capAssistEnabled == false then return end
	self:_ensureCapAssistRuntime()
	local pendingRecord = self._capAssistPendingByTargetzone[targetZoneName]
	if not pendingRecord or pendingRecord.token ~= pendingToken then return end
	self._capAssistPendingByTargetzone[targetZoneName] = nil

	local now = timer.getAbsTime()
	if not self:_capAssistHasActiveRedCapForTargetzone(targetZoneName) then
		return
	end

	local assistMode = pendingRecord.assistMode or self:_capAssistResolveBlueRetaskMode(targetZoneName)
	local coverageDistanceNm = GlobalSettings.capAssistCoverageNm or 30
	local desiredPatrolStation = nil
	local desiredPatrolPoint = nil
	local desiredPatrolSafeNm = nil
	if assistMode == 'attack' then
		local hasCoverage = self:_capAssistHasBlueAttackCoverage(targetZoneName, coverageDistanceNm)
		if hasCoverage then
			self._capAssistCooldownByTargetzone[targetZoneName] = now + (GlobalSettings.capAssistTargetZoneCooldownSec or 300)
			return
		end
	else
		desiredPatrolStation, desiredPatrolPoint, desiredPatrolSafeNm = self:_capAssistBuildBluePatrolStation(targetZoneName)
		if not desiredPatrolStation then
			self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
			return
		end
		local hasCoverage = self:_capAssistHasBluePatrolCoverage(targetZoneName, desiredPatrolPoint, coverageDistanceNm)
		if hasCoverage then
			self._capAssistCooldownByTargetzone[targetZoneName] = now + (GlobalSettings.capAssistTargetZoneCooldownSec or 300)
			return
		end
	end

	local candidateCommander = nil
	local candidateStation = nil
	local candidateBufferNm = nil
	local pendingBlueName = pendingRecord.blueGroupName
	if pendingBlueName then
		candidateCommander = self._airborneBlueCapByName[pendingBlueName]
	end

	if candidateCommander
	and (not self:_capAssistIsBlueCapActiveState(candidateCommander.state) or candidateCommander._capAssistRetaskedThisSortie == true) then
		candidateCommander = nil
	end

	if candidateCommander then
		if assistMode == 'attack' then
			local originZoneName = self:_capAssistGetBlueOriginZoneName(candidateCommander)
			local attackStation, stationPoint, attackOffsetNm = self:_capAssistBuildBlueAttackStation(originZoneName, targetZoneName)
			if attackStation and stationPoint then
				candidateStation = attackStation
				candidateBufferNm = attackOffsetNm
			else
				candidateCommander = nil
			end
		else
			candidateStation = desiredPatrolStation
			candidateBufferNm = desiredPatrolSafeNm or 30
		end
	end

	if not candidateCommander then
		if assistMode == 'attack' then
			candidateCommander, _, candidateStation, candidateBufferNm = self:_capAssistSelectBlueAttackCandidate(targetZoneName)
		else
			candidateCommander = self:_capAssistSelectBluePatrolCandidate(desiredPatrolPoint)
			candidateStation = desiredPatrolStation
			candidateBufferNm = desiredPatrolSafeNm or 30
		end
	end

	if not candidateCommander or not candidateStation then
		self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
		return
	end

	if not self:_capAssistIsBlueCapActiveState(candidateCommander.state) then
		self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
		return
	end

	local candidateGroup = candidateCommander:_getDcsGroupCached()
	if not candidateGroup or not candidateGroup:isExist() then
		self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
		return
	end

	local orbitDistanceNm = (assistMode == 'attack') and math.random(35, 40) or math.random(30, 40)
	local safeNm = candidateBufferNm or ((assistMode == 'attack') and 25 or 30)
	SetUpCAP(candidateGroup, { x = candidateStation.x, z = candidateStation.y }, candidateCommander.Altitude, orbitDistanceNm, candidateCommander._landUnitID, safeNm, 2)
	candidateCommander._currentCapHoldingPoint = { x = candidateStation.x, z = candidateStation.y }
	candidateCommander._currentCapOrbitDistanceNm = orbitDistanceNm
	candidateCommander._currentCapBufferNm = safeNm
	candidateCommander._capAssistRetaskedThisSortie = true
	candidateCommander._capAssistRetaskedTargetzone = targetZoneName
	self:_capAssistTrackBlueAirborne(candidateCommander, true)
	self._capAssistCooldownByTargetzone[targetZoneName] = now + (GlobalSettings.capAssistTargetZoneCooldownSec or 300)
end

function BattleCommander:_tryScheduleBlueCapAssistFromRedCap(redGroupCommander)
	if GlobalSettings.capAssistEnabled == false then return false end
	if not redGroupCommander then return false end
	if redGroupCommander.side ~= 1 or redGroupCommander.MissionType ~= 'CAP' then return false end
	local targetZoneName = redGroupCommander.targetzone
	if not targetZoneName then return false end

	if not self._capBucketsBuilt then
		self:buildCapActiveBuckets()
	end
	self:_ensureCapAssistRuntime()
	if not self._hasAirborneBlueCap then return false end

	local now = timer.getAbsTime()
	local cooldownUntil = self._capAssistCooldownByTargetzone[targetZoneName] or 0
	if now < cooldownUntil then return false end

	local pendingRecord = self._capAssistPendingByTargetzone[targetZoneName]
	if pendingRecord then
		local pendingUntil = pendingRecord.executeAt or 0
		if now < pendingUntil then
			return false
		end
		self._capAssistPendingByTargetzone[targetZoneName] = nil
	end

	local assistMode = self:_capAssistResolveBlueRetaskMode(targetZoneName)
	local coverageDistanceNm = GlobalSettings.capAssistCoverageNm or 30
	local candidateCommander = nil
	local assistBufferNm = nil
	if assistMode == 'attack' then
		local hasCoverage = self:_capAssistHasBlueAttackCoverage(targetZoneName, coverageDistanceNm)
		if hasCoverage then
			self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
			return false
		end
		candidateCommander, _, _, assistBufferNm = self:_capAssistSelectBlueAttackCandidate(targetZoneName)
	else
		local patrolStation, stationPoint, safeDistanceNm = self:_capAssistBuildBluePatrolStation(targetZoneName)
		if not patrolStation then
			self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
			return false
		end
		local hasCoverage = self:_capAssistHasBluePatrolCoverage(targetZoneName, stationPoint, coverageDistanceNm)
		if hasCoverage then
			self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
			return false
		end
		candidateCommander = self:_capAssistSelectBluePatrolCandidate(stationPoint)
		assistBufferNm = safeDistanceNm
	end

	if not candidateCommander then
		self._capAssistCooldownByTargetzone[targetZoneName] = now + 60
		return false
	end

	local minimumDelaySec = GlobalSettings.capAssistDelayMinSec or 120
	local maximumDelaySec = GlobalSettings.capAssistDelayMaxSec or 300
	if minimumDelaySec < 1 then minimumDelaySec = 1 end
	if maximumDelaySec < minimumDelaySec then maximumDelaySec = minimumDelaySec end
	local delaySeconds = math.random(minimumDelaySec, maximumDelaySec)
	local pendingToken = string.format("%s|%s|%d", tostring(targetZoneName), tostring(candidateCommander.name or "blue_cap"), math.floor(now))
	local executeAt = now + delaySeconds

	self._capAssistPendingByTargetzone[targetZoneName] = {
		token = pendingToken,
		executeAt = executeAt,
		blueGroupName = candidateCommander.name,
		assistMode = assistMode,
		assistBufferNm = assistBufferNm,
	}

	redGroupCommander._capAssistPendingTargetzone = targetZoneName
	redGroupCommander._capAssistPendingToken = pendingToken

	timer.scheduleFunction(function(param, scheduledTime)
		local battleCommander = param and param.battleCommander or nil
		if battleCommander and battleCommander._executeBlueCapAssistForTargetzone then
			battleCommander:_executeBlueCapAssistForTargetzone(param.targetZoneName, param.pendingToken)
		end
		return nil
	end, { battleCommander = self, targetZoneName = targetZoneName, pendingToken = pendingToken }, timer.getTime() + delaySeconds)

	return true
end

function BattleCommander:_syncCapSpawnBucketsForGroup(gc)
	if not self._capBucketsBuilt then return end

	local st = gc.state
	local isCap = gc.MissionType == 'CAP'
	local trackMission = (gc.mission == 'patrol' or gc.mission == 'attack') and gc.mission or nil
	local capActive = isCap and (st == 'takeoff' or st == 'inair' or gc.Spawned)

	if capActive then
		local side = gc.side
		local missionType = trackMission
		if gc._capActiveSide then
			if gc._capActiveSide ~= side or gc._capActiveMission ~= missionType then
				self:_capDelta(gc._capActiveSide, gc._capActiveMission, -1)
				self:_capDelta(side, missionType, 1)
				gc._capActiveSide = side
				gc._capActiveMission = missionType
			end
		else
			self:_capDelta(side, missionType, 1)
			gc._capActiveSide = side
			gc._capActiveMission = missionType
		end
	else
		if gc._capActiveSide then
			self:_capDelta(gc._capActiveSide, gc._capActiveMission, -1)
			gc._capActiveSide = nil
			gc._capActiveMission = nil
		end
	end

	local isBlueCapAssistActive = isCap and gc.side == 2 and self:_capAssistIsBlueCapActiveState(st)
	self:_capAssistTrackBlueAirborne(gc, isBlueCapAssistActive)
end

function BattleCommander:_nonCapDeltaSupply(side, targetZone, delta)
	local bySide = self._activeSupplyCount[side]
	if not bySide then bySide={} self._activeSupplyCount[side]=bySide end
	local n = (bySide[targetZone] or 0) + delta
	if n <= 0 then bySide[targetZone]=nil else bySide[targetZone]=n end
end

function BattleCommander:_nonCapDeltaCasSead(side, missionType, delta)
	local bySide = self._activeCasSeadCount[side]
	if not bySide then bySide={_all=0} self._activeCasSeadCount[side]=bySide end
	bySide._all = (bySide._all or 0) + delta
	if bySide._all < 0 then bySide._all = 0 end
	if missionType then
		local n = (bySide[missionType] or 0) + delta
		if n <= 0 then bySide[missionType]=nil else bySide[missionType]=n end
	end
end

function BattleCommander:_nonCapDeltaStrike(side, missionType, missionRole, unitCategory, delta)
	local bySide = self._activeStrikeCount[side]
	if not bySide then bySide={} self._activeStrikeCount[side]=bySide end
	local byMission = bySide[missionType]
	if not byMission then byMission={} bySide[missionType]=byMission end
	local byRole = byMission[missionRole]
	if not byRole then byRole={_all=0} byMission[missionRole]=byRole end
	byRole._all = (byRole._all or 0) + delta
	if byRole._all < 0 then byRole._all = 0 end
	if unitCategory ~= nil then
		local n = (byRole[unitCategory] or 0) + delta
		if n <= 0 then byRole[unitCategory]=nil else byRole[unitCategory]=n end
	end
end

function BattleCommander:_syncNonCapSpawnBucketsForGroup(gc)
	if not self._nonCapBucketsBuilt then return end

	local st = gc.state

	local supplyActive = (gc.mission == 'supply') and gc.targetzone and (st == 'takeoff' or st == 'inair' or st == 'landed')
	if supplyActive then
		local side = gc.side
		local targetZone = gc.targetzone
		if gc._nonCapSupplySide then
			if gc._nonCapSupplySide ~= side or gc._nonCapSupplyZone ~= targetZone then
				self:_nonCapDeltaSupply(gc._nonCapSupplySide, gc._nonCapSupplyZone, -1)
				self:_nonCapDeltaSupply(side, targetZone, 1)
				gc._nonCapSupplySide = side
				gc._nonCapSupplyZone = targetZone
			end
		else
			self:_nonCapDeltaSupply(side, targetZone, 1)
			gc._nonCapSupplySide = side
			gc._nonCapSupplyZone = targetZone
		end
	else
		if gc._nonCapSupplySide then
			self:_nonCapDeltaSupply(gc._nonCapSupplySide, gc._nonCapSupplyZone, -1)
			gc._nonCapSupplySide = nil
			gc._nonCapSupplyZone = nil
		end
	end

	local mt = gc.MissionType
	local casSeadType = (mt == 'CAS' or mt == 'SEAD' or mt == 'RUNWAYSTRIKE' or mt == 'ANTISHIP')
	local casSeadActive = casSeadType and gc.Spawned and st ~= 'dead' and st ~= 'inhangar'
	if casSeadActive then
		local side = gc.side
		local missionType = gc.mission
		if gc._nonCapCasSeadSide then
			if gc._nonCapCasSeadSide ~= side or gc._nonCapCasSeadMission ~= missionType then
				self:_nonCapDeltaCasSead(gc._nonCapCasSeadSide, gc._nonCapCasSeadMission, -1)
				self:_nonCapDeltaCasSead(side, missionType, 1)
				gc._nonCapCasSeadSide = side
				gc._nonCapCasSeadMission = missionType
			end
		else
			self:_nonCapDeltaCasSead(side, missionType, 1)
			gc._nonCapCasSeadSide = side
			gc._nonCapCasSeadMission = missionType
		end
	else
		if gc._nonCapCasSeadSide then
			self:_nonCapDeltaCasSead(gc._nonCapCasSeadSide, gc._nonCapCasSeadMission, -1)
			gc._nonCapCasSeadSide = nil
			gc._nonCapCasSeadMission = nil
		end
	end

	local strikeActive = gc.mission and gc.MissionType and (st == 'takeoff' or st == 'inair' or gc.Spawned)
	if strikeActive then
		local side = gc.side
		local missionType = gc.mission
		local missionRole = gc.MissionType
		local unitCategory = gc.unitCategory
		if gc._nonCapStrikeSide then
			if gc._nonCapStrikeSide ~= side or gc._nonCapStrikeMission ~= missionType or gc._nonCapStrikeRole ~= missionRole or gc._nonCapStrikeUnitCategory ~= unitCategory then
				self:_nonCapDeltaStrike(gc._nonCapStrikeSide, gc._nonCapStrikeMission, gc._nonCapStrikeRole, gc._nonCapStrikeUnitCategory, -1)
				self:_nonCapDeltaStrike(side, missionType, missionRole, unitCategory, 1)
				gc._nonCapStrikeSide = side
				gc._nonCapStrikeMission = missionType
				gc._nonCapStrikeRole = missionRole
				gc._nonCapStrikeUnitCategory = unitCategory
			end
		else
			self:_nonCapDeltaStrike(side, missionType, missionRole, unitCategory, 1)
			gc._nonCapStrikeSide = side
			gc._nonCapStrikeMission = missionType
			gc._nonCapStrikeRole = missionRole
			gc._nonCapStrikeUnitCategory = unitCategory
		end
	else
		if gc._nonCapStrikeSide then
			self:_nonCapDeltaStrike(gc._nonCapStrikeSide, gc._nonCapStrikeMission, gc._nonCapStrikeRole, gc._nonCapStrikeUnitCategory, -1)
			gc._nonCapStrikeSide = nil
			gc._nonCapStrikeMission = nil
			gc._nonCapStrikeRole = nil
			gc._nonCapStrikeUnitCategory = nil
		end
	end
end

function BattleCommander:getActiveSupplyCount(side, targetZone)
	if not self._nonCapBucketsBuilt then
		self:buildNonCapSpawnBuckets()
	end
	if self._nonCapBucketsBuilt then
		local bySide = self._activeSupplyCount and self._activeSupplyCount[side]
		if bySide then return bySide[targetZone] or 0 end
	end
    local count = 0
    for _, zoneCom in ipairs(self.zones) do
        for _, groupCom in ipairs(zoneCom.groups) do
            if groupCom.side == side and groupCom.mission == 'supply' and groupCom.targetzone == targetZone then
                if groupCom.state == 'takeoff' or groupCom.state == 'inair' or groupCom.state == 'landed' then
                    count = count + 1
                end
            end
        end
    end
    return count
end

function BattleCommander:getActiveCasSeadCount(side, missionType)
	if not self._nonCapBucketsBuilt then
		self:buildNonCapSpawnBuckets()
	end
	if self._nonCapBucketsBuilt then
		local bySide = self._activeCasSeadCount and self._activeCasSeadCount[side]
		if bySide then
			if not missionType then return bySide._all or 0 end
			return bySide[missionType] or 0
		end
	end
    local count = 0
    for _, zoneCom in ipairs(self.zones) do
        for _, groupCom in ipairs(zoneCom.groups) do
            if groupCom.side == side and (groupCom.MissionType == 'CAS' or groupCom.MissionType == 'SEAD' or groupCom.MissionType == 'RUNWAYSTRIKE' or groupCom.MissionType == 'ANTISHIP') then
                if not missionType or groupCom.mission == missionType then
                    if groupCom.Spawned and groupCom.state ~= 'dead' and groupCom.state ~= 'inhangar' then
                        count = count + 1
                    end
                end
            end
        end
    end
    return count
end

function BattleCommander:getActiveStrikeCount(side, missionType, missionRole, unitCategory)
	if not self._nonCapBucketsBuilt then
		self:buildNonCapSpawnBuckets()
	end
	if self._nonCapBucketsBuilt then
		local bySide = self._activeStrikeCount and self._activeStrikeCount[side]
		local byMission = bySide and bySide[missionType]
		local byRole = byMission and byMission[missionRole]
		if byRole then
			if unitCategory ~= nil then return byRole[unitCategory] or 0 end
			return byRole._all or 0
		end
	end
	local count = 0
	for _, zoneCom in ipairs(self.zones) do
		for _, groupCom in ipairs(zoneCom.groups) do
			if groupCom.side == side and groupCom.mission == missionType and groupCom.MissionType == missionRole then
				if (not unitCategory) or groupCom.unitCategory == unitCategory then
					if groupCom.state == 'takeoff' or groupCom.state == 'inair' or groupCom.Spawned then
						count = count + 1
					end
				end
			end
		end
	end
	return count
end

function BattleCommander:getActiveCAPCount(side, missionType)
	if not self._capBucketsBuilt then
		self:buildCapActiveBuckets()
	end
	if self._capBucketsBuilt then
		local bySide = self._activeCapCount and self._activeCapCount[side]
		if bySide then
			if missionType then return bySide[missionType] or 0 end
			return bySide._all or 0
		end
	end

    local count = 0
    for _, zoneCom in ipairs(self.zones) do
        for _, groupCom in ipairs(zoneCom.groups) do
            if groupCom.side == side and groupCom.MissionType == 'CAP' then
                if missionType then
                    if groupCom.mission == missionType then
                        if groupCom.state == 'takeoff' or groupCom.state == 'inair' or groupCom.Spawned then
                            count = count + 1
                        end
                    end
                else
                    if groupCom.state == 'takeoff' or groupCom.state == 'inair' or groupCom.Spawned then
                        count = count + 1
                    end
                end
            end
        end
    end
    return count
end

DebugIsOn = false
DebugIsOnCAP = false
RunwayHandler = nil
RUNWAY_ZONE_COOLDOWN = {}
runwayCooldown = 0
runwayCompleted = false
function generateRunwayStrikeMission()
  if runwayMission or runwayTarget then return true end
  if timer.getTime() < runwayCooldown then return true end
local cand, capCand = {}, {}
	for _, z in ipairs(bc.zones) do
		if z.side == 1 and z.active and not z.suspended and z.airbaseName and ZONE_CONNECTED_TO_BLUE[z.zone]
			and (RUNWAY_ZONE_COOLDOWN[z.zone] or 0) < timer.getTime()
		then
			local hostile, capCnt = false, 0
			for _, g in ipairs(z.groups or {}) do
				if g.side == 1 and g.unitCategory == 0 then
					if g.mission == 'attack' or g.mission == 'patrol' then hostile = true end
					if g.MissionType == 'CAP' then capCnt = capCnt + 1 end
				end
			end
			if hostile then
				local ab = AIRBASE:FindByName(z.airbaseName)
				if ab and ab:IsAirdrome() then
					local entry = { zone = z, airbase = ab }
					if capCnt > 2 then capCand[#capCand + 1] = entry else cand[#cand + 1] = entry end
				end
			end
		end
	end
	cand = (#capCand > 0) and capCand or cand
	do
		local blueAnchors = {}
		for _, bz in ipairs(bc.zones) do
			if bz.side == 2 and bz.active and not bz.suspended then blueAnchors[#blueAnchors + 1] = bz.zone end
		end
		for _, e in ipairs(cand) do
			local best = math.huge
			local znB = e.zone.zone
			for _, znA in ipairs(blueAnchors) do
				local d = ZONE_DISTANCES[znA] and ZONE_DISTANCES[znA][znB] or math.huge
				if d < best then best = d end
			end
			e.dist = best
		end
		table.sort(cand, function(a, b) return a.dist < b.dist end)
		local rankBonus = {5, 3, 0}
		for idx, e in ipairs(cand) do
			local grpScore = 0
			for _, g in ipairs(e.zone.groups or {}) do
				if g.side == 1 and g.unitCategory == 0 then
					grpScore = grpScore + 2
					if g.MissionType == 'CAP' then grpScore = grpScore + 1 end
				end
			end
			e.score = grpScore + (rankBonus[math.min(idx, 3)] or 0)
		end
		table.sort(cand, function(a, b)
			if a.score == b.score then return a.dist < b.dist else return a.score > b.score end
		end)
	end
  if #cand==0 then
    local blueAnchors={}
    for _,bz in ipairs(bc.zones) do
      if bz.side==2 and bz.active and not bz.suspended then blueAnchors[#blueAnchors+1]=bz.zone end
    end
    for _,z in ipairs(bc.zones) do
      if z.side==1 and z.active and not z.suspended and z.airbaseName and
	  (RUNWAY_ZONE_COOLDOWN[z.zone] or 0) < timer.getTime() then
        local hostile=false
        if z.groups then
          for _,g in ipairs(z.groups) do
            if g.side==1 and g.unitCategory == 0 and (g.mission=='attack' or g.mission=='patrol') then
			hostile=true 
			break 
			end
          end
        end
        if hostile then
          local bestdist=math.huge
          local znB=z.zone
          for _,znA in ipairs(blueAnchors) do
            local d=ZONE_DISTANCES[znA] and ZONE_DISTANCES[znA][znB] or math.huge
            if d<bestdist then bestdist=d end
          end
          if bestdist<=60*1852 then
            local ab=AIRBASE:FindByName(z.airbaseName)
            if ab and ab:IsAirdrome() then
              local score=0
              for _,g in ipairs(z.groups or {}) do
                if g.side==1 and g.unitCategory==0 then
                  score=score+2
                  if g.MissionType=="CAP" then score=score+1 end
                end
              end
              cand[#cand+1]={zone=z,airbase=ab,dist=bestdist,score=score}
            end
          end
        end
      end
    end
	table.sort(cand,function(a,b) return a.dist<b.dist end)
	local rankBonus={5,3,0}
	for i,e in ipairs(cand) do
	e.score=(e.score or 0)+(rankBonus[i] or 0)
	end
	table.sort(cand,function(a,b) return a.score>b.score end)
	end
    for i=1,math.min(3,#cand) do
      local e=cand[i]
      --env.info(string.format("RUNWAY-DBG: option %d  %s  dist=%.0f  score=%d",i,e.zone.zone,e.dist,e.score))
    end
  
  if #cand==0 then return false end
  if not cand[1] then return false end
  local ab=cand[1].airbase
  local hitZones={}
  runwayNames={}
  local done = {}
  
  do
    local seen={}
    local runwaytgt=ab:GetRunways() or {}
    for _,r in ipairs(runwaytgt) do
      if r.zone then
        local hdg=(r.heading or 0)%360
        local num=math.floor((hdg+5)/10)%36 ; if num==0 then num=36 end
        local side=r.isLeft==nil and '' or (r.isLeft and 'L' or 'R')
        if num>18 then num=num-18 ; if side=='L' then side='R' elseif side=='R' then side='L' end end
        local id=(num<10 and'0'or'')..tostring(num)..side
        if not seen[id] then
          hitZones[#hitZones+1]=r.zone
          runwayNames[#runwayNames+1]=id
          seen[id]=true
        end
      end
    end
  end
  if #hitZones==0 then return false end
  hits,need=0,#hitZones
  runwayTarget=ab:GetName()
  runwayTargetZone = cand[1].zone.zone
  runwayMission = "Active"
  runwayCompleted = false
  --env.info('RUNWAY-DBG: picked airdrome '..runwayTargetZone.. ' with '..need..' runways to hit')
  RunwayHandler=EVENT:New()
  function RunwayHandler:OnEventShot(EventData)
    if not (EventData and EventData.IniUnit and EventData.weapon and EventData.IniPlayerName) then return end
    local wp=WEAPON:New(EventData.weapon)
    if not wp:IsBomb() then return end
    --env.info('RUNWAY-DBG: '..EventData.IniPlayerName..' dropped '..wp:GetTypeName()..' on '..runwayTargetZone)
    local pilot = EventData.IniPlayerName or 'Unknown hero'
	local playerUnit = EventData.IniUnit
	local playerGroupID = playerUnit:GetGroup():GetID()
    wp:SetFuncImpact(function(self)
      local p=self:GetImpactVec3()
    if not p or not runwayMission or not runwayTargetZone then
	self:StopTrack() return	end
      for i, z in ipairs(hitZones) do
        local cp=COORDINATE:NewFromVec3(p)
		if not done[z] and (z:IsVec3InZone(p) or z:GetCoordinate():Get2DDistance(cp)<=10) then
		env.info('RUNWAY-DBG: bomb hit '..z:GetName())
		done[z] = true
          hits=hits+1
		 if #runwayNames > 1 then  MESSAGE:New(L10N:FormatForGroup(playerGroupID, "MISSION_BOMB_RUNWAY_HIT", runwayNames[i]), 10, ''):ToUnit(playerUnit) end
          if hits>=need then
			self:StopTrack()
			bomberName = pilot
			runwayCompleted = true
			bc:blockRunwayPlaneSpawns(runwayTargetZone, 3300)
			if bc.playerContributions[2][bomberName]~=nil then
			local reward = (need>1 and 200 or 100)
           	bc:addContribution(bomberName, 2, reward)
			local jp = bc.jointPairs and bc.jointPairs[bomberName]
			if jp and bc:_jointPartnerAlive(bomberName) and bc:_jointPartnerAlive(jp) and bc.playerContributions[2][jp] ~= nil then
				bc:addContribution(jp, 2, reward)
				bc:addTempStat(jp,'Bomb runway (Joint mission)',1)
				bc:addTempStat(bomberName,'Bomb runway (Joint mission)',1)
				runwayPartnerName = jp
				env.info('RUNWAY-DBG: '..bomberName..' and '..jp..' completed runway strike mission at '..runwayTargetZone)
			else
				 bc:addTempStat(bomberName,'Bomb runway',1)
				runwayPartnerName = nil
				env.info('RUNWAY-DBG: '..bomberName..' completed runway strike mission at '..runwayTargetZone)
			end
			end
			if 	RunwayHandler then
				RunwayHandler:UnHandleEvent(EVENTS.Shot)
				RunwayHandler=nil
				runwayMission = nil
			end
          end
          break
        end
      end
    end)
    wp:StartTrack()
  end
  RunwayHandler:HandleEvent(EVENTS.Shot)
  return true
end

function checkAndGenerateCASMission()
	if casMissionTarget ~= nil or timer.getTime() < casMissionCooldownUntil then
		return true
	end
	casTargetKills = math.random(10,16)
	casMissionTarget = 'Active'
	return true
end

local function _buildReconMissionClientSet()
	return SET_CLIENT:New()
		:FilterCoalitions("blue")
		:FilterCategories("plane")
		:FilterCategories("helicopter")
		:FilterActive(true)
		:FilterStart()
end

local function _reconMissionPlayerName(controllable)
	local name = controllable:GetName()
	local unit = Unit.getByName(name)
	if unit and unit:isExist() and unit:getPlayerName() then
		local player = unit:getPlayerName()
		if player and player ~= "" then
			return tostring(player)
		end
	end
	return tostring(name)
end

function startReconMissionZoneTracker(targetName)
	if not targetName then return false end

	if not ReconMissionClientSet then
		ReconMissionClientSet = _buildReconMissionClientSet()
	end

	local tracker = ReconMissionTrackers[targetName]
	if not tracker then
		local zone = ZONE:New(targetName)
		tracker = {
			zone = zone,
			targetName = targetName,
			active = false,
			enteredBy = {},
		}
		ReconMissionTrackers[targetName] = tracker

		zone:Trigger(ReconMissionClientSet)
		function zone:OnAfterEnteredZone(From, Event, To, Controllable)
			if not tracker.active then return end
			if not reconMissionTarget or reconMissionTarget ~= tracker.targetName then return end
			if not Controllable:IsAlive() then return end

			local targetZone = bc:getZoneByName(tracker.targetName)
			if not targetZone or targetZone.side ~= 1 or targetZone.suspended or not targetZone.active then return end

			local playerName = _reconMissionPlayerName(Controllable)
			tracker.enteredBy[playerName] = true
		end

		function zone:OnAfterLeftZone(From, Event, To, Controllable)
			if not tracker.active then return end
			if not reconMissionTarget or reconMissionTarget ~= tracker.targetName then return end
			if not Controllable:IsAlive() then return end

			local targetZone = bc:getZoneByName(tracker.targetName)
			if not targetZone or targetZone.side ~= 1 or targetZone.suspended or not targetZone.active then return end

			local playerName = _reconMissionPlayerName(Controllable)
			if not tracker.enteredBy[playerName] then return end

			tracker.enteredBy[playerName] = nil
			reconMissionWinner = playerName
			reconMissionCompleted = true
			reconMissionCompletedTarget = tracker.targetName
			tracker.active = false
			tracker.enteredBy = {}
		end
	end

	tracker.active = true
	tracker.enteredBy = {}
	return true
end

function stopReconMissionZoneTracker(targetName)
	if not targetName then return end
	local tracker = ReconMissionTrackers[targetName]
	if not tracker then return end
	tracker.active = false
	tracker.enteredBy = {}
end

function checkAndGenerateReconMissionV2()
	local now = timer.getTime()
	if reconMissionTarget ~= nil or now < reconMissionCooldownUntil then
		return true
	end

	local validzones = {}
	local seen = {}
	for _, connection in ipairs(bc.connections or {}) do
		local from, to = bc:getConnectionZones(connection)

		local function checkValid(zone)
			local lname = zone.zone:lower()
			local zoneIntelActive = (intelActiveZones and intelActiveZones[zone.zone] == true)
			local zoneIntelExpire = tonumber((intelExpireTimes and intelExpireTimes[zone.zone]) or 0) or 0
			local intelStillActive = zoneIntelActive and (zoneIntelExpire <= 0 or zoneIntelExpire > now)
			return zone.side == 1 and zone.active and not zone.suspended and not zone.isHidden and
				not intelStillActive and
				not isZoneUnderSEADMission(zone.zone) and
				not lname:find('hidden') and not lname:find('sam') and not lname:find('defence') and
				not lname:find('papa') and not lname:find('juliett') and not lname:find('india') and
				not lname:find('delta') and not lname:find('bravo') and not lname:find('hotel')
		end

		if from and to and from.side ~= to.side and from.side ~= 0 and to.side ~= 0 and
			((not to.suspended) or from.suspended) then
			if checkValid(from) and not seen[from.zone] then
				seen[from.zone] = true
				validzones[#validzones + 1] = from.zone
			end
			if checkValid(to) and not seen[to.zone] then
				seen[to.zone] = true
				validzones[#validzones + 1] = to.zone
			end
		end
	end

	if #validzones == 0 then return false end

	local availablezones = {}
	for _, zoneName in ipairs(validzones) do
		if not bc:_hasActiveJtacOnZone(zoneName) then
			availablezones[#availablezones + 1] = zoneName
		end
	end

	if #availablezones == 0 then return false end

	reconMissionTarget = availablezones[math.random(1, #availablezones)]
	reconMissionWinner = nil
	reconMissionCompleted = false
	reconMissionCompletedTarget = nil
	return true
end


function checkAndGenerateCAPMission()
	if capMissionTarget ~= nil or timer.getTime() < capMissionCooldownUntil then
		return true
	end
	local countInAir = 0
	for _, zC in pairs(bc.zones) do
		if zC.side == 1 and zC.active then
			for _, groupCom in ipairs(zC.groups) do
				if groupCom.side == 1
				and (groupCom.mission == 'attack' or groupCom.mission == 'patrol')
				and (groupCom.state == 'inair' or groupCom.state == 'takeoff') then
					countInAir = countInAir + 1
				end
			end
		end
	end
	local players = getBluePlayersCount()
	local limit = getCapLimit(players)
	if players == 0 then return false end
	if countInAir >= 1 then
		local target = 0
		if limit == 1 then
			target = 2
		elseif limit == 2 then
			target = math.random(2,4)
		elseif limit == 3 then
			target = math.random(3,5)
		elseif limit == 4 then
			target = math.random(4,6)
		elseif limit == 5 then
			target = math.random(5,6)
		elseif limit == 99999 then
			target = math.random(6,8)
		end
		if target > 0 then
			capTargetPlanes = target
			capMissionTarget = "Active"
			return true
		end
	end
	return false
end

function getClosestCapZonesToPlayers(missionType, side, preMeta)
	local t_sort=table.sort
	local zoneSide
	if missionType == 'patrol' then
		zoneSide = side
	elseif missionType == 'attack' then
		zoneSide = (side == 1) and 2 or 1
	else
		zoneSide = (side == 1) and 2 or 1
	end

	local anchorSide = (missionType == 'patrol') and ((side == 1) and 2 or 1) or side
	local spawnList = playerZoneSpawn
	local anchors = {}
	if type(spawnList) == 'table' then
		for _, spawnZoneName in pairs(spawnList) do
			local spawnZC = bc.indexedZones[spawnZoneName]
			if spawnZC and spawnZC.side==anchorSide and spawnZC.active and not spawnZC.suspended and not spawnZC.isHidden and CapAnchorRowByZoneName[spawnZC.zone] then
				anchors[#anchors+1] = { zoneName = spawnZC.zone }
			end
		end
	end
	if #anchors == 0 then
		local cached = (CapAnchors and CapAnchors[side] and CapAnchors[side][missionType]) or {}
		for i=1,#cached do anchors[i]=cached[i] end
	end
	if #anchors == 0 then return {}, preMeta end

	local anchorCount = #anchors
	local anchorRows = {}
	for i=1,anchorCount do
		anchorRows[i] = CapAnchorRowByZoneName[anchors[i].zoneName]
	end

	local candidates = {}
	local enemyAdjMap = {}
	local ttab = CapTargets and CapTargets[side] and CapTargets[side][missionType] or nil
	if ttab then
		local connectionMap = bc.connectionMap or {}
		local function hasEnemyNeighbor(zoneName, s)
			local neighbors = connectionMap[zoneName]; if not neighbors then return false end
			for k,v in pairs(neighbors) do
				local n = (type(k)=="string") and k or v
				local nz = bc.indexedZones[n]
				if nz and not nz.isHidden and nz.active and not nz.suspended and nz.side~=0 and nz.side~=s then return true end
			end
			return false
		end
		for tz,_ in pairs(ttab) do
			local z = bc.indexedZones[tz]
			if z and z.active and not z.suspended and not z.isHidden then
				local ok = (missionType=='patrol') and (z.side==zoneSide) or ((missionType=='attack') and (z.side~=side and z.side~=0))
				if ok then
					candidates[#candidates+1] = tz
					enemyAdjMap[tz] = hasEnemyNeighbor(tz, zoneSide) and true or false
				end
			end
		end
	end

	local BIG=99999999
	local zoneDistances = {}
	for i=1,#candidates do
		local znB = candidates[i]
		local sum = 0
		for j=1,anchorCount do
			local row = anchorRows[j]
			local d = (row and row[znB]) or BIG
			sum = sum + d
		end
		local avg = sum / anchorCount
		if enemyAdjMap[znB] then avg = avg * 0.6 end
		zoneDistances[#zoneDistances+1] = { zone = znB, distance = avg }
	end
	t_sort(zoneDistances, function(a,b) return a.distance < b.distance end)

	local capMeta = preMeta
	if missionType=='patrol' or missionType=='attack' then
		local targets = (CapTargets and CapTargets[side] and CapTargets[side][missionType]) or {}
		if not capMeta then
			local bluePlayers = getBluePlayersCount() or 0
			local limit = (side==2) and getBlueCapLimit(bluePlayers) or getCapLimit(bluePlayers)
			local currentCap = bc:getActiveCAPCount(side, missionType)
			local capLeft = limit - currentCap
			if capLeft < 1 then capLeft = 1 end
			capMeta = { side=side, mission=missionType, bluePlayers=bluePlayers, limit=limit, currentCap=currentCap, capLeft=capLeft, targets=targets, enemyAdj=enemyAdjMap }
		else
			capMeta.targets = targets
			capMeta.enemyAdj = enemyAdjMap
		end
	end

	if DebugIsOnCAP then
		env.info("[DEBUG] Anchors for "..missionType..":")
		for i=1,#anchors do env.info("  - "..tostring(anchors[i].zoneName)) end
		env.info("[DEBUG] Candidates for "..missionType.." (side="..tostring(zoneSide).."):")
		for i=1,#candidates do
			local znB = candidates[i]
			local tCZ = CustomZone:getByName(znB)
			if tCZ and not tCZ.isHidden then
				local sum, bad = 0, 0
				for j=1,#anchors do
					local znA = anchors[j].zoneName
					local d = ((CapAnchorRowByZoneName[znA]) and CapAnchorRowByZoneName[znA][znB]) or nil
					if not d then bad = bad + 1 ; d = BIG end
					sum = sum + d
				end
				local avg = sum / #anchors
				if enemyAdjMap[znB] then avg = avg * 0.6 end
				env.info(string.format("[DEBUG] cand=%s avg=%.0f missing=%d", tostring(znB), avg, bad))
			else
				env.info("[DEBUG] cand skipped (no CZ): "..tostring(znB))
			end
		end
	end

	return zoneDistances, capMeta
end


function GroupCommander:_shouldSpawnImmediate()
	local isUrgent = type(self.urgent) == "function" and self.urgent() or self.urgent
	return (self.forceSpawn == true) or (isUrgent == true) or (self._spawnNowImmediateCheck == true)
end

function GroupCommander:_consumeShouldSpawnDecision(triggerState, ignore)
	if self:_shouldSpawnImmediate() then
		return self:shouldSpawn(ignore)
	end
	local bcObj = self.zoneCommander and self.zoneCommander.battleCommander
	if not bcObj or bcObj.spawnEvalEnabled == false then
		return self:shouldSpawn(ignore)
	end
	local decision = bcObj:_consumeShouldSpawnEval(self, triggerState, ignore)
	if decision == nil then
		bcObj:_queueShouldSpawnEval(self, triggerState, ignore)
	end
	return decision
end

function GroupCommander:shouldSpawn(ignore)
	local plane = Unit.Category.AIRPLANE
	local heli = Unit.Category.HELICOPTER
	local force = self.forceSpawn == true

	if self._dynamicHybridRetired == true then
		return false
	end

	if not self.zoneCommander.active then
		return false
	end

	if self.mission == 'supply' and self.side == 2 and NoAIBlueSupplies == true then
		return false
	end

	if self.ShopLaunchOnly and self._shopLaunchRequested ~= true then
		return false
	end

	if self.zoneCommander.battleCommander:isRunwayPlaneSpawnBlockedForGroup(self) then
		return false
	end

	if self.zoneCommander.suspended and not ignore and not force then
--[[ 		if not allow then
			return false
		end ]]
		local allowSuspendedShopSupply = self.mission == 'supply'
			and self.ShopLaunchOnly == true
			and self.side == 2
			and self._allowSuspendedShopSupplySpawn == true
		if self.mission ~= 'attack' and self.mission ~= 'patrol' and not allowSuspendedShopSupply then
			return false
		end
	end

	if self.side == 1 and self.zoneCommander.BlueIsNear and not force then
		self:_enterHangar(false)
		return false
	end

	local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)

	if not tg or tg.suspended or tg.active == false then return false end

	if force then
		if self.template then
			self:_ensureTemplateCache()
			local zside = self.zoneCommander.side
			if zside~=0 and self.side~=zside then
				local lst=self._tplBySide[zside]
				if lst and #lst>0 then self.side=zside else return false end
			end
			if self.side~=0 then
				local lst=self._tplBySide[self.side]
				if not lst or #lst==0 then return false end
			end
		end

		if self.side ~= self.zoneCommander.side then
			return false 
		end

		if self.MissionType == 'SEAD' then
			if not self.zoneCommander.battleCommander:HasSeadTargets(tg.zone) then
				return false
			end
			self.SpawnHot = true
		end

		return true
	end

	if self.template then
        self:_ensureTemplateCache()
        local zside = self.zoneCommander.side
        if zside~=0 and self.side~=zside then
            local lst=self._tplBySide[zside]
            if lst and #lst>0 then self.side=zside else return false end
        end
        if self.side~=0 then
            local lst=self._tplBySide[self.side]
            if not lst or #lst==0 then return false end
        end
    end

    if self.side ~= self.zoneCommander.side then
		return false 
	end
	
	if self.condition and self:condition() == false then return false end

	if self.Bluecondition then
		if self.side == 2 then
			if not self:Bluecondition() then return false end
	else
			return false
		end
	end

	if self.Redcondition then
		if self.side == 1 then
			if not self:Redcondition() then return false end
	else
			return false
		end
	end

	local isUrgent = type(self.urgent) == "function" and self.urgent() or self.urgent

	local distNm = Frontline.ZoneDistToFrontNm(self.targetzone)
	if distNm == nil then
		return false
	end

	if self.mission ~= 'supply' then
	
	local cutoff = (self.side == 2) and GlobalSettings.frontlineDistanceLimitBlue or GlobalSettings.frontlineDistanceLimitRed
	if distNm < -cutoff then return false end
	end
		

	if self.side==2 and self.MissionType=='CAP' then
		if distNm and distNm < -(GlobalSettings.capRearlineNmBlue or 30) then return false end
	end


	if self.side==1 and self.MissionType=='CAP' then
		if distNm and distNm < -(GlobalSettings.capRearlineNmRed or 60) then return false end
	end

  

    if tg and tg.active then
		if self.mission=='attack' and (self.MissionType=='CAS' or self.MissionType=='SEAD' or self.MissionType=='RUNWAYSTRIKE' or self.MissionType=='ANTISHIP') then
			if tg.side ~= self.side and tg.side ~= 0 then
				if self.side == 1 then
					if self.MissionType=='SEAD' and not self.zoneCommander.battleCommander:HasSeadTargets(tg.zone) then
						return false
					end
					local players = getRedCasPlayersCount() or 0
					if self.MissionType ~='CAS' and players == 0 then
						return false
					end
					local planeLimit = 0
					if self.MissionType=='CAS' then
						planeLimit = getRedCasLimit(players) or 0
					elseif self.MissionType=='SEAD' then
						planeLimit = getRedSeadLimit(players) or 0
					elseif self.MissionType=='RUNWAYSTRIKE' then
						planeLimit = getRedRunwayStrikeLimit(players) or 0
					elseif self.MissionType=='ANTISHIP' then
						planeLimit = getRedAntiShipLimit(players) or 0
					else
						planeLimit = getRedCasLimit(players) or 0
					end
					local heloBonus = 1
					local totalLimit = math.max(0, planeLimit) + heloBonus
					local activePlanes = self.zoneCommander.battleCommander:getActiveStrikeCount(1,'attack',self.MissionType,plane)
					local activeHelos = self.zoneCommander.battleCommander:getActiveStrikeCount(1,'attack',self.MissionType,heli)
					local activeTotal = self.zoneCommander.battleCommander:getActiveStrikeCount(1,'attack',self.MissionType,nil)

					-- Hybrid cap: keep plane limit from config, but allow one extra helicopter slot.
					if self.unitCategory == plane then
						if planeLimit <= 0 then return false end
						if activePlanes >= planeLimit then return false end
						return true
					elseif self.unitCategory == heli then
						if activeHelos >= heloBonus then return false end
						if activeTotal >= totalLimit then return false end
						return true
					end
					return false
				end
				if self.side==2 then
					if self.MissionType=='SEAD' and not self.zoneCommander.battleCommander:HasSeadTargets(tg.zone) then
						return false
					end
					local bluePlayers = getBluePlayersCount() or 0
					local playersCas = getBlueCasPlayersCount() or 0
					if self.MissionType=='ANTISHIP' and bluePlayers > 1 then return false end

					local limit = 0
					if self.MissionType=='CAS' then
						limit = getBlueCasLimit(playersCas) or 0
					elseif self.MissionType=='SEAD' then
						limit = getBlueSeadLimit(bluePlayers) or 0
					else
						-- RUNWAYSTRIKE / ANTISHIP follow blue CAS support scale.
						limit = getBlueCasLimit(playersCas) or 0
					end
					if limit <= 0 then return false end

					local active = self.zoneCommander.battleCommander:getActiveStrikeCount(2,'attack',self.MissionType,nil)
					if active >= limit then return false end
					return true
				end
			end
		end
		if self.mission == 'supply' then
			if tg.side == 0 and (not tg.firstCaptureByRed or self.ForceUrgent) then
				if isUrgent then return true end
			end
			if tg.side == self.side or tg.side == 0 then
				self.urgent = false
				if tg:canRecieveSupply() then
					local cap = (self.side==2) and (GlobalSettings.maxSupplyPerZoneBlue or 1) or (GlobalSettings.maxSupplyPerZoneRed or 2)
					local active = self.zoneCommander.battleCommander:getActiveSupplyCount(self.side, self.targetzone)
					if active >= cap and not self._paidSupplyParallelLaunch then return false end
					local cost = 0
					if self.side==2 and not isUrgent and getAnyPlayersCount() > 0 then
						local zones = bc.blueZoneCount or 0
						cost = math.min(zones * 10, 100)
						if (bc.accounts[2] ~= nil and bc.accounts[2] < cost) then
							env.info(string.format("[SUPPLY-SPAWN] not enough funds for supply in %s (have %d, need %d)", tg.zone, bc.accounts[2] or 0, cost))
							return false
						end
					end
					if self.side == 2 then
						self._pendingBlueSupplyCost = (cost > 0) and cost or nil
					end
					return true
				end
				return false
			end
			return false
		end

        if (self.mission == 'patrol') and (self.MissionType == 'CAP') then
            if tg.side == self.side then
                local bluePlayers = getBluePlayersCount() or 0
                local limit = (self.side==2) and getBlueCapLimit(bluePlayers) or getCapLimit(bluePlayers)
                local currentCap = bc:getActiveCAPCount(self.side, 'patrol')

                if self.side==2 and limit==0 then return false end
                if currentCap >= limit then
                    if DebugIsOn then
                        env.info(string.format("[DEBUG] CAP patrol limit reached: currentCap=%d, limit=%d, mission=%s", currentCap, limit, self.name))
                    end
                    return false
                end
                local capLeft = limit - currentCap
                if capLeft < 1 then capLeft = 1 end
                local zoneDistances, capMeta
				if self.side == 2 and bc.getCapSpawnRankingForSide then
					local capMetaSeed = {
						side = self.side,
						mission = 'patrol',
						bluePlayers = bluePlayers,
						limit = limit,
						currentCap = currentCap,
						capLeft = capLeft
					}
					zoneDistances, capMeta = bc:getCapSpawnRankingForSide('patrol', self.side, capMetaSeed)
				else
					zoneDistances, capMeta = getClosestCapZonesToPlayers('patrol', self.side, nil)
				end
				if #zoneDistances==0 then return true end
                local capWindow = math.min(#zoneDistances, capLeft)
                local tgRank=nil; for i=1,#zoneDistances do if zoneDistances[i].zone==tg.zone then tgRank=i break end end
                
				local enemyAdj = (capMeta and capMeta.enemyAdj and capMeta.enemyAdj[tg.zone]) or false
                
				local bonusTop = math.max(3, capWindow)
                if not tgRank or (tgRank>capWindow and not (enemyAdj and tgRank<=bonusTop)) then
                    if DebugIsOn then
                        env.info(string.format("[DEBUG] CAP patrol is not within the top %d zones; skipping spawn: mission=%s", capWindow, self.name))
                        local topN = math.min(capWindow, #zoneDistances)
                        for i=1,topN do
                            local zdi=zoneDistances[i]
                            env.info(string.format("[CAP TOP] #%d %s dist=%.0f", i, zdi.zone, zdi.distance))
                        end
                    end
                    self:_enterHangar(false)
                    return false
                end
                local ctx = capMeta and capMeta.targets and capMeta.targets[tg.zone]
                if ctx then
                    local myRank = ctx.ranksByName and ctx.ranksByName[self.name] or nil
                    local capLeft = capMeta and capMeta.capLeft or (limit - currentCap)
                    if myRank then
                        local activeAhead=0
                        for i=1,myRank-1 do
                            local rec=ctx.candidates[i]
                            local gc=CapRef and CapRef[rec.name]
                            local st=gc and gc.state or rec.state
                            if st=='preparing' then activeAhead=activeAhead+1 end
                        end
                        if activeAhead>=capLeft then
                            self:_enterHangar(false)
                            return false
                        end
                    end
                end
                if DebugIsOn then
                    env.info(string.format("[CAP PATROL] target=%s rank=%s capWindow=%d", tg.zone, tostring(tgRank), capWindow))
                    local topN = math.min(capWindow, #zoneDistances)
                    for i=1,topN do
                        local zdi=zoneDistances[i]
                        env.info(string.format("[CAP TOP] #%d %s dist=%.0f", i, zdi.zone, zdi.distance))
                    end
                end
                return true
            end
            return false
        end

        if (self.mission == 'attack') and (self.MissionType == 'CAP') then
            if tg.side ~= self.side and tg.side ~= 0 then
                local bluePlayers = getBluePlayersCount() or 0
                local limit = (self.side==2) and getBlueCapLimit(bluePlayers) or getCapLimit(bluePlayers)
                local currentCap = bc:getActiveCAPCount(self.side, 'attack')
                if self.side==2 and limit==0 then return false end
                if currentCap >= limit then
                    if DebugIsOn then
                        env.info(string.format("[DEBUG] CAP attack limit reached: currentCap=%d, limit=%d, mission=%s", currentCap, limit, self.name))
                    end
                    return false
                end
                local capLeft = limit - currentCap
                if capLeft < 1 then capLeft = 1 end
                local zoneDistances, capMeta
				if self.side == 2 and bc.getCapSpawnRankingForSide then
					local capMetaSeed = {
						side = self.side,
						mission = 'attack',
						bluePlayers = bluePlayers,
						limit = limit,
						currentCap = currentCap,
						capLeft = capLeft
					}
					zoneDistances, capMeta = bc:getCapSpawnRankingForSide('attack', self.side, capMetaSeed)
				else
					zoneDistances, capMeta = getClosestCapZonesToPlayers('attack', self.side, nil)
				end
				if #zoneDistances==0 then return true end
                local capWindow = math.min(#zoneDistances, capLeft)

                local tgRank=nil; for i=1,#zoneDistances do if zoneDistances[i].zone==tg.zone then tgRank=i break end end
				
				local enemyAdj = (capMeta and capMeta.enemyAdj and capMeta.enemyAdj[tg.zone]) or false
                
				local bonusTop = math.max(3, capWindow)
                if not tgRank or (tgRank>capWindow and not (enemyAdj and tgRank<=bonusTop)) then
                    if DebugIsOn then
                        env.info(string.format("[DEBUG] attack CAP is not within the top %d zones; skipping spawn: mission=%s", capWindow, self.name))
                    end
                    return false
                end
                local ctx = capMeta and capMeta.targets and capMeta.targets[tg.zone]
                if ctx then
                    local myRank = ctx.ranksByName and ctx.ranksByName[self.name] or nil
                    local capLeft = capMeta and capMeta.capLeft or (limit - currentCap)
                    if myRank then
                        local activeAhead=0
                        for i=1,myRank-1 do
                            local rec=ctx.candidates[i]
                            local gc=CapRef and CapRef[rec.name]
                            local st=gc and gc.state or rec.state
                            if st=='preparing' then activeAhead=activeAhead+1 end
                        end
                        if activeAhead>=capLeft then
                            return false
                        end
                    end
                end
                return true
            end
        end


        if (self.mission == 'attack') and not (self.MissionType == 'CAP' or self.MissionType == 'CAS' or self.MissionType == 'SEAD' or self.MissionType == 'RUNWAYSTRIKE') then
            if tg.side ~= self.side and tg.side ~= 0 then
				return true
            end
        end

		if (self.mission == 'patrol') and not (self.MissionType == 'CAP' or self.MissionType == 'CAS' or self.MissionType == 'SEAD') then
            if tg.side == self.side then
                return true
            end
        end

        return false
    end
    return false
end

	function GroupCommander:clearWreckage()
		local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
		tg:clearWreckage()
	end

function GroupCommander:_jtacMessage(txt, instant, z, soundFile)
    z = z or self.targetzone or (self.zoneCommander and self.zoneCommander.zone)
    if not z then return false end
    for _,v in ipairs(jtacQueue or {}) do
        if v.tgtzone and v.tgtzone.zone and v.tgtzone.zone == z then
            if instant then
                if soundFile then trigger.action.outSoundForCoalition(2, soundFile) end
                trigger.action.outTextForCoalition(2, txt..' '..z, 25)
            else
                timer.scheduleFunction(
                    function(args)
                        if args.soundFile then trigger.action.outSoundForCoalition(2, args.soundFile) end
                        trigger.action.outTextForCoalition(2, args.txt..' '..args.z, 25)
                    end,
                    { txt = txt, z = z, soundFile = soundFile }, timer.getTime() + math.random(30,60)
                )
            end
            return true
        end
    end
    return false
end

function GroupCommander:_spawnFromGroundAt(resolved, originZone, targetZone, hot)
	if self.unitCategory == Unit.Category.AIRPLANE then return nil end
    local tpl = self:_getAirTemplate(resolved); if not tpl then return nil end
    local base = originZone and (originZone.."-land") or nil
    local pool = (base and _getLandingSpotPoolForPrefix(base)) or nil
    if pool and #pool == 0 then
        pool = _getForcedLandingSpotPool(originZone)
    end
    local p
    if pool and #pool>0 then
        LandingSpotsUsedIndex = LandingSpotsUsedIndex or {}
        local idx = ((LandingSpotsUsedIndex[base] or 0) % #pool) + 1
        LandingSpotsUsedIndex[base] = idx
        p = pool[idx]
    else
		local lz = self:_findFlatLZ(originZone, 50, 0.06)
		if lz then p = { name = string.format("%s-flat", originZone or "unknown"), x=lz.x, z=lz.z } end
    end
    if not p then return nil end
    local jitter = 20
    local lx, lz = p.x + math.random(-jitter,jitter), p.z + math.random(-jitter,jitter)

    local ly = land.getHeight({x=lx, y=lz})
    tpl.x = lx; tpl.y = lz
    tpl.route = tpl.route or {}; tpl.route.points = tpl.route.points or {}; tpl.route.points[1] = tpl.route.points[1] or {}
	tpl.route.points[1].type = hot and "TakeOffGroundHot" or "TakeOffGround"; tpl.route.points[1].action = hot and "From Ground Area Hot" or "From Ground Area"; tpl.route.points[1].x = lx; tpl.route.points[1].y = lz; tpl.route.points[1].alt = 0; tpl.route.points[1].alt_type = "RADIO"
	for i=1,#tpl.units do local u=tpl.units[i]; local dx=(#tpl.units==2) and 0 or (i-1)*4; local dy=(#tpl.units==2) and ((i==1) and -15 or 15) or 0; u.x=lx+dx; u.y=lz+dy; u.alt=ly; u.parking=nil; u.parking_id=nil end
    self._lastGroundSpawnSpot = { zone = p.name or base or originZone, x = lx, z = lz }
    local sp = SPAWN:NewFromTemplate(tpl, resolved, self:_getSpawnAlias(), true)
    if self.mission=='supply' and self.unitCategory==Unit.Category.HELICOPTER then
		if WarehouseLogistics == true and (not self.NotCargo) then
        sp = sp:OnSpawnGroup(function(g)timer.scheduleFunction(function()
			local assigned = self:_assignHeloLogisticsRoute(g:GetName(), self.targetzone, originZone, self.side)
			if assigned ~= true then
				self._pendingSupplyLaunchMessage = nil
			end
		end, {}, timer.getTime() + 10) end)
	else
		 sp = sp:OnSpawnGroup(function(g)
			local assigned = self:_assignHeloRoute(g:GetName(), self.targetzone)
			if assigned ~= true then
				self._pendingSupplyLaunchMessage = nil
			end
		 end)
		end
    elseif self.MissionType=='CAS' and self.unitCategory==Unit.Category.HELICOPTER and self.template then
        sp = sp:OnSpawnGroup(function(g) bc:EngageHeloCasMission(self.targetzone, g:GetName(), nil, nil, self._landUnitID) end)
    elseif self.MissionType=='CAS' and self.unitCategory==Unit.Category.AIRPLANE and self.template then
        sp = sp:OnSpawnGroup(function(g) bc:EngageCasMission(self.targetzone, g:GetName(), nil, nil, self.Altitude or self.AltitudeFt, self._landUnitID) end)
    end
	local spawned = sp:Spawn()
	if spawned then
		self._lastSpawnTemplate = resolved
	end
    return spawned
end

function GroupCommander:_spawnFromGroundAtCtldFarp(spawnObj, farpAb, farpLaunch, hot)
	if self.unitCategory ~= Unit.Category.HELICOPTER then return nil end
	if not spawnObj or not spawnObj.SpawnTemplate or not farpAb then return nil end

	local tpl = spawnObj.SpawnTemplate
	local units = tpl.units or {}
	if #units == 0 then return nil end

	local termType = AIRBASE.TerminalType.HelicopterUsable
	local spots = farpAb:GetFreeParkingSpotsTable(termType, false) or {}
	if #spots == 0 then
		local spots2 = farpAb:GetFreeParkingSpotsTable(termType, true) or {}
		if #spots2 > #spots then spots = spots2 end
	end
	if #spots == 0 then
		spots = farpAb:GetParkingSpotsTable(termType) or {}
	end
	if #spots == 0 then return nil end

	table.sort(spots, function(a, b) return (a.TerminalID or 0) < (b.TerminalID or 0) end)

	local bcObj = self.zoneCommander and self.zoneCommander.battleCommander or nil
	if bcObj then
		bcObj._ctldFarpGroundSpawnState = bcObj._ctldFarpGroundSpawnState or {}
	end
	local farpName = farpLaunch and farpLaunch.name or (farpAb.GetName and farpAb:GetName() or nil)
	local state = bcObj and farpName and bcObj._ctldFarpGroundSpawnState[farpName] or nil
	local startIndex = state and tonumber(state.index) or 0
	local spotIndex = (startIndex % #spots) + 1
	if bcObj and farpName then
		bcObj._ctldFarpGroundSpawnState[farpName] = { index = spotIndex }
	end

	local firstSpot = spots[spotIndex]
	local firstCoord = firstSpot and firstSpot.Coordinate or nil
	if not firstCoord then return nil end
	local firstVec2 = firstCoord:GetVec2()
	local lx = firstCoord.x or firstVec2.x
	local lz = firstCoord.z or firstVec2.y
	local ly = land.getHeight({ x = lx, y = lz })

	tpl.x = lx
	tpl.y = lz
	tpl.route = tpl.route or {}
	tpl.route.points = tpl.route.points or {}
	tpl.route.points[1] = tpl.route.points[1] or {}
	tpl.route.points[1].type = hot and "TakeOffGroundHot" or "TakeOffGround"
	tpl.route.points[1].action = hot and "From Ground Area Hot" or "From Ground Area"
	tpl.route.points[1].x = lx
	tpl.route.points[1].y = lz
	tpl.route.points[1].alt = 0
	tpl.route.points[1].alt_type = "RADIO"

	for i = 1, #units do
		local spot = spots[((spotIndex + i - 2) % #spots) + 1]
		local coord = spot and spot.Coordinate or nil
		local vec2 = coord and coord:GetVec2() or nil
		local ux = (coord and coord.x) or (vec2 and vec2.x) or (lx + (i - 1) * 4)
		local uz = (coord and coord.z) or (vec2 and vec2.y) or lz
		local uy = land.getHeight({ x = ux, y = uz })
		local u = units[i]
		u.x = ux
		u.y = uz
		u.alt = uy
		u.parking = nil
		u.parking_id = nil
	end

	return spawnObj:Spawn()
end

function GroupCommander:_getAirTemplate(resolved)
	local grp = GROUP:FindByName(resolved)
	local tpl = (_DATABASE.Templates.Groups[resolved] and UTILS.DeepCopy(_DATABASE.Templates.Groups[resolved].Template)) or (grp and grp:GetTemplate())
	return tpl
end

function GroupCommander:_getAirType()
	local gr = Group.getByName(self.name)
	if gr then
		local u = gr:getUnit(1)
		if u then
			local name = UTILS.GetReportingName(u:getTypeName())
			name = name:gsub("_%u$", ""):gsub("_", " ")
			local cnt  = gr:getSize()
			if cnt and cnt > 1 then
				return cnt .. " enemy " .. name .. "s"
			end
			return "enemy " .. name
		end
	end
	return "enemy Bogey"
end

	function GroupCommander:_getDcsGroupCached()
		local currentName = self.spawnedName or self.name
		if self._dcsGroup and self._dcsGroup:isExist() and self._dcsGroup:getName() == currentName then
			return self._dcsGroup
		end
		if not currentName then return nil end
		local gr = Group.getByName(currentName)
		if gr and gr:isExist() then
			self._dcsGroup = gr
			return gr
		end
		self._dcsGroup = nil
		return nil
	end

	function GroupCommander:_resolveRestoreHome(originZone)
		local out = { originZone = originZone or self.zoneCommander.zone, landUnitID = nil, airbaseName = nil, homeVec2 = nil }
		local originName = out.originZone
		if not originName then return out end
		local oz = self.zoneCommander.battleCommander:getZoneByName(originName)
		local abn = oz and oz.airbaseName or nil
		if abn then
			local ab = AIRBASE:FindByName(abn)
			if ab and ab.GetID then
				out.landUnitID = ab:GetID()
				out.airbaseName = abn
				return out
			end
		end

		local prefix = originName .. "-land"
		local pool = _getLandingSpotPoolForPrefix(prefix)
		if (not pool or #pool == 0) then
			pool = _getForcedLandingSpotPool(originName)
		end
		if pool and #pool > 0 then
			local pick = pool[1]
			if pick then
				out.homeVec2 = { x = pick.x, y = pick.z }
			end
		end
		return out
	end

	function GroupCommander:_getRestoreCasSpawnPoint(savedX, savedZ, originZone)
		if self.MissionType ~= 'CAS' then return savedX, savedZ end

		local home = self:_resolveRestoreHome(originZone)
		local anchor = home.homeVec2 or (originZone and zoneCentroid(originZone)) or { x = savedX, y = savedZ }
		local targetPoint = nil

		if self.unitCategory == Unit.Category.HELICOPTER then
			targetPoint = zoneCentroid(self.targetzone)
		else
			local zn = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
			if zn and zn.built then
				for _, v in pairs(zn.built) do
					local p = self.zoneCommander.battleCommander:getTargetPos(v)
					if p then
						targetPoint = { x = p.x, y = p.z }
						break
					end
					local gg = Group.getByName(v)
					if gg and gg:getSize() > 0 then
						local gp = gg:getUnit(1):getPoint()
						targetPoint = { x = gp.x, y = gp.z }
						break
					end
				end
			end
			targetPoint = targetPoint or zoneCentroid(self.targetzone)
		end
		if not (anchor and targetPoint) then return savedX, savedZ end

		local dx = targetPoint.x - anchor.x
		local dz = targetPoint.y - anchor.y
		local len = math.sqrt(dx * dx + dz * dz)
		if len <= 1 then return savedX, savedZ end
		local ux = dx / len
		local uz = dz / len

		local engageDistanceNm = (self.unitCategory == Unit.Category.HELICOPTER) and 5.0 or 20.0
		local clampBufferNm = 1.0
		local engageX = targetPoint.x - ux * UTILS.NMToMeters(engageDistanceNm)
		local engageZ = targetPoint.y - uz * UTILS.NMToMeters(engageDistanceNm)

		local savedProj = ((savedX - anchor.x) * ux) + ((savedZ - anchor.y) * uz)
		local engageProj = ((engageX - anchor.x) * ux) + ((engageZ - anchor.y) * uz)
		if savedProj <= engageProj then
			return savedX, savedZ
		end

		return engageX - ux * UTILS.NMToMeters(clampBufferNm), engageZ - uz * UTILS.NMToMeters(clampBufferNm)
	end

	function GroupCommander:_assignRestoreRtb(groupName, originZone)
		local gr = Group.getByName(groupName)
		if not gr or not gr:isExist() or gr:getSize() == 0 then return end
		local gmoose = GROUP:FindByName(groupName)
		if not gmoose or not gmoose:IsAlive() then return end

		local home = self:_resolveRestoreHome(originZone)
		if home.landUnitID then
			self._landUnitID = home.landUnitID
		end
		if home.airbaseName then
			self.Airbase = home.airbaseName
		end

		local unit = gr:getUnit(1)
		if not unit then return end
		local pos = unit:getPoint()
		local speedKmh = (self.unitCategory == Unit.Category.HELICOPTER) and UTILS.MpsToKmph(70) or UTILS.MpsToKmph(280)
		local landKmh = (self.unitCategory == Unit.Category.HELICOPTER) and UTILS.MpsToKmph(50) or UTILS.KnotsToKmph(300)
		local alt = tonumber(pos.y) or land.getHeight({ x = pos.x, y = pos.z })

		local wp = {}
		wp[#wp+1] = COORDINATE:New(pos.x, alt, pos.z):WaypointAirTurningPoint("RADIO", speedKmh, {}, "Restore RTB")
		if self._landUnitID then
			local ab = AIRBASE:FindByID(self._landUnitID)
			if ab then
				wp[#wp+1] = ab:GetCoordinate():WaypointAirLanding(landKmh, ab, {}, "RTB Land (Airbase)")
			end
		end
		if #wp == 1 then
			local lx = home.homeVec2 and tonumber(home.homeVec2.x) or pos.x
			local ly = home.homeVec2 and tonumber(home.homeVec2.y) or pos.z
			wp[#wp+1] = COORDINATE:New(lx, 0, ly):WaypointAirTurningPoint(
				"RADIO", landKmh, { gmoose:TaskLandAtVec2({ x = lx, y = ly }, nil, false, nil) }, "RTB Land (Vec2)"
			)
		end
		gmoose:Route(wp, 1)
	end

	function GroupCommander:_assignMissionAfterInAirRestore(groupName, originZone)
		local gr = Group.getByName(groupName)
		if not gr or not gr:isExist() or gr:getSize() == 0 then return end
		local home = self:_resolveRestoreHome(originZone)
		local side = self._sortieSide or self.side
		self.side = side
		local restoreSavedSide = tonumber(self._restoreSavedSide) or self.side
		local approachFromVec2 = home.homeVec2 or (originZone and zoneCentroid(originZone)) or nil
		if home.landUnitID then
			self._landUnitID = home.landUnitID
		end
		if home.airbaseName then
			self.Airbase = home.airbaseName
		end

		if self.mission == 'attack' and self.MissionType ~= 'CAP' then
			local originState = self.zoneCommander.battleCommander:getZoneByName(originZone)
			local targetZone = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
			if targetZone and (not originState or originState.side == restoreSavedSide) and (targetZone.side == 0 or targetZone.side == restoreSavedSide) then
				self._restoreSavedSide = nil
				self:_assignRestoreRtb(groupName, originZone)
				return
			end
		end
		self._restoreSavedSide = nil

		if self.MissionType == 'CAP' and self.mission == 'patrol' then
			local savedPoint = self._currentCapHoldingPoint
			local safe = tonumber(self._currentCapBufferNm) or ((side == 1) and 35 or 30)
			local st = savedPoint and savedPoint.x and (savedPoint.z or savedPoint.y) and { x = savedPoint.x, y = savedPoint.z or savedPoint.y } or nil
			if not st then
				local towardEnemyNm = 30
				local off = (side == 2) and -towardEnemyNm or towardEnemyNm
				st = Frontline.PickStationNearZone(self.targetzone, side, off, 0, 0, 0, safe)
			end
			if not st then return end
			local dist = tonumber(self._currentCapOrbitDistanceNm) or ((side == 1) and math.random(30, 40) or math.random(30, 40))
			SetUpCAP(gr, { x = st.x, z = st.y }, self.Altitude, dist, self._landUnitID, safe, side)
			self._currentCapHoldingPoint = { x = st.x, z = st.y }
			self._currentCapOrbitDistanceNm = dist
			self._currentCapBufferNm = safe
		elseif self.MissionType == 'CAP' and self.mission == 'attack' then
			local savedPoint = self._currentCapHoldingPoint
			local offsetNm = tonumber(self._currentCapBufferNm) or ((side == 1) and 35 or 25)
			local st = savedPoint and savedPoint.x and (savedPoint.z or savedPoint.y) and { x = savedPoint.x, y = savedPoint.z or savedPoint.y } or nil
			if not st then
				st = Frontline.PickCapStationFromOrigin(originZone, self.targetzone, side, 100, offsetNm)
			end
			if not st then return end
			local dist = tonumber(self._currentCapOrbitDistanceNm) or ((side == 1) and math.random(35, 45) or math.random(35, 40))
			SetUpCAP(gr, { x = st.x, z = st.y }, self.Altitude, dist, self._landUnitID, offsetNm, side)
			self._currentCapHoldingPoint = { x = st.x, z = st.y }
			self._currentCapOrbitDistanceNm = dist
			self._currentCapBufferNm = offsetNm
		elseif self.mission == 'supply' and (self.unitCategory == Unit.Category.HELICOPTER or self.unitCategory == Unit.Category.AIRPLANE) then
			local targetZone = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
			local returnZone = originZone or self.zoneCommander.zone
			local validSupplyTarget = targetZone and targetZone.active and (targetZone.side == 0 or targetZone.side == side)
			local restoreReturnHome = self._restoreSupplyReturnHome == true
			self._restoreSupplyReturnHome = nil
			local shouldReturnHome = restoreReturnHome or not validSupplyTarget

			if shouldReturnHome then
				self._supplyReturnHome = true
			else
				self._supplyReturnHome = nil
			end

			if self.unitCategory == Unit.Category.HELICOPTER then
				if not shouldReturnHome then
					self:_assignHeloRoute(groupName, self.targetzone)
				else
					self:_assignHeloRoute(groupName, returnZone)
				end
			else
				if not shouldReturnHome then
					self:_assignPlaneRoute(groupName, self.targetzone, self.Altitude, originZone, side, true)
				else
					self:_assignPlaneRoute(groupName, returnZone, self.Altitude, originZone, side, true)
				end
			end
		elseif self.MissionType == 'CAS' and self.unitCategory == Unit.Category.AIRPLANE then
			bc:EngageCasMission(self.targetzone, groupName, nil, nil, self.Altitude, self._landUnitID, side, approachFromVec2, true)
		elseif self.MissionType == 'CAS' and self.unitCategory == Unit.Category.HELICOPTER then
			bc:EngageHeloCasMission(self.targetzone, groupName, nil, nil, self._landUnitID, home.homeVec2, approachFromVec2, true)
		elseif self.MissionType == 'SEAD' and self.unitCategory == Unit.Category.AIRPLANE then
			bc:EngageSeadMission(self.targetzone, groupName, nil, self.Altitude, self._landUnitID)
		elseif self.MissionType == 'RUNWAYSTRIKE' and self.unitCategory == Unit.Category.AIRPLANE then
			bc:EngageRunwayBombing(self.zoneCommander.airbaseName, self.targetzone, groupName, self.Altitude, side)
		elseif self.MissionType == 'ANTISHIP' and self.unitCategory == Unit.Category.AIRPLANE then
			bc:EngageAntiShipMission(self.targetzone, groupName, nil, nil, self.Altitude, self._landUnitID)
		end
	end

	ProblemGroups = {}
	function GroupCommander:processAir()
		local originZone = self.zoneCommander.zone
		local gr = self:_getDcsGroupCached()
		--local gr = Group.getByName(self.spawnedName or self.name)
		local zside = self.zoneCommander.side
		local plane = Unit.Category.AIRPLANE
		local heli = Unit.Category.HELICOPTER
		if self.unitCategory and self.unitCategory ~= plane and self.unitCategory ~= heli then
			if not self._processAirErrorReported then
				trigger.action.outText("GroupCommander:processAir called for non-air unit "..tostring(self.name).." Report it to leka",30)
				self._processAirErrorReported = true
			end
			return
		end
		
		if self._sortieSide then
			self.side = self._sortieSide
		elseif self.template then
			if zside and zside ~= 0 and zside ~= self.side then self.side = zside end
		end

		local coalition = self.side
		local isUrgent = type(self.urgent) == "function" and self.urgent() or self.urgent
		--local respawnTimers = isUrgent and GlobalSettings.urgentRespawnTimers or GlobalSettings.respawnTimers[coalition][self.mission]
		local rt=GlobalSettings.respawnTimers
		local respawnTimers=isUrgent and GlobalSettings.urgentRespawnTimers or (rt and rt[coalition] and rt[coalition][self.mission])
		if not respawnTimers then if coalition ~= 0 then local reason=(not rt and "GlobalSettings.respawnTimers") or (rt[coalition]==nil and ("respawnTimers["..tostring(coalition).."]")) or ("respawnTimers["..tostring(coalition).."]["..tostring(self.mission).."]"); local msg="ERROR: Report to Leka and send log! respawnTimers nil "..reason.." name="..tostring(self.name).." mission="..tostring(self.mission).." side="..tostring(coalition).." urgent="..tostring(isUrgent); env.info(msg); trigger.action.outText(msg,30); ProblemGroups[self.name]=true end; return end

		local spawnDelayFactor = self.spawnDelayFactor or 1
		
		
		if self.mission == 'supply' and not isUrgent and self.side == 1 then
			local pc = getBluePlayersCount()
			if pc == 0 then
				spawnDelayFactor = spawnDelayFactor * 1.5
			elseif pc == 1 then
				spawnDelayFactor = spawnDelayFactor * 1.3
			end
		end
		
		if self.Spawned then self.Spawned = false end

		if (not gr) or (not gr:isExist()) or (gr:getSize() == 0) then
			if gr and gr:getSize() == 0 then
				gr:destroy()
			end

			self:_destroyLogiCargo()

			if self.state ~= 'inhangar' and self.state ~= 'preparing' and self.state ~= 'dead' then
				local now = timer.getAbsTime()
				local blueSupplyHelo = self.side == 2
					and self.mission == 'supply'
					and self.unitCategory == heli
					and not self._supplyReturnHome
				if blueSupplyHelo
					and (self.state == 'takeoff' or self.state == 'inair')
					and not self._supplyCtldFarpTakeoff
					and self._supplyEarlyDeathRetried ~= true
				then
					local age = now - (self.lastStateTime or now)
					if age < 60 then
						return
					elseif age <= 120 then
						self._supplyEarlyDeathRetried = true
						self:_resetSupplyHeloToPreparing(originZone, {
							now = now,
							destroyCargo = false,
							retryNoCargo = true,
							skipBlockedHelo = true,
						})
						return
					end
				end
				self:_removeFromSuspendedLiveFsm()
				self.state = 'dead'
				self.lastStateTime = now
			end
		end

		local ctldFarpLaunch = self._supplyCtldFarpTakeoff
		if self.mission == 'supply' and self.unitCategory == heli and ctldFarpLaunch and not self._supplyReturnHome then
			local now = timer.getAbsTime()
			local existsCheckAt = self._supplyCtldFarpExistenceCheckAt
			if existsCheckAt and now >= existsCheckAt then
				self._supplyCtldFarpExistenceCheckAt = nil
				if not (gr and gr:isExist() and gr:getSize() > 0) then
					self:_resetSupplyHeloToPreparing(originZone, {
						now = now,
						destroyCargo = false,
					})
					return
				end
			end
			local checkAt = self._supplyCtldFarpTakeoffCheckAt or ((self.lastStateTime or now) + 180)
			if now >= checkAt then
				self:_clearSupplyLaunchState({ keepPendingFarp = true, keepActiveFarp = true })
				if gr and gr:isExist() and self:_isGroupInCtldFarpLaunchZone(gr, ctldFarpLaunch) then
					self:_destroyLogiCargo()
					if gr and gr:isExist() then gr:destroy() end
					self:_resetSupplyHeloToPreparing(originZone, {
						now = timer.getAbsTime(),
						destroyCargo = false,
						message = false,
						pendingFarpLaunch = {
							name = ctldFarpLaunch.name,
							x = ctldFarpLaunch.x,
							z = ctldFarpLaunch.z,
							routeOnly = true,
						},
					})
					return
				end
			end
		elseif self._supplyCtldFarpTakeoff or self._supplyCtldFarpTakeoffCheckAt or self._supplyCtldFarpExistenceCheckAt then
			self:_clearSupplyLaunchState({ keepPendingFarp = true, keepActiveFarp = true })
		end

    if self.state == 'inhangar' then
        if timer.getAbsTime() - self.lastStateTime > (respawnTimers.hangar * spawnDelayFactor) then
            if self.diceChance and self.diceChance > 0 and not self.diceRolled then
                self.diceRolled = true
                local roll = math.random(1, 100)
                if roll > self.diceChance then
                    self:_removeFromSuspendedLiveFsm()
                    self.state = 'dead'
                    self.lastStateTime = timer.getAbsTime()
                    self.diceRolled = false
                    return
                end
            end

            local canSpawn = self:_consumeShouldSpawnDecision('inhangar', false)
            if canSpawn == nil then return end
            if canSpawn then
                self.state = 'preparing'
                self.lastStateTime = timer.getAbsTime()
			else
				self:_enterHangar(false)
			end
        end
	elseif self.state == 'preparing' then
		if timer.getAbsTime() - self.lastStateTime > respawnTimers.preparing then
			local restoreData = self._pendingInAirRestore
			if restoreData then
				self._pendingInAirRestore = nil
				local savedPos = restoreData.position
				local px = savedPos and tonumber(savedPos.x)
				local pz = savedPos and tonumber(savedPos.z)
				local py = savedPos and tonumber(savedPos.y)
				if not px or not pz then
					env.info("[AirPersistence] invalid restore position for "..tostring(self.name))
					self:_enterHangar(false)
					return
				end

				local restoreTemplate = restoreData.templateName or self._lastSpawnTemplate
				if (not restoreTemplate or restoreTemplate == "") and self._resolveTemplateName then
					restoreTemplate = self:_resolveTemplateName()
				end
				if not restoreTemplate or restoreTemplate == "" then
					env.info("[AirPersistence] missing restore template for "..tostring(self.name))
					self:_enterHangar(false)
					return
				end

				local restoreOriginZone = restoreData.originZone or restoreData.zoneName or originZone
				if self.MissionType == 'CAS' then
					px, pz = self:_getRestoreCasSpawnPoint(px, pz, restoreOriginZone)
				elseif self.mission == 'supply' and self.unitCategory == Unit.Category.HELICOPTER then
					local restoreTargetZone = self.targetzone
					local restoreSide = tonumber(restoreData.side) or self.side
					local targetZone = self.zoneCommander.battleCommander:getZoneByName(restoreTargetZone)
					local validSupplyTarget = targetZone and targetZone.active and (targetZone.side == 0 or targetZone.side == restoreSide)
					local restoreReturnHome = restoreData.supplyReturnHome == true
					local restoreDestinationZone = (restoreReturnHome or not validSupplyTarget) and restoreOriginZone or restoreTargetZone
					local restoreApproachZone = (restoreReturnHome or not validSupplyTarget) and restoreTargetZone or restoreOriginZone
					local approachPoint = restoreApproachZone and zoneCentroid(restoreApproachZone) or nil
					px, pz = self:_getRestoreHeloSupplySpawnPoint(px, pz, restoreDestinationZone, approachPoint and approachPoint.x or nil, approachPoint and approachPoint.y or nil)
				elseif self.mission == 'supply' and self.unitCategory == Unit.Category.AIRPLANE then
					local restoreAlt
					local restoreTargetZone = self.targetzone
					local restoreSide = tonumber(restoreData.side) or self.side
					local targetZone = self.zoneCommander.battleCommander:getZoneByName(restoreTargetZone)
					local validSupplyTarget = targetZone and targetZone.active and (targetZone.side == 0 or targetZone.side == restoreSide)
					local restoreReturnHome = restoreData.supplyReturnHome == true
					local restoreDestinationZone = (restoreReturnHome or not validSupplyTarget) and restoreOriginZone or restoreTargetZone
					local restoreApproachZone = (restoreReturnHome or not validSupplyTarget) and restoreTargetZone or restoreOriginZone
					local approachPoint = restoreApproachZone and zoneCentroid(restoreApproachZone) or nil
					px, pz, restoreAlt = self:_getRestorePlaneSupplySpawnPoint(px, pz, restoreDestinationZone, self.Altitude, approachPoint and approachPoint.x or nil, approachPoint and approachPoint.y or nil)
					if restoreAlt then py = restoreAlt end
				end

				local headingDeg = tonumber(restoreData.headingDeg) or 0
				if headingDeg < 0 then headingDeg = headingDeg + 360 end
				local groundY = land.getHeight({ x = px, y = pz })
				py = py or groundY
				if self.unitCategory == Unit.Category.HELICOPTER then
					local minAgl = 60
					local maxAgl = 300
					local savedAgl = py - groundY
					if savedAgl < minAgl then savedAgl = minAgl end
					if savedAgl > maxAgl then savedAgl = maxAgl end
					py = groundY + UTILS.FeetToMeters(1500)
				end

				local tpl = self:_getAirTemplate(restoreTemplate)
				if not tpl or not tpl.units or #tpl.units == 0 then
					env.info("[AirPersistence] missing restore template data for "..tostring(self.name).." template="..tostring(restoreTemplate))
					self:_enterHangar(false)
					return
				end

				local ht = _getHeadingTrig(headingDeg)
				local h = ht.h
				local psi = ht.psi
				local c, s = ht.cos, ht.sin
				local refX, refZ = tpl.units[1].x, tpl.units[1].y
				for _,u in ipairs(tpl.units) do
					local dx, dz = u.x-refX, u.y-refZ
					u.x = px + dx*c - dz*s
					u.y = pz + dx*s + dz*c
					u.heading = h
					u.psi = psi
					u.alt = py
				end

				local d = 2 * 1852
				local wpX = px + d*math.cos(h)
				local wpZ = pz + d*math.sin(h)
				tpl.route = tpl.route or { points = {} }
				tpl.route.points = tpl.route.points or {}
				tpl.route.points[1] = {
					type = "Turning Point",
					action = "Turning Point",
					x = tpl.units[1].x,
					y = tpl.units[1].y,
					alt = py,
					alt_type = "BARO",
					speed = tpl.units[1].speed or 380,
					psi = psi,
					task = { id = "ComboTask", params = { tasks = {} } }
				}
				tpl.route.points[2] = {
					type = "Turning Point",
					action = "Turning Point",
					x = wpX,
					y = wpZ,
					alt = py,
					alt_type = "BARO",
					speed = tpl.route.points[1].speed,
					psi = psi,
					task = { id = "ComboTask", params = { tasks = {} } }
				}

				local wantedAlive = math.max(0, math.floor(tonumber(restoreData.aliveCount) or 0))
				local elapsed = tonumber(restoreData.lastStateDuration) or 0
				if elapsed < 0 then elapsed = 0 end

				self:clearWreckage()
				local sp = SPAWN:NewFromTemplate(tpl, restoreTemplate, self:_getSpawnAlias(), true)
				local SpawnSkill = (self.side == 1) and tostring(AiPlaneSkill or "Excellent") or "Excellent"
				sp = sp:InitSkill(SpawnSkill):OnSpawnGroup(function(g)
					local gname = g and g.GetName and g:GetName() or self.name
					self.spawnedName = gname
					self._lastSpawnTemplate = restoreTemplate
					self._restoreSavedSide = tonumber(restoreData.side) or self.side
					self._sortieSide = tonumber(restoreData.side) or self.side
					self.side = self._sortieSide
					self.Spawned = true
					self.state = 'inair'
					self.pinged = false
					self._zonePinged = nil
					self._landedAt = nil
					self.lastStateTime = timer.getAbsTime() - elapsed
					self.zoneCommander:_forceIncludeRestoreLiveGc(self)

					local dcsGroup = Group.getByName(gname)
					self._dcsGroup = dcsGroup
					if dcsGroup and dcsGroup:isExist() and wantedAlive > 0 then
						local currentSize = dcsGroup:getSize() or 0
						if currentSize > wantedAlive then
							for ui = currentSize, wantedAlive + 1, -1 do
								local u = dcsGroup:getUnit(ui)
								if u and u:isExist() then
									u:destroy()
								end
							end
						end
					end

					local missionAssignDelay = (self.MissionType == 'CAS') and 0.5 or 2.5
					self._restoreSupplyReturnHome = restoreData.supplyReturnHome == true
					timer.scheduleFunction(function(param, time)
						local gc = param.gc
						if not gc then return nil end
						local rg = Group.getByName(param.groupName)
						if not rg or not rg:isExist() or rg:getSize() == 0 then return nil end
						gc:_assignMissionAfterInAirRestore(param.groupName, param.originZone)
						return nil
					end, { gc = self, groupName = gname, originZone = restoreOriginZone }, timer.getTime() + missionAssignDelay)
				end)

				local restoredGroup = sp:Spawn()
				if not restoredGroup then
					env.info("[AirPersistence] restore spawn failed for "..tostring(self.name).." template="..tostring(restoreTemplate))
					self:_enterHangar(false)
					return
				end
			else
				local canSpawn = self:_consumeShouldSpawnDecision('preparing', false)
				if canSpawn == nil then return end
				if canSpawn then
					if self.MissionType == 'SEAD' then
					local bcObj = self.zoneCommander and self.zoneCommander.battleCommander
					if bcObj and not bcObj:HasSeadTargets(self.targetzone, true) then
						self:_enterHangar(false)
						return
					end
				end
				self:clearWreckage()
				local didSpawn = false
				if self.template then
					local set = self:_getTemplateSet(self.template)
					if set and #set > 0 then
						self.Spawned = false
						local farpLaunch = (self.mission == 'supply' and self.unitCategory == heli) and self._pendingSupplyFarpLaunch or nil
						local retrySkipBlockedHelo = self._supplyRetrySkipBlockedHelo == true
						local resolved
						if farpLaunch or retrySkipBlockedHelo then
							resolved = self:_resolveCtldFarpTemplateName()
							if not resolved then
								if farpLaunch then
									self._pendingSupplyFarpLaunch = nil
									farpLaunch = nil
									self._pendingSupplyLaunchMessage = 'A friendly helicopter is scrambling from '..originZone..' to '..self.targetzone
									resolved = self:_resolveTemplateName()
								else
									self:_enterHangar(false)
									return
								end
							end
						else
							resolved = self:_resolveTemplateName()
						end
						self._supplyRetrySkipBlockedHelo = nil
						local SpawnType = self:_resolveSpawn()
						self._landUnitID = SpawnType and SpawnType.airbaseId or nil
						if SpawnType and SpawnType.isShip then self.landsatcarrier = true end
						if (not SpawnType or not (SpawnType.airbase and SpawnType.spots and #SpawnType.spots>0)) and self.unitCategory==Unit.Category.AIRPLANE then
							SpawnType = self:_resolveParkingWithBelonging()
						end
						local hasParkingSpawn = SpawnType and SpawnType.kind == 'parking' and SpawnType.airbase and SpawnType.spots and #SpawnType.spots>0
						if farpLaunch or (self.Airbase) or hasParkingSpawn then
							local tpl = self:_getAirTemplate(resolved)
							if tpl then
								local spawnUnitCount = (tpl.units and #tpl.units) or 1
								local sp = SPAWN:NewFromTemplate(tpl, resolved, self:_getSpawnAlias(), true)
										local SpawnSkill = (self.side == 1) and tostring(AiPlaneSkill or "Excellent") or "Excellent"
										sp = sp:InitSkill(SpawnSkill):OnSpawnGroup(function(g)

										if self.MissionType == 'CAP' and self.mission== 'patrol' then
											local gr = Group.getByName(g:GetName()); if not gr then return end
											local side = self.side
											local savedPoint = self._currentCapHoldingPoint
											local safe = tonumber(self._currentCapBufferNm) or ((side == 1) and 40 or 30)
											local st = savedPoint and savedPoint.x and (savedPoint.z or savedPoint.y) and { x = savedPoint.x, y = savedPoint.z or savedPoint.y } or nil
											if not st then
												local towardEnemyNm = 35
												local off = (self.side == 2) and -towardEnemyNm or towardEnemyNm
												st = Frontline.PickStationNearZone(self.targetzone, self.side, off, 0, 0, 0, safe)
											end
											if not st then return end
											local dist = tonumber(self._currentCapOrbitDistanceNm) or ((side == 1) and math.random(30, 40) or math.random(30, 40))
											SetUpCAP(gr, { x = st.x, z = st.y }, self.Altitude, dist, self._landUnitID, safe, side)
											self._currentCapHoldingPoint = { x = st.x, z = st.y }
											self._currentCapOrbitDistanceNm = dist
											self._currentCapBufferNm = safe

										elseif self.MissionType == 'CAP' and self.mission== 'attack' then
											local gr = Group.getByName(g:GetName()); if not gr then return end
											local side = self.side
											local savedPoint = self._currentCapHoldingPoint
											local offsetNm = tonumber(self._currentCapBufferNm) or ((side == 1) and 35 or 25)
											local st = savedPoint and savedPoint.x and (savedPoint.z or savedPoint.y) and { x = savedPoint.x, y = savedPoint.z or savedPoint.y } or nil
											if not st then
												st = Frontline.PickCapStationFromOrigin(originZone, self.targetzone, side, 100, offsetNm)
											end
											if not st then return end
											local dist = tonumber(self._currentCapOrbitDistanceNm) or ((side == 1) and math.random(35, 45) or math.random(35, 40))
											SetUpCAP(gr, { x = st.x, z = st.y }, self.Altitude, dist, self._landUnitID, offsetNm, side)
											self._currentCapHoldingPoint = { x = st.x, z = st.y }
											self._currentCapOrbitDistanceNm = dist
											self._currentCapBufferNm = offsetNm

									elseif self.mission == 'supply' and self.unitCategory == heli then
										local supplyOriginZone = self._activeSupplyLaunchSourceZone or originZone
										local supplyFarpLaunch = self._activeSupplyFarpLaunch
										if self.side == 2 and self._pendingBlueSupplyCost and self._pendingBlueSupplyCost > 0 then
											self.zoneCommander.battleCommander.accounts[2] = math.max((self.zoneCommander.battleCommander.accounts[2] or 0) - self._pendingBlueSupplyCost, 0)
											self._pendingBlueSupplyCost = nil end
											if supplyFarpLaunch then
												self._supplyCtldFarpTakeoff = supplyFarpLaunch
												self._supplyCtldFarpTakeoffCheckAt = timer.getAbsTime() + 180
												self._supplyCtldFarpExistenceCheckAt = timer.getAbsTime() + 30
												self:_clearSupplyLaunchState({ keepPendingFarp = true, keepCtldFarpTakeoff = true })
											else
												self:_clearSupplyLaunchState({ keepPendingFarp = true })
											end
											timer.scheduleFunction(function(param)
												local assigned
												if param.retryNoCargo then
													param.gc._supplyRetryNoCargo = nil
													assigned = param.gc:_assignHeloRoute(param.groupName, param.targetZone)
												elseif param.farpLaunch and param.farpLaunch.routeOnly == true then
													assigned = param.gc:_assignHeloRoute(param.groupName, param.targetZone)
												elseif param.farpLaunch and WarehouseLogistics == true and (not param.gc.NotCargo) then
													assigned = param.gc:_assignHeloLogisticsRoute(param.groupName, param.targetZone, param.originZone, param.side, param.farpLaunch)
													-- assigned = param.gc:_assignHeloRoute(param.groupName, param.targetZone)
												elseif param.farpLaunch then
													assigned = param.gc:_assignHeloRoute(param.groupName, param.targetZone)
												elseif WarehouseLogistics == true and (not param.gc.NotCargo) then
													assigned = param.gc:_assignHeloLogisticsRoute(param.groupName, param.targetZone, param.originZone, param.side, param.farpLaunch)
												else
													assigned = param.gc:_assignHeloRoute(param.groupName, param.targetZone)
												end
												if assigned == false and param.farpLaunch then
													param.gc:_clearSupplyLaunchState()
													param.gc._pendingSupplyLaunchMessage = 'A friendly helicopter is scrambling from '..param.fallbackOriginZone..' to '..param.targetZone
													param.gc.spawnedName = nil
													param.gc:forceSpawnNow(param.targetZone)
												elseif assigned ~= true then
													param.gc._pendingSupplyLaunchMessage = nil
													param.gc.zoneCommander.battleCommander:_failPendingShopPurchase(param.gc, "LOGISTICS_NO_AVAILABLE_PILOTS")
												end
												return nil
											end, {
												gc = self,
												groupName = g:GetName(),
												targetZone = self.targetzone,
												originZone = supplyOriginZone,
												fallbackOriginZone = originZone,
												side = self.side,
												farpLaunch = supplyFarpLaunch,
												retryNoCargo = self._supplyRetryNoCargo == true,
											}, timer.getTime() + 2)

									elseif self.mission == 'supply' and self.unitCategory == plane then
										if self.side == 2 and self._pendingBlueSupplyCost and self._pendingBlueSupplyCost > 0 then
												self.zoneCommander.battleCommander.accounts[2] = math.max((self.zoneCommander.battleCommander.accounts[2] or 0) - self._pendingBlueSupplyCost, 0)
												self._pendingBlueSupplyCost = nil end
											timer.scheduleFunction(function(param)
												local assigned = param.gc:_assignPlaneRoute(param.groupName, param.targetZone, param.altitude, param.originZone, param.side)
												if assigned ~= true then
													param.gc._pendingSupplyLaunchMessage = nil
													param.gc.zoneCommander.battleCommander:_failPendingShopPurchase(param.gc, "LOGISTICS_NO_AVAILABLE_PILOTS")
												end
												return nil
											end, {
												gc = self,
												groupName = g:GetName(),
												targetZone = self.targetzone,
												altitude = self.Altitude,
												originZone = originZone,
												side = self.side,
											}, timer.getTime() + 2)

										elseif self.MissionType=='CAS' and self.unitCategory == plane then
											bc:EngageCasMission(self.targetzone, g:GetName(), nil, nil, self.Altitude, self._landUnitID, self.side)
											
										elseif self.MissionType=='CAS' and self.unitCategory == heli then
											bc:EngageHeloCasMission(self.targetzone, g:GetName(), nil, nil, self._landUnitID)
										elseif self.MissionType=='SEAD' and self.unitCategory == plane then
											bc:EngageSeadMission(self.targetzone, g:GetName(), nil, self.Altitude, self._landUnitID)

										elseif self.MissionType=='RUNWAYSTRIKE' and self.unitCategory == plane then
											bc:EngageRunwayBombing(self.zoneCommander.airbaseName, self.targetzone, g:GetName(), self.Altitude, self.side)
										
										elseif self.MissionType=='ANTISHIP' and self.unitCategory == plane then
											bc:EngageAntiShipMission(self.targetzone, g:GetName(),nil,nil, self.Altitude, self._landUnitID)
										end

								end)
									local spawnHot = ((self.mission == 'supply' and self.side == 2) or self.SpawnHot) and true or false
									local tk = spawnHot and SPAWN.Takeoff.Hot or SPAWN.Takeoff.Cold
									local spawned = nil
									local farpSpawnFailed = false
									if farpLaunch then
										self._pendingSupplyFarpLaunch = nil
										local farpAb = AIRBASE:FindByName(farpLaunch.name)
										if farpAb then
											self._activeSupplyLaunchSourceZone = farpLaunch.name
											self._activeSupplyFarpLaunch = farpLaunch
											-- spawned = self:_spawnFromGroundAtCtldFarp(sp, farpAb, farpLaunch, true)
											spawned = sp:SpawnAtAirbase(farpAb, SPAWN.Takeoff.Hot, nil, nil, false)
											if not spawned then
												self._activeSupplyLaunchSourceZone = nil
												self._activeSupplyFarpLaunch = nil
												farpSpawnFailed = true
											end
										else
											self._activeSupplyLaunchSourceZone = nil
											self._activeSupplyFarpLaunch = nil
											farpSpawnFailed = true
										end
									end
									if not spawned then
										self._activeSupplyLaunchSourceZone = nil
										self._activeSupplyFarpLaunch = nil
										if farpSpawnFailed then
											self._pendingSupplyLaunchMessage = 'A friendly helicopter is scrambling from '..originZone..' to '..self.targetzone
										end
										if self.unitCategory == heli and (self.ForceFromGround or (not self.Airbase and not hasParkingSpawn)) then
											local tk = spawnHot and true or false
											spawned = self:_spawnFromGroundAt(resolved, originZone, self.targetzone, tk)
										else
											if not self.Airbase then
												spawned = sp:SpawnAtParkingSpot(SpawnType.airbase, SpawnType.spots, tk)
												if not spawned then spawned = sp:SpawnAtAirbase(SpawnType.airbase, tk, nil, nil, false) end
												if spawned and self.unitCategory == heli then spawned:OptionPreferVerticalLanding() end
											else
												local ab = AIRBASE:FindByName(self.Airbase)
												if ab and ab:GetCoalition()==self.side then
													self._landUnitID = ab:GetID()
													if ab:IsShip() then if IsGroupActive(ab:GetName()) then
														self.landsatcarrier = true
														spawned = sp:SpawnAtAirbase(ab, tk, nil, nil, false) end
													else
														spawned = sp:SpawnAtAirbase(ab, tk, nil, nil, false)
													end
												end
											end
										end
									end
								if not spawned then self:_enterHangar(false); return end
								if spawned then
									spawned:OptionPreferVerticalLanding()
									self.spawnedName = spawned:GetName()
									self._lastSpawnTemplate = resolved
									didSpawn = true
								end
							end
						else
							if self.unitCategory == plane then
								self:_enterHangar(false)
							else
								local spawnHot = ((self.mission == 'supply' and self.side == 2) or self.SpawnHot) and true or false
								local tk = spawnHot and SPAWN.Takeoff.Hot or SPAWN.Takeoff.Cold
								if farpLaunch then
									self._pendingSupplyFarpLaunch = nil
									self._pendingSupplyLaunchMessage = 'A friendly helicopter is scrambling from '..originZone..' to '..self.targetzone
								end
								local spawned = self:_spawnFromGroundAt(resolved, originZone, self.targetzone, tk)
								if spawned then
									if (self.mission=='supply' or self.MissionType=='CAS') and self.unitCategory == heli then spawned:OptionPreferVerticalLanding() end
									self.spawnedName = spawned:GetName()
									self._lastSpawnTemplate = resolved
									didSpawn = true
								end
							end
						end
					end
				else
					if self.side == zside then
						Respawn.Group(self.name)
						self.spawnedName = self.name
						self._lastSpawnTemplate = self.name
						didSpawn = true
					end
				end
				if didSpawn then
					if self.mission == 'supply' and self._pendingShopPurchase then
						self.zoneCommander.battleCommander:_completePendingShopPurchase(self)
					end
					self._sortieSide = self._sortieSide or self.side
					local logName = self.spawnedName or self:_getSpawnAlias() or self.name
					if isUrgent then
						env.info("Group [" .. logName .. "] is spawning urgently!")
					else
						env.info("Group [" .. logName .. "] is spawning normally.")
					end
					local gv = Group.getByName(self.spawnedName or self.name)
					if gv and Utils.someOfGroupInZone(gv, originZone) then
					local tp = self:_getAirType()
					self.pinged = false
					self:_jtacMessage(L10N:Format("JTAC_AIR_STARTING_UP_AT", tp), nil, originZone, "Intel.ogg")
					_zoneIntelBroadcast(originZone, L10N:Format("INTEL_AIR_STARTING_UP_AT", tp, tostring(originZone)), 25, "Intel.ogg")
					self._zonePinged = nil
					self.pinged = true
					end
					self.Spawned = true
					self.state = 'takeoff'
					self.lastStateTime = timer.getAbsTime()
				else
					self:_enterHangar(false)
				end
			elseif self._pendingShopPurchase then
				self:_enterHangar(false)
				return
			end
			end
		end

		elseif self.state == 'takeoff' then
			if timer.getAbsTime() - self.lastStateTime > GlobalSettings.blockedDespawnTime then
				if gr and Utils.allGroupIsLanded(gr, self.landsatcarrier) then
				gr:destroy()
				self:_enterHangar(false)
				end
			elseif gr and Utils.someOfGroupInAir(gr) then
					if self.pinged then
					local tp = self:_getAirType()
					self:_jtacMessage(L10N:Format("JTAC_AIR_TOOK_OFF_FROM", tp), true, originZone, "Intel.ogg")
					_zoneIntelBroadcast(originZone, L10N:Format("INTEL_AIR_TOOK_OFF_FROM", tp, tostring(originZone)), 25, "Intel.ogg")
					end
					--env.info("Group [" .. self.name .. "] is airborne")
					self.state = 'inair'
					self.pinged = false
					self.lastStateTime = timer.getAbsTime()
					if self.side == 1 and self.MissionType == 'CAP' and self._capAssistCheckedOnAirborne ~= true then
						self.zoneCommander.battleCommander:_tryScheduleBlueCapAssistFromRedCap(self)
						self._capAssistCheckedOnAirborne = true
					end
			end

		elseif self.state == 'inair' then
			if self.mission == 'supply' and self.unitCategory == heli and not self._supplyReturnHome and timer.getAbsTime() - self.lastStateTime > 280 then
				local hb = self.zoneCommander.battleCommander:getZoneByName(self.zoneCommander.zone)
				if hb and gr and Utils.someOfGroupInZone(gr, hb.zone) then
					if gr and gr:isExist() then gr:destroy() end
					self:_resetSupplyHeloToPreparing(originZone, { retryNoCargo = true, message = false })
					return
				end
			end
			if self.mission=='supply' and not self._zonePinged then
				local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
				if tg and gr and Utils.someOfGroupInZone(gr, tg.zone) then
					local tp = self:_getAirType()
					self:_jtacMessage(L10N:Format("JTAC_AIR_INBOUND_LANDING_AT", tp),true,tg.zone, "Intel.ogg")
					_zoneIntelBroadcast(tg.zone, L10N:Format("INTEL_AIR_INBOUND_LANDING_AT", tp, tostring(tg.zone)), 25, "Intel.ogg")
					self._zonePinged = true
				end
			end
			if gr and Utils.allGroupIsLanded(gr, self.landsatcarrier) then
				self.state = 'landed'
				self.lastStateTime = timer.getAbsTime()
				self._landedAt = self._landedAt or self.lastStateTime
			end
		elseif self.state == 'landed' then
			self._landedAt = self._landedAt or timer.getAbsTime()
			if self.mission == 'supply' then
				local hb = self.zoneCommander.battleCommander:getZoneByName(self.zoneCommander.zone)
				if self._supplyReturnHome and hb and gr and Utils.someOfGroupInZone(gr, hb.zone) then
					self:_destroyLogiCargo()
					self:_enterHangar(false)
					self._landedAt = nil
					self._supplyReturnHome = nil
					SCHEDULER:New(nil,function() if gr and gr:isExist() then gr:destroy() end end,{},0.5,0)
					return
				end

				local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
				if tg and gr and Utils.someOfGroupInZone(gr, tg.zone) then
					local validSupplyTarget = tg.active and (tg.side == self.side or tg.side == 0)
					if not validSupplyTarget then
						self:_destroyLogiCargo()
						self:_enterHangar(false)
						self._landedAt = nil
						self._supplyReturnHome = nil
						SCHEDULER:New(nil,function() if gr and gr:isExist() then gr:destroy() end end,{},0.5,0)
						return
					end
					if tg.side == self.side and self.side == 1 and self.unitCategory == heli and tg.BlueIsNear then
						local delaySec = 60
						local elapsed = timer.getAbsTime() - self.lastStateTime
						if elapsed <= delaySec then
							return
						end
					end
					self:_enterHangar(false)
					self._landedAt = nil
					self._supplyReturnHome = nil
					if tg.side == 0 then
						env.info("Group [" .. self.name .. "] landed in zone [" .. tg.zone .. "], capturing zone for side " .. self.side)
						SCHEDULER:New(nil,function() tg:capture(self.side) end,{},0.3,0)
					elseif tg.side == self.side then
						env.info("Group [" .. self.name .. "] landed in zone [" .. tg.zone .. "], upgrading zone for side " .. self.side)
						tg:upgrade()
					end
					local abName = tg.airbaseName
					if abName and WarehouseLogistics and self.side == 2 then
						if AIDeliveryamount == nil then AIDeliveryamount = 20 end
						local amount = (self.unitCategory == plane) and 50 or AIDeliveryamount
						local bcObj = self.zoneCommander.battleCommander
						if bcObj and bcObj.addWarehouseItemsAtZone and amount > 0 then
							bcObj:addWarehouseItemsAtZone(tg, self.side, amount)
						end
						self:_destroyLogiCargo()
					end
					SCHEDULER:New(nil,function() if gr and gr:isExist() then gr:destroy() end end,{},0.5,0)
					return
				else
					if hb and gr and Utils.someOfGroupInZone(gr, hb.zone) then
						self:_enterHangar(false)
						self._landedAt = nil
						self._supplyReturnHome = nil
						SCHEDULER:New(nil,function() if gr and gr:isExist() then gr:destroy() end end,{},0.5,0)
						return
					end
				end
				local landedDespawnTime = (self.unitCategory == plane) and 180 or GlobalSettings.landedDespawnTime
				if timer.getAbsTime() - (self._landedAt or self.lastStateTime) > landedDespawnTime then
					if gr and gr:isExist() then gr:destroy() end
					self:_enterHangar(false)
					self._landedAt = nil
					self._supplyReturnHome = nil
				end
			else
				local hb = self.zoneCommander.battleCommander:getZoneByName(self.zoneCommander.zone)
				if hb and gr and Utils.someOfGroupInZone(gr, hb.zone) then
					if self.side == 1 and self.mission ~= 'supply' then
						self.zoneCommander.battleCommander:addFunds(1,100)
					end
					self:_enterHangar(false)
					self._landedAt = nil
					SCHEDULER:New(nil,function() if gr and gr:isExist() then gr:destroy() end end,{},0.5,0)
					return
				else
					local landedDespawnTime = (self.unitCategory == plane) and 180 or GlobalSettings.landedDespawnTime
					if timer.getAbsTime() - (self._landedAt or self.lastStateTime) > landedDespawnTime then
						self:_enterHangar(false)
						self._landedAt = nil
						SCHEDULER:New(nil,function() if gr and gr:isExist() then gr:destroy() end end,{},0.5,0)
					end
				end
			end
		elseif self.state == 'dead' then
			if timer.getAbsTime() - self.lastStateTime > (respawnTimers.dead * spawnDelayFactor) then
				local canSpawn = self:_consumeShouldSpawnDecision('dead', false)
				if canSpawn == nil then return end
				if canSpawn then
					self:_enterHangar(false)
				end
			end
		end
	end

	function GroupCommander:_buildSurfaceMissionTask(useZoneRoadHooks, useMultiRoadHooks, useTargetMultiRoadHooks)
		local isArtilleryMission = self.MissionType == 'ARTY'
		if self.playerGroundAttack == true and self.playerGroundAttackRoutePoint and self.mission == 'attack' and not isArtilleryMission then
			local routeOptions = nil
			if useZoneRoadHooks == true and (useMultiRoadHooks == true or useTargetMultiRoadHooks == true) then
				routeOptions = {
					useOriginMultiRoadHooks = useMultiRoadHooks == true,
					useTargetMultiRoadHooks = useTargetMultiRoadHooks == true or useMultiRoadHooks == true,
				}
				if routeOptions.useOriginMultiRoadHooks and routeOptions.useTargetMultiRoadHooks then
					routeOptions.useMultiRoadHooks = true
				end
			end
			local task, startVec2 = dc.BuildPlayerGroundAttackRouteFromPoint(self.playerGroundAttackRoutePoint, self.targetzone, dc.DEFAULT_SPEED, nil, useZoneRoadHooks == true, routeOptions)
			return task, startVec2, false
		end
		if self.mission == 'supply' then
			if useZoneRoadHooks == true then
				local task, startVec2 = dc.GetSupplyConvoyRoute(self.zoneCommander.zone, self.targetzone, dc.DEFAULT_SPEED, true, useMultiRoadHooks == true, useTargetMultiRoadHooks == true)
				return task, startVec2, false
			end
			local task, startVec2 = dc.GetSupplyConvoyRoute(self.zoneCommander.zone, self.targetzone, dc.DEFAULT_SPEED)
			return task, startVec2, false
		end
		if isArtilleryMission then
			local artilleryRangeNm = dc.ResolveArtilleryRangeNm(self)
			local task, startVec2 = dc.GetArtilleryRoute(self.zoneCommander.zone, self.targetzone, dc.DEFAULT_SPEED, artilleryRangeNm)
			return task, startVec2, true
		end
		if useZoneRoadHooks == true then
			local task, startVec2 = dc.GetAttackConvoyRoute(self.zoneCommander.zone, self.targetzone, dc.DEFAULT_SPEED, true, useMultiRoadHooks == true, useTargetMultiRoadHooks == true)
			return task, startVec2, false
		end
		local task, startVec2 = dc.GetAttackConvoyRoute(self.zoneCommander.zone, self.targetzone, dc.DEFAULT_SPEED)
		return task, startVec2, false
	end

	function GroupCommander:_buildSurfaceRestoreTask(savedX, savedZ, restoreZoneName)
		if self.mission == 'supply' then
			local routeOptions = {
				useTargetRoadHook = true,
				useTargetMultiRoadHooks = true,
				allowNearestRoadStart = true,
			}
			local savedPos = { x = savedX, y = land.getHeight({ x = savedX, y = savedZ }), z = savedZ }
			local savedZone = bc:getZoneOfPoint(savedPos)
			if savedZone and savedZone.zone == self.zoneCommander.zone then
				routeOptions.originRoadHookZoneName = self.zoneCommander.zone
			end
			local task = select(1, dc.BuildSupplyConvoyRouteFromPoint({ x = savedX, y = savedZ }, restoreZoneName or self.targetzone, dc.DEFAULT_SPEED, false, routeOptions))
			return task, false
		end
		local selectedTask, startVec2, isArtilleryMission
		local useHomeRoadHook = nil
		local savedZoneName = nil
		if self.playerGroundAttack == true and self.mission == 'attack' and self.MissionType ~= 'ARTY' then
			local savedPos = { x = savedX, y = land.getHeight({ x = savedX, y = savedZ }), z = savedZ }
			local savedZone = bc:getZoneOfPoint(savedPos)
			savedZoneName = savedZone and savedZone.zone or nil
			useHomeRoadHook = savedZone and savedZone.zone == self.zoneCommander.zone
			if self.playerGroundAttackRoutePoint then
				local routeOptions = {
					useTargetRoadHook = true,
					useTargetMultiRoadHooks = true,
					allowNearestRoadStart = true,
				}
				if useHomeRoadHook then
					routeOptions.originRoadHookZoneName = self.zoneCommander.zone
				end
				selectedTask, startVec2 = dc.BuildPlayerGroundAttackRouteFromPoint(self.playerGroundAttackRoutePoint, self.targetzone, dc.DEFAULT_SPEED, nil, false, routeOptions)
				isArtilleryMission = false
			else
				selectedTask, startVec2 = dc.BuildAttackConvoyRoute(self.zoneCommander.zone, self.targetzone, dc.DEFAULT_SPEED, false, false, true, useHomeRoadHook, true, true)
				isArtilleryMission = false
			end
		else
			selectedTask, startVec2, isArtilleryMission = self:_buildSurfaceMissionTask()
		end
		if not (selectedTask and startVec2) then
			return nil, isArtilleryMission
		end

		local task = UTILS.DeepCopy(selectedTask)
		local route = task and task.params and task.params.route
		local points = route and route.points
		if type(points) ~= "table" or #points == 0 then
			return task, isArtilleryMission
		end

		local startIndex = (#points >= 2) and 2 or 1
		local bestDistSq = math.huge
		for i = 2, #points do
			local wp = points[i]
			local wx = wp and tonumber(wp.x)
			local wy = wp and tonumber(wp.y)
			if wx and wy then
				local dx = wx - savedX
				local dy = wy - savedZ
				local distSq = dx * dx + dy * dy
				if distSq < bestDistSq then
					bestDistSq = distSq
					startIndex = i
				end
			end
		end

		local hasRoadPhase = false
		local roadContinueIndex = nil
		local lastRoadIndex = nil
		for i = 1, #points do
			local action = points[i] and points[i].action or nil
			if action == "On Road" or action == "on_road" then
				hasRoadPhase = true
				lastRoadIndex = i
				if i > 1 and not roadContinueIndex then
					roadContinueIndex = i
				end
			end
		end
		if self._passedRoadExit == true and lastRoadIndex and (lastRoadIndex + 1) <= #points then
			local offroadStartIndex = lastRoadIndex + 1
			local bestOffroadDistSq = math.huge
			for i = offroadStartIndex, #points do
				local wp = points[i]
				local wx = wp and tonumber(wp.x)
				local wy = wp and tonumber(wp.y)
				if wx and wy then
					local dx = wx - savedX
					local dy = wy - savedZ
					local distSq = dx * dx + dy * dy
					if distSq < bestOffroadDistSq then
						bestOffroadDistSq = distSq
						startIndex = i
					end
				end
			end
			bestDistSq = bestOffroadDistSq
		end
		if self._passedRoadExit ~= true and hasRoadPhase and lastRoadIndex and startIndex == (lastRoadIndex + 1) then
			startIndex = lastRoadIndex
		end

		env.info(string.format(
			"[SurfaceRestoreRoute] group=%s mission=%s target=%s passedRoadExit=%s hasRoadPhase=%s startIndex=%s lastRoadIndex=%s roadContinueIndex=%s points=%s",
			tostring(self.name),
			tostring(self.mission),
			tostring(self.targetzone),
			tostring(self._passedRoadExit == true),
			tostring(hasRoadPhase),
			tostring(startIndex),
			tostring(lastRoadIndex),
			tostring(roadContinueIndex),
			tostring(#points)
		))

		if hasRoadPhase and lastRoadIndex and startIndex <= lastRoadIndex and (self.mission == 'attack' or isArtilleryMission) then
			local rx, rz = land.getClosestPointOnRoads("roads", savedX, savedZ)
			if rx and rz then
				local joinIndex = math.max(roadContinueIndex or 1, startIndex)
				local appendIndex = joinIndex
				local firstAction = points[1] and points[1].action or nil
				if joinIndex == roadContinueIndex and (firstAction == "Off Road" or firstAction == "off_road") then
					appendIndex = joinIndex + 1
				end
				local firstPoint = UTILS.DeepCopy(points[1] or points[joinIndex])
				firstPoint.x = savedX
				firstPoint.y = savedZ
				firstPoint.action = "Off Road"
				firstPoint.task = nil
				local joinPoint = UTILS.DeepCopy(points[joinIndex] or points[1])
				joinPoint.x = rx
				joinPoint.y = rz
				joinPoint.action = "On Road"
				joinPoint.task = nil
				local newPoints = { firstPoint, joinPoint }

				for i = appendIndex, #points do
					newPoints[#newPoints + 1] = UTILS.DeepCopy(points[i])
				end
				route.points = newPoints
				return task, isArtilleryMission
			end
		end

		local retainedPoint = points[startIndex] or points[1]
		local newPoints = {}
		local firstPoint = UTILS.DeepCopy(retainedPoint)
		firstPoint.x = savedX
		firstPoint.y = savedZ
		firstPoint.action = "Off Road"
		firstPoint.task = nil
		newPoints[1] = firstPoint
		for i = startIndex, #points do
			newPoints[#newPoints + 1] = UTILS.DeepCopy(points[i])
		end
		route.points = newPoints
		return task, isArtilleryMission
	end

	function GroupCommander:_applySurfaceRestoreAliveMask(gr, restoreData)
		if not gr or not gr:isExist() then return end
		local aliveUnitTypes = restoreData and restoreData.aliveUnitTypes or nil
		if type(aliveUnitTypes) == "table" and #aliveUnitTypes > 0 then
			local wanted = {}
			for i = 1, #aliveUnitTypes do
				local tname = aliveUnitTypes[i]
				wanted[tname] = (wanted[tname] or 0) + 1
			end
			for ui = (gr:getSize() or 0), 1, -1 do
				local u = gr:getUnit(ui)
				if u and u:isExist() then
					local tname = u:getTypeName()
					local remaining = wanted[tname] or 0
					if remaining > 0 then
						wanted[tname] = remaining - 1
					else
						u:destroy()
					end
				end
			end
			return
		end

		local wantedAlive = math.max(0, math.floor(tonumber(restoreData and restoreData.aliveCount) or 0))
		local currentSize = gr:getSize() or 0
		if currentSize > wantedAlive then
			for ui = currentSize, wantedAlive + 1, -1 do
				local u = gr:getUnit(ui)
				if u and u:isExist() then
					u:destroy()
				end
			end
		end
	end

	function GroupCommander:_rememberSurfaceRoadPhase(task, preservePassedRoadExit)
		self._surfaceRoadExitPoint = nil
		self._surfacePostRoadPoint = nil
		self._surfaceRoadExitSeen = false
		self._surfaceRoadExitClosestDistSq = nil
		if preservePassedRoadExit ~= true then
			self._passedRoadExit = false
		end

		local route = task and task.params and task.params.route
		local points = route and route.points
		if type(points) ~= "table" or #points == 0 then
			return
		end

		local lastRoadIndex = nil
		for i = 1, #points do
			local action = points[i] and points[i].action or nil
			if action == "On Road" or action == "on_road" then
				lastRoadIndex = i
			end
		end
		if not lastRoadIndex then
			return
		end

		local roadPoint = points[lastRoadIndex]
		local rx = roadPoint and tonumber(roadPoint.x) or nil
		local ry = roadPoint and tonumber(roadPoint.y) or nil
		if rx and ry then
			self._surfaceRoadExitPoint = { x = rx, y = ry }
		end

		local nextPoint = points[lastRoadIndex + 1]
		local nx = nextPoint and tonumber(nextPoint.x) or nil
		local ny = nextPoint and tonumber(nextPoint.y) or nil
		if nx and ny then
			self._surfacePostRoadPoint = { x = nx, y = ny }
		end
	end

	function GroupCommander:_updateSurfaceRoadExitProgress(gr)
		if self._passedRoadExit == true then return end
		if not gr or not gr:isExist() or gr:getSize() == 0 then return end
		local exitPoint = self._surfaceRoadExitPoint
		if not exitPoint then return end

		local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
		if tg and Utils.someOfGroupInZone(gr, tg.zone) then
			self._passedRoadExit = true
			if self.MissionType ~= 'ARTY' and self._surfaceIsArtillery ~= true then
				_surfaceIntelClearLastKnownMarker(self.name)
			end
			return
		end

		local lead = gr:getUnit(1)
		if not lead or not lead:isExist() then return end
		local pos = lead:getPoint()
		if not pos then return end

		local dx = pos.x - exitPoint.x
		local dz = pos.z - exitPoint.y
		local exitDistSq = dx * dx + dz * dz
		local armMeters = 750
		local passMeters = 600
		local armDistSq = armMeters * armMeters
		local passDistSq = passMeters * passMeters
		if exitDistSq <= armDistSq then
			self._surfaceRoadExitSeen = true
		end
		local bestExitDistSq = self._surfaceRoadExitClosestDistSq
		if not bestExitDistSq or exitDistSq < bestExitDistSq then
			self._surfaceRoadExitClosestDistSq = exitDistSq
		end

		local offroadPoint = self._surfacePostRoadPoint
		if offroadPoint then
			local odx = pos.x - offroadPoint.x
			local odz = pos.z - offroadPoint.y
			local offroadDistSq = odx * odx + odz * odz
			if offroadDistSq <= passDistSq then
				self._passedRoadExit = true
				if self.MissionType ~= 'ARTY' and self._surfaceIsArtillery ~= true then
					_surfaceIntelClearLastKnownMarker(self.name)
				end
				return
			end
			if self._surfaceRoadExitSeen and offroadDistSq < exitDistSq then
				self._passedRoadExit = true
				if self.MissionType ~= 'ARTY' and self._surfaceIsArtillery ~= true then
					_surfaceIntelClearLastKnownMarker(self.name)
				end
				return
			end
		elseif self._surfaceRoadExitSeen and self._surfaceRoadExitClosestDistSq and exitDistSq > (self._surfaceRoadExitClosestDistSq + (250 * 250)) then
			self._passedRoadExit = true
			if self.MissionType ~= 'ARTY' and self._surfaceIsArtillery ~= true then
				_surfaceIntelClearLastKnownMarker(self.name)
			end
		end
	end

	function GroupCommander:_surfaceIntelContactLabel()
		if self._surfaceIsArtillery == true or self.MissionType == 'ARTY' then
			return "artillery"
		end
		return "attack group"
	end

	function GroupCommander:_surfaceIntelReportLastKnown(groupName, point, prefix)
		if self.side ~= 1 or self.mission ~= 'attack' or not point then return end
		local groupKey = self.name
		local contactLabel = self:_surfaceIntelContactLabel()
		local grid = _surfaceIntelApproxGrid(point)
		local approxCoord = _surfaceIntelApproxLatLon(point)
		local targetName = tostring(self.targetzone or "target zone")
		local originName = tostring(self.zoneCommander and self.zoneCommander.zone or "unknown")
		local messagePrefix = prefix or "Intel"
		local placedAt = _surfaceIntelMissionTime()
		local templates = {
			L10N:Format("SURFACE_INTEL_LAST_KNOWN_1", messagePrefix, contactLabel, grid, approxCoord, originName, targetName),
			L10N:Format("SURFACE_INTEL_LAST_KNOWN_2", messagePrefix, contactLabel, grid, approxCoord, originName, targetName),
			L10N:Format("SURFACE_INTEL_LAST_KNOWN_3", messagePrefix, contactLabel, grid, approxCoord, originName, targetName),
		}
		local text = templates[math.random(1, #templates)]
		local markerLabel = L10N:Format("SURFACE_INTEL_MARKER_LAST_KNOWN", contactLabel, grid, targetName, placedAt)
		_surfaceIntelUpdateLastKnownMarker(groupKey, point, markerLabel)
		self.groundconvoyMessaged = true
		trigger.action.outTextForCoalition(2, text, 25)
		trigger.action.outSoundForCoalition(2, "Intel.ogg")
	end

	function GroupCommander:_scheduleSurfaceIntelRouteReports(task, groupName)
		if self.side ~= 1 or self.mission ~= 'attack' then return end
		if self._artilleryReturnHome == true then return end
		if type(groupName) ~= "string" or groupName == "" then return end

		local etaMinutes = _surfaceTaskEtaMinutes(task)
		local etaSeconds = (etaMinutes and etaMinutes > 0) and (etaMinutes * 60) or 0
		local checkpoints = {
			{ key = "route25", fraction = 0.25, fallback = 600 },
			{ key = "route75", fraction = 0.75, fallback = 1800 },
		}
		self._surfaceIntelRouteToken = (self._surfaceIntelRouteToken or 0) + 1
		self._surfaceIntelRouteReportsSent = {}
		local token = self._surfaceIntelRouteToken

		for _, checkpoint in ipairs(checkpoints) do
			local delay = etaSeconds > 0 and (etaSeconds * checkpoint.fraction) or checkpoint.fallback
			delay = math.max(60, math.floor(delay + 0.5))
			SCHEDULER:New(nil, function()
				if self._surfaceIntelRouteToken ~= token then return end
				if self._surfaceIntelRouteReportsSent and self._surfaceIntelRouteReportsSent[checkpoint.key] then return end
				local liveGroupName = self.spawnedName or groupName
				local liveGroup = Group.getByName(liveGroupName)
				if not liveGroup or not liveGroup:isExist() or liveGroup:getSize() == 0 then return end
				if self.state ~= 'enroute' or self._artilleryReturnHome == true then return end
				local lead = liveGroup:getUnit(1)
				local point = lead and lead:isExist() and lead:getPoint() or nil
				if not point then return end
				self._surfaceIntelRouteReportsSent = self._surfaceIntelRouteReportsSent or {}
				self._surfaceIntelRouteReportsSent[checkpoint.key] = true
				self:_surfaceIntelReportLastKnown(liveGroupName, point, "Intel")
			end, {}, delay)
		end
	end

	function GroupCommander:_tryRetaskPlayerGroundAttack(gr)
		if self.playerGroundAttack ~= true then return false end
		if not gr or not gr:isExist() or gr:getSize() == 0 then return false end

		local lead = gr:getUnit(1)
		if not lead or not lead:isExist() then return false end

		local pos = lead:getPoint()
		local px = pos and tonumber(pos.x)
		local pz = pos and tonumber(pos.z)
		if not px or not pz then return false end

		local bc = self.zoneCommander.battleCommander
		local previousTarget = self.targetzone
		local bestZone = nil
		local bestTask = nil
		local bestDistMeters = nil

		for _, zoneObj in ipairs(bc.zones or {}) do
			if zoneObj
				and zoneObj.active
				and zoneObj.side == 1
				and not zoneObj.suspended
				and not zoneObj.isHidden
				and not isCarrierZoneName(zoneObj.zone)
			then
				local zoneCenter = getZoneCenter(zoneObj.zone)
				if zoneCenter then
					local distMeters = dc.PlayerGroundAttackDistanceMeters(px, pz, zoneCenter.x, zoneCenter.y)
					if distMeters <= dc.PLAYER_GROUND_ATTACK_MAX_METERS then
						if (not bestDistMeters)
							or distMeters < bestDistMeters
							or (distMeters == bestDistMeters and bestZone and zoneObj.zone < bestZone.zone)
							or (distMeters == bestDistMeters and not bestZone)
						then
							self.targetzone = zoneObj.zone
							local previousPassedRoadExit = self._passedRoadExit
							self._passedRoadExit = false
							local candidateTask = self:_buildSurfaceRestoreTask(px, pz)
							self._passedRoadExit = previousPassedRoadExit
							self.targetzone = previousTarget
							if candidateTask then
								bestZone = zoneObj
								bestTask = candidateTask
								bestDistMeters = distMeters
							end
						end
					end
				end
			end
		end

		self.targetzone = previousTarget
		if not bestZone or not bestTask then
			return false
		end

		self.targetzone = bestZone.zone
		self.dynamicHybridTargetZone = bestZone.zone
		local meta = bc.dynamicHybrid.groupsByName[self.name]
		bc:_dynamicHybridRemoveIndex(meta.origin, meta.target, meta.role)
		meta.target = bestZone.zone
		self.dynamicHybridTargetZone = bestZone.zone
		bc:_dynamicHybridSetIndex(meta.origin, meta.target, meta.role, self.name)

		local c = gr:getController()
		if c then
			c:popTask()
			self:_rememberSurfaceRoadPhase(bestTask, false)
			local retaskGroupName = self.spawnedName or self.name
			local retaskTask = bestTask
			SCHEDULER:New(nil, function()
				local liveGroup = Group.getByName(retaskGroupName)
				if liveGroup and liveGroup:isExist() then
					local liveController = liveGroup:getController()
					if liveController then
						liveController:pushTask(retaskTask)
					end
				end
			end, {}, 2, 0)
		end

		self.state = 'enroute'
		self.lastStateTime = timer.getAbsTime()
		trigger.action.outTextForCoalition(2, L10N:Format("GROUND_ATTACK_DISPATCHED", bestZone.zone), 15)
		env.info(string.format("[PlayerGroundAttack] retasked name=%s from=%s to=%s", tostring(self.name), tostring(previousTarget), tostring(bestZone.zone)))
		return true
	end

	
	function GroupCommander:processSurface()
		local gr
		if self.spawnedName and self.spawnedName ~= "" then gr = Group.getByName(self.spawnedName) end
		if not gr and self.name and self.name ~= "" then gr = Group.getByName(self.name) end

		if self._sortieSide then
			self.side = self._sortieSide
		elseif self.template then
			if self.zoneCommander.side and self.zoneCommander.side ~= 0 and self.zoneCommander.side ~= self.side then self.side = self.zoneCommander.side end
		end
		local coalition = self.side
		local isUrgent = type(self.urgent) == "function" and self.urgent() or self.urgent
		local respawnTimers = isUrgent and GlobalSettings.urgentRespawnTimers or GlobalSettings.respawnTimers[coalition][self.mission]
		local spawnDelayFactor = self.spawnDelayFactor or 1
		if self.mission == 'supply' and not isUrgent and self.side == 1 then
			local pc = getBluePlayersCount()
			if pc == 0 then
				spawnDelayFactor = spawnDelayFactor * 3
			elseif pc == 1 then
				spawnDelayFactor = spawnDelayFactor * 2.5
			elseif pc == 2 then
				spawnDelayFactor = spawnDelayFactor * 2
			elseif pc == 3 then
				spawnDelayFactor = spawnDelayFactor * 1.5				
			end
			--env.info(string.format("[SUPPLY_DELAY] players=%d factor=%.2f mission=%s", pc, spawnDelayFactor, self.name))
		elseif self.mission == 'attack' and not isUrgent then
			local pc = getBluePlayersCount()
			if pc == 0 then
				spawnDelayFactor = spawnDelayFactor * 3
			elseif pc == 1 then
				spawnDelayFactor = spawnDelayFactor * 2.5
			elseif pc == 2 then
				spawnDelayFactor = spawnDelayFactor * 2
			elseif pc == 3 then
				spawnDelayFactor = spawnDelayFactor * 1.5
			elseif pc == 4 then
				spawnDelayFactor = spawnDelayFactor * 1.25
			end
		end
		-- local uc = (self.zoneCommander and self.zoneCommander.upgradeCompletion) or 0
		-- local lack = 1 - uc
		-- local expo = (self.mission == 'supply') and 1 or (GlobalSettings.upgradeSlowExpo or 1)
		-- local maxm = (self.mission == 'supply') and (GlobalSettings.supplySlowMax or 1.0) or (GlobalSettings.upgradeSlowMax or 1)
		-- local slowMul = 1 + (lack ^ expo) * maxm
		-- spawnDelayFactor = spawnDelayFactor * slowMul

		if not gr or gr:getSize() == 0 then
			if gr and gr:getSize() == 0 then
				gr:destroy()
			end

			if self.state ~= 'inhangar' and self.state ~= 'preparing' and self.state ~= 'dead' then
				self._artilleryOnStation = nil
				self._artilleryReturnHome = nil
				self._surfaceIsArtillery = nil
				self._artilleryFireTargetZone = nil
				self._artilleryFireStartedAt = nil
				self._artilleryFiringIntelToken = (self._artilleryFiringIntelToken or 0) + 1
				self._artilleryFiringIntelScheduled = nil
				self._artilleryFiringIntelSent = nil
				self._artilleryStillFiringIntelSent = nil
				local tracked = self.zoneCommander and self.zoneCommander._suspendedLiveFsm
				if tracked then
					tracked[self.name] = nil
					if not next(tracked) then
						self.zoneCommander._suspendedLiveFsm = nil
					end
				end
				self.state = 'dead'
				self.lastStateTime = timer.getAbsTime()
			end
		end

   		 if self.state == 'inhangar' then
			if timer.getAbsTime() - self.lastStateTime > (respawnTimers.hangar * spawnDelayFactor) then
				if self.diceChance and self.diceChance > 0 and not self.diceRolled then
					self.diceRolled = true
					local roll = math.random(1, 100)
					if roll > self.diceChance then
						local tracked = self.zoneCommander and self.zoneCommander._suspendedLiveFsm
						if tracked then
							tracked[self.name] = nil
							if not next(tracked) then
								self.zoneCommander._suspendedLiveFsm = nil
							end
						end
						self.state = 'dead'
						self.lastStateTime = timer.getAbsTime()
						self.diceRolled = false
						return
					end
				end
            local canSpawn = self:_consumeShouldSpawnDecision('inhangar', false)
            if canSpawn == nil then return end
            if canSpawn then
                self.state = 'preparing'
                self.lastStateTime = timer.getAbsTime()
            end
        end
    elseif self.state == 'preparing' then
        if timer.getAbsTime() - self.lastStateTime > (respawnTimers.preparing * spawnDelayFactor) then
			local restoreData = self._pendingSurfaceRestore
			if restoreData then
				self._pendingSurfaceRestore = nil
				local savedPos = restoreData.position
				local px = savedPos and tonumber(savedPos.x)
				local pz = savedPos and tonumber(savedPos.z)
				if not px or not pz then
					env.info("[SurfacePersistence] invalid restore position for "..tostring(self.name))
					self:_enterHangar(false)
					return
				end

				local bc = self.zoneCommander.battleCommander
				local restoreSide = tonumber(restoreData.side) or self._sortieSide or self.side
				local homeZoneName = restoreData.originZone or restoreData.zoneName or self.zoneCommander.zone
				local homeZone = bc:getZoneByName(homeZoneName) or self.zoneCommander
				self.playerGroundAttackRoutePoint = restoreData.playerGroundAttackRoutePoint or self.playerGroundAttackRoutePoint
				self._passedRoadExit = restoreData.passedRoadExit == true
				local targetZone = bc:getZoneByName(self.targetzone)
				local restorePointZone = bc:getZoneOfPoint({ x = px, y = land.getHeight({ x = px, y = pz }), z = pz })
				local validAttackTarget = targetZone and targetZone.active and targetZone.side ~= restoreSide and targetZone.side ~= 0
				local validSupplyTarget = targetZone and targetZone.active and (targetZone.side == restoreSide or targetZone.side == 0)
				local validHomeZone = homeZone and homeZone.active and homeZone.side == restoreSide
				local supplyReturnHome = restoreData.supplyReturnHome == true
				local artilleryReturnHome = restoreData.artilleryReturnHome == true
				local allowRestore = false

				if artilleryReturnHome then
					allowRestore = validHomeZone
				else
					if restorePointZone then
						if homeZone and restorePointZone.zone == homeZone.zone then
							allowRestore = validHomeZone
						elseif targetZone and restorePointZone.zone == targetZone.zone then
							if self.mission == 'supply' then
								allowRestore = supplyReturnHome and validHomeZone or validSupplyTarget
							elseif self.mission == 'attack' then
								allowRestore = validAttackTarget
							else
								allowRestore = restorePointZone.active and restorePointZone.side == restoreSide
							end
						else
							allowRestore = restorePointZone.active and restorePointZone.side == restoreSide
						end
					else
						if self.mission == 'supply' then
							allowRestore = supplyReturnHome and validHomeZone or validSupplyTarget
						elseif self.mission == 'attack' then
							allowRestore = validAttackTarget
						else
							allowRestore = homeZone and homeZone.active and homeZone.side == restoreSide
						end
					end
				end

				if not allowRestore then
					env.info("[SurfacePersistence] restore skipped invalid zone state for "..tostring(self.name).." pointZone="..tostring(restorePointZone and restorePointZone.zone).." homeZone="..tostring(homeZoneName).." targetZone="..tostring(self.targetzone).." side="..tostring(restoreSide))
					self:_enterHangar(false)
					return
				end

				local restoreTemplate = restoreData.templateName or self._lastSpawnTemplate or self:_resolveTemplateName()
				if not restoreTemplate or restoreTemplate == "" then
					env.info("[SurfacePersistence] missing restore template for "..tostring(self.name))
					self:_enterHangar(false)
					return
				end

				local savedState = (restoreData.savedState == 'atdestination') and 'atdestination' or 'enroute'
				if artilleryReturnHome and savedState == 'atdestination' and not (restorePointZone and homeZone and restorePointZone.zone == homeZone.zone) then
					savedState = 'enroute'
				end
				local artilleryOnStation = (restoreData.artilleryOnStation == true) and artilleryReturnHome ~= true
				local elapsed = tonumber(restoreData.lastStateDuration) or 0
				if elapsed < 0 then elapsed = 0 end

				local tpl = self:_getAirTemplate(restoreTemplate)
				if not tpl or not tpl.units or #tpl.units == 0 then
					env.info("[SurfacePersistence] missing restore template data for "..tostring(self.name).." template="..tostring(restoreTemplate))
					self:_enterHangar(false)
					return
				end
				local isFreshFarpSpawn = restoreData.farpSpawn == true and restoreData.freshLaunch == true

				local headingDeg = tonumber(restoreData.headingDeg) or 0
				if headingDeg < 0 then headingDeg = headingDeg + 360 end
				if not isFreshFarpSpawn then
					_applyTemplateHeadingDeg(tpl, headingDeg)
				end

				local allowCaptureFarpFallback = restoreData.captureFarpLaunch == true and self.mission == 'supply'
				local selectedTask = nil
				local freshSpawnGroupHeadingDeg = nil
				if artilleryReturnHome then
					if savedState == 'enroute' then
						selectedTask = bc:_buildSurfaceArtilleryHomeTaskFromPoint({ x = px, z = pz }, homeZoneName)
						if not selectedTask then
							env.info("[SurfacePersistence] artillery return-home route failed for "..tostring(self.name).." homeZone="..tostring(homeZoneName))
							self:_enterHangar(false)
							return
						end
					end
				elseif savedState == 'enroute' and not artilleryOnStation then
					local restoreZoneName = (self.mission == 'supply' and supplyReturnHome) and homeZoneName or nil
					selectedTask = self:_buildSurfaceRestoreTask(px, pz, restoreZoneName)
					if not selectedTask then
						if allowCaptureFarpFallback then
							env.info("[SurfacePersistence] capture FARP route fallback to origin for "..tostring(self.name))
						else
							local bc = self.zoneCommander.battleCommander
							local removed = bc:_dynamicHybridRemoveTrackedGroup(self.name)
							if not removed then
								self._dynamicHybridRetired = true
								self._dynamicHybridRetiredAt = timer.getAbsTime()
								local tracked = self.zoneCommander and self.zoneCommander._suspendedLiveFsm
								if tracked then
									tracked[self.name] = nil
									if not next(tracked) then
										self.zoneCommander._suspendedLiveFsm = nil
									end
								end
								self.state = 'dead'
								self.lastStateTime = timer.getAbsTime()
								bc:markFsmGroupFilterDirty()
								bc:markReindexCombatFilterDirty()
								bc:markSupplyCacheDirty()
							end
							return
						end
					end
				elseif savedState == 'atdestination'
					and self.mission == 'attack'
					and self.MissionType ~= 'ARTY'
					and targetZone
					and targetZone.active
					and targetZone.side ~= restoreSide
				then
					selectedTask = dc.BuildPlayerGroundAttackRouteFromPoint({ x = px, y = pz }, self.targetzone, dc.DEFAULT_SPEED, 100, false, { useTargetRoadHook = true, useTargetMultiRoadHooks = true })
				end
				if selectedTask then
					self:_rememberSurfaceRoadPhase(selectedTask, self._passedRoadExit == true and artilleryReturnHome ~= true)
					if isFreshFarpSpawn then
						freshSpawnGroupHeadingDeg = _surfaceTaskSpawnHeadingDeg(selectedTask)
					end
				end

				if selectedTask or artilleryOnStation or artilleryReturnHome then
					self:clearWreckage()
					local sp = SPAWN:NewFromTemplate(tpl, restoreTemplate, self.name, true)
					if isFreshFarpSpawn and freshSpawnGroupHeadingDeg then
						sp = sp:InitGroupHeading(freshSpawnGroupHeadingDeg, freshSpawnGroupHeadingDeg, 0)
					end
					if restoreData.farpSpawn == true then
						sp = sp:InitValidateAndRepositionGroundUnits(true)
					end
					sp = sp:OnSpawnGroup(function(g)
						local gname = g and g.GetName and g:GetName() or self.name
						local liveGroup = Group.getByName(gname)
						self.spawnedName = gname
						self._lastSpawnTemplate = restoreTemplate
						self._sortieSide = tonumber(restoreData.side) or self._sortieSide or self.side
						self.side = self._sortieSide
						self._dcsGroup = liveGroup
						self._surfaceIsArtillery = self.MissionType == 'ARTY' or bc:_groupHasArtilleryAttribute(liveGroup)
						self.state = savedState
						self.lastStateTime = timer.getAbsTime() - elapsed
						self.groundconvoyMessaged = restoreData.groundconvoyMessaged == true or artilleryReturnHome == true
						self._supplyReturnHome = restoreData.supplyReturnHome == true
						self._artilleryReturnHome = artilleryReturnHome
						self._artilleryOnStation = nil
						self._artilleryFireTargetZone = nil
						self._artilleryFireStartedAt = nil
						if selectedTask then
							self:_scheduleSurfaceIntelRouteReports(selectedTask, gname)
						end
						self.zoneCommander:_forceIncludeRestoreLiveGc(self)
						if self.SetActiveMission then
							ActiveMission[self.name] = true
						end

						if liveGroup and liveGroup:isExist() then
							self:_applySurfaceRestoreAliveMask(liveGroup, restoreData)
							local c = liveGroup:getController()
							if c then
								c:popTask()
								if selectedTask then
									SCHEDULER:New(nil, function() c:pushTask(selectedTask) end, {}, 5)
									if self._pendingSupplyLaunchMessage then
										trigger.action.outTextForCoalition(2, self._pendingSupplyLaunchMessage, 10)
										self._pendingSupplyLaunchMessage = nil
									end
									self.zoneCommander.battleCommander:_completePendingShopPurchase(self)
									if isFreshFarpSpawn and self.playerGroundAttack == true then
										local convoyMessage = _surfaceTaskFreshGroundAttackMessage(self, selectedTask)
										trigger.action.outTextForCoalition(2, convoyMessage, 30)
										self._freshPlayerGroundAttackDeployOrigin = nil
									end
								elseif artilleryOnStation then
									local fireTarget = restoreData.artilleryFireTargetZone or restoreData.targetZone or self.targetzone
									SCHEDULER:New(nil, function()
										self.zoneCommander.battleCommander:startFiringAtZone(gname, fireTarget, 10, true)
									end, {}, 5)
								end
							end
						end
					end)
					local restored = sp:SpawnFromPointVec2(COORDINATE:NewFromVec2({ x = px, y = pz }))
					if restored then
						return
					end
					env.info("[SurfacePersistence] restore spawn failed for "..tostring(self.name).." template="..tostring(restoreTemplate))
					if not allowCaptureFarpFallback then
						self:_enterHangar(false)
						return
					end
					env.info("[SurfacePersistence] capture FARP spawn fallback to origin for "..tostring(self.name))
				end
			end

            local canSpawn = self:_consumeShouldSpawnDecision('preparing', false)
            if canSpawn == nil then return end
            if canSpawn then
				self:clearWreckage()
				_surfaceIntelClearLastKnownMarker(self.name)
				self._surfaceIntelRouteToken = (self._surfaceIntelRouteToken or 0) + 1
				self._surfaceIntelRouteReportsSent = nil
				self._artilleryOnStation = nil
				self._artilleryReturnHome = nil
				self._surfaceIsArtillery = nil
				self._artilleryFireTargetZone = nil
				self._artilleryFireStartedAt = nil
				self._artilleryFiringIntelToken = (self._artilleryFiringIntelToken or 0) + 1
				self._artilleryFiringIntelScheduled = nil
				self._artilleryFiringIntelSent = nil
				self._artilleryStillFiringIntelSent = nil
				local templateName = self.template or self.name
                self:_ensureTemplateCache()
                local set = self:_getTemplateSet(templateName)
				if set and #set>0 then
					local selectedTask, startVec2 = self:_buildSurfaceMissionTask(true, true)
					if not (startVec2 and selectedTask) then
						local bc = self.zoneCommander.battleCommander
						local removed = bc:_dynamicHybridRemoveTrackedGroup(self.name)
						if self._pendingShopPurchase then
							bc:_failPendingShopPurchase(self, "LOGISTICS_NO_AVAILABLE_PILOTS")
						end

						if not removed then
							self._dynamicHybridRetired = true
							self._dynamicHybridRetiredAt = timer.getAbsTime()
							local tracked = self.zoneCommander and self.zoneCommander._suspendedLiveFsm
							if tracked then
								tracked[self.name] = nil
								if not next(tracked) then
									self.zoneCommander._suspendedLiveFsm = nil
								end
							end
							self.state = 'dead'
							self.lastStateTime = timer.getAbsTime()
							bc:markFsmGroupFilterDirty()
							bc:markReindexCombatFilterDirty()
							bc:markSupplyCacheDirty()
						end
						return
					end
					self:_rememberSurfaceRoadPhase(selectedTask, false)
					if startVec2 and selectedTask then
                        local chosenTemplate = self:_resolveTemplateName()
                        if chosenTemplate then
                            local tpl = self:_getAirTemplate(chosenTemplate)
                            if tpl then
								local routeHeadingDeg = _surfaceTaskSpawnHeadingDeg(selectedTask)
                                local sp = SPAWN:NewFromTemplate(tpl, chosenTemplate, self.name, true)
								if routeHeadingDeg then
									sp = sp:InitGroupHeading(routeHeadingDeg, routeHeadingDeg, 0)
								end
                                sp = sp:OnSpawnGroup(function(g)
									local groupName = g:GetName()
									local gr = Group.getByName(groupName); if not gr then return end
									self._surfaceIsArtillery = self.MissionType == 'ARTY' or self.zoneCommander.battleCommander:_groupHasArtilleryAttribute(gr)
									self:_scheduleSurfaceIntelRouteReports(selectedTask, groupName)
									local c = gr:getController()
									if c then
										c:popTask()
										SCHEDULER:New(nil,function() c:pushTask(selectedTask) end,{},5)
										SCHEDULER:New(nil,function()
											local liveGroup = Group.getByName(groupName)
											if not liveGroup or not liveGroup:isExist() then return end
											local totalSpeed = getGroupSpeed(liveGroup)
											if not totalSpeed or totalSpeed > 0 then return end
											local liveController = liveGroup:getController()
											if not liveController then return end
											liveController:popTask()
											liveController:pushTask(selectedTask)
										end,{},35)
									end
								end)
                                local p = COORDINATE:NewFromVec2(startVec2)
                                local spawned = sp:SpawnFromPointVec2(p)
                                if spawned then
                                    self.spawnedName = spawned:GetName()
									self._lastSpawnTemplate = chosenTemplate
									self._sortieSide = self._sortieSide or self.side
									local spawnedGroup = Group.getByName(self.spawnedName)
									if self._pendingShopPurchase and (not spawnedGroup or not spawnedGroup:isExist() or not spawnedGroup:getController()) then
										self:_enterHangar(false)
										return
									end
									if self._pendingSupplyLaunchMessage then
										trigger.action.outTextForCoalition(2, self._pendingSupplyLaunchMessage, 10)
										self._pendingSupplyLaunchMessage = nil
									end
									self.zoneCommander.battleCommander:_completePendingShopPurchase(self)
									if self.playerGroundAttack == true then
										local convoyMessage = _surfaceTaskFreshGroundAttackMessage(self, selectedTask)
										trigger.action.outTextForCoalition(2, convoyMessage, 30)
										self._freshPlayerGroundAttackDeployOrigin = nil
									end
                                    if isUrgent then env.info("Dynamic Group [" .. self.name .. "] is spawning urgently!") else env.info("Dynamic Group [" .. self.name .. "] is spawning normally.") end
                                else
                                    env.info("ERROR: Dynamic Group [" .. self.name .. "] failed to spawn!")
									if self._pendingShopPurchase then
										self:_enterHangar(false)
										return
									end
                                end
                            else
                                env.info("ERROR: No template found for ["..tostring(chosenTemplate).."]")
								if self._pendingShopPurchase then
									self:_enterHangar(false)
									return
								end
                            end
                        else
                            env.info("ERROR: No valid template for side "..tostring(self.side).." in set "..tostring(self.template))
							if self._pendingShopPurchase then
								self:_enterHangar(false)
								return
							end
                        end
					end
                else
                    Respawn.Group(self.name)
					self._surfaceIsArtillery = self.MissionType == 'ARTY' or self.zoneCommander.battleCommander:_groupHasArtilleryAttribute(Group.getByName(self.name))
					self:_scheduleSurfaceIntelRouteReports(nil, self.name)
					local respawnedGroup = Group.getByName(self.name)
					if respawnedGroup and respawnedGroup:isExist() and respawnedGroup:getController() then
						if self._pendingSupplyLaunchMessage then
							trigger.action.outTextForCoalition(2, self._pendingSupplyLaunchMessage, 10)
							self._pendingSupplyLaunchMessage = nil
						end
						self.zoneCommander.battleCommander:_completePendingShopPurchase(self)
					elseif self._pendingShopPurchase then
						self:_enterHangar(false)
						return
					end
                    if isUrgent then env.info("Group [" .. self.name .. "] is spawning urgently!") else env.info("Group [" .. self.name .. "] is spawning normally.") end
                end
                self:_jtacMessage(L10N:Get("JTAC_ENEMY_CONVOY_MOVING_OUT_FROM"), nil, self.zoneCommander.zone, "Intel.ogg")
				_zoneIntelBroadcast(self.zoneCommander.zone, L10N:Format("INTEL_ENEMY_CONVOY_MOVING_OUT_FROM", tostring(self.zoneCommander.zone)), 25, "Intel.ogg")
                self.state = 'enroute'
				self.groundconvoyMessaged = false
                self.lastStateTime = timer.getAbsTime()
				if self.SetActiveMission then
					ActiveMission[self.name] = true
				end
            elseif self._pendingShopPurchase then
                self:_enterHangar(false)
                return
            end
        end

		elseif self.state == 'enroute' then
			if self._artilleryOnStation == true and self._artilleryReturnHome ~= true then
				return
			end
			if self.mission == 'attack' and self._artilleryReturnHome ~= true then
				self:_updateSurfaceRoadExitProgress(gr)
			end
			local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
			if self._artilleryReturnHome ~= true and self.playerGroundAttack == true and ((not tg) or (not tg.active) or tg.side == self.side) then
				if self:_tryRetaskPlayerGroundAttack(gr) then
					return
				end
				if gr and gr:isExist() then gr:destroy() end
				trigger.action.outTextForCoalition(2, L10N:Get("GROUND_ATTACK_ABORTED_NO_ENEMY"), 15)
				self:_retirePlayerGroundAttack()
				return
			end
			local arrivalZone = tg
			if self._artilleryReturnHome == true then
				arrivalZone = self.zoneCommander.battleCommander:getZoneByName(self.zoneCommander.zone)
			elseif self.mission == 'supply' and self._supplyReturnHome then
				arrivalZone = self.zoneCommander.battleCommander:getZoneByName(self.zoneCommander.zone)
			end
			if arrivalZone and gr and Utils.someOfGroupInZone(gr, arrivalZone.zone) then
				if not self._supplyReturnHome and self._artilleryReturnHome ~= true and self.side ~= 2 then
					self:_jtacMessage(L10N:Get("JTAC_ENEMY_CONVOY_ARRIVING_AT"), true, arrivalZone.zone, "Intel.ogg")
					_zoneIntelBroadcast(arrivalZone.zone, L10N:Format("INTEL_ENEMY_CONVOY_ARRIVING_AT", tostring(arrivalZone.zone)), 25, "Intel.ogg")
				end
				self.state = 'atdestination'
				self.lastStateTime = timer.getAbsTime()
			else
				if not self.groundconvoyMessaged and self.side == 1 then
					local shouldWeSend = math.random(0,100)
					if shouldWeSend > 98 then
						if self.mission == 'supply' then
							trigger.action.outTextForCoalition(2,L10N:Format("INTEL_ENEMY_SUPPLY_CONVOY_INBOUND", self.zoneCommander.zone, self.targetzone),15)
							self.groundconvoyMessaged = true
							trigger.action.outSoundForCoalition(2, "Intel.ogg")
						else
							trigger.action.outTextForCoalition(2,L10N:Format("INTEL_ENEMY_ATTACK_CONVOY_INBOUND", self.zoneCommander.zone, self.targetzone),15)
							self.groundconvoyMessaged = true
							trigger.action.outSoundForCoalition(2, "Intel.ogg")
						end
					end
				end
			end
		elseif self.state == 'atdestination' then
			if self._artilleryReturnHome == true then
				if timer.getAbsTime() - self.lastStateTime > GlobalSettings.landedDespawnTime then
					local hb = self.zoneCommander.battleCommander:getZoneByName(self.zoneCommander.zone)
					if hb and gr and Utils.someOfGroupInZone(gr, hb.zone) then
						self:_enterHangar(false)
						self._artilleryReturnHome = nil
						if gr and gr:isExist() then
							gr:destroy()
						end
					end
				end
				return
			end
			if self.mission == 'attack' then
				self:_updateSurfaceRoadExitProgress(gr)
			end
			if self.mission == 'supply' then
				if timer.getAbsTime() - self.lastStateTime > GlobalSettings.landedDespawnTime then
					local hb = self.zoneCommander.battleCommander:getZoneByName(self.zoneCommander.zone)
					if self._supplyReturnHome and hb and gr and Utils.someOfGroupInZone(gr, hb.zone) then
						self:_enterHangar(false)
						self._supplyReturnHome = nil
						if gr and gr:isExist() then
							gr:destroy()
						end
						return
					end
					local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
					if tg and gr and Utils.someOfGroupInZone(gr, tg.zone) then
						local validSupplyTarget = tg.active and (tg.side == self.side or tg.side == 0)
						if not validSupplyTarget then
							self:_enterHangar(false)
							self._supplyReturnHome = nil
							if gr and gr:isExist() then
								gr:destroy()
							end
							return
						end
						if tg.side == self.side and self.side == 1 and tg.BlueIsNear then
							local delaySec = 60
							local elapsed = timer.getAbsTime() - self.lastStateTime
							if elapsed <= delaySec then
								return
							end
						end
						self:_enterHangar(false)
						self._supplyReturnHome = nil
						if tg.side == 0 then
							SCHEDULER:New(nil,function()
							tg:capture(self.side)
							end,{},1.0,0)
						elseif tg.side == self.side then
							tg:upgrade()
						end
						local abName = tg.airbaseName
						if abName and WarehouseLogistics and self.side == 2 then
							if AIDeliveryamount == nil then AIDeliveryamount = 20 end
							local amount = AIDeliveryamount
							local bcObj = self.zoneCommander.battleCommander
							if bcObj and bcObj.addWarehouseItemsAtZone and amount > 0 then
								bcObj:addWarehouseItemsAtZone(tg, self.side, amount)
							end
						end
						if gr then
							gr:destroy()
						end
					end
				end
			elseif self.mission == 'attack' then
				local tg = self.zoneCommander.battleCommander:getZoneByName(self.targetzone)
				if self.playerGroundAttack == true and ((not tg) or (not tg.active) or tg.side == self.side) then
					if self:_tryRetaskPlayerGroundAttack(gr) then
						return
					end
					if gr and gr:isExist() then gr:destroy() end
					trigger.action.outTextForCoalition(2, L10N:Get("GROUND_ATTACK_ABORTED_NO_ENEMY"), 15)
					self:_retirePlayerGroundAttack()
					return
				end
				if timer.getAbsTime() - self.lastStateTime > GlobalSettings.landedDespawnTime then
					if tg and gr and Utils.someOfGroupInZone(gr, tg.zone) then
						if self.side == 1 and tg.BlueIsNear then
							local delaySec = 60
							local elapsed = timer.getAbsTime() - self.lastStateTime
							if elapsed <= delaySec then
								return
							end
						end
						local completedAction = false
						if tg.side == 0 then
							tg:capture(self.side)
							completedAction = true
						end
						local abName = tg.airbaseName
						if tg.side == self.side and abName and WarehouseLogistics and self.side == 2 then
							if AIDeliveryamount == nil then AIDeliveryamount = 20 end
							local amount = AIDeliveryamount
							local bcObj = self.zoneCommander.battleCommander
							if bcObj and bcObj.addWarehouseItemsAtZone and amount > 0 then
								bcObj:addWarehouseItemsAtZone(tg, self.side, amount)
								completedAction = true
							end
						end
						if completedAction then
							if gr and gr:isExist() then gr:destroy() end
							if self.playerGroundAttack == true then
								self:_retirePlayerGroundAttack()
							else
								self:_enterHangar(false)
							end
						end
					end
				end
			end
		elseif self.state == 'dead' then
			_surfaceIntelClearLastKnownMarker(self.name)
			self._surfaceIntelRouteReportsSent = nil
			if self.playerGroundAttack == true then
				self:_retirePlayerGroundAttack()
				return
			end
			if timer.getAbsTime() - self.lastStateTime > (respawnTimers.dead * spawnDelayFactor) then
				local canSpawn = self:_consumeShouldSpawnDecision('dead', false)
				if canSpawn == nil then return end
				if canSpawn then
					self.state = 'preparing'
					self.lastStateTime = timer.getAbsTime()
				end
			end
		end
	end

	function GroupCommander:update()
		if self._dynamicHybridRetired == true then
			return
		end
		local bcRef = self.zoneCommander.battleCommander
		bcRef._fsmCrashCurrentGroup = self.name
		if self.type == 'air' or self.type == 'carrier_air' then
			bcRef._fsmCrashPhase = 'processAir'
			local prevState=self.state
			local prevSpawned=self.Spawned and true or false
			local prevSide=self.side
			local prevMission=self.mission
			local prevMissionType=self.MissionType
			local prevUnitCategory=self.unitCategory
			local prevTargetzone=self.targetzone

			self:processAir()

			local spawnedNow=self.Spawned and true or false
			if prevState~=self.state or prevSpawned~=spawnedNow or prevSide~=self.side or prevMission~=self.mission or prevMissionType~=self.MissionType or prevUnitCategory~=self.unitCategory or prevTargetzone~=self.targetzone then
				bcRef:_syncNonCapSpawnBucketsForGroup(self)
				bcRef:_syncCapSpawnBucketsForGroup(self)
			end
		elseif self.type == 'surface' then
			bcRef._fsmCrashPhase = 'processSurface'
			self:processSurface()
		end
	end

end

BudgetCommander = {}
do
	--{ battleCommander = object, side=coalition, decissionFrequency=seconds, decissionVariance=seconds, skipChance=percent}
	function BudgetCommander:new(obj)
		obj = obj or {}
		setmetatable(obj, self)
		self.__index = self
		return obj
	end
	
	function BudgetCommander:update()
		local budget = self.battleCommander.accounts[self.side]
		local options = self.battleCommander.shops[self.side] or {}
		local canAfford = {}
		for i,v in pairs(options) do
			if v.cost<=budget and (v.stock==-1 or v.stock>0) then
				table.insert(canAfford, i)
			end
		end
		if #canAfford == 0 then
			return
		end
		
		local dice = math.random(1,100)
		if dice > self.skipChance then
			local maxAttempts = math.min(10, #canAfford)
			for i=1,maxAttempts,1 do
				local choice = math.random(1, #canAfford)
				local picked = table.remove(canAfford, choice)
				local err = self.battleCommander:buyShopItem(self.side, picked)
				if not err then
					break
				end
				if #canAfford == 0 then break end
			end
		end
	end
	
	function BudgetCommander:scheduleDecission()
		local variance = math.random(1, self.decissionVariance)
		SCHEDULER:New(nil,self.update,{self},variance,0)
	end
	
	function BudgetCommander:init()
		SCHEDULER:New(nil,self.scheduleDecission,{self},self.decissionFrequency,self.decissionFrequency)
	end
end

EventCommander = {}
do
	--{ decissionFrequency=seconds, decissionVariance=seconds, skipChance=percent}
	function EventCommander:new(obj)
		obj = obj or {}
		obj.events = {}
		setmetatable(obj, self)
		self.__index = self
		return obj
	end
	
	function EventCommander:addEvent(event)--{id=string, action=function, canExecute=function}
		table.insert(self.events, event)
	end
	
	function EventCommander:triggerEvent(id)
		for _,v in ipairs(self.events) do
			if v.id == id and v:canExecute() then
				v:action()
				break
			end
		end
	end
	
	function EventCommander:chooseAndStart(time)
		local canRun = {}
		for i,v in ipairs(self.events) do
			if v:canExecute() then
				table.insert(canRun, v)
			end
		end
		
		if #canRun == 0 then return end
		
		local dice = math.random(1,100)
		if dice > self.skipChance then
			local choice = math.random(1, #canRun)
			local err = canRun[choice]:action()
		end
	end
	
	function EventCommander:scheduleDecission(time)
		local variance = math.random(1, self.decissionVariance)
		timer.scheduleFunction(self.chooseAndStart, self, time + variance)
		return time + self.decissionFrequency + variance
	end
	
	function EventCommander:init()
		timer.scheduleFunction(self.scheduleDecission, self, timer.getTime() + self.decissionFrequency)
	end
end
SelfJtac = {}

do
    SelfJtac.categories = {}
	SelfJtac.categories['SAM'] = {'SAM SR', 'SAM TR', 'IR Guided SAM'}
	SelfJtac.categories['Infantry'] = {'Infantry'}
	SelfJtac.categories['Armor'] = {'Tanks','IFV','APC'}
	SelfJtac.categories['Support'] = {'Unarmed vehicles','Artillery','SAM LL','SAM CC'}
	SelfJtac.categories['Structures'] = {'StaticObjects'}
	SelfJtac.savedPlayerSettings = SelfJtac.savedPlayerSettings or {}

	local function selfJtacClonePersistentSettings(src)
		return {
			autoSearch = (src and src.autoSearch == true) or false,
			autoNext = (src and src.autoNext == true) or false
		}
	end

	local function selfJtacStorePlayerSettings(playerName, settings)
		if type(playerName) ~= "string" or playerName == "" then return end
		SelfJtac.savedPlayerSettings[playerName] = selfJtacClonePersistentSettings(settings)
	end

	function SelfJtac.fetchPlayerSettings(playerName)
		if type(playerName) ~= "string" or playerName == "" then return nil end
		local entry = SelfJtac.savedPlayerSettings[playerName]
		if type(entry) ~= "table" then return nil end
		return selfJtacClonePersistentSettings(entry)
	end

	function SelfJtac.exportPlayerSettings()
		local exported = {}
		for playerName, settings in pairs(SelfJtac.savedPlayerSettings or {}) do
			exported[#exported + 1] = {
				name = playerName,
				settings = selfJtacClonePersistentSettings(settings)
			}
		end
		return exported
	end

	function SelfJtac.importPlayerSettings(entries)
		SelfJtac.savedPlayerSettings = {}
		if type(entries) ~= "table" then return end
		for _, entry in ipairs(entries) do
			if type(entry) == "table" and type(entry.name) == "string" and entry.name ~= "" then
				selfJtacStorePlayerSettings(entry.name, entry.settings)
			end
		end
	end

    	--{name = 'groupname'}
	function SelfJtac:new(obj)
		obj = obj or {}
		obj.lasers = {tgt=nil, ir=nil}
		obj.target = nil
		obj.priority = nil
		obj.jtacMenu = nil
		obj.laserCode = 1688
        obj.groupID = Group.getByName(obj.name):getID()
		obj.side = Group.getByName(obj.name):getCoalition()
        obj.timer = nil
		obj.distUnit='NM'
		obj.autoNext=false
		obj.autoTimer=nil
		obj.optionsMenu=nil
		obj._optionItems={}
		obj.playerName = obj.playerName
		obj._settingsDirty = false
		setmetatable(obj, self)
		self.__index = self
		local savedSettings = SelfJtac.fetchPlayerSettings(obj.playerName)
		if savedSettings then
			obj.autoNext = savedSettings.autoNext == true
			if savedSettings.autoSearch == true then
				obj.autoTimer = timer.scheduleFunction(function(p) p:searchTarget(true) return timer.getTime()+30 end, obj, timer.getTime()+30)
			end
		end
		return obj
	end

    function SelfJtac:setCode(code)
        if code>=1111 and code <= 1788 then
            self.laserCode = code
            trigger.action.outTextForGroup(self.groupID, L10N:FormatForGroup(self.groupID, "SELF_JTAC_LASER_CODE_SET", code), 10)
        else
            trigger.action.outTextForGroup(self.groupID, L10N:GetForGroup(self.groupID, "JTAC_CODE_INVALID"), 10)
        end
    end
	
	function SelfJtac:showMenu(forceRefresh)
		local gr = Group.getByName(self.name)
		if not gr then
			return
		end
		local T = L10N:ForGroup(self.groupID)
		if forceRefresh and self.jtacMenu then
			missionCommands.removeItemForGroup(self.groupID, self.jtacMenu)
			self.jtacMenu = nil
			self.selectTargetMenu = nil
			self._cmdIds = {}
			self._moreMenus = {}
			self.optionsMenu = nil
			self._optionItems = {}
		end
		
		if not self.jtacMenu then
			self.jtacMenu = missionCommands.addSubMenuForGroup(self.groupID, T:Get("SELF_JTAC_MENU_TITLE"))

			missionCommands.addCommandForGroup(self.groupID, T:Get("SELF_JTAC_MENU_SEARCH"), self.jtacMenu, function(dr)
				if Group.getByName(dr.name) then
					dr:searchTarget()
				end
			end, self)
			
			missionCommands.addCommandForGroup(self.groupID, T:Get("SELF_JTAC_MENU_TARGET_INFO"), self.jtacMenu, function(dr)
				if Group.getByName(dr.name) then
					dr:printTarget(true)
				end
			end, self)
			
			missionCommands.addCommandForGroup(self.groupID, T:Get("SELF_JTAC_MENU_MARK_WITH_SMOKE"), self.jtacMenu, function(dr)
				if Group.getByName(dr.name) then
					dr:markWithSmoke()
				end
			end, self)
            
			missionCommands.addCommandForGroup(self.groupID, T:Get("COMMON_CLEAR"), self.jtacMenu, function(dr)
				if Group.getByName(dr.name) then
					dr:clearTarget()
                    trigger.action.outTextForGroup(dr.groupID, L10N:GetForGroup(dr.groupID, "SELF_JTAC_TARGET_CLEARED"), 10)
				end
			end, self)
			
			local priomenu = missionCommands.addSubMenuForGroup(self.groupID, T:Get("SELF_JTAC_MENU_PRIORITY"), self.jtacMenu)
			for i,v in pairs(SelfJtac.categories) do
				missionCommands.addCommandForGroup(self.groupID, i, priomenu, function(dr, cat)
					if Group.getByName(dr.name) then
						dr:setPriority(cat)
                        if dr.target then
						    dr:searchTarget()
                        end
					end
				end, self, i)
			end
			self.optionsMenu=missionCommands.addSubMenuForGroup(self.groupID,T:Get("SELF_JTAC_MENU_OPTIONS"),self.jtacMenu)
			self:refreshOptionsMenu()
			
			missionCommands.addCommandForGroup(self.groupID, T:Get("COMMON_CLEAR"), priomenu, function(dr)
				if Group.getByName(dr.name) then
					dr:clearPriority()
				end
			end, self)
			self.selectTargetMenu = missionCommands.addSubMenuForGroup(self.groupID, T:Get("JTAC_MENU_SELECT_TARGET"), self.jtacMenu)
			self:buildSelectTargetMenu()
		end
	end

	function SelfJtac:refreshOptionsMenu()
		if not self.jtacMenu then return end
		local T = L10N:ForGroup(self.groupID)
		if not self.optionsMenu then
			self.optionsMenu=missionCommands.addSubMenuForGroup(self.groupID,T:Get("SELF_JTAC_MENU_OPTIONS"),self.jtacMenu)
		end
		for _, handle in ipairs(self._optionItems or {}) do
			missionCommands.removeItemForGroup(self.groupID, handle)
		end
		self._optionItems = {}
		local function remember(handle)
			self._optionItems[#self._optionItems + 1] = handle
			return handle
		end
		local opt = self.optionsMenu
		remember(missionCommands.addCommandForGroup(self.groupID,T:Get("SELF_JTAC_MENU_TOGGLE_UNIT"),opt,SelfJtac.toggleUnit,self))
		local autoSearchState = self:isAutoSearchEnabled() and T:Get("SELF_JTAC_STATE_ON") or T:Get("SELF_JTAC_STATE_OFF")
		local autoSearchMenu = remember(missionCommands.addSubMenuForGroup(self.groupID, T:Format("SELF_JTAC_MENU_AUTO_SEARCH", autoSearchState), opt))
		missionCommands.addCommandForGroup(self.groupID, T:Get("SELF_JTAC_STATE_ON"), autoSearchMenu, function(dr)
			if Group.getByName(dr.name) then
				dr:setAutoSearch(true)
			end
		end, self)
		missionCommands.addCommandForGroup(self.groupID, T:Get("SELF_JTAC_STATE_OFF"), autoSearchMenu, function(dr)
			if Group.getByName(dr.name) then
				dr:setAutoSearch(false)
			end
		end, self)
		local autoNextState = self.autoNext and T:Get("SELF_JTAC_STATE_ON") or T:Get("SELF_JTAC_STATE_OFF")
		local autoNextMenu = remember(missionCommands.addSubMenuForGroup(self.groupID, T:Format("SELF_JTAC_MENU_AUTO_NEXT", autoNextState), opt))
		missionCommands.addCommandForGroup(self.groupID, T:Get("SELF_JTAC_STATE_ON"), autoNextMenu, function(dr)
			if Group.getByName(dr.name) then
				dr:setAutoNext(true)
			end
		end, self)
		missionCommands.addCommandForGroup(self.groupID, T:Get("SELF_JTAC_STATE_OFF"), autoNextMenu, function(dr)
			if Group.getByName(dr.name) then
				dr:setAutoNext(false)
			end
		end, self)

		local dial = remember(missionCommands.addSubMenuForGroup(self.groupID, T:Get("SELF_JTAC_MENU_CODE"), opt))
		for i2=1,7,1 do
			local digit2 = missionCommands.addSubMenuForGroup(self.groupID, '1'..i2..'__', dial)
			for i3=1,9,1 do
				local digit3 = nil
				for i4=1,9,1 do
					local code = tonumber('1'..i2..i3..i4)
					if code>=1111 and code<=1788 then
						if not digit3 then
							digit3 = missionCommands.addSubMenuForGroup(self.groupID, '1'..i2..i3..'_', digit2)
						end
						missionCommands.addCommandForGroup(self.groupID, '1'..i2..i3..i4, digit3, self.setCode, self, code)
					end
				end
			end
		end
	end

	function SelfJtac:toggleUnit()
		self.distUnit = self.distUnit=='NM' and 'KM' or 'NM'
		trigger.action.outTextForGroup(self.groupID,L10N:FormatForGroup(self.groupID, "SELF_JTAC_DISTANCE_UNIT", self.distUnit),10)
		self:printTarget(true)
	end

	function SelfJtac:isAutoSearchEnabled()
		return self.autoTimer ~= nil
	end

	function SelfJtac:_persistSettings()
		if not self._settingsDirty then return end
		selfJtacStorePlayerSettings(self.playerName, {
			autoSearch = self:isAutoSearchEnabled(),
			autoNext = self.autoNext == true
		})
		self._settingsDirty = false
	end

	function SelfJtac:setAutoSearch(enabled, silent)
		local desired = enabled == true
		local current = self:isAutoSearchEnabled()
		if desired ~= current then
			if desired then
				self.autoTimer = timer.scheduleFunction(function(p) p:searchTarget(true) return timer.getTime()+30 end, self, timer.getTime()+30)
			else
				timer.removeFunction(self.autoTimer)
				self.autoTimer = nil
			end
			self._settingsDirty = true
			self:_persistSettings()
		end
		if not silent then
			local T = L10N:ForGroup(self.groupID)
			trigger.action.outTextForGroup(self.groupID,T:Format("SELF_JTAC_AUTO_SEARCH_STATE", desired and T:Get("SELF_JTAC_STATE_ON") or T:Get("SELF_JTAC_STATE_OFF")),10)
		end
		self:refreshOptionsMenu()
	end

	function SelfJtac:setAutoNext(enabled, silent)
		local desired = enabled == true
		if self.autoNext ~= desired then
			self.autoNext = desired
			self._settingsDirty = true
			self:_persistSettings()
		end
		if not silent then
			local T = L10N:ForGroup(self.groupID)
			trigger.action.outTextForGroup(self.groupID,T:Format("SELF_JTAC_AUTO_NEXT_STATE", desired and T:Get("SELF_JTAC_STATE_ON") or T:Get("SELF_JTAC_STATE_OFF")),5)
		end
		self:refreshOptionsMenu()
	end

	function SelfJtac:toggleAuto()
		self:setAutoSearch(not self:isAutoSearchEnabled())
	end
	
	function SelfJtac:setPriority(prio)
		self.priority = SelfJtac.categories[prio]
		self.prioname = prio
        trigger.action.outTextForGroup(self.groupID, L10N:FormatForGroup(self.groupID, "SELF_JTAC_FOCUSING_ON", prio), 10)
	end
	
	function SelfJtac:toggleNext()
		self:setAutoNext(not self.autoNext)
	end

	function SelfJtac:clearPriority()
		self.priority = nil
	end
	
	function SelfJtac:setTarget(unit)
		
		local me = Group.getByName(self.name)
		if not me then return end

        local meun = me:getUnit(1)
        local stats = SelfJtac.getAircraftStats(meun:getDesc().typeName)
		
		local pnt = unit:getPoint()

        local unitPos = meun:getPosition()
        local unitheading = math.deg(math.atan2(unitPos.x.z, unitPos.x.x))
        local bearing = SelfJtac.getBearing(meun:getPoint(), pnt)
        local unitDistance = SelfJtac.getDist(pnt, meun:getPoint())
        
        local deviation = math.abs(SelfJtac.getHeadingDiff(unitheading, bearing))

        local from = meun:getPoint()
        from.y = from.y+1.5
        local to = unit:getPoint()
        to.y = to.y+1.5

        if unitDistance > (stats.minDist * 1000) or deviation > stats.maxDeviation or not land.isVisible(from, to) then
            self:clearTarget()
			trigger.action.outTextForGroup(self.groupID, L10N:GetForGroup(self.groupID, "SELF_JTAC_TARGET_OUT_OF_BOUNDS"), 10)
            return
        end

        local dst = 99999
        if self.prevPnt then
            dst = SelfJtac.getDist(pnt, self.prevPnt)
        end
        
        if not self.prevPnt or dst >= 0.5 then

            if self.lasers.tgt then
                self.lasers.tgt:setPoint(pnt)
            else
                self.lasers.tgt = Spot.createLaser(meun, { x = 0, y = 5.0, z = 0 }, SelfJtac.getPointOnSurface(pnt), self.laserCode)
            end
            
            if self.lasers.ir then
                self.lasers.ir:setPoint(pnt)
            else
                self.lasers.ir = Spot.createInfraRed(meun, stats.laserOffset, pnt)
            end

            self.prevPnt = pnt
        end
		
		self.target = unit:getName()

        timer.scheduleFunction(function(param, time)
            param:updateTarget()
        end, self, timer.getTime()+0.5)
	end
	
function SelfJtac:printTarget(makeitlast)
		local toprint = ''
		if self.target then
			local tgtunit = Unit.getByName(self.target)
			local isStructure = false
			if not tgtunit then 
				tgtunit = StaticObject.getByName(self.target)
				isStructure = true
			end
			if tgtunit and tgtunit:isExist() and (not tgtunit.isActive or tgtunit:isActive()) and tgtunit:getLife()>=1 then
				local pnt = tgtunit:getPoint()
				local meun = Group.getByName(self.name):getUnit(1)
				local bearing = math.floor(SelfJtac.getBearing(meun:getPoint(), pnt)+0.5)
				local dist = SelfJtac.getDist(meun:getPoint(), pnt)
				local distStr=self.distUnit=='KM' and string.format('%.2f km',dist/1000) or string.format('%.1f NM',dist/1852)
				local tgttype = L10N:Get("SELF_JTAC_TARGET_TYPE_UNIDENTIFIED")
				if isStructure then
					tgttype = L10N:Get("SELF_JTAC_TARGET_TYPE_STRUCTURE")
				else
					tgttype = renameType(tgtunit:getTypeName())
				end
				if self.priority then
					toprint = L10N:Format("JTAC_PRIORITY_TARGETS", self.prioname)
				end
				toprint = toprint..L10N:Format("SELF_JTAC_REPORT", tgttype, self.laserCode, bearing, distStr)
				local lat,lon,alt = coord.LOtoLL(pnt)
				local c = COORDINATE:NewFromVec3(pnt)
				local function ddm(v,h)local d=math.floor(math.abs(v))local m=(math.abs(v)-d)*60 return string.format("[%s %02d %06.3f']",h,d,m)end
				local function dms(v,h)local a=math.abs(v)local d=math.floor(a)local m=math.floor((a-d)*60)local s=((a-d)*60-m)*60 return string.format("[%s %02d %02d' %05.2f\"]",h,d,m,s)end
				local ddmStr = ddm(lat,lat>=0 and 'N' or 'S')..'⇢ '..ddm(lon,lon>=0 and 'E' or 'W')
				local dmsStr = dms(lat,lat>=0 and 'N' or 'S')..'⇢ '..dms(lon,lon>=0 and 'E' or 'W')
				local mgrs = c:ToStringMGRS():gsub("^MGRS%s*","")
				toprint = toprint..'\nDDM:  '..ddmStr
				toprint = toprint..'\nDMS:  '..dmsStr
				toprint = toprint..'\nMGRS: '..mgrs
				toprint = toprint..L10N:Format("JTAC_ALTITUDE_LINE", math.floor(alt), math.floor(alt*3.280839895))
			else
				makeitlast = false
				toprint = L10N:Get("JTAC_NO_TARGET_TITLE")
			end
		else
			makeitlast = false
			toprint = L10N:Get("JTAC_NO_TARGET")
		end
		local gr = Group.getByName(self.name)
		if makeitlast then
			trigger.action.outTextForCoalition(gr:getCoalition(), toprint, 60, true)
		else
			trigger.action.outTextForCoalition(gr:getCoalition(), toprint, 10)
		end
	end

	
	function SelfJtac:markWithSmoke()
		if self.target then
			local tgtunit = Unit.getByName(self.target) or StaticObject.getByName(self.target)
			if tgtunit and tgtunit:isExist() and (not tgtunit.isActive or tgtunit:isActive()) and tgtunit:getLife()>=1 then
				local pnt = tgtunit:getPoint()
				trigger.action.smoke(pnt, trigger.smokeColor.Blue)
				trigger.action.outTextForGroup(self.groupID, L10N:GetForGroup(self.groupID, "SELF_JTAC_MARKING_BLUE_SMOKE"), 10)
			else
				trigger.action.outTextForGroup(self.groupID, L10N:GetForGroup(self.groupID, "SELF_JTAC_INVALID_OBJECTIVE"), 10)
			end
		else
			trigger.action.outTextForGroup(self.groupID, L10N:GetForGroup(self.groupID, "SELF_JTAC_NO_OBJECTIVE"), 10)
		end
	end

	function SelfJtac:clearTarget()
		self.target = nil
        self.prevPnt = nil
		self.targetList = {}
	
		if self.lasers.tgt then
			self.lasers.tgt:destroy()
			self.lasers.tgt = nil
		end
		
		if self.lasers.ir then
			self.lasers.ir:destroy()
			self.lasers.ir = nil
		end
		self:buildSelectTargetMenu()
	end

	function SelfJtac:updateTarget()
		local player = Group.getByName(self.name)
		if not player or player:getSize() == 0 then
			self:clearTarget()
			return
		end
		if self.target then
			local un = Unit.getByName(self.target)
			if un and un:isExist() then
				if un:getLife() >= 1 then
					self:setTarget(un)
					self:buildSelectTargetMenu()
				else
				self:clearTarget()
				if self.autoNext then
					self:searchTarget(true)
					if #self.targetList > 0 then
						for _,obj in ipairs(self.targetList) do
							if obj and obj:isExist() and obj:getLife()>=1 then
								self:setTarget(obj)
								trigger.action.outTextForGroup(self.groupID,L10N:GetForGroup(self.groupID, "SELF_JTAC_KILL_CONFIRMED"),5)
								timer.scheduleFunction(function()
								self:printTarget(true)
								end, {}, timer.getTime() + 5)
								break
							end
						end
					end
				else
					trigger.action.outTextForGroup(self.groupID,L10N:GetForGroup(self.groupID, "SELF_JTAC_KILL_CONFIRMED_STOPPING"),10)
				end
			end
		else
			self:clearTarget()
				if self.autoNext then
					self:searchTarget(true)
					if #self.targetList > 0 then
						for _,obj in ipairs(self.targetList) do
							if obj and obj:isExist() and obj:getLife()>=1 then
								self:setTarget(obj)
								trigger.action.outTextForGroup(self.groupID,L10N:GetForGroup(self.groupID, "SELF_JTAC_KILL_CONFIRMED"),5)
								timer.scheduleFunction(function()
								self:printTarget(true)
								end, {}, timer.getTime() + 5)
								break
							end
						end
					end
				else
					trigger.action.outTextForGroup(self.groupID,L10N:GetForGroup(self.groupID, "SELF_JTAC_KILL_CONFIRMED_STOPPING"),10)
				end
			end
		end
	end


	function SelfJtac.getBearing(fromvec, tovec)
		local fx = fromvec.x
		local fy = fromvec.z
		
		local tx = tovec.x
		local ty = tovec.z
		
		local brg = math.atan2(ty - fy, tx - fx)
		
		
		if brg < 0 then
			 brg = brg + 2 * math.pi
		end
		
		brg = brg * 180 / math.pi
		

		return brg
	end

    function SelfJtac.getPointOnSurface(point)
		return {x = point.x, y = land.getHeight({x = point.x, y = point.z}), z= point.z}
	end

	function SelfJtac.getHeadingDiff(heading1, heading2) -- heading1 + result == heading2
		local diff = heading1 - heading2
		local absDiff = math.abs(diff)
		local complementaryAngle = 360 - absDiff
	
		if absDiff <= 180 then 
			return -diff
		elseif heading1 > heading2 then
			return complementaryAngle
		else
			return -complementaryAngle
		end
	end

    function SelfJtac.getDist(point1, point2)
        local vec = {x = point1.x - point2.x, y = point1.y - point2.y, z = point1.z - point2.z}
        return (vec.x^2 + vec.y^2 + vec.z^2)^0.5
    end
	
		function SelfJtac:searchTarget(silent)
			local gr = Group.getByName(self.name)
			if not gr or not gr:isExist() then
				if self.autoTimer then           -- cancel 30-s scheduler
					timer.removeFunction(self.autoTimer)
					self.autoTimer = nil
				end
				return
			end
			local un = gr:getUnit(1)
			if not un then
				self:clearTarget()
				if self.autoTimer then
					timer.removeFunction(self.autoTimer)
					self.autoTimer = nil
				end
				return
			end
            local stats = SelfJtac.getAircraftStats(un:getDesc().typeName)

            local ppos = un:getPoint()
            local volume = {
                id = world.VolumeType.SPHERE,
                params = {
                    point = {x = ppos.x, z = ppos.z, y = land.getHeight({x = ppos.x, y = ppos.z})},
                    radius = stats.minDist * 1000
                }
            }

            local targets = {}
            world.searchObjects({Object.Category.UNIT, Object.Category.STATIC}, volume, function(unit, collection)
                if unit and unit:isExist() and (not unit.isActive or unit:isActive()) then
                    collection[unit:getName()] = unit
                end
                return true
            end, targets)

            local viabletgts = {}
            for i, v in pairs(targets) do
                if v and v:isExist() and v:getLife() >= 1 and i ~= un:getName() and v:getCoalition() ~= un:getCoalition() then
                    local unitPos = un:getPosition()
                    local unitheading = math.deg(math.atan2(unitPos.x.z, unitPos.x.x))
                    local bearing = SelfJtac.getBearing(un:getPoint(), v:getPoint())
                    local deviation = math.abs(SelfJtac.getHeadingDiff(unitheading, bearing))
                    local unitDistance = SelfJtac.getDist(un:getPoint(), v:getPoint())

                    if unitDistance <= (stats.minDist * 1000) and deviation <= stats.maxDeviation then
                        local from = un:getPoint()
                        from.y = from.y + 1.5
                        local to = v:getPoint()
                        to.y = to.y + 1.5
                        if land.isVisible(from, to) then
                            table.insert(viabletgts, v)
                        end
                    end
                end
            end

            if self.priority then
                local priorityTargets = {}
                for _, v in ipairs(viabletgts) do
                    for _, v2 in ipairs(self.priority) do
                        if v2 == "StaticObjects" and Object.getCategory(v) == Object.Category.STATIC then
                            table.insert(priorityTargets, v)
                            break
                        elseif v:hasAttribute(v2) and v:getLife() >= 1 then
                            table.insert(priorityTargets, v)
                            break
                        end
                    end
                end
                if #priorityTargets > 0 then
                    viabletgts = priorityTargets
                else
                    trigger.action.outTextForGroup(self.groupID, L10N:GetForGroup(self.groupID, "SELF_JTAC_NO_PRIORITY_SEARCHING"), 10)
                end
            end

		self.targetList = viabletgts

		if self.target then
			if #viabletgts == 0 then
				self:clearTarget()
				if not silent then
					trigger.action.outTextForGroup(self.groupID,L10N:GetForGroup(self.groupID, "SELF_JTAC_TARGET_LOST"),5)
				end
			end
		else
			if #viabletgts > 0 then
				self:setTarget(viabletgts[1])
				self:printTarget(true)
			elseif not silent then
				trigger.action.outTextForGroup(self.groupID,L10N:GetForGroup(self.groupID, "SELF_JTAC_NO_TARGETS_FOUND"),10)
			end
		end

		self:buildSelectTargetMenu()
	end

	function SelfJtac:sortByThreat(targets)
		local threatRank = {
			['SAM TR']          = 1,
			['IR Guided SAM']   = 2,
			['SAM SR']          = 3,
			['Tanks']           = 4,
			['IFV']             = 5,
			['APC']             = 6,
			['Artillery']       = 7,
			['SAM LL']          = 8,
			['SAM CC']          = 9,
			['Unarmed vehicles']= 10,
			['Infantry']        = 11,
			['Structures']   	= 12
		}

		local function getScore(u)
			local best = 999
			for attr, rank in pairs(threatRank) do
				if u:hasAttribute(attr) and rank < best then
					best = rank
				end
			end
			return best
		end

		table.sort(targets, function(a,b) return getScore(a) < getScore(b) end)
		return targets
	end

	function SelfJtac:buildSelectTargetMenu()
		if not self.jtacMenu then return end
		local T = L10N:ForGroup(self.groupID)
		if not self.selectTargetMenu then
			self.selectTargetMenu = missionCommands.addSubMenuForGroup(self.groupID,T:Get("JTAC_MENU_SELECT_TARGET"),self.jtacMenu)
			self._cmdIds = {}
			self._moreMenus = {}
		end
		for _,id in ipairs(self._cmdIds or {}) do missionCommands.removeItemForGroup(self.groupID,id) end
		for _,m in ipairs(self._moreMenus or {}) do missionCommands.removeItemForGroup(self.groupID,m) end
		self._cmdIds = {}
		self._moreMenus = {}
		local tgtlist = self.targetList or {}
		if #tgtlist == 0 then
			table.insert(self._cmdIds,missionCommands.addCommandForGroup(self.groupID,T:Get("JTAC_MENU_NO_VALID_TARGETS"),self.selectTargetMenu,function() end))
			return
		end
		if self.sortByThreat then tgtlist = self:sortByThreat(tgtlist) end
		local sub = nil
		local shown = 0
		for i,obj in ipairs(tgtlist) do
			if obj and obj:isExist() and (not obj.isActive or obj:isActive()) and obj:getLife()>=1 then
				shown = shown + 1
				local label
				if Object.getCategory(obj)==Object.Category.STATIC then
					label='('..shown..') '..(obj:getName() or 'Unknown')
				else
					label='('..shown..') '..renameType(obj:getTypeName())
				end
				if self.target==obj:getName() then label=label..T:Get("JTAC_MENU_LASING_SUFFIX") end
				local cb=function()
					self:setTarget(obj)
					self:printTarget(true)
					self:buildSelectTargetMenu()
				end
				local id
				if shown<10 then
					id=missionCommands.addCommandForGroup(self.groupID,label,self.selectTargetMenu,cb)
				elseif shown==10 then
					sub=missionCommands.addSubMenuForGroup(self.groupID,T:Get("MENU_MORE"),self.selectTargetMenu)
					table.insert(self._moreMenus,sub)
					id=missionCommands.addCommandForGroup(self.groupID,label,sub,cb)
				elseif (shown-10)%9==0 then
					sub=missionCommands.addSubMenuForGroup(self.groupID,T:Get("MENU_MORE"),sub)
					table.insert(self._moreMenus,sub)
					id=missionCommands.addCommandForGroup(self.groupID,label,sub,cb)
				else
					id=missionCommands.addCommandForGroup(self.groupID,label,sub,cb)
				end
				table.insert(self._cmdIds,id)
			end
		end
		if shown == 0 then
			table.insert(self._cmdIds,missionCommands.addCommandForGroup(self.groupID,T:Get("JTAC_MENU_NO_VALID_TARGETS"),self.selectTargetMenu,function() end))
		end
	end


    function SelfJtac.getAircraftStats(aircraftType)
