	function LogisticCommander:_bumpGroupMenuToken(groupid)
		self.groupMenuTokens = self.groupMenuTokens or {}
		self.groupMenuTokens[groupid] = (self.groupMenuTokens[groupid] or 0) + 1
		return self.groupMenuTokens[groupid]
	end

	function LogisticCommander:pruneGroupMenus(groupid, groupname)
		self:_bumpGroupMenuToken(groupid)

		local mooseGroup = groupname and GROUP:FindByName(groupname) or nil
		if mooseGroup then
			mooseGroup.CTLDTopmenu = nil
		end

		local bcObj = self.battleCommander
		local jointSide = bcObj:_jointPruneGroup(groupid)
		if bcObj.groupSupportMenus[groupid] then
			local supportState = bcObj.groupSupportMenus[groupid]
			for _, handle in ipairs(supportState.items or {}) do
				missionCommands.removeItemForGroup(groupid, handle)
			end
			if supportState.menu then
				missionCommands.removeItemForGroup(groupid, supportState.menu)
			end
			bcObj.groupSupportMenus[groupid] = nil
		end

		bcObj:_removeDynamicControlMenuForGroup(groupid)

		if bcObj.zoneStatusMenus[groupid] then
			missionCommands.removeItemForGroup(groupid, bcObj.zoneStatusMenus[groupid])
			bcObj.zoneStatusMenus[groupid] = nil
			bcObj.redSideMenus[groupid] = nil
			bcObj.blueSideMenus[groupid] = nil
		end

		if self.statsMenus[groupid] then
			missionCommands.removeItemForGroup(groupid, self.statsMenus[groupid])
			self.statsMenus[groupid] = nil
		end
		self.languageMenus[groupid] = nil

		if self.csarGroupMenus[groupid] then
			if self.csarGroupMenus[groupid] ~= true then
				missionCommands.removeItemForGroup(groupid, self.csarGroupMenus[groupid])
			end
			self.csarGroupMenus[groupid] = nil
		end

		local mooseMenu = LogisticCommander.mooseLogisticsMenus[groupid]
		if mooseMenu then
			mooseMenu:Remove()
			LogisticCommander.mooseLogisticsMenus[groupid] = nil
		elseif self.groupMenus[groupid] then
			missionCommands.removeItemForGroup(groupid, self.groupMenus[groupid])
		end
		self.groupMenus[groupid] = nil
		self.staticMenus[groupid] = nil
		self.groupIdToName[groupid] = nil
		self.csarGroups[groupid] = nil

		if ewrs and ewrs.removeGroupF10Menu then
			ewrs.removeGroupF10Menu(groupid)
		end

		if MissionsRootMenus[groupid] then
			missionCommands.removeItemForGroup(groupid, MissionsRootMenus[groupid])
			MissionsRootMenus[groupid] = nil
		end
		printMissionMenus[groupid] = nil
		removeMenusForGroupID(groupid)
		mc.strikeMenuByGroup[groupid] = nil
		mc.intelMenuByGroup[groupid] = nil

		if SelfJtac.jtacs[groupid] then
			local oldjtac = SelfJtac.jtacs[groupid]
			if oldjtac.autoTimer then
				timer.removeFunction(oldjtac.autoTimer)
				oldjtac.autoTimer = nil
			end
			oldjtac:clearTarget()
			if oldjtac.jtacMenu then
				missionCommands.removeItemForGroup(groupid, oldjtac.jtacMenu)
			end
			SelfJtac.jtacs[groupid] = nil
		end

		if jointSide then
			bcObj:refreshJointMenusForSide(jointSide)
		end
	end



	function LogisticCommander:loadSupplies(groupName, supplyCount)
		local gr = Group.getByName(groupName)
		if gr then
			local gid = gr:getID()
			local T = L10N:ForGroup(gid)
			local un = gr:getUnit(1)
			if un then
				if Utils.isInAir(un) then
					trigger.action.outTextForGroup(gid, T:Get("LOGISTICS_CANNOT_LOAD_IN_AIR"), 10)
					return
				end
				
				self._lastLoadTs = self._lastLoadTs or {}
				local now = timer.getTime()
				if self._lastLoadTs[gid] and now - self._lastLoadTs[gid] < 1 then return end
				self._lastLoadTs[gid] = now

				local unitType = un:getTypeName()
				local loadCount = supplyCount or 1
				if loadCount > 1 then
					if not (LogisticCommander.doubleSupplyTypes and LogisticCommander.doubleSupplyTypes[unitType]) then
						loadCount = 1
					end
				end
				if loadCount < 1 then
					loadCount = 1
				end
				local existingCargo = self.carriedCargo[gr:getID()]
				if existingCargo then
					local count = type(existingCargo) == "table" and existingCargo.count or 1
					local cap = (LogisticCommander.doubleSupplyTypes and LogisticCommander.doubleSupplyTypes[unitType]) and 2 or 1
					if count < cap then
						local newCount = count + loadCount
						if newCount > cap then newCount = cap end
						self.carriedCargo[gr:getID()] = { source = (type(existingCargo) == "table" and existingCargo.source or existingCargo), count = newCount }
						trigger.action.setUnitInternalCargo(un:getName(), 100 * newCount)
						local msg
						if newCount > 1 then
							msg = T:Format("LOGISTICS_SUPPLIES_LOADED_COUNT", newCount)
						else
							msg = T:Get("LOGISTICS_SUPPLIES_LOADED")
						end
						trigger.action.outTextForGroup(gid, msg, 10)
					else
						local msg
						if count > 1 then
							msg = T:Format("LOGISTICS_ALREADY_LOADED_COUNT", count)
						else
							msg = T:Get("LOGISTICS_ALREADY_LOADED")
						end
						trigger.action.outTextForGroup(gid, msg, 10)
					end
					return
				end
				local zn = self.battleCommander:getZoneOfUnit(un:getName())
				if not zn then
					local carrierUnit
					local nearestCarrier = GetNearestCarrierName(COORDINATE:NewFromVec3(un:getPoint()))
					if nearestCarrier then
						carrierUnit = Unit.getByName(nearestCarrier)
					end

					if carrierUnit then
						local carrierPos  = carrierUnit:getPoint()
						local playerPos   = un:getPoint()
						if COORDINATE:NewFromVec3(carrierPos):Get2DDistance(playerPos) < 200 then
							self.carriedCargo[gr:getID()] = { source = carrierUnit:getName(), count = loadCount }
							trigger.action.setUnitInternalCargo(un:getName(), 100 * loadCount)
							local msg
							if loadCount > 1 then
								msg = T:Format("LOGISTICS_SUPPLIES_LOADED_COUNT_CAP", loadCount)
							else
								msg = T:Get("LOGISTICS_SUPPLIES_LOADED")
							end
							trigger.action.outTextForGroup(gid, msg, 20)
							return
						end
					else
						local group = GROUP:FindByName(groupName)
						if group then
							for _, zName in ipairs(self.supplyZones) do
								if string.find(zName, "CTLD FARP") or string.find(zName, "Escort Mission FARP") then
									local zObj = ZONE:FindByName(zName)
									if zObj and group:IsInZone(zObj) then
										self.carriedCargo[gr:getID()] = { source = zName, count = loadCount }
										trigger.action.setUnitInternalCargo(un:getName(), 100 * loadCount)
										local msg
										if loadCount > 1 then
											msg = T:Format("LOGISTICS_SUPPLIES_LOADED_COUNT", loadCount)
										else
											msg = T:Get("LOGISTICS_SUPPLIES_LOADED")
										end
										trigger.action.outTextForGroup(gid, msg, 20)
										return
									end
								end
							end
						end
					end
					trigger.action.outTextForGroup(gid, T:Get("LOGISTICS_LOAD_ONLY_FRIENDLY_OR_CARRIER"), 10)
					return
				end
				if zn.side ~= un:getCoalition() and not zn.wasBlue then
					trigger.action.outTextForGroup(gid, T:Get("LOGISTICS_LOAD_ONLY_FRIENDLY"), 10)
					return
				end
				for i, v in ipairs(self.supplyZones) do
					if v == zn.zone then
						self.carriedCargo[gr:getID()] = { source = zn.zone, count = loadCount }
						trigger.action.setUnitInternalCargo(un:getName(), 100 * loadCount)
						local msg
						if loadCount > 1 then
							msg = T:Format("LOGISTICS_SUPPLIES_LOADED_COUNT", loadCount)
						else
							msg = T:Get("LOGISTICS_SUPPLIES_LOADED")
						end
						trigger.action.outTextForGroup(gid, msg, 20)
						return
					end
				end
				trigger.action.outTextForGroup(gid, T:Get("LOGISTICS_LOAD_ONLY_FRIENDLY"), 10)
				return
			end
		end
end
	function LogisticCommander:unloadSupplies(groupName)
		local gr = Group.getByName(groupName)
		if gr then
			local gid = gr:getID()
			local T = L10N:ForGroup(gid)
			local un = gr:getUnit(1)
			if un then
				local playerName = un:getPlayerName()
				if Utils.isInAir(un) then
					trigger.action.outTextForGroup(gid, T:Get("LOGISTICS_CANNOT_UNLOAD_IN_AIR"), 10)
					return
				end

				local cargoData = self.carriedCargo[gid]
				if not cargoData then
					trigger.action.outTextForGroup(gid,T:Get("LOGISTICS_NO_SUPPLIES_LOADED"),10)
					return
				end

				local originalSource = type(cargoData) == "table" and cargoData.source or cargoData
				local totalDrops = type(cargoData) == "table" and cargoData.count or 1
				if not totalDrops or totalDrops < 1 then
					totalDrops = 1
				end
				local remainingDrops = totalDrops
				local didLandingEvent = false
				local didAnnounce = false

				local function handleZoneRewards(zone)
					if not zone then
						return false
					end
					if originalSource == zone.zone then
						return false
					end
					if zone.side == 0 and zone.active then
						if self.battleCommander.playerRewardsOn then
							if playerName and bc.playerContributions[2][playerName] ~= nil then
								bc:addContribution(playerName, 2, self.battleCommander.rewards.crate)
								self.battleCommander:addTempStat(playerName, 'Zone capture', 1)
								--trigger.action.outTextForCoalition(un:getCoalition(),'['..playerName..'] Capture +'..self.battleCommander.rewards.crate..' credits',10)
							else
								self.battleCommander:addFunds(un:getCoalition(), self.battleCommander.rewards.crate)
								trigger.action.outTextForCoalition(un:getCoalition(),L10N:Format("LOGISTICS_CAPTURE_CREDITS", tostring(self.battleCommander.rewards.crate)),10)
							end
						end
						zone:capture(un:getCoalition())
						return true
					elseif zone.side == un:getCoalition() then
						if self.battleCommander.playerRewardsOn then
							if zone:canRecieveSupply() then
								if playerName and bc.playerContributions[2][playerName] ~= nil then
									bc:addContribution(playerName, 2, self.battleCommander.rewards.crate)
									self.battleCommander:addTempStat(playerName, 'Zone upgrade', 1)
									--trigger.action.outTextForCoalition(un:getCoalition(),'['..playerName..'] Resupply +'..self.battleCommander.rewards.crate..' credits',5)
								else
									self.battleCommander:addFunds(un:getCoalition(), self.battleCommander.rewards.crate)
									trigger.action.outTextForCoalition(un:getCoalition(),L10N:Format("LOGISTICS_RESUPPLY_CREDITS", tostring(self.battleCommander.rewards.crate)),5)
								end
							else
								local reward = self.battleCommander.rewards.crate * 0.25
								if playerName and bc.playerContributions[2][playerName] ~= nil then
									bc:addContribution(playerName, 2, reward)
									self.battleCommander:addTempStat(playerName, 'Zone upgrade', 1)
									trigger.action.outTextForCoalition(un:getCoalition(),L10N:Format("LOGISTICS_PLAYER_RESUPPLY_NO_DEMAND", playerName, tostring(reward)),5)
								else
									self.battleCommander:addFunds(un:getCoalition(), reward)
									trigger.action.outTextForCoalition(un:getCoalition(),L10N:Format("LOGISTICS_RESUPPLY_NO_DEMAND", tostring(reward)),5)
								end
							end
						end
						zone:upgrade()
						return true
					end
					return false
				end

				local function performDrop(zone)
					if remainingDrops <= 0 then
						return
					end
					if not didAnnounce then
						local msg = totalDrops > 1 and T:Format("LOGISTICS_SUPPLIES_UNLOADED_COUNT", totalDrops) or T:Get("LOGISTICS_SUPPLIES_UNLOADED")
						trigger.action.outTextForGroup(gid, msg, 10)
						didAnnounce = true
					end
					self.carriedCargo[gid] = nil
					trigger.action.setUnitInternalCargo(un:getName(), 0)
					local wasNeutral = zone and zone.side == 0 and zone.active
					local changed = handleZoneRewards(zone)
					if zone and totalDrops > 1 and (wasNeutral or zone.side == un:getCoalition()) then
						SCHEDULER:New(nil,function()
							local z2 = self.battleCommander:getZoneOfUnit(un:getName()) or zone
							handleZoneRewards(z2)
						end,{},3,0)
					end
					if changed and not didLandingEvent then
						SCHEDULER:New(nil,function()
							if zone and zone.wasBlue and un:isExist() then
								local landingEvent = {
									id = world.event.S_EVENT_LAND,
									time = timer.getAbsTime(),
									initiator = un,
									initiatorPilotName = un:getPlayerName(),
									initiator_unit_type = un:getTypeName(),
									initiator_coalition = un:getCoalition(),
									skipRewardMsg = true,
								}
								world.onEvent(landingEvent)
							end
						end,{},5,0)
						didLandingEvent = true
					end
					remainingDrops = 0
				end


				local function scheduleAdditionalDrops(initialZone)
					if remainingDrops <= 0 then
						return
					end
					SCHEDULER:New(nil,function()
						if not un:isExist() then
							remainingDrops = 0
							return
						end
						if not self.carriedCargo[gid] then
							remainingDrops = 0
							trigger.action.setUnitInternalCargo(un:getName(),0)
							return
						end
						local followZone = self.battleCommander:getZoneOfUnit(un:getName()) or initialZone
						performDrop(followZone)
						didLandingEvent = false
						return
					end,{},1,0)
				end

				local zn = self.battleCommander:getZoneOfUnit(un:getName())
				if not zn then
					local carrierName = GetNearestCarrierName(COORDINATE:NewFromVec3(un:getPoint()))
					if carrierName then
						performDrop(nil)
						scheduleAdditionalDrops(nil)
						return
					end

					local group = GROUP:FindByName(groupName)
					if group then
						for _, zName in ipairs(self.supplyZones) do
							if string.find(zName, "CTLD FARP") or string.find(zName, "Escort Mission FARP") then
								local zObj = ZONE:FindByName(zName)
								if zObj and group:IsInZone(zObj) then
									performDrop(nil)
									scheduleAdditionalDrops(nil)

									return
								end
							end
						end
					end

					trigger.action.outTextForGroup(gid,T:Get("LOGISTICS_UNLOAD_ONLY_FRIENDLY_NEUTRAL"),10)
					env.info('LogisticCommander:unloadSupplies - no zone found for unit '..un:getName())
					return
				end
				if not(zn.side == un:getCoalition() or zn.side == 0)then
					trigger.action.outTextForGroup(gid,T:Get("LOGISTICS_UNLOAD_ONLY_FRIENDLY_NEUTRAL"),10)
					env.info('LogisticCommander:unloadSupplies - wrong side for unit '..un:getName()..' in zone '..zn.zone)
					return
				end
				if originalSource == zn.zone then
					self.carriedCargo[gid] = nil
					trigger.action.setUnitInternalCargo(un:getName(), 0)
					local msg = totalDrops > 1 and T:Format("LOGISTICS_SUPPLIES_UNLOADED_COUNT", totalDrops) or T:Get("LOGISTICS_SUPPLIES_UNLOADED")
					trigger.action.outTextForGroup(gid, msg, 10)
					return
				end
				scheduleAdditionalDrops(zn)
				return
			end
		end
	end

	function LogisticCommander:listSupplyZones(groupName)
		local gr = Group.getByName(groupName)
		if gr then
			local gid = gr:getID()
			local T = L10N:ForGroup(gid)
			local msg = T:Get("LOGISTICS_FRIENDLY_SUPPLY_ZONES")
			for i,v in ipairs(self.supplyZones) do
				local z = self.battleCommander:getZoneByName(v)
				if z and z.side == gr:getCoalition() then
					msg = msg..'\n'..v
				end
			end
			
			trigger.action.outTextForGroup(gid, msg, 15)
		end
	end

	function LogisticCommander:_appendUniqueCsarHostileGroup(list, groupName)
		if type(list) ~= 'table' then return end
		if type(groupName) ~= 'string' or groupName == '' then return end
		for _, existing in ipairs(list) do
			if existing == groupName then
				return
			end
		end
		list[#list + 1] = groupName
	end

	function LogisticCommander:_bindCsarHostilesToPilot(pid, pilotData, hostileGroupNames)
		if type(hostileGroupNames) ~= 'table' or #hostileGroupNames == 0 then return end
		if pilotData then
			pilotData.csarHostileGroups = pilotData.csarHostileGroups or {}
			for _, groupName in ipairs(hostileGroupNames) do
				self:_appendUniqueCsarHostileGroup(pilotData.csarHostileGroups, groupName)
			end
		end
		if pid then
			self.csarHostileGroupsByPilotObject = self.csarHostileGroupsByPilotObject or {}
			self.csarHostileGroupsByPilotObject[pid] = self.csarHostileGroupsByPilotObject[pid] or {}
			for _, groupName in ipairs(hostileGroupNames) do
				self:_appendUniqueCsarHostileGroup(self.csarHostileGroupsByPilotObject[pid], groupName)
			end
		end
	end

	function LogisticCommander:trackCsarHostilesForRescuedPilot(groupid, pid, pilotData)
		local toCarry = {}
		if pilotData and type(pilotData.csarHostileGroups) == 'table' then
			for _, groupName in ipairs(pilotData.csarHostileGroups) do
				self:_appendUniqueCsarHostileGroup(toCarry, groupName)
			end
		end
		if pid then
			self.csarHostileGroupsByPilotObject = self.csarHostileGroupsByPilotObject or {}
			local byPid = self.csarHostileGroupsByPilotObject[pid]
			if type(byPid) == 'table' then
				for _, groupName in ipairs(byPid) do
					self:_appendUniqueCsarHostileGroup(toCarry, groupName)
				end
			end
			self.csarHostileGroupsByPilotObject[pid] = nil
		end
		-- A single downed pilot can be rebound to a new object ID; consume any alias keys
		-- that reference the same hostile groups so cleanup is not orphaned by stale PID keys.
		if #toCarry > 0 and self.csarHostileGroupsByPilotObject then
			local toCarrySet = {}
			for _, groupName in ipairs(toCarry) do
				toCarrySet[groupName] = true
			end
			for otherPid, groups in pairs(self.csarHostileGroupsByPilotObject) do
				if otherPid ~= pid and type(groups) == 'table' then
					local overlap = false
					for _, groupName in ipairs(groups) do
						if toCarrySet[groupName] then
							overlap = true
							break
						end
					end
					if overlap then
						for _, groupName in ipairs(groups) do
							if not toCarrySet[groupName] then
								toCarrySet[groupName] = true
								toCarry[#toCarry + 1] = groupName
							end
						end
						self.csarHostileGroupsByPilotObject[otherPid] = nil
					end
				end
			end
		end
		if #toCarry > 0 then
			self.carriedPilotHostileGroups = self.carriedPilotHostileGroups or {}
			self.carriedPilotHostileGroups[groupid] = self.carriedPilotHostileGroups[groupid] or {}
			for _, groupName in ipairs(toCarry) do
				self:_appendUniqueCsarHostileGroup(self.carriedPilotHostileGroups[groupid], groupName)
			end
			if pilotData then
				pilotData.csarHostileGroups = toCarry
			end
		end
	end

	function LogisticCommander:destroyCsarHostileGroups(groupNames)
		if type(groupNames) ~= 'table' then return 0 end
		local destroyed = 0
		local seen = {}
		for _, groupName in ipairs(groupNames) do
			if type(groupName) == 'string' and groupName ~= '' and not seen[groupName] then
				seen[groupName] = true
				local hostileGroup = Group.getByName(groupName)
				if hostileGroup and hostileGroup:isExist() then
					local alive = false
					local units = hostileGroup:getUnits()
					if units then
						for _, unit in pairs(units) do
							if unit and unit:isExist() and (unit:getLife() or 0) > 0 then
								alive = true
								break
							end
						end
					end
					if alive then
						hostileGroup:destroy()
						destroyed = destroyed + 1
					end
				end
			end
		end
		return destroyed
	end

	function LogisticCommander:cleanupCarriedCsarHostiles(groupid)
		local groups = self.carriedPilotHostileGroups and self.carriedPilotHostileGroups[groupid]
		local destroyed = self:destroyCsarHostileGroups(groups)
		if self.carriedPilotHostileGroups then
			self.carriedPilotHostileGroups[groupid] = nil
		end
		return destroyed
	end

	function LogisticCommander:loadPilot(groupname)
		local gr=Group.getByName(groupname)
		local groupid=gr:getID()
		if gr then
			local T = L10N:ForGroup(groupid)
			local un=gr:getUnit(1)
			if Utils.getAGL(un)>50 then
				trigger.action.outTextForGroup(groupid,T:Get("CSAR_TOO_HIGH"),15)
				return
			end
			if UTILS.VecNorm(un:getVelocity()) > 5 then
				trigger.action.outTextForGroup(groupid,T:Get("CSAR_TOO_FAST"),15)
				return
			end
			local unitType=un:getTypeName()
			local maxCarriedPilots = LogisticCommander.AllowedCsar[unitType]
			if self.carriedPilots[groupid]>=maxCarriedPilots then
				trigger.action.outTextForGroup(groupid,T:Get("CSAR_AT_MAX_CAPACITY"),15)
				return
			end
			for i,v in ipairs(self.ejectedPilots)do
				local dist=UTILS.VecDist3D(un:getPoint(),v:getPoint())
				if dist<150 then
					self.carriedPilots[groupid]=self.carriedPilots[groupid]+1
					self.carriedPilotData=self.carriedPilotData or {}
					self.carriedPilotData[groupid]=self.carriedPilotData[groupid] or {}
					local pid=v:getObjectID()
					local pilotData=landedPilotOwners[pid]
					self:_clearCsarHomeState(pid)
					self:trackCsarHostilesForRescuedPilot(groupid, pid, pilotData)
					if pilotData then
						table.insert(self.carriedPilotData[groupid],pilotData)
						landedPilotOwners[pid]=nil
					end
					table.remove(self.ejectedPilots,i)
					v:destroy()
					trigger.action.outTextForGroup(groupid,T:Format("CSAR_PILOT_ONBOARD", self.carriedPilots[groupid], maxCarriedPilots),15)
					return
				end
			end
			trigger.action.outTextForGroup(groupid,T:Get("CSAR_NO_EJECTED_PILOTS"),15)
		end
	end

	function LogisticCommander:unloadPilot(groupname)
			local gr=Group.getByName(groupname)
			if gr then
				local groupid=gr:getID()
				local T = L10N:ForGroup(groupid)
				local un=gr:getUnit(1)
				if (self.carriedPilots[groupid] or 0)==0 then
					trigger.action.outTextForGroup(groupid,T:Get("CSAR_NO_ONE_ONBOARD"),15)
					return
				end
--[[ 				if Utils.isInAir(un) then
					trigger.action.outTextForGroup(groupid,"Can not drop off pilots while in air",15)
					return
				end ]]
				local playerName=un:getPlayerName()
					local count=self.carriedPilots[groupid] or 0
					trigger.action.outTextForGroup(groupid,T:Get("CSAR_PILOTS_DROPPED_OFF"),15)
					if self.battleCommander.playerRewardsOn then
						local rescuedPlayers=self.carriedPilotData[groupid] or {}
						local dropped={}
						for _,pilotData in ipairs(rescuedPlayers) do
							local pname=pilotData and pilotData.player
							if pname and pname~='' then
								self.battleCommander:addStat(pname,'Deaths',-1)
								dropped[#dropped+1]=pname
							end
						end
						if #dropped>0 then
							trigger.action.outTextForCoalition(un:getCoalition(),L10N:Format("CSAR_PLAYER_DROPPED_OFF", playerName, table.concat(dropped,", ")),5)
						end
					end
					self:cleanupCarriedCsarHostiles(groupid)
					self.carriedPilotData[groupid]=nil
					self.carriedPilots[groupid]=0
					trigger.action.setUnitInternalCargo(un:getName(),0)
				return
			end
		end

	function LogisticCommander:markPilot(groupname)
		local gr = Group.getByName(groupname)
		if gr then
			local gid = gr:getID()
			local T = L10N:ForGroup(gid)
			local un = gr:getUnit(1)
			
			local maxdist = 300000
			local targetpilot = nil
			for i, v in ipairs(self.ejectedPilots) do
				local dist = UTILS.VecDist3D(un:getPoint(), v:getPoint())
				if dist < maxdist then
					maxdist = dist
					targetpilot = v
				end
			end
			
			if targetpilot then
				trigger.action.smoke(targetpilot:getPoint(), 4)
				trigger.action.outTextForGroup(gid, T:Get("CSAR_BLUE_SMOKE_MARKED"), 15)
			else
				trigger.action.outTextForGroup(gid, T:Get("CSAR_NO_EJECTED_PILOTS"), 15)
			end
		end
	end

	function LogisticCommander:_signalPilotFlareBurst(pilotObj, flareCount, delaySec)
		if not pilotObj or not pilotObj.isExist or not pilotObj:isExist() then return end
		flareCount = flareCount or 3
		delaySec = delaySec or 5
		if flareCount < 1 then return end
		for i = 0, flareCount - 1 do
			timer.scheduleFunction(function(args, _)
				local pObj = args and args.pilot
				if not pObj or not pObj.isExist or not pObj:isExist() then
					return nil
				end
				local p = pObj:getPoint()
				if p then
					trigger.action.signalFlare(p, 0, math.floor(math.random(0,359)))
				end
				return nil
			end, { pilot = pilotObj }, timer.getTime() + (i * delaySec))
		end
	end
	
	function LogisticCommander:flarePilot(groupname)
		local gr = Group.getByName(groupname)
		if gr then
			local gid = gr:getID()
			local T = L10N:ForGroup(gid)
			local un = gr:getUnit(1)
			
			local maxdist = 300000
			local targetpilot = nil
			for i,v in ipairs(self.ejectedPilots) do
				local dist = UTILS.VecDist3D(un:getPoint(), v:getPoint())
				if dist<maxdist then
					maxdist = dist
					targetpilot = v
				end
			end
			
			if targetpilot then
				self:_signalPilotFlareBurst(targetpilot, 3, 5)
			else
				trigger.action.outTextForGroup(gid, T:Get("CSAR_NO_EJECTED_PILOTS"), 15)
			end
		end
	end
	
	function LogisticCommander:infoPilot(groupname)
		local gr = Group.getByName(groupname)
		if gr then
			local gid = gr:getID()
			local T = L10N:ForGroup(gid)
			local un = gr:getUnit(1)
			
			local maxdist = 300000
			local targetpilot = nil
			for i,v in ipairs(self.ejectedPilots) do
				local dist = UTILS.VecDist3D(un:getPoint(), v:getPoint())
				if dist<maxdist then
					maxdist = dist
					targetpilot = v
				end
			end
			
			if targetpilot then
				self:printPilotInfo(targetpilot, gid, un, 60)
				self:_signalPilotFlareBurst(targetpilot, 3, 5)
			else
				trigger.action.outTextForGroup(gid, T:Get("CSAR_NO_EJECTED_PILOTS"), 15)
			end
		end
	end

	function LogisticCommander:infoTopPilots(groupname, limit)
		local gr = Group.getByName(groupname)
		if not gr then return end
		local gid = gr:getID()
		local T = L10N:ForGroup(gid)
		local un = gr:getUnit(1)
		if not un or not un:isExist() then return end
		limit = limit or 3

		local list = {}
		local up = un:getPoint()
		for _, v in ipairs(self.ejectedPilots) do
			if v and v:isExist() then
				local vp = v:getPoint()
				if vp then
					local dist = UTILS.VecDist3D(up, vp)
					list[#list+1] = { pilot = v, dist = dist }
				end
			end
		end

		if #list == 0 then
			trigger.action.outTextForGroup(gid, T:Get("CSAR_NO_EJECTED_PILOTS"), 15)
			return
		end

		table.sort(list, function(a,b) return a.dist < b.dist end)
		local count = math.min(limit, #list)
		for i = 1, count do
			self:printPilotInfo(list[i].pilot, gid, un, 60)
		end
	end
	
		function LogisticCommander:infoHumanPilot(groupname)
		local gr = Group.getByName(groupname)
		if not gr then return end
		local gid = gr:getID()
		local T = L10N:ForGroup(gid)
		local un = gr:getUnit(1)
		if not un or not un:isExist() then return end
		local maxdist = 300000
		local targetpilot = nil
		for i,ejectedObj in ipairs(self.ejectedPilots) do
			local pid = ejectedObj:getObjectID()
			local pilotData = landedPilotOwners[pid] or ejectedPilotOwners[pid]
			if pilotData and pilotData.player then
				local dist = UTILS.VecDist3D(un:getPoint(), ejectedObj:getPoint())
				if dist < maxdist then
					maxdist = dist
					targetpilot = ejectedObj
				end
			end
		end
		if targetpilot then
			self:printPilotInfo(targetpilot, gid, un, 60)
		else
			trigger.action.outTextForGroup(gid, T:Get("CSAR_NO_EJECTED_FRIENDLY_PILOTS"), 15)
		end
	end
	
	function LogisticCommander:printPilotVectorInfo(pilotObj, groupid, referenceUnit, duration)
		local T = L10N:ForGroup(groupid)
		self.csarBeaconFreq = self.csarBeaconFreq or {}
		self.csarBeaconName = self.csarBeaconName or {}
		self.csarPilotDataByObject = self.csarPilotDataByObject or {}
		if not pilotObj or not pilotObj:isExist() or not referenceUnit or not referenceUnit:isExist() then return false end
		local pnt = pilotObj:getPoint()
		local refPoint = referenceUnit:getPoint()
		if not pnt or not refPoint then return false end
		local objectID = pilotObj:getObjectID()
		if not objectID then return false end
		local pilotData = landedPilotOwners[objectID] or self.csarPilotDataByObject[objectID] or ejectedPilotOwners[objectID]

		local freq = self.csarBeaconFreq[objectID]
		if not freq then
			self.csarBeaconName[objectID] = self.csarBeaconName[objectID] or ("FOOTHOLD_CSAR_"..objectID.."_BEACON")
			freq = 250000 + math.random(0,1000)*1000
			self.csarBeaconFreq[objectID] = freq
		end

		local dist = UTILS.VecDist3D(refPoint, pnt)
		local dstkm = string.format('%.2f', dist/1000)
		local dstnm = string.format('%.2f', dist/1852)
		local refCoord = COORDINATE:NewFromVec3(refPoint)
		local pilotCoord = COORDINATE:NewFromVec3(pnt)
		local brg = (refCoord:HeadingTo(pilotCoord)-refCoord:GetMagneticDeclination()+360)%360
		local pilotLine = T:Get("CSAR_DOWNED_PILOT")
		if pilotData and pilotData.player and pilotData.player ~= '' then
			pilotLine = T:Format("CSAR_NEAREST_PILOT_LOST_CREDITS", pilotData.player, tostring(pilotData.lostCredits or 0))
		end
		local toprint = T:Get("CSAR_NEAREST_PILOT_TO_YOU")
			..'\n'..pilotLine
			..'\n\n'..T:Format("CSAR_DISTANCE_NM_KM_LINE", dstkm, dstnm)
			..'\n'..T:Format("CSAR_BEARING_TEXT_LINE", string.format('%03d', math.floor(brg)))
			..'\n'..T:Format("CSAR_ADF_LINE", string.format('%.0f', freq/1000))
		trigger.action.outTextForGroup(groupid, toprint, duration or 15)
		return true
	end

	function LogisticCommander:printPilotInfo(pilotObj,groupid,referenceUnit,duration,short)
		local T = L10N:ForGroup(groupid)
		self.csarBeaconFreq = self.csarBeaconFreq or {}
		self.csarPilotDataByObject = self.csarPilotDataByObject or {}
		if not pilotObj or not pilotObj:isExist() then return end
		local pnt=pilotObj:getPoint() or nil
		if not pnt then return end
		local objectID=pilotObj:getObjectID()
		local pilotData=landedPilotOwners[objectID] or self.csarPilotDataByObject[objectID] or ejectedPilotOwners[objectID]
		local freq=self.csarBeaconFreq[objectID]
		local c=COORDINATE:NewFromVec3(pnt)
		local runningHomeState = self:_getRunningCsarHomeState(objectID)

			if short then
			local pilotName = (pilotData and pilotData.player and pilotData.player~='') and ('['..pilotData.player..']') or T:Get("CSAR_DOWNED_PILOT")
			local plural = false
			if self.ejectedPilots then
				for _, other in ipairs(self.ejectedPilots) do
					if other and other:isExist() and other ~= pilotObj then
						local op = other:getPoint()
						if op then
							local dx = op.x - pnt.x
							local dz = op.z - pnt.z
							if (dx*dx + dz*dz) <= (92*92) then
								plural = true
								break
							end
						end
					end
				end
			end
			local toprint=plural and ((pilotData and pilotData.hostileZoneName) and T:Format("CSAR_WE_HEAR_YOU_HOSTILE", pilotName) or T:Format("CSAR_WE_HEAR_YOU", pilotName)) or ((pilotData and pilotData.hostileZoneName) and T:Format("CSAR_I_HEAR_YOU_HOSTILE", pilotName) or T:Format("CSAR_I_HEAR_YOU", pilotName))
			if freq and freq>0 then
				toprint = toprint .. '\n\n' .. T:Format("CSAR_ADF_LINE", string.format('%.0f',freq/1000))
			end
			if referenceUnit then
				local dist=UTILS.VecDist3D(referenceUnit:getPoint(),pilotObj:getPoint())
				local dstkm=string.format('%.2f',dist/1000)
				local dstnm=string.format('%.2f',dist/1852)
				toprint=toprint..'\n\n'..T:Format("CSAR_DISTANCE_LINE", dstkm, dstnm)
				local refCoord=COORDINATE:NewFromVec3(referenceUnit:getPoint())
				local brg=(refCoord:HeadingTo(c)-refCoord:GetMagneticDeclination()+360)%360
				toprint=toprint..'\n'..T:Format("CSAR_BEARING_LINE", math.floor(brg))
			end
			trigger.action.outTextForGroup(groupid,toprint,duration)
			return
		end


		local toprint=T:Get("CSAR_PILOT_EXTRACTION_HEADER")
		local isAdditionalSurvivor = pilotData and pilotData.rescueRewardPaid == true and (pilotData.lostCredits or 0) <= 0
		if pilotData and pilotData.hostileZoneName then
			local pilotName = isAdditionalSurvivor and T:Get("CSAR_ADDITIONAL_SURVIVOR") or ((pilotData.player and pilotData.player~='') and ('['..pilotData.player..']') or T:Get("CSAR_DOWNED_PILOT"))
			toprint=T:Format("CSAR_RESCUE_HOSTILE", pilotName, pilotData.hostileZoneName)
			toprint = toprint .. '\n\n' .. T:Get("CSAR_HOSTILE_CAUTION")
		end
		if (pilotData and pilotData.player) then		
			if isAdditionalSurvivor then
				toprint = toprint .. '\n\n' .. T:Get("CSAR_ADDITIONAL_SURVIVOR")
			else
				if pilotData.hostileZoneName then
					toprint = toprint .. '\n\n' .. T:Format("CSAR_LOST_CREDITS", tostring(pilotData.lostCredits))
				else
					toprint = toprint .. '\n\n' .. T:Format("CSAR_PLAYER_LOST_CREDITS", pilotData.player, tostring(pilotData.lostCredits))
				end
				toprint = toprint .. '\n\n' .. T:Get("CSAR_SAVE_TO_RETRIEVE")
			end
		end
		if runningHomeState then
			local destinationName = runningHomeState.displayName or runningHomeState.zoneName or runningHomeState.targetName
			toprint = toprint .. '\n\n' .. T:Format("CSAR_RUNNING_HOME_STATUS", destinationName)
		end
		if freq and freq>0 then
			toprint = toprint .. '\n\n' .. T:Format("CSAR_ADF_LINE", string.format('%.0f',freq/1000))
		end
		local ddm=c:ToStringLLDDM():gsub("^LL DDM%s*","")
		local dms=c:ToStringLLDMS():gsub("^LL DMS%s*","")
		local mgrs=c:ToStringMGRS():gsub("^MGRS%s*","")
		local alt=c:GetLandHeight()
		toprint=toprint..'\n\n'..T:Format("ZONE_COORD_DDM", ddm)
		toprint=toprint..'\n'..T:Format("ZONE_COORD_DMS", dms)
		toprint=toprint..'\n'..T:Format("ZONE_COORD_MGRS", mgrs)
		toprint=toprint..'\n\n'..T:Format("ZONE_COORD_ALT", math.floor(alt), math.floor(alt*3.280839895))
		if referenceUnit then
			local dist=UTILS.VecDist3D(referenceUnit:getPoint(),pilotObj:getPoint())
			local dstkm=string.format('%.2f',dist/1000)
			local dstnm=string.format('%.2f',dist/1852)
			toprint=toprint..'\n\n'..T:Format("CSAR_DISTANCE_LINE", dstkm, dstnm)
			local refCoord=COORDINATE:NewFromVec3(referenceUnit:getPoint())
			local brg=(refCoord:HeadingTo(c)-refCoord:GetMagneticDeclination()+360)%360
			toprint=toprint..'\n'..T:Format("CSAR_BEARING_LINE", math.floor(brg))
		end
		trigger.action.outTextForGroup(groupid,toprint,duration)
	end

	function LogisticCommander:_csarMarkerLabel(pilotObj)
		self.csarBeaconFreq = self.csarBeaconFreq or {}
		self.csarBeaconName = self.csarBeaconName or {}
		self.csarPilotDataByObject = self.csarPilotDataByObject or {}
		if not pilotObj or not pilotObj:isExist() then return nil end
		local pid = pilotObj:getObjectID()
		if not pid then return nil end
		local pilotData = landedPilotOwners[pid] or self.csarPilotDataByObject[pid] or ejectedPilotOwners[pid]
		local freq = self.csarBeaconFreq[pid]
		if not freq then
			self.csarBeaconName[pid] = self.csarBeaconName[pid] or ("FOOTHOLD_CSAR_"..pid.."_BEACON")
			freq = 250000 + math.random(0,1000)*1000
			self.csarBeaconFreq[pid] = freq
		end

		local label
		if pilotData and pilotData.player and pilotData.player ~= '' then
			if pilotData.rescueRewardPaid == true and (pilotData.lostCredits or 0) <= 0 then
				label = L10N:Get("CSAR_ADDITIONAL_SURVIVOR")
			else
				local lost = pilotData.lostCredits or 0
				label = L10N:Format("CSAR_MARKER_LOST_CREDITS", pilotData.player, tostring(lost))
			end
		else
			label = L10N:Get("CSAR_DOWNED_PILOT")
		end
		if freq and freq > 0 then
			label = label .. '\n' .. L10N:Format("CSAR_ADF_LINE", string.format('%.0f',freq/1000))
		end
		return label
	end

	function LogisticCommander:createCsarMarker(pilotObj)
		if not pilotObj or not pilotObj:isExist() then return end
		self.csarPilotMarks = self.csarPilotMarks or {}
		local pid = pilotObj:getObjectID()
		if not pid or self.csarPilotMarks[pid] then return end
		self:refreshCsarMarker(pilotObj)
	end

	function LogisticCommander:refreshCsarMarker(pilotObj)
		if not pilotObj or not pilotObj:isExist() then return end
		self.csarPilotMarks = self.csarPilotMarks or {}
		local pid = pilotObj:getObjectID()
		if not pid then return end
		local p = pilotObj:getPoint()
		if not p then return end
		local entry = self.csarPilotMarks[pid]
		if entry and entry.id then
			trigger.action.removeMark(entry.id)
		end
		local label = self:_csarMarkerLabel(pilotObj) or L10N:Get("CSAR_DOWNED_PILOT")
		missionMarkId = missionMarkId + 1
		local id = missionMarkId
		trigger.action.markToCoalition(id, label, p, 2, false, false)
		self.csarPilotMarks[pid] = { id = id, label = label, point = { x = p.x, y = p.y, z = p.z } }
	end

	function LogisticCommander:removeCsarMarker(pilotOrId)
		self.csarPilotMarks = self.csarPilotMarks or {}
		local pid = pilotOrId
		if type(pilotOrId) == "table" and pilotOrId.getObjectID then
			pid = pilotOrId:getObjectID()
		end
		local entry = pid and self.csarPilotMarks[pid]
		if entry and entry.id then
			trigger.action.removeMark(entry.id)
		end
		if pid then
			self.csarPilotMarks[pid] = nil
		end
	end

	function LogisticCommander:_bindPilotDataToObject(objectID, data)
		if not (objectID and data) then return end
		self.csarPilotDataByObject = self.csarPilotDataByObject or {}
		self.csarPilotTimestampByObject = self.csarPilotTimestampByObject or {}
		local timestamp = tonumber(data.timestamp) or timer.getTime()
		data.timestamp = timestamp
		landedPilotOwners[objectID] = data
		self.csarPilotDataByObject[objectID] = data
		self.csarPilotTimestampByObject[objectID] = timestamp
	end

	function LogisticCommander:_csarHasPriorityPilotData(pilotData)
		return pilotData ~= nil and pilotData.hasPilotData ~= false
	end

	function LogisticCommander:_trackCsarPilotTimestamp(pilotObj, preferredTimestamp)
		self.csarPilotDataByObject = self.csarPilotDataByObject or {}
		self.csarPilotTimestampByObject = self.csarPilotTimestampByObject or {}
		if not pilotObj or not pilotObj.isExist or not pilotObj:isExist() then return nil end
		local objectID = pilotObj.getObjectID and pilotObj:getObjectID() or nil
		if not objectID then return nil end
		local pilotData = landedPilotOwners[objectID] or self.csarPilotDataByObject[objectID] or ejectedPilotOwners[objectID]
		local timestamp = tonumber(preferredTimestamp) or tonumber(pilotData and pilotData.timestamp) or tonumber(self.csarPilotTimestampByObject[objectID]) or timer.getTime()
		if pilotData then
			pilotData.timestamp = timestamp
		end
		self.csarPilotTimestampByObject[objectID] = timestamp
		return timestamp
	end

	function LogisticCommander:_getCsarPilotData(pid)
		return pid and (landedPilotOwners[pid] or self.csarPilotDataByObject[pid] or ejectedPilotOwners[pid]) or nil
	end

	function LogisticCommander:_findCsarPilotByPid(pid)
		if not pid then return nil, nil end
		for i, pilotObj in ipairs(self.ejectedPilots or {}) do
			if pilotObj and pilotObj:isExist() and pilotObj:getObjectID() == pid then
				return pilotObj, i
			end
		end
		return nil, nil
	end

	function LogisticCommander:_csarHomeCandidateFromZone(zoneObj, pilotPoint)
		local zoneName = zoneObj and zoneObj.zone
		if not zoneName or not pilotPoint then return nil end
		local best = nil
		local function consider(pointName, x, z)
			if not x or not z then return end
			local dx = pilotPoint.x - x
			local dz = pilotPoint.z - z
			local dist = math.sqrt(dx * dx + dz * dz)
			if (not best) or dist < best.distance then
				best = {
					kind = "zone",
					zoneName = zoneName,
					targetName = pointName or zoneName,
					displayName = zoneName,
					side = zoneObj.side,
					x = x,
					z = z,
					distance = dist
				}
			end
		end

		local center = getZoneCenter(zoneName)
		if center then consider(zoneName, center.x, center.y) end

		for _, subName in ipairs(collectSubZones(zoneName)) do
			local subCenter = getZoneCenter(subName)
			if subCenter then consider(subName, subCenter.x, subCenter.y) end
		end

		local pooledLand = _getLandingSpotPoolForPrefix(zoneName .. "-land")
		for _, spot in ipairs(pooledLand or {}) do
			consider(spot.name, spot.x, spot.z)
		end

		local pooledForced = _getForcedLandingSpotPool(zoneName)
		for _, spot in ipairs(pooledForced or {}) do
			consider(spot.name, spot.x, spot.z)
		end

		return best
	end

	function LogisticCommander:_findCsarHomeCandidate(pilotPoint)
		local best = nil
		local bestBlue = nil
		local bestRed = nil
		local seenZones = {}
		local function consider(candidate)
			if candidate and ((not best) or candidate.distance < best.distance) then
				best = candidate
			end
			if candidate and candidate.side == 2 and ((not bestBlue) or candidate.distance < bestBlue.distance) then
				bestBlue = candidate
			end
			if candidate and candidate.side == 1 and ((not bestRed) or candidate.distance < bestRed.distance) then
				bestRed = candidate
			end
		end
		local function considerZone(zoneObj, side)
			if zoneObj and zoneObj.zone and zoneObj.active and zoneObj.side == side and not zoneObj.suspended and not zoneObj.isHidden and not seenZones[zoneObj.zone] then
				seenZones[zoneObj.zone] = true
				consider(self:_csarHomeCandidateFromZone(zoneObj, pilotPoint))
			end
		end

		for _, zoneObj in ipairs(self.battleCommander._blueActiveZones) do
			considerZone(zoneObj, 2)
		end
		for _, entry in ipairs((self.battleCommander._shopSelectorBuckets and self.battleCommander._shopSelectorBuckets.blue_unsuspended) or {}) do
			considerZone(entry.z, 2)
		end
		for _, zoneObj in ipairs(self.battleCommander._redActiveZones) do
			considerZone(zoneObj, 1)
		end
		for _, entry in ipairs((self.battleCommander._shopSelectorBuckets and self.battleCommander._shopSelectorBuckets.enemy_unsuspended) or {}) do
			considerZone(entry.z, 1)
		end
		for _, farpEntry in ipairs((self.battleCommander.dynamicFarpsBySide and self.battleCommander.dynamicFarpsBySide[2]) or {}) do
			local dx = pilotPoint.x - farpEntry.x
			local dz = pilotPoint.z - farpEntry.z
			consider({
				kind = "farp",
				zoneName = farpEntry.name,
				targetName = farpEntry.name,
				displayName = farpEntry.name,
				side = 2,
				x = farpEntry.x,
				z = farpEntry.z,
				distance = math.sqrt(dx * dx + dz * dz)
			})
		end

		local limit = LogisticCommander.csarHomeDistance or (3 * NM)
		if bestBlue and bestBlue.distance <= limit then return bestBlue end
		if bestRed and bestRed.distance <= limit then return bestRed end
		return best
	end

	function LogisticCommander:_clearCsarHomeState(pid)
		self.csarHomeByPilot = self.csarHomeByPilot or {}
		self.csarHomeByZone = self.csarHomeByZone or {}
		local state = self.csarHomeByPilot[pid]
		if state and state.zoneName and self.csarHomeByZone[state.zoneName] then
			self.csarHomeByZone[state.zoneName][pid] = nil
			if not next(self.csarHomeByZone[state.zoneName]) then
				self.csarHomeByZone[state.zoneName] = nil
			end
		end
		self.csarHomeByPilot[pid] = nil
	end

	function LogisticCommander:_setCsarHomeState(pid, state)
		self:_clearCsarHomeState(pid)
		self.csarHomeByPilot[pid] = state
		if state.zoneName then
			self.csarHomeByZone[state.zoneName] = self.csarHomeByZone[state.zoneName] or {}
			self.csarHomeByZone[state.zoneName][pid] = true
		end
	end

	function LogisticCommander:_getRunningCsarHomeState(pid)
		local state = self.csarHomeByPilot and self.csarHomeByPilot[pid]
		if state and state.status == "running" then return state end
		return nil
	end

	function LogisticCommander:_isCsarContactInBlueHomeArea(unit)
		if not unit or not unit:isExist() then return false end
		local point = unit:getPoint()
		if not point then return false end
		local zoneObj = self.battleCommander:getZoneOfPoint(point)
		if zoneObj and zoneObj.side == 2 then return true end

		local dcsGroup = unit:getGroup()
		local group = dcsGroup and GROUP:FindByName(dcsGroup:getName()) or nil
		if group then
			for _, zName in ipairs(self.supplyZones) do
				if string.find(zName, "CTLD FARP") or string.find(zName, "Escort Mission FARP") then
					local zObj = getMooseZone(zName)
					if zObj and group:IsInZone(zObj) then return true end
				end
			end
		end

		return false
	end

	function LogisticCommander:_pauseCsarRunnerHomeForRescue(pid, pilotObj, heliUnit)
		local state = self:_getRunningCsarHomeState(pid)
		if not state then return false end
		local grp = GROUP:FindByName(pilotObj:getGroup():getName())
		grp:RouteStop()
		state.status = "paused"
		self:refreshCsarMarker(pilotObj)
		state.skipCsarContact = nil
		state.pauseGroupId = heliUnit:getGroup():getID()
		state.resumeToken = (state.resumeToken or 0) + 1
		local token = state.resumeToken
		timer.scheduleFunction(function()
			local current = self.csarHomeByPilot and self.csarHomeByPilot[pid]
			if current ~= state or current.status ~= "paused" or current.resumeToken ~= token then return nil end
			if self.csarAssignedGroup[pid] or self.csarRouteIssued[pid] then return timer.getTime() + 10 end
			if not pilotObj or not pilotObj:isExist() then
				self:_clearCsarHomeState(pid)
				return nil
			end
			state.status = "running"
			state.skipCsarContact = nil
			state.ignoreRunnerContactGroupId = state.pauseGroupId
			state.pauseGroupId = nil
			self:_routeCsarPilotHome(pid, pilotObj, state)
			return nil
		end, {}, timer.getTime() + 60)
		return true
	end

	function LogisticCommander:_completeCsarHome(pid, pilotObj, state)
		local current = self.csarHomeByPilot and self.csarHomeByPilot[pid]
		if current ~= state then return false end
		local pilotData = self:_getCsarPilotData(pid)
		if pilotData and pilotData.player and pilotData.player ~= '' then
			local side = pilotData.coalition or 2
			local restored = tonumber(pilotData.lostCredits) or 0
			self.battleCommander:addStat(pilotData.player, 'Deaths', -1)
			if restored > 0 then
				self.battleCommander:addFunds(side, restored)
				self.battleCommander:addStat(pilotData.player, 'Points', restored)
				pilotData.lostCredits = 0
			end
			local homeName = state.displayName or state.zoneName or "home"
			local toprint = L10N:Format("CSAR_PLAYER_HOME_SAFE", pilotData.player, homeName)
			if restored > 0 then
				toprint = L10N:Format("CSAR_PLAYER_HOME_RECOVERED_CREDITS", pilotData.player, homeName, tostring(restored))
			end
			trigger.action.outTextForCoalition(side, toprint, 10)
			pilotData.hostileZoneName = nil
			pilotData.hostileGraceUntil = nil
		end
		local _, index = self:_findCsarPilotByPid(pid)
		if index then
			self:_cleanupCsarPilotAtIndex(index, true)
		else
			self:_clearCsarHomeState(pid)
		end
		return true
	end

	function LogisticCommander:_scheduleCsarHomeArrival(pid, pilotObj, state)
		state.arrivalToken = (state.arrivalToken or 0) + 1
		local token = state.arrivalToken
		local speed = LogisticCommander.csarHomeRunSpeed or 3.6
		local delay = 30
		timer.scheduleFunction(function()
			local current = self.csarHomeByPilot and self.csarHomeByPilot[pid]
			if current ~= state or current.arrivalToken ~= token or current.status ~= "running" then return nil end
			if not pilotObj or not pilotObj:isExist() then
				self:_clearCsarHomeState(pid)
				return nil
			end
			local point = pilotObj:getPoint()
			if not point then return nil end
			local dx = point.x - state.x
			local dz = point.z - state.z
			local dist = math.sqrt(dx * dx + dz * dz)
			if dist <= (LogisticCommander.csarHomeArrivalDistance or 120) then
				self:_completeCsarHome(pid, pilotObj, state)
				return nil
			end
			self:refreshCsarMarker(pilotObj)
			return timer.getTime() + 30
		end, {}, timer.getTime() + delay)
	end

	function LogisticCommander:_routeCsarPilotHome(pid, pilotObj, state)
		local grp = GROUP:FindByName(pilotObj:getGroup():getName())
		grp:SetAIOn()
		grp:OptionAlarmStateGreen()
		local point = pilotObj:getPoint()
		if point and state.x and state.z then
			local dx = point.x - state.x
			local dz = point.z - state.z
			state.distance = math.sqrt(dx * dx + dz * dz)
		end
		grp:RouteToVec2({ x = state.x, y = state.z }, LogisticCommander.csarHomeRunSpeed or 3.6)
		env.info("CSAR: RouteToVec2 "..grp:GetName().." -> "..tostring(state.displayName or state.zoneName or state.targetName))
		self:refreshCsarMarker(pilotObj)
		self:_scheduleCsarHomeArrival(pid, pilotObj, state)
	end

	function LogisticCommander:_announceCsarPlayerRunningHome(pilotData, destinationName)
		local pname = pilotData and pilotData.player
		if pname and pname ~= '' then
			local side = pilotData.coalition or 2
			trigger.action.outTextForCoalition(side, L10N:Format("CSAR_PLAYER_RUNNING_HOME", pname, destinationName), 10)
			return
		end
		for groupid in pairs(self.csarGroupMenus) do
			local T = L10N:ForGroup(groupid)
			trigger.action.outTextForGroup(groupid, T:Format("CSAR_PILOT_RUNNING_HOME", T:Get("CSAR_DOWNED_PILOT"), destinationName), 10)
		end
	end

	function LogisticCommander:_startCsarHomeForPilot(pilotObj, pilotData, zoneSide, zoneName)
		if not pilotObj or not pilotObj:isExist() then return false end
		local pid = pilotObj:getObjectID()
		if not pid or (self.csarHomeByPilot and self.csarHomeByPilot[pid]) then return false end

		if zoneSide == 1 and zoneName then
			local zoneObj = self.battleCommander:getZoneByName(zoneName)
			local candidate = self:_csarHomeCandidateFromZone(zoneObj, pilotObj:getPoint())
			self:_setCsarHomeState(pid, {
				status = "pending",
				side = 1,
				kind = "zone",
				zoneName = zoneName,
				targetName = candidate and candidate.targetName or zoneName,
				displayName = zoneName,
				x = candidate and candidate.x or nil,
				z = candidate and candidate.z or nil,
				distance = candidate and candidate.distance or nil,
				inZone = true
			})
			return true
		end

		local point = pilotObj:getPoint()
		local candidate = self:_findCsarHomeCandidate(point)
		if not candidate or candidate.distance > (LogisticCommander.csarHomeDistance or (3 * NM)) then return false end

		local state = {
			status = candidate.side == 2 and "running" or "pending",
			side = candidate.side,
			kind = candidate.kind,
			zoneName = candidate.zoneName,
			targetName = candidate.targetName,
			displayName = candidate.displayName,
			x = candidate.x,
			z = candidate.z,
			distance = candidate.distance,
			inZone = false
		}
		self:_setCsarHomeState(pid, state)
		if candidate.side == 2 then
			self:_announceCsarPlayerRunningHome(pilotData, candidate.displayName)
			self:_routeCsarPilotHome(pid, pilotObj, state)
		end
		return true
	end

	function LogisticCommander:_processCsarHomeZoneCaptured(zoneName)
		local pending = self.csarHomeByZone and self.csarHomeByZone[zoneName]
		if not pending then return end
		local pids = {}
		for pid in pairs(pending) do
			pids[#pids + 1] = pid
		end
		for _, pid in ipairs(pids) do
			local state = self.csarHomeByPilot and self.csarHomeByPilot[pid]
			if state and state.zoneName == zoneName and state.status == "pending" then
				local pilotObj = self:_findCsarPilotByPid(pid)
				if pilotObj then
					if state.inZone then
						state.side = 2
						state.status = "running"
						self:_completeCsarHome(pid, pilotObj, state)
					else
						local zoneObj = self.battleCommander:getZoneByName(zoneName)
						local candidate = self:_csarHomeCandidateFromZone(zoneObj, pilotObj:getPoint())
						if candidate then
							state.side = 2
							state.status = "running"
							state.targetName = candidate.targetName
							state.displayName = candidate.displayName
							state.x = candidate.x
							state.z = candidate.z
							state.distance = candidate.distance
							local pilotData = self:_getCsarPilotData(pid)
							self:_announceCsarPlayerRunningHome(pilotData, candidate.displayName)
							self:_routeCsarPilotHome(pid, pilotObj, state)
						end
					end
				else
					self:_clearCsarHomeState(pid)
				end
			end
		end
	end

	function LogisticCommander:_cleanupCsarPilotAtIndex(index, suppressMessage)
		local pilot = self.ejectedPilots[index]
		local pid = pilot and ((pilot.getObjectID and pilot:getObjectID()) or self.ejectedPilotPidByObj[pilot]) or nil
		local pilotData = pid and (landedPilotOwners[pid] or self.csarPilotDataByObject[pid] or ejectedPilotOwners[pid]) or nil
		if not suppressMessage then
			local pname = pilotData and pilotData.player
			local msg
			local now = timer.getTime()
			if pilotData and pilotData.player and pilotData.player~='' and pilotData.hostileZoneName and pilotData.hostileGraceUntil then
				if now >= pilotData.hostileGraceUntil then
					self.battleCommander:addStat(pilotData.player,'Captured by enemy',1)
					trigger.action.outTextForCoalition(2,L10N:Format("CSAR_PLAYER_CAPTURED", pilotData.player, pilotData.hostileZoneName),10)
				end
			else
				if pname and pname~='' then
					msg = L10N:Format("CSAR_PLAYER_KIA", pname)
					trigger.action.outTextForCoalition(2,msg,10)
				else
					msg = L10N:Get("CSAR_DOWNED_PILOT_KIA")
					for groupid in pairs(self.csarGroupMenus) do
						trigger.action.outTextForGroup(groupid,msg,10)
					end
				end
			end
		end
		if pid then
			self:_clearCsarHomeState(pid)
			landedPilotOwners[pid]=nil
			self.csarPilotDataByObject[pid]=nil
			ejectedPilotOwners[pid]=nil
			self.csarPilotTimestampByObject[pid]=nil
			if self.csarHostileGroupsByPilotObject then
				self.csarHostileGroupsByPilotObject[pid]=nil
			end
			self.csarAssignedGroup[pid]=nil
			self.csarRouteIssued[pid]=nil
			self.csarNextTick[pid]=nil
			self.csarVisibleMsg[pid]=nil
			self.csarCloseMsg[pid]=nil
			self.csarRunEta[pid]=nil
			self.csarSmokeTick[pid]=nil
			self.csarGuidanceStatus[pid]=nil
			local bname = self.csarBeaconName[pid]
			if bname then trigger.action.stopRadioTransmission(bname) end
			self.csarBeaconName[pid]=nil
			self.csarBeaconFreq[pid]=nil
			self.csarBeaconNext[pid]=nil
			self:removeCsarMarker(pid)
		end
		if pilot and pilot:isExist() then
			pilot:destroy()
		end
		if pilot then self.ejectedPilotPidByObj[pilot] = nil end
		table.remove(self.ejectedPilots, index)
	end

	function LogisticCommander:_enforceCsarPilotLimit()
		local maxPilots = tonumber(LogisticCommander.csarMaxAtSpawn) or 10
		if maxPilots < 0 then maxPilots = 0 end
		while #self.ejectedPilots > maxPilots do
			local oldestIndex = nil
			local oldestTimestamp = math.huge
			local oldestHasPilotData = true
			for i, pilotObj in ipairs(self.ejectedPilots) do
				local pid = pilotObj and pilotObj.getObjectID and pilotObj:getObjectID() or nil
				local pilotData = pid and (landedPilotOwners[pid] or self.csarPilotDataByObject[pid] or ejectedPilotOwners[pid]) or nil
				local hasPilotData = self:_csarHasPriorityPilotData(pilotData)
				local timestamp = tonumber(pilotData and pilotData.timestamp) or tonumber(pid and self.csarPilotTimestampByObject[pid]) or 0
				if oldestIndex == nil
					or ((not hasPilotData) and oldestHasPilotData)
					or (hasPilotData == oldestHasPilotData and timestamp < oldestTimestamp)
				then
					oldestTimestamp = timestamp
					oldestHasPilotData = hasPilotData
					oldestIndex = i
				end
			end
			if not oldestIndex then break end
			self:_cleanupCsarPilotAtIndex(oldestIndex, true)
		end
	end

	function LogisticCommander:_addPilotToCsarQueues(pilotObj, preferredTimestamp)
		if not pilotObj then return end
		self:_trackCsarPilotTimestamp(pilotObj, preferredTimestamp)
		table.insert(self.ejectedPilots,pilotObj)
		self:createCsarMarker(pilotObj)
		local pid = pilotObj.getObjectID and pilotObj:getObjectID() or nil
		for groupid in pairs(self.csarGroupMenus) do
			SCHEDULER:New(nil,function()
				if pilotObj and pilotObj:isExist() then
					local homeState = pid and self.csarHomeByPilot and self.csarHomeByPilot[pid] or nil
					if homeState and homeState.status == "running" then return end
					self:printPilotInfo(pilotObj,groupid,nil,15)
				end
			end,{},15,0)
		end
		self:_enforceCsarPilotLimit()
	end

	function LogisticCommander:_restorePendingCsarPilots()
		local pending = self.battleCommander._pendingCsarPilotPersistence
		if type(pending) ~= "table" or #pending == 0 then
			self.battleCommander._pendingCsarPilotPersistence = nil
			return
		end

		local maxPilots = tonumber(LogisticCommander.csarMaxRestoreAtSpawn) or tonumber(LogisticCommander.csarMaxAtSpawn) or 10
		local liveCap = tonumber(LogisticCommander.csarMaxAtSpawn) or 10
		if maxPilots > liveCap then
			maxPilots = liveCap
		end
		if maxPilots < 0 then maxPilots = 0 end

		local newestFirst = {}
		for i, entry in ipairs(pending) do
			newestFirst[i] = entry
		end
		self.battleCommander._pendingCsarPilotPersistence = nil
		table.sort(newestFirst, function(a, b)
			local ah = a and a.hasPilotData == true or false
			local bh = b and b.hasPilotData == true or false
			if ah ~= bh then
				return ah and not bh
			end
			local ta = tonumber(a and a.timestamp) or 0
			local tb = tonumber(b and b.timestamp) or 0
			return ta > tb
		end)

		local toRestore = {}
		for i = 1, math.min(#newestFirst, maxPilots) do
			toRestore[#toRestore + 1] = newestFirst[i]
		end
		table.sort(toRestore, function(a, b)
			local ta = tonumber(a and a.timestamp) or 0
			local tb = tonumber(b and b.timestamp) or 0
			return ta < tb
		end)

		local function pointInActiveZone(obj)
			if not obj then return nil end
			for _, z in ipairs(self.battleCommander.zones) do
				if z.active and z.side and z.side ~= 0 and z.zone then
					if Utils.isInZone(obj, z.zone) then
						return z.side, z.zone
					end
				end
			end
			return nil
		end

		for index, entry in ipairs(toRestore) do
			local point = coord.LLtoLO(entry.latitude, entry.longitude, entry.altitude or 0)
			if point then
				local surfaceType = land.getSurfaceType({ x = point.x, y = point.z })
				local overWater = (surfaceType == land.SurfaceType.WATER) or (surfaceType == land.SurfaceType.SHALLOW_WATER)
				local skipRestore, nearestEnemyName, nearestEnemyNm = self.battleCommander:_restorePointTooFarFromEnemy(point, 120)
				if overWater then
					env.info(string.format("[CSAR-RESTORE] skip pilot timestamp=%s over water",
						tostring(entry.timestamp)))
				elseif skipRestore then
					env.info(string.format("[CSAR-RESTORE] skip pilot timestamp=%s nearestEnemy=%s dist=%.1fNm limit=120.0Nm",
						tostring(entry.timestamp),
						tostring(nearestEnemyName),
						nearestEnemyNm or -1))
				else
					point.y = point.y or land.getHeight({ x = point.x, y = point.z })
					local spawnCoord = COORDINATE:NewFromVec3(point)
					local alias = "FOOTHOLD_CSAR_RESTORE_"..tostring(math.floor(tonumber(entry.timestamp) or timer.getTime())).."_"..tostring(index).."_"..tostring(math.random(1000,9999))
					local sp = SPAWN:NewWithAlias("Downed Pilot", alias)
					if sp.InitCoalition then
						sp = sp:InitCoalition(tonumber(entry.coalition) or coalition.side.BLUE)
					end
					local spawned = sp:SpawnFromPointVec3(spawnCoord)
					if spawned then
						local unitWrapper = spawned:GetUnit(1)
						local pilotObj = unitWrapper and unitWrapper:GetDCSObject() or nil
						if pilotObj then
							local player = entry.player
							if (type(player) ~= "string" or player == "" or player == "Unknown") and type(entry.playerName) == "string" and entry.playerName ~= "" and entry.playerName ~= "Unknown" then
								player = entry.playerName
							end
							if player == "Unknown" then player = nil end
							local pilotData = {
								player = player,
								lostCredits = tonumber(entry.lostCredits) or 0,
								coalition = tonumber(entry.coalition) or coalition.side.BLUE,
								timestamp = tonumber(entry.timestamp) or timer.getTime(),
								hasPilotData = entry.hasPilotData == true,
							}
							self:_bindPilotDataToObject(pilotObj:getObjectID(), pilotData)
							self:_addPilotToCsarQueues(pilotObj, pilotData.timestamp)
							local zoneSide, zoneName = pointInActiveZone(pilotObj)
							self:_startCsarHomeForPilot(pilotObj, pilotData, zoneSide, zoneName)
						end
					end
				end
			end
		end
	end

	function LogisticCommander:update()
		self.csarBeaconName = self.csarBeaconName or {}
		self.csarBeaconFreq = self.csarBeaconFreq or {}
		self.csarBeaconNext = self.csarBeaconNext or {}
		self.csarAssignedGroup = self.csarAssignedGroup or {}
		self.csarRouteIssued = self.csarRouteIssued or {}
		self.csarPilotDataByObject = self.csarPilotDataByObject or {}
		self.csarPilotTimestampByObject = self.csarPilotTimestampByObject or {}
		self.csarHoverStatus = self.csarHoverStatus or {}
		self.csarGuidanceStatus = self.csarGuidanceStatus or {}
		self.csarNearStatus = self.csarNearStatus or {}
		self.ejectedPilotPidByObj = self.ejectedPilotPidByObj or {}
		local tocleanup = {}
		self.ejectedPilotsState = self.ejectedPilotsState or {}
		for i = #self.ejectedPilotsState, 1, -1 do
			self.ejectedPilotsState[i] = nil
		end

		for i, v in ipairs(self.ejectedPilots) do
			if v and v:isExist() then
				local keep = true
				if v.getLife and v:getLife() <= 0 then
					local pid = v.getObjectID and v:getObjectID() or nil
					table.insert(tocleanup, { index = i, kia = true, pid = pid })
					keep = false
				end
				if keep then
					local ejectedPilotTable = {
						playerName = "Unknown",
						lostCredits = 0
					}
					local objectID = v:getObjectID()
					self.ejectedPilotPidByObj[v] = objectID
					local pilotData = (landedPilotOwners and landedPilotOwners[objectID]) or self.csarPilotDataByObject[objectID] or (ejectedPilotOwners and ejectedPilotOwners[objectID])
					local timestamp = self:_trackCsarPilotTimestamp(v)
					if pilotData then
						ejectedPilotTable.playerName = pilotData.player or "Unknown"
						ejectedPilotTable.player = pilotData.player
						ejectedPilotTable.lostCredits = pilotData.lostCredits or 0
						ejectedPilotTable.coalition = pilotData.coalition or coalition.side.BLUE
					end
					ejectedPilotTable.timestamp = timestamp
					ejectedPilotTable.hasPilotData = self:_csarHasPriorityPilotData(pilotData)
					local point = v:getPoint()
					if point then
						ejectedPilotTable.latitude, ejectedPilotTable.longitude, ejectedPilotTable.altitude = coord.LOtoLL(point)
					end
					table.insert(self.ejectedPilotsState, ejectedPilotTable)
				end
				else
					local pid = self.ejectedPilotPidByObj[v] or nil
					table.insert(tocleanup, { index = i, kia = true, pid = pid })
				end
			end

		local function hasValidRemainingCsarPilot(excludePid)
			for _, v in ipairs(self.ejectedPilots or {}) do
				if v and v:isExist() and v:getObjectID() ~= excludePid and v:getPoint() then
					return true
				end
			end
			return false
		end

		local function scheduleClosestPilotInfo(groupName, excludePid)
			if not groupName or not hasValidRemainingCsarPilot(excludePid) then return end
			self.csarAutoClosestInfoCooldownByGroup = self.csarAutoClosestInfoCooldownByGroup or {}
			local now = timer.getTime()
			if now < (self.csarAutoClosestInfoCooldownByGroup[groupName] or 0) then return end
			self.csarAutoClosestInfoCooldownByGroup[groupName] = now + 30
			timer.scheduleFunction(function()
				local gr = Group.getByName(groupName)
				if not gr or not gr:isExist() then return nil end
				local gid = gr:getID()
				local un = gr:getUnit(1)
				if not un or not un:isExist() then return nil end

				local maxdist = 300000
				local targetpilot = nil
				for _, v in ipairs(self.ejectedPilots or {}) do
					if v and v:isExist() and v:getObjectID() ~= excludePid then
						local vp = v:getPoint()
						if vp then
							local dist = UTILS.VecDist3D(un:getPoint(), vp)
							if dist < maxdist then
								maxdist = dist
								targetpilot = v
							end
						end
					end
				end

				if targetpilot then
					self:printPilotVectorInfo(targetpilot, gid, un, 15)
				end
				return nil
			end, {}, timer.getTime() + 5)
		end

		local function boardPilot(pilotObj, heliUnit, groupid, fromScheduler)
			local T = L10N:ForGroup(groupid)
			local pid = pilotObj:getObjectID()
			local pilotData = landedPilotOwners[pid] or self.csarPilotDataByObject[pid] or ejectedPilotOwners[pid]
			local current = self.carriedPilots[groupid] or 0
			local unitType = heliUnit:getTypeName()
			local maxCarriedPilots = LogisticCommander.AllowedCsar[unitType]

			if Utils.isInAir(heliUnit) then
				local pp = pilotObj:getPoint()
				local hp = heliUnit:getPoint()
				local dx = hp.x - pp.x
				local dz = hp.z - pp.z
				local hoverDist = LogisticCommander.csarHoverDistance or 10
				local guidanceDist = LogisticCommander.csarGuidanceDistance or (hoverDist + 30)
				local horizontalDistSquared = (dx*dx + dz*dz)
				if horizontalDistSquared <= (hoverDist*hoverDist) then
					if self.csarGuidanceStatus and self.csarGuidanceStatus[pid] then
						self.csarGuidanceStatus[pid][groupid] = nil
					end
					local agl = Utils.getAGL(heliUnit)
					if agl <= (LogisticCommander.csarHoverHeight or 20) and UTILS.VecNorm(heliUnit:getVelocity()) <= 5 then
						self.csarHoverStatus = self.csarHoverStatus or {}
						local st = self.csarHoverStatus[pid]
						if not st then
							st = {}
							self.csarHoverStatus[pid] = st
						end
						local now = timer.getTime()
						local deadline = st[groupid]
						if not deadline then
							deadline = now + (LogisticCommander.csarHoverSeconds or 10)
							st[groupid] = deadline
							if not st["sched_"..groupid] then
								st["sched_"..groupid] = true
								timer.scheduleFunction(function()
									if not self.csarHoverStatus or not self.csarHoverStatus[pid] or not self.csarHoverStatus[pid][groupid] then
										st["sched_"..groupid] = nil
										return
									end
									if boardPilot(pilotObj, heliUnit, groupid, true) then
										st["sched_"..groupid] = nil
										return
									end
									if not self.csarHoverStatus or not self.csarHoverStatus[pid] or not self.csarHoverStatus[pid][groupid] then
										st["sched_"..groupid] = nil
										return
									end
									return timer.getTime() + 2
								end, {}, now + 0.1)
							end
						end
						local remaining = math.floor((deadline - now) + 0.999)
						if remaining > 0 then
							if fromScheduler then
								local pilotName = (pilotData and pilotData.player and pilotData.player~='') and pilotData.player or T:Get("CSAR_DOWNED_PILOT")
								trigger.action.outTextForGroup(groupid, T:Format("CSAR_PICKING_UP_HOVER", pilotName, remaining), 1)
							end
							return false
						end
						st[groupid] = nil
					else
						if self.csarHoverStatus and self.csarHoverStatus[pid] then
							self.csarHoverStatus[pid][groupid] = nil
						end
						return false
					end
				elseif guidanceDist > hoverDist and horizontalDistSquared <= (guidanceDist*guidanceDist) then
					if self.csarHoverStatus and self.csarHoverStatus[pid] then
						self.csarHoverStatus[pid][groupid] = nil
					end
					local horizontalDist = math.sqrt(horizontalDistSquared)
					local remaining = horizontalDist - hoverDist
					if remaining > 0 then
						local bucket = math.ceil(remaining / 5) * 5
						if bucket < 5 then bucket = 5 end
						local gst = self.csarGuidanceStatus[pid]
						if not gst then
							gst = {}
							self.csarGuidanceStatus[pid] = gst
						end
						local guidanceKey = tostring(bucket)
						local heightCue = ""
						local agl = Utils.getAGL(heliUnit)
						local hoverHeight = LogisticCommander.csarHoverHeight or 20
						if agl and agl > hoverHeight then
							local descendFeet = math.ceil(((agl - hoverHeight) * 3.280839895) / 10) * 10
							if descendFeet < 10 then descendFeet = 10 end
							heightCue = T:Format("CSAR_GUIDANCE_DESCEND_SUFFIX", descendFeet)
							guidanceKey = guidanceKey .. "|D" .. tostring(descendFeet)
						end
						if gst[groupid] ~= guidanceKey then
							local direction = T:Get("CSAR_DIRECTION_FORWARD")
							local pos = heliUnit:getPosition()
							if hp and pp and pos and pos.x then
								local bearing = math.deg(math.atan2(pp.z - hp.z, pp.x - hp.x))
								if bearing < 0 then bearing = bearing + 360 end
								local heading = math.deg(math.atan2(pos.x.z, pos.x.x))
								if heading < 0 then heading = heading + 360 end
								local rel = (bearing - heading) % 360
								local forwardComponent = math.cos(math.rad(rel)) * horizontalDist
								local lateralComponent = math.sin(math.rad(rel)) * horizontalDist
								if math.abs(lateralComponent) > (math.abs(forwardComponent) + 5) then
									direction = lateralComponent >= 0 and T:Get("CSAR_DIRECTION_RIGHT") or T:Get("CSAR_DIRECTION_LEFT")
								else
									direction = forwardComponent >= 0 and T:Get("CSAR_DIRECTION_FORWARD") or T:Get("CSAR_DIRECTION_BACK")
								end
							end
							trigger.action.outTextForGroup(groupid, T:Format("CSAR_GUIDANCE_MOVE", direction, bucket, heightCue), 3)
							gst[groupid] = guidanceKey
						end
					end
					return false
				else
					if self.csarHoverStatus and self.csarHoverStatus[pid] then
						self.csarHoverStatus[pid][groupid] = nil
					end
					if self.csarGuidanceStatus and self.csarGuidanceStatus[pid] then
						self.csarGuidanceStatus[pid][groupid] = nil
					end
					return false
				end
			else
				if self.csarHoverStatus and self.csarHoverStatus[pid] then
					self.csarHoverStatus[pid][groupid] = nil
				end
				if self.csarGuidanceStatus and self.csarGuidanceStatus[pid] then
					self.csarGuidanceStatus[pid][groupid] = nil
				end
			end

			if current >= maxCarriedPilots then
				trigger.action.outTextForGroup(groupid, T:Get("CSAR_AT_MAX_CAPACITY"), 8)
				return false
			end
			self:trackCsarHostilesForRescuedPilot(groupid, pid, pilotData)
			self.carriedPilots[groupid] = current + 1
			self.carriedPilotData[groupid] = self.carriedPilotData[groupid] or {}
			if pilotData then table.insert(self.carriedPilotData[groupid], pilotData) end
			self:_clearCsarHomeState(pid)
			landedPilotOwners[pid] = nil
			self.csarPilotDataByObject[pid] = nil
			ejectedPilotOwners[pid] = nil
			self.csarNextTick[pid] = nil
			self.csarHoverStatus[pid] = nil
			self.csarGuidanceStatus[pid] = nil
			trigger.action.setUnitInternalCargo(heliUnit:getName(), (self.carriedPilots[groupid] or 0) * (LogisticCommander.PilotWeight or 80))
			local playerName = heliUnit:getPlayerName()
			local pickupReward=0
			if self.battleCommander.playerRewardsOn and playerName and bc.playerContributions[2][playerName] ~= nil then
				local restoreAmount = (pilotData and pilotData.lostCredits) or 0
				local totalReward = (self.battleCommander.rewards.rescue or 0) + restoreAmount
				if totalReward>0 then
					bc:addContribution(playerName, 2, totalReward)
					self.battleCommander:addTempStat(playerName,'Pilot Rescue',1)
					pickupReward=totalReward
					if pilotData then
						pilotData.rescueRewardPaid=true
						pilotData.rescueRewardPaidAmount=totalReward
						pilotData.lostCredits=0
					end
				end
			end
			if playerName then
				local pilotName = (pilotData and pilotData.player and pilotData.player~='') and pilotData.player or L10N:Get("CSAR_DOWNED_PILOT")
				if pickupReward>0 then
					trigger.action.outTextForCoalition(heliUnit:getCoalition(),L10N:Format("CSAR_RESCUED_WITH_CREDITS", playerName, pilotName, tostring(pickupReward)),10)
				else
					trigger.action.outTextForCoalition(heliUnit:getCoalition(),L10N:Format("CSAR_RESCUED", playerName, pilotName),10)
				end
			end
			if fromScheduler then
				for j = #self.ejectedPilots, 1, -1 do
					local p = self.ejectedPilots[j]
					if p and p:getObjectID() == pid then
						table.remove(self.ejectedPilots, j)
						break
					end
				end
			end

			pilotObj:destroy()
			trigger.action.outTextForGroup(groupid, T:Format("CSAR_PILOT_ONBOARD", self.carriedPilots[groupid], maxCarriedPilots), 10)
			local rescueGroup = heliUnit:getGroup()
			scheduleClosestPilotInfo(rescueGroup and rescueGroup:getName() or nil, pid)
			self.csarAssignedGroup[pid] = nil
			self.csarRouteIssued[pid] = nil
			self.csarVisibleMsg[pid] = nil
			self.csarCloseMsg[pid] = nil
			self.csarRunEta[pid] = nil

			self:removeCsarMarker(pid)
			return true

		end

		local function refreshPilotBeacon(pid, pilotObj)
			local bname = self.csarBeaconName[pid]
			local freq = self.csarBeaconFreq[pid]
			if not bname then
				bname = "FOOTHOLD_CSAR_"..pid.."_BEACON"
				freq = 250000 + math.random(0,1000)*1000
				self.csarBeaconName[pid] = bname
				self.csarBeaconFreq[pid] = freq
				self.csarBeaconNext[pid] = 0
			end
			local nextT = self.csarBeaconNext[pid] or 0
			local t = timer.getTime()
			if t >= nextT then
				trigger.action.stopRadioTransmission(bname)
				trigger.action.radioTransmission("l10n/DEFAULT/beacon.ogg", pilotObj:getPoint(), 0, true, freq, 1000, bname)
				self.csarBeaconNext[pid] = t + 25
			end
		end

		local function runPilotToHelo(pilotObj, heliUnit)
			local grp = GROUP:FindByName(pilotObj:getGroup():getName())
			grp:SetAIOn()
			grp:OptionAlarmStateGreen()
			local dest = heliUnit:getPoint()
			grp:RouteToVec2({ x = dest.x, y = dest.z },5)
			env.info("CSAR: RouteToVec2 "..grp:GetName().." -> "..heliUnit:getName())
		end

		local function approachMessage(pid, heliUnit, pilotObj)
			local gid = heliUnit:getGroup():getID()
			local shown = self.csarVisibleMsg[pid]
			if not shown then
				shown = {}
				self.csarVisibleMsg[pid] = shown
			end
			if not shown[gid] then
				self.csarApproachClusterMsg = self.csarApproachClusterMsg or {}
				local now = timer.getTime()
				local p = pilotObj:getPoint()
				local cluster = self.csarApproachClusterMsg[gid]
				if cluster and (now - cluster.t) < 20 and p then
					local dx = p.x - cluster.x
					local dz = p.z - cluster.z
					if (dx*dx + dz*dz) <= (92*92) then
						shown[gid] = true
						return
					end
				end
				if p then
					self.csarApproachClusterMsg[gid] = { t = now, x = p.x, z = p.z }
				end
				self:printPilotInfo(pilotObj, gid, heliUnit, 15, true)
				self:_signalPilotFlareBurst(pilotObj, 3, 5)
				shown[gid] = true
			end
		end

		local function closeMessage(pid, heliUnit, pilotObj)
			local gid = heliUnit:getGroup():getID()
			local shown = self.csarCloseMsg[pid]
			if not shown then
				shown = {}
				self.csarCloseMsg[pid] = shown
			end
			if not shown[gid] then
				self.csarCloseClusterMsg = self.csarCloseClusterMsg or {}
				local now = timer.getTime()
				local p = pilotObj:getPoint()
				local cluster = self.csarCloseClusterMsg[gid]
				if cluster and (now - cluster.t) < 20 and p then
					local dx = p.x - cluster.x
					local dz = p.z - cluster.z
					if (dx*dx + dz*dz) <= (92*92) then
						shown[gid] = true
						return
					end
				end
				if p then
					self.csarCloseClusterMsg[gid] = { t = now, x = p.x, z = p.z }
				end
				local msg = "You're close now! Land in a safe place, we will come to you."
				local hp = heliUnit:getPoint()
				if hp and p then
					local bearing = math.deg(math.atan2(p.z - hp.z, p.x - hp.x))
					if bearing < 0 then bearing = bearing + 360 end
					local pos = heliUnit:getPosition()
					local heading = math.deg(math.atan2(pos.x.z, pos.x.x))
					if heading < 0 then heading = heading + 360 end
					local rel = bearing - heading
					rel = rel % 360
					local clock = math.floor((rel + 15) / 30)
					if clock == 0 then clock = 12 end
					msg = "You're close now! I'm at your " .. clock .. " o'clock. Land in a safe place, we will come to you."
				end
				trigger.action.outTextForGroup(gid, msg, 10)
				self:_signalPilotFlareBurst(pilotObj, 3, 5)
				shown[gid] = true
			end
		end

		local function handleRunnerContact(pid, pilotObj, heliUnit, dist)
			local state = self.csarHomeByPilot and self.csarHomeByPilot[pid]
			if not state then return false, false end
			if state.status == "paused" then return false, true end
			if state.status ~= "running" then return false, false end
			local gid = heliUnit:getGroup():getID()
			if state.ignoreRunnerContactGroupId == gid then
				if dist >= self.csarExtractDistance or not Utils.isInAir(heliUnit) then
					state.ignoreRunnerContactGroupId = nil
				else
					return true, false
				end
			end
			if state.skipCsarContact then return true, false end
			if dist >= 300 then return true, false end
			if self:_isCsarContactInBlueHomeArea(heliUnit) then
				state.skipCsarContact = true
				self.csarAssignedGroup[pid] = nil
				self.csarRouteIssued[pid] = nil
				return true, false
			end

			self.csarVisibleMsg[pid] = self.csarVisibleMsg[pid] or {}
			self.csarVisibleMsg[pid][gid] = true
			closeMessage(pid, heliUnit, pilotObj)
			local paused = self:_pauseCsarRunnerHomeForRescue(pid, pilotObj, heliUnit)
			return false, paused
		end


		-- iterate helos vs pilots
		local now = timer.getTime()
		local guidanceTriggerDist = math.max(LogisticCommander.csarGuidanceDistance or 0, (LogisticCommander.csarHoverDistance or 10) + (LogisticCommander.csarHoverHeight or 20))
		for i, pilotObj in ipairs(self.ejectedPilots) do
			if pilotObj and pilotObj:isExist() then
				local pid = pilotObj:getObjectID()
				refreshPilotBeacon(pid, pilotObj)
				local pilotPoint = pilotObj:getPoint()

				-- collect candidate player helos via Moose SET_GROUP (mirroring CSAR) and drop stale hulks with no player
				local candidates = {}
				local seen = {}
				local function addUnit(un)
					if not un or not un:isExist() then return end
					if not un:getPlayerName() then return end -- ignore empty or ejected hulks
					local g = un:getGroup()
					if not g then return end
					local gid = g:getID()
					if seen[gid] then return end
					if not self.csarGroupMenus[gid] then return end
					seen[gid] = true
					candidates[#candidates+1] = { unit = un, groupid = gid }
				end

			local heliSet = self.csarSet
			if heliSet and heliSet.ForEachGroupAlive then
				heliSet:ForEachGroupAlive(function(mooseGroup)
					local gidObj = mooseGroup and mooseGroup:GetDCSObject()
					local gid = gidObj and gidObj:getID()
					local unitWrapper = mooseGroup and mooseGroup:GetUnit(1)
					local unitRef = unitWrapper and unitWrapper:GetDCSObject()
					if unitRef and unitRef:isExist() and unitRef:getPlayerName() and self.allowedTypes[unitRef:getTypeName()] then
						local gname = mooseGroup:GetName()
						if gid then self.csarGroups[gid] = { name = gname, player = unitRef:getPlayerName() } end
						addUnit(unitRef)
					elseif gid then
						self.csarGroups[gid] = nil
					end
				end)
			else
				for gid, entry in pairs(self.csarGroups) do
					local gname = (entry and entry.name) or (self.groupIdToName and self.groupIdToName[gid])
					local gr = gname and Group.getByName(gname) or nil
					local unitRef = gr and gr:getUnit(1) or nil
					if unitRef and unitRef:isExist() and unitRef:getPlayerName() and self.allowedTypes[unitRef:getTypeName()] then
						entry.name = gname
						entry.player = unitRef:getPlayerName()
						addUnit(unitRef)
					else
						self.csarGroups[gid] = nil
					end
				end
			end

				local assignedGroupid = self.csarAssignedGroup[pid]
				if assignedGroupid then
					local assignedFound = false
					for _, entry in ipairs(candidates) do
						if entry.groupid == assignedGroupid then
							assignedFound = true
							break
						end
					end
					if not assignedFound then
						self.csarAssignedGroup[pid] = nil
						assignedGroupid = nil
					end
				end
				local anyNear = false
				local bestNextTick = now + 10
				for _, entry in ipairs(candidates) do
					local un = entry.unit
					local groupid = entry.groupid
					if not assignedGroupid or groupid == assignedGroupid then
						local dist = UTILS.VecDist3D(un:getPoint(), pilotPoint)
						if self.csarGuidanceStatus[pid] and ((not Utils.isInAir(un)) or dist > guidanceTriggerDist) then
							self.csarGuidanceStatus[pid][groupid] = nil
						end

						local skipRunnerContact, runnerStopped = handleRunnerContact(pid, pilotObj, un, dist)
						if not skipRunnerContact and dist < 2500 then
							if not self.csarNearStatus[pid] then
								self.csarNearStatus[pid] = true
								timer.scheduleFunction(function()
									if not self.csarNearStatus or not self.csarNearStatus[pid] then return end
									if not pilotObj or not pilotObj:isExist() then
										self.csarNearStatus[pid] = nil
										return
									end
									local pilotPointFast = pilotObj:getPoint()
									local candidatesFast = {}
									local seenFast = {}
									local function addUnitFast(unFast)
										if not unFast or not unFast:isExist() then return end
										if not unFast:getPlayerName() then return end
										local gFast = unFast:getGroup()
										if not gFast then return end
										local gidFast = gFast:getID()
										if seenFast[gidFast] then return end
										if not self.csarGroupMenus[gidFast] then return end
										seenFast[gidFast] = true
										candidatesFast[#candidatesFast+1] = { unit = unFast, groupid = gidFast }
									end

									local heliSetFast = self.csarSet
									if heliSetFast and heliSetFast.ForEachGroupAlive then
										heliSetFast:ForEachGroupAlive(function(mooseGroup)
											local unitWrapper = mooseGroup and mooseGroup:GetUnit(1)
											local unitRef = unitWrapper and unitWrapper:GetDCSObject()
											if unitRef and unitRef:isExist() and unitRef:getPlayerName() and self.allowedTypes[unitRef:getTypeName()] then
												addUnitFast(unitRef)
											end
										end)
									else
										for gid, entry in pairs(self.csarGroups) do
											local gname = (entry and entry.name) or (self.groupIdToName and self.groupIdToName[gid])
											local gr = gname and Group.getByName(gname) or nil
											local unitRef = gr and gr:getUnit(1) or nil
											if unitRef and unitRef:isExist() and unitRef:getPlayerName() and self.allowedTypes[unitRef:getTypeName()] then
												addUnitFast(unitRef)
											end
										end
									end

									local anyCloseFast = false
									for _, entryFast in ipairs(candidatesFast) do
										local unFast = entryFast.unit
										local groupidFast = entryFast.groupid
										local distFast = UTILS.VecDist3D(unFast:getPoint(), pilotPointFast)
										if self.csarGuidanceStatus[pid] and ((not Utils.isInAir(unFast)) or distFast > guidanceTriggerDist) then
											self.csarGuidanceStatus[pid][groupidFast] = nil
										end

										local skipRunnerContact, runnerStopped = handleRunnerContact(pid, pilotObj, unFast, distFast)
										if not skipRunnerContact then
											if distFast < 2500 then
												anyCloseFast = true
											end

											if distFast < self.csarApproachNear and not runnerStopped then
												approachMessage(pid, unFast, pilotObj)
											end
											if distFast < self.csarExtractDistance and not runnerStopped then
												closeMessage(pid, unFast, pilotObj)
											end
											if not Utils.isInAir(unFast) and distFast < self.csarExtractDistance then
												if not self.csarAssignedGroup[pid] then
													self.csarAssignedGroup[pid] = groupidFast
												end
												local runEta = self.csarRunEta[pid]
												if not runEta then
													runEta = {}
													self.csarRunEta[pid] = runEta
												end
												if not runEta[groupidFast] then
													local pilotData = landedPilotOwners[pid] or self.csarPilotDataByObject[pid] or ejectedPilotOwners[pid]
													local TFast = L10N:ForGroup(groupidFast)
													local pilotName = (pilotData and pilotData.player and pilotData.player~='') and pilotData.player or TFast:Get("CSAR_DOWNED_PILOT")
													local eta = math.floor((distFast - self.csarLoadDistance) / 3.6)
													if eta < 0 then eta = 0 end
													runEta[groupidFast] = eta
													trigger.action.outTextForGroup(groupidFast, TFast:Format("CSAR_COMING_TO_YOU_ETA", pilotName, eta), 10)
												end
												if self.csarRouteIssued[pid] ~= groupidFast then
													self.csarRouteIssued[pid] = groupidFast
													runPilotToHelo(pilotObj, unFast)
												end
											end

											if distFast < self.csarLoadDistance then
												if boardPilot(pilotObj, unFast, groupidFast) then
													for j = #self.ejectedPilots, 1, -1 do
														if self.ejectedPilots[j] == pilotObj then
															table.remove(self.ejectedPilots, j)
															break
														end
													end
													self.csarNearStatus[pid] = nil
													self.csarNextTick[pid] = nil
													return
												end
											elseif Utils.isInAir(unFast) and distFast <= guidanceTriggerDist then
												if boardPilot(pilotObj, unFast, groupidFast) then
													for j = #self.ejectedPilots, 1, -1 do
														if self.ejectedPilots[j] == pilotObj then
															table.remove(self.ejectedPilots, j)
															break
														end
													end
													self.csarNearStatus[pid] = nil
													self.csarNextTick[pid] = nil
													return
												end
											end
										end
									end

									if not anyCloseFast then
										self.csarNearStatus[pid] = nil
										return
									end

									return timer.getTime() + 3
								end, {}, timer.getTime() + 3)
							end
						end

						if not skipRunnerContact and assignedGroupid and (Utils.isInAir(un) or dist > self.csarExtractDistance) then
							self.csarAssignedGroup[pid] = nil
							self.csarRouteIssued[pid] = nil
							assignedGroupid = nil
						end

						local skip = false
						if not skipRunnerContact and dist < self.csarApproachNear then
							anyNear = true
						end
						if dist >= self.csarApproachNear then
							local nextAllowed = self.csarNextTick[pid] or 0
							if now < nextAllowed then
								skip = true
							end
						end
						if not skip and not skipRunnerContact then
							if dist < self.csarApproachNear and not runnerStopped then
								approachMessage(pid, un, pilotObj)
							end							
							if dist < self.csarExtractDistance and not runnerStopped then
								closeMessage(pid, un, pilotObj)
							end
							if not Utils.isInAir(un) and dist < self.csarExtractDistance then
								if not assignedGroupid then
									self.csarAssignedGroup[pid] = groupid
									assignedGroupid = groupid
								end
								local runEta = self.csarRunEta[pid]
								if not runEta then
									runEta = {}
									self.csarRunEta[pid] = runEta
								end
								if not runEta[groupid] then
									local pilotData = landedPilotOwners[pid] or self.csarPilotDataByObject[pid] or ejectedPilotOwners[pid]
									local TGroup = L10N:ForGroup(groupid)
									local pilotName = (pilotData and pilotData.player and pilotData.player~='') and pilotData.player or TGroup:Get("CSAR_DOWNED_PILOT")
									local eta = math.floor((dist - self.csarLoadDistance) / 3.6)
									if eta < 0 then eta = 0 end
									runEta[groupid] = eta
									trigger.action.outTextForGroup(groupid, TGroup:Format("CSAR_COMING_TO_YOU_ETA", pilotName, eta), 10)
								end
								if self.csarRouteIssued[pid] ~= groupid then
									self.csarRouteIssued[pid] = groupid
									runPilotToHelo(pilotObj, un)
								end
							end
							if dist < self.csarLoadDistance then
								if boardPilot(pilotObj, un, groupid) then
									self.csarNextTick[pid] = nil
									table.remove(self.ejectedPilots, i)
									return
								end
							elseif Utils.isInAir(un) and dist <= guidanceTriggerDist then
								if boardPilot(pilotObj, un, groupid) then
									self.csarNextTick[pid] = nil
									table.remove(self.ejectedPilots, i)
									return
								end
							end
							local candidateNextTick
							if dist < self.csarLoadDistance then
								candidateNextTick = now + 1
							elseif Utils.isInAir(un) and dist <= guidanceTriggerDist then
								candidateNextTick = now + 1
							elseif dist < self.csarExtractDistance then
								candidateNextTick = now + 3
							elseif dist >= self.csarApproachNear then
								candidateNextTick = now + 10
							else
								candidateNextTick = now + 5
							end
							if candidateNextTick < bestNextTick then
								bestNextTick = candidateNextTick
							end
						end
					end
				end
				self.csarNextTick[pid] = bestNextTick
				if not anyNear then
					self.csarVisibleMsg[pid] = nil
					self.csarCloseMsg[pid] = nil
					self.csarRunEta[pid] = nil
					self.csarGuidanceStatus[pid] = nil
				end
			end
		end

		for i = #tocleanup, 1, -1 do
			self:_cleanupCsarPilotAtIndex(tocleanup[i].index, false)
		end
	end

playerZoneSpawn = {}
MissionsRootMenus = {}
printMissionMenus = {}

function LogisticCommander:init()
	local ev = {}
    ev.context = self
    function ev:onEvent(event)
		if event.id == 15 and event.initiator and event.initiator.getPlayerName then
            local player = event.initiator:getPlayerName()
            if player then
					local plist = net.get_player_list()
					local un = event.initiator
					local zn = BattleCommander:getZoneOfUnit(un:getName())
					local gr = un:getGroup()
					local groupId = gr:getID()
					local unitCat = Unit.getCategoryEx(un)
					local hasIllegalName = player:find("[\'/\\]")
					local playerLocale = L10N:GetPlayerLocale(player)

					if hasIllegalName then
						for i, v in pairs(plist) do
							if net.get_name(v) == player then
								net.send_chat_to(L10N:Get("PLAYER_ILLEGAL_NAME_CHARACTERS"), v)
								timer.scheduleFunction(function(param, time)
									net.force_player_slot(param, 0, '')
								end, v, timer.getTime() + 0.1)
								break
							end
						end
						if event.initiator and event.initiator:isExist() then
							event.initiator:destroy()
						end
						return
					end
					if PVE_Only and un:getCoalition() == 1 then
						for i, v in pairs(plist) do
							if net.get_name(v) == player then
								net.send_chat_to(L10N:Get("PVP_MODE_DISABLED_RED_SLOTS"), v)
								timer.scheduleFunction(function(param, time)
									net.force_player_slot(param, 0, '')
								end, v, timer.getTime() + 0.1)
								break
							end
						end
						if gr and gr:isExist() then
							trigger.action.outTextForGroup(gr:getID(), L10N:FormatForLocale(playerLocale, "PVP_MODE_DISABLED"), 5)
						end
						if event.initiator and event.initiator:isExist() then
							event.initiator:destroy()
						end
						return
					end
				local escortFarpSpawn = false
				if  Object.getCategory(un) == Object.Category.UNIT and
					(unitCat == Unit.Category.AIRPLANE or unitCat == Unit.Category.HELICOPTER) then
					if zn then
						local isDifferentSide = zn.side ~= un:getCoalition()
						
						if isDifferentSide and not zn.wasBlue and not zn.isHidden then
							for i, v in pairs(plist) do
								if net.get_name(v) == player then
									net.send_chat_to(L10N:Format("PVP_CANNOT_SPAWN_IN_ZONE", gr:getName()), v)
									timer.scheduleFunction(function(param, time)
										net.force_player_slot(param, 0, '')
									end, v, timer.getTime() + 0.1)
									break
								end
							end
							trigger.action.outTextForGroup(gr:getID(), L10N:FormatForLocale(playerLocale, "PVP_CANNOT_SPAWN_IN_ZONE", gr:getName()), 5)
							if event.initiator and event.initiator:isExist() then
								event.initiator:destroy()
							end
							return
						else
							if handleMission and unitCat == Unit.Category.HELICOPTER then
								timer.scheduleFunction(function()
									if gr and gr:isExist() then
										handleMission(zn.zone, gr:getName(), gr:getID(), gr)
									end
								end, {}, timer.getTime() + 30)
							end
							if unitCat == Unit.Category.AIRPLANE then
								if capMissionTarget ~= nil and capKillsByPlayer[player] then
									capKillsByPlayer[player] = 0
								end
							if un:getTypeName() ~= "A-10C_2" and un:getTypeName() ~= "Hercules" and un:getTypeName() ~= "A-10A" and un:getTypeName() ~= "AV8BNA"
							and un:getTypeName() ~= "C-130J-30" then
									playerZoneSpawn[player] = zn.zone
								end
							end
							if casMissionTarget ~= nil and casKillsByPlayer[player] then casKillsByPlayer[player] = 0 end
						end
					else
						zn=getEscortFarpZoneOfUnit(gr:getName())
						if zn then
							escortFarpSpawn = true
							if handleMission and unitCat == Unit.Category.HELICOPTER then
									timer.scheduleFunction(function()
									if gr and gr:isExist() then
										handleMission(zn.zone, gr:getName(), gr:getID(), gr)
									end
								end, {}, timer.getTime() + 30)
							end
						end
					end
				end

				RankSave = RankSave or {players={},version=1}
				RankSave.players = RankSave.players or {}
				RankSave.ucidToName = RankSave.ucidToName or {}
				local ucid = nil
				for i = 1, #plist do
					local pid = plist[i]
					if net.get_name(pid) == player then
						ucid = net.get_player_info(pid, 'ucid')
						break
					end
				end

				if ucid and ucid ~= "" then
					local oldName = RankSave.ucidToName[ucid]
					if oldName and oldName ~= player then
						if RankSave.players[oldName] and not RankSave.players[player] then
							RankSave.players[player] = RankSave.players[oldName]
							RankSave.players[oldName] = nil
						end
						if self.context.battleCommander.playerStats and self.context.battleCommander.playerStats[oldName] and not self.context.battleCommander.playerStats[player] then
							self.context.battleCommander.playerStats[player] = self.context.battleCommander.playerStats[oldName]
							self.context.battleCommander.playerStats[oldName] = nil
						end
					end
					RankSave.ucidToName[ucid] = player
				end
                local groupObj = gr
                local groupid = groupId
                local groupname = groupObj:getName()
                local desc = un:getDesc()
                local unitType = desc.typeName
				local playerCoalition = event.initiator:getCoalition()
				local savedLocale = L10N:GetPlayerLocale(player)
				local previousLocale = L10N:GetGroupLocale(groupid)
				if previousLocale ~= savedLocale then
					L10N:BindGroupLocale(groupid, player)
				end
				local T = L10N:ForGroup(groupid)
				if printMissionMenus[groupid] then
					self.context:pruneGroupMenus(groupid, groupname)
				end
				local groupMenuToken = self.context:_bumpGroupMenuToken(groupid)
				self.context.battleCommander.playerNames = self.context.battleCommander.playerNames or {}
                self.context.battleCommander.playerNames[groupid] = player
				self.context.battleCommander:refreshShopMenuForGroup(groupid, groupObj)
				self.context.battleCommander:buildZoneStatusMenuForGroup(groupid)
				timer.scheduleFunction(function()
					if buildCapControlMenu then
						buildCapControlMenu()
					end
				end, {}, timer.getTime() + 1)

				self.context.battleCommander.groupByPlayer = self.context.battleCommander.groupByPlayer or {}
				self.context.battleCommander.groupNameByPlayer = self.context.battleCommander.groupNameByPlayer or {}
				self.context.battleCommander.groupByPlayer[player] = groupid
				self.context.battleCommander.groupNameByPlayer[player] = groupname
				self.context.battleCommander:_jointRegisterMenuOwner(groupid, groupname, player, playerCoalition)


				if not self.context.statsMenus[groupid] then

					local statsMenu = missionCommands.addSubMenuForGroup(groupid, T:Get("STATS_MENU_ROOT"))
					local statsSubMenu = missionCommands.addSubMenuForGroup(groupid, T:Get("STATS_MENU_STATS"), statsMenu)
					missionCommands.addCommandForGroup(groupid, T:Get("STATS_MENU_MY_STATS"), statsSubMenu, self.context.battleCommander.printMyStats, self.context.battleCommander, event.initiator:getID(), player)
					missionCommands.addCommandForGroup(groupid, T:Get("STATS_MENU_ALL_STATS"), statsSubMenu, self.context.battleCommander.printStats, self.context.battleCommander, event.initiator:getID(), 10)
					missionCommands.addCommandForGroup(groupid, T:Get("STATS_MENU_TOP_5_PLAYERS"), statsSubMenu, self.context.battleCommander.printStats, self.context.battleCommander, event.initiator:getID(), 5)
					missionCommands.addCommandForGroup(groupid, T:Get("STATS_MENU_TOP_5_TODAY"), statsSubMenu, self.context.battleCommander.printDailyTop, self.context.battleCommander, event.initiator:getID(), 5)
					missionCommands.addCommandForGroup(groupid, T:Get("STATS_MENU_RANK_HELP"), statsSubMenu, self.context.battleCommander.printRankHelp, self.context.battleCommander, groupid)
					local languageMenu = missionCommands.addSubMenuForGroup(groupid, T:Get("LANGUAGE_MENU_SET"), statsMenu)
					self.context.languageMenus[groupid] = languageMenu
					for _, option in ipairs(FootholdLanguageOptions) do
						missionCommands.addCommandForGroup(groupid, option.label, languageMenu, function(args)
							local selectedLocale = L10N:SetPlayerLocale(args.player, args.locale)
							local selectedLabel = footholdLanguageLabel(selectedLocale)
							local message = L10N:FormatForLocale(selectedLocale, "LANGUAGE_SET_RESLOT", selectedLabel)
							trigger.action.outTextForGroup(args.groupid, message, 20)
						end, { player = player, groupid = groupid, locale = option.locale })
					end
					
					self.context.statsMenus[groupid] = statsMenu
				end
				if ewrs then
					EWRS_MENU_PARENT_BY_GROUP = EWRS_MENU_PARENT_BY_GROUP or {}
					EWRS_MENU_PARENT_BY_GROUP[tostring(groupid)] = self.context.statsMenus[groupid]
					if ewrs.builtF10Menus then
						local ewrsMenu = ewrs.builtF10Menus[tostring(groupid)]
						if ewrsMenu and ewrsMenu ~= true then
							if type(ewrsMenu) == "table" and ewrsMenu.root then
								missionCommands.removeItemForGroup(groupid, ewrsMenu.root)
							else
								missionCommands.removeItemForGroup(groupid, ewrsMenu)
							end
						end
						ewrs.builtF10Menus[tostring(groupid)] = nil
					end
				end
--[[ 				if MissionsRootMenus[groupid] then
					missionCommands.removeItemForGroup(groupid, MissionsRootMenus[groupid])
					MissionsRootMenus[groupid] = nil
				end
				printMissionMenus[groupid] = nil ]]

				local missionsRoot = MissionsRootMenus[groupid] or missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MISSIONS"))
				MissionsRootMenus[groupid] = missionsRoot
			if not printMissionMenus[groupid] then
				printMissionMenus[groupid] = missionCommands.addCommandForGroup(groupid, T:Get("MENU_MISSIONS"), missionsRoot, mc.printMissions, mc, groupid)
				mc:createStrikeMissionSubMenuForGroup(groupid, missionsRoot)
				mc:refreshStrikeMissionMenuForGroup(groupid)
				
				--SCHEDULER:New(nil, function()
				if self.context.groupMenuTokens[groupid] ~= groupMenuToken then return end
				self.context.battleCommander:refreshJointMenusForSide(playerCoalition)
				--end, {}, 1)


				if self.context.allowedTypes[unitType] then
					if not LogisticCommander.mooseLogisticsMenus[groupid] and not self.context.groupMenus[groupid] then
						self.context.carriedCargo[groupid] = 0
						self.context.carriedPilots[groupid] = 0

						local mooseMenu = LogisticCommander.mooseLogisticsMenus[groupid]
						if mooseMenu then
							if mooseMenu.Remove then
								mooseMenu:Remove()
							end
							LogisticCommander.mooseLogisticsMenus[groupid] = nil
						elseif self.context.groupMenus[groupid] then
							missionCommands.removeItemForGroup(groupid, self.context.groupMenus[groupid])
						end
							self.context.groupMenus[groupid] = nil
						if LogisticCommander.AllowedCsar[unitType] > 0 then
							local csar = missionCommands.addSubMenuForGroup(groupid, T:Get("CSAR_MENU"))
							self.context.csarGroupMenus[groupid] = csar
							missionCommands.addCommandForGroup(groupid, T:Get("CSAR_INFO_CLOSEST_PILOT"), csar, self.context.infoPilot, self.context, groupname)
							missionCommands.addCommandForGroup(groupid, T:Get("CSAR_INFO_THREE_CLOSEST_PILOTS"), csar, self.context.infoTopPilots, self.context, groupname, 3)
							missionCommands.addCommandForGroup(groupid, T:Get("CSAR_DEPLOY_SMOKE_CLOSEST"), csar, self.context.markPilot, self.context, groupname)
							missionCommands.addCommandForGroup(groupid, T:Get("CSAR_DEPLOY_FLARE_CLOSEST"), csar, self.context.flarePilot, self.context, groupname)
						missionCommands.addCommandForGroup(groupid, T:Get("CSAR_SMOKE_NEAREST_ZONE"), csar, function() Foothold_ctld:SmokeZoneNearBy(GROUP:FindByName(groupname):GetUnit(1), false) end)
						missionCommands.addCommandForGroup(groupid, T:Get("CSAR_FLARE_NEAREST_ZONE"), csar, function() Foothold_ctld:SmokeZoneNearBy(GROUP:FindByName(groupname):GetUnit(1), true) end)
						--missionCommands.addCommandForGroup(groupid, 'Pick up pilot', csar, self.context.loadPilot, self.context, groupname)
						--missionCommands.addCommandForGroup(groupid, 'Drop off pilot', csar, self.context.unloadPilot, self.context, groupname)
						--missionCommands.addCommandForGroup(groupid, 'Info on closest pilot with credits', csar, self.context.infoHumanPilot, self.context, groupname)
					else
						self.context.csarGroupMenus[groupid] = nil
					end
					SCHEDULER:New(nil, function()
						if self.context.groupMenuTokens[groupid] ~= groupMenuToken then return end
						local cargomenuObj = nil
						local mooseGroup = GROUP:FindByName(groupname)
						if mooseGroup and MENU_GROUP.New then
							cargomenuObj = MENU_GROUP:New(mooseGroup, T:Get("LOGISTICS_MENU"), nil)
							LogisticCommander.mooseLogisticsMenus[groupid] = cargomenuObj
						end
						local cargomenu = cargomenuObj and cargomenuObj.MenuPath or missionCommands.addSubMenuForGroup(groupid, T:Get("LOGISTICS_MENU"))
						if LogisticCommander.AllowedToCarrySupplies[unitType] and WarehouseLogistics == false then
							missionCommands.addCommandForGroup(groupid, T:Get("LOGISTICS_LOAD_SUPPLIES"), cargomenu, self.context.loadSupplies, self.context, groupname)
							if LogisticCommander.doubleSupplyTypes and LogisticCommander.doubleSupplyTypes[unitType] then
								missionCommands.addCommandForGroup(groupid, T:Format("LOGISTICS_LOAD_SUPPLIES_COUNT", 2), cargomenu, self.context.loadSupplies, self.context, groupname, 2)
							end
							missionCommands.addCommandForGroup(groupid, T:Get("LOGISTICS_UNLOAD_SUPPLIES"), cargomenu, self.context.unloadSupplies, self.context, groupname)
							missionCommands.addCommandForGroup(groupid, T:Get("LOGISTICS_LIST_SUPPLY_ZONES"), cargomenu, self.context.listSupplyZones, self.context, groupname)
							missionCommands.addCommandForGroup(groupid, T:Get("LOGISTICS_SUPPLIES_STATUS"), cargomenu, self.context.checkSuppliesStatus, self.context, groupid)
						end
                        -- Mirror CTLD static cargo menus under Logistics.

						if Foothold_ctld and Foothold_ctld.Cargo_Statics and WarehouseLogistics == true then
							missionCommands.addCommandForGroup(groupid, T:Get("LOGISTICS_SUPPLIES_HELP"), cargomenu, function()
								local txt = T:Get("LOGISTICS_OVERVIEW_HELP")
								trigger.action.outTextForGroup(groupid, txt, 45)
							end)
						
							self.context.staticMenus = self.context.staticMenus or {}
							self.context.staticMenus[groupid] = self.context.staticMenus[groupid] or {}
							local staticMenuPages = {}
							local crateStockSummary = nil
							if Foothold_ctld.showstockinmenuitems then
								crateStockSummary = Foothold_ctld:_CountStockPlusInHeloPlusAliveGroups(false)
							end
							local function getStaticCtldMenuLabel(label)
								return Foothold_ctld:GetFootholdLocalizedCargoLabel(T, label)
							end
                            local function ensureStaticSubMenu(label)
                                if self.context.staticMenus[groupid][label] then
                                    return self.context.staticMenus[groupid][label]
                                end
								local menuLabel = getStaticCtldMenuLabel(label)
                                local handle
                                if cargomenuObj then
                                    handle = MENU_GROUP:New(mooseGroup, menuLabel, cargomenuObj)
                                else
                                    handle = missionCommands.addSubMenuForGroup(groupid, menuLabel, cargomenu)
                                end
                                self.context.staticMenus[groupid][label] = handle
                                return handle
                            end

							local function getPagedStaticMenu(label)
								local state = staticMenuPages[label]
								if not state then
									state = { current = ensureStaticSubMenu(label), count = 0 }
									staticMenuPages[label] = state
								end
								if state.count >= 9 then
									local nextHandle
									if cargomenuObj then
										nextHandle = MENU_GROUP:New(mooseGroup, T:Get("MENU_MORE"), state.current)
									else
										nextHandle = missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MORE"), state.current)
									end
									state.current = nextHandle
									state.count = 0
								end
								state.count = state.count + 1
								return state.current
							end

                            local function unitCanCarryStatic(cargoObj)
                                if not cargoObj or not cargoObj.UnitCanCarry then
                                    return true
                                end
                                local unitRef = mooseGroup and mooseGroup:GetUnit(1)
                                return unitRef and cargoObj:UnitCanCarry(unitRef) or false
                            end

                            local function addStaticCommand(cargoObj)
                                if not unitCanCarryStatic(cargoObj) then return end
								local parentMenu = getPagedStaticMenu(cargoObj.Subcategory or "Statics")
                                local needed = cargoObj:GetCratesNeeded() or 1
                                local mass = cargoObj.PerCrateMass or 0
                                local cargoLabel = cargoObj.Name
                                if cargoObj.GetDisplayName then
                                    local displayName = cargoObj:GetDisplayName()
                                    if displayName and displayName ~= "" then
                                        cargoLabel = displayName
                                    end
                                end
                                cargoLabel = getStaticCtldMenuLabel(cargoLabel)
                                local title
                                if needed > 1 then
                                    local plural = Foothold_ctld:_GetMenuPluralSuffix(needed, "crate", mooseGroup)
                                    title = string.format(Foothold_ctld:_GetEntryForGroup("MENU_CRATES_NEEDED", mooseGroup),needed,plural,cargoLabel,mass)
                                else
                                    title = string.format(Foothold_ctld:_GetEntryForGroup("MENU_CRATE_SINGLE", mooseGroup),cargoLabel,mass)
                                end
                                if cargoObj.Location then title = title.."[R]" end
                                if Foothold_ctld.showstockinmenuitems then
                                    local suffix = Foothold_ctld:_FormatCrateStockSuffix(cargoObj,crateStockSummary)
                                    if suffix then title = title..suffix end
                                end
                                if cargomenuObj then
                                    local unitRef = mooseGroup and mooseGroup:GetUnit(1)
                                    if unitRef then
                                        local mSet = MENU_GROUP:New(mooseGroup, title, parentMenu)
                                        Foothold_ctld:_AddCrateQuantityMenus(mooseGroup, unitRef, mSet, cargoObj, crateStockSummary)
                                    end
                                else
                                    local function handler()
                                        local unitRef = mooseGroup and mooseGroup:GetUnit(1)
                                        if unitRef then
                                            Foothold_ctld:_GetCrates(mooseGroup, unitRef, cargoObj, cargoObj:GetCratesNeeded())
                                        end
                                    end
                                    missionCommands.addCommandForGroup(groupid, title, parentMenu, handler)
                                end
                            end

							for _, cargoObj in pairs(Foothold_ctld.Cargo_Statics) do
								if cargoObj then
									addStaticCommand(cargoObj)
								end
							end
							
                        end
						local main = missionCommands.addSubMenuForGroup(groupid, T:Get("LOGISTICS_MARK_ZONE"), cargomenu)
						local sub1
						for i, v in ipairs(self.context.battleCommander.zones) do
							if i < 10 then
								missionCommands.addCommandForGroup(groupid, v.zone, main, v.markWithSmoke, v, event.initiator:getCoalition())
							elseif i == 10 then
								sub1 = missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MORE"), main)
								missionCommands.addCommandForGroup(groupid, v.zone, sub1, v.markWithSmoke, v, event.initiator:getCoalition())
							elseif i % 9 == 1 then
								sub1 = missionCommands.addSubMenuForGroup(groupid, T:Get("MENU_MORE"), sub1)
								missionCommands.addCommandForGroup(groupid, v.zone, sub1, v.markWithSmoke, v, event.initiator:getCoalition())
							else
								missionCommands.addCommandForGroup(groupid, v.zone, sub1, v.markWithSmoke, v, event.initiator:getCoalition())
							end
						end
						
						self.context.groupMenus[groupid] = cargomenu
						self.context.groupIdToName[groupid] = groupname
						self.context.csarGroups[groupid] = { name = groupname, player = player }
						if self.context.csarSet and self.context.csarSet.AddGroup then
							local mg = GROUP:FindByName(groupname)
							if mg then self.context.csarSet:AddGroup(mg) end
						end
						self.context.carriedCargo[groupid] = nil
					end, {}, 0.5)
				  end
				end
				local unitNameForMoose = un:getName()
				local zoneNameForMoose = nil
				if not escortFarpSpawn and zn then
					zoneNameForMoose = zn.zone
				end
				SCHEDULER:New(nil, function()
					if self.context.groupMenuTokens[groupid] ~= groupMenuToken then return end
					local mooseUnit = UNIT:FindByName(unitNameForMoose)
					if mooseUnit and mooseUnit:IsAlive() then
						static:processPlayerSpawn(mooseUnit, zoneNameForMoose)
					end
				end, {}, 0.5)
				local stats = SelfJtac.getAircraftStats(desc.typeName)
                if stats then
                    if SelfJtac.jtacs[groupid] then
                        local oldjtac = SelfJtac.jtacs[groupid]
                        oldjtac:clearTarget()
                        missionCommands.removeItemForGroup(groupid, oldjtac.jtacMenu)
                        SelfJtac.jtacs[groupid] = nil
                    end

                    if not SelfJtac.jtacs[groupid] then
                        local newjtac = SelfJtac:new({name = groupname, playerName = player})
                        newjtac:showMenu()
                        SelfJtac.jtacs[groupid] = newjtac
                    end
                end
			end
        end
	end

        if event.id == world.event.S_EVENT_TAKEOFF
           and event.initiator and event.initiator.getPlayerName
        then
            local groupid = event.initiator:getGroup():getID()
            local unitType = event.initiator:getDesc()['typeName']
            local player = event.initiator:getPlayerName()
			local bc = self.context.battleCommander
			if player then
				if CreditLosewhenKilled == true or RankLoseWhenKilled == true then
					bc.lossPenaltyArmByPlayer = bc.lossPenaltyArmByPlayer or {}
					bc.lossPenaltyArmByPlayer[player] = true
				end
                if RewardFlightTime and (RewardAllAircraft == true or LogisticCommander.AllowedFlightTimeReward[unitType]) then
                    bc.flightTimeTakeoffByPlayer = bc.flightTimeTakeoffByPlayer or {}
                    local ft = bc.flightTimeTakeoffByPlayer[player]
                    if not ft or ft.gid ~= groupid then
                        bc.flightTimeTakeoffByPlayer[player] = { t = timer.getTime(), gid = groupid }
                    end
                end
            end

            if WarehouseLogistics == false then
                local un = event.initiator
                local zn = self.context.battleCommander:getZoneOfUnit(un:getName())

                if zn and (zn.side == un:getCoalition() or (un:getCoalition() == 2 and zn.wasBlue)) then
                    for _, v in ipairs(self.context.supplyZones) do
                        if v == zn.zone then
                            if self.context.AllowedToCarrySupplies[unitType] and not self.context.carriedCargo[groupid] then
                                trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "LOGISTICS_WARNING_NOT_LOADED"), 30,true)
                                if trigger.misc.getUserFlag(180) == 0 then
                                    trigger.action.outSoundForGroup(groupid, "micclick.ogg")
                                end
                            end
                            return
                        end
                    end
                else
                    local group = GROUP:FindByName(un:getGroup():getName())
                    if group and un:getCoalition() == 2 then
                        for _, zName in ipairs(self.context.supplyZones) do
                            if string.find(zName, "CTLD FARP") or string.find(zName, "Escort Mission FARP") then
                                local zObj = ZONE:FindByName(zName)
                                if zObj and group:IsInZone(zObj) then
                                    if self.context.allowedTypes[unitType] and not self.context.carriedCargo[groupid] then
                                        trigger.action.outTextForGroup(groupid, L10N:GetForGroup(groupid, "LOGISTICS_WARNING_NOT_LOADED"), 30,true)
                                        if trigger.misc.getUserFlag(180) == 0 then
                                            trigger.action.outSoundForGroup(groupid, "micclick.ogg")
                                        end
                                    end
                                    return
                                end
                            end
                        end
                    end
                end
            end
        end


		if event.id==world.event.S_EVENT_LANDING_AFTER_EJECTION then
			local aircraftID=event.place and event.place.id_
			local coalitionSide = event.initiator:getCoalition()
			local pilotObjectID=event.initiator and event.initiator:getObjectID()
			local hostileEnemyMessageAt = nil
			local hostileSpawnedGroupNames = {}
			ejectedPilotOwnersByAircraft = ejectedPilotOwnersByAircraft or {}
			local list = aircraftID and ejectedPilotOwnersByAircraft[aircraftID]
			local pilotData = list and table.remove(list,1) or nil
			if list and #list == 0 then ejectedPilotOwnersByAircraft[aircraftID] = nil end

			self.context.csarPilotProcessedByAircraft = self.context.csarPilotProcessedByAircraft or {}
			local processed = aircraftID and (self.context.csarPilotProcessedByAircraft[aircraftID] or 0) or 0
			if pilotData then
				processed = processed + 1
				if aircraftID then self.context.csarPilotProcessedByAircraft[aircraftID] = processed end
			end

			
			local function pointInActiveZone(obj)
				if not obj then return nil end
				local bc = self.context and self.context.battleCommander
				for _, z in ipairs(bc.zones) do
					if z.active and z.side and z.side ~= 0 and z.zone then
						if Utils.isInZone(obj, z.zone) then
							return z.side, z.zone
						end
					end
				end
				return nil
			end

			if coalitionSide == coalition.side.RED then
				event.initiator:destroy()
				return
			end

			local zoneSide, zoneName = pointInActiveZone(event.initiator)
			if zoneSide and pilotData and pilotData.player and pilotData.player ~= '' and pilotData.coalition and zoneSide ~= pilotData.coalition then
				pilotData.hostileZoneName = zoneName
				pilotData.hostileGraceUntil = timer.getTime() + 60
			elseif zoneSide then
				if pilotData and pilotData.player and pilotData.player ~= '' then
					if pilotData.coalition and zoneSide ~= pilotData.coalition then
						self.context.battleCommander:addStat(pilotData.player,'Captured by enemy',1)
						trigger.action.outTextForCoalition(2,L10N:Format("CSAR_PLAYER_CAPTURED", pilotData.player, zoneName),10)
					else
						local side = pilotData.coalition or zoneSide or 2
						local restored = tonumber(pilotData.lostCredits) or 0
						self.context.battleCommander:addStat(pilotData.player,'Deaths',-1)
						if restored > 0 then
							self.context.battleCommander:addFunds(side, restored)
							self.context.battleCommander:addStat(pilotData.player,'Points', restored)
							pilotData.lostCredits = 0
						end
						local toprint = L10N:Format("CSAR_PLAYER_LANDED_SAFELY", pilotData.player, zoneName)
						if restored > 0 then
							toprint = L10N:Format("CSAR_PLAYER_LANDED_RECOVERED_CREDITS", pilotData.player, zoneName, tostring(restored))
						end
						trigger.action.outTextForCoalition(side, toprint, 10)
					end
				end
				landedPilotOwners[pilotObjectID]=nil
				event.initiator:destroy()
				return
			end

			if not pilotData then
				local spawnChance = LogisticCommander.CsarPilotSpawnWithoutCreditsChance or 50
				if spawnChance < 0 then spawnChance = 0 end
				if spawnChance > 100 then spawnChance = 100 end
				if spawnChance <= 0 or math.random(100) > spawnChance then
					landedPilotOwners[pilotObjectID]=nil
					if event.initiator and event.initiator:isExist() then
						event.initiator:destroy()
					end
					return
				end
			end

			local downedCoalition = (pilotData and pilotData.coalition) or coalitionSide
			if (not zoneSide) and downedCoalition then
				local templateKey = nil
				if LogisticCommander.csarHostileInfantryDistanceByTemplate then
					local n = 0
					for k in pairs(LogisticCommander.csarHostileInfantryDistanceByTemplate) do
						n = n + 1
						if math.random(n) == 1 then templateKey = k end
					end
				end
				if templateKey and templateKey ~= '' then
					local chance = LogisticCommander.csarHostileInfantryChance or 20
					if chance > 0 and math.random(100) <= chance then
						local coord = event.initiator:getPoint()
						local surfaceType = land.getSurfaceType({ x = coord.x, y = coord.z })
						local overWater = (surfaceType == land.SurfaceType.WATER) or (surfaceType == land.SurfaceType.SHALLOW_WATER)
						if not overWater then
							local range = 20*NM
							local limitSq = range*range
							local bc = self.context.battleCommander
							local inRange = false
							for _, z in ipairs(bc.zones) do
								if z.active and z.side and z.side ~= 0 and z.side ~= downedCoalition and z.zone then
									local c = getZoneCenter(z.zone)
									if c then
										local dx = coord.x - c.x
										local dz = coord.z - c.y
										if (dx*dx + dz*dz) <= limitSq then
											inRange = true
											break
										end
									end
								end
							end
							if inRange then
								local pilotCoord = COORDINATE:NewFromVec3(coord)
								local templateConfig = LogisticCommander.csarHostileInfantryDistanceByTemplate and LogisticCommander.csarHostileInfantryDistanceByTemplate[templateKey]
								if type(templateConfig) == 'function' then
									templateConfig = templateConfig(templateKey, pilotData, event)
								end
								local minDist = (LogisticCommander.csarHostileInfantryMinDistanceNM or 1) * NM
								local maxDist = (LogisticCommander.csarHostileInfantryMaxDistanceNM or 2) * NM
								local spawnCount = (LogisticCommander.csarHostileInfantrySpawnCount or 1)
								if templateConfig then
									if type(templateConfig) == 'number' then
										minDist = templateConfig * NM
										maxDist = minDist
									else
										if templateConfig.count ~= nil then
											local c = templateConfig.count
											if type(c) == 'function' then
												c = c(templateKey, pilotData, event)
											end
											if type(c) == 'table' then
												local cmin = c.min or c.minCount or c[1]
												local cmax = c.max or c.maxCount or c[2]
												if tonumber(cmin) and tonumber(cmax) then
													local a = math.floor(tonumber(cmin))
													local b = math.floor(tonumber(cmax))
													if a > b then a, b = b, a end
													spawnCount = math.max(1, math.random(a, b))
												end
											elseif tonumber(c) then
												spawnCount = math.max(1, math.floor(tonumber(c)))
											end
										end
										if templateConfig.nm then
											minDist = templateConfig.nm * NM
											maxDist = minDist
										else
											if templateConfig.minNM then minDist = templateConfig.minNM * NM end
											if templateConfig.maxNM then maxDist = templateConfig.maxNM * NM else maxDist = minDist end
										end
									end
								end

								local function pickTemplateName()
									if type(templateConfig) == 'table' then
										local list = templateConfig.templates or templateConfig.groups
										if type(list) == 'table' and #list > 0 then
											return list[math.random(#list)]
										end
										if #templateConfig > 0 then
											return templateConfig[math.random(#templateConfig)]
										end
									end
									return templateKey
								end

								local baseHeading = math.random(0, 359)
								local stepDeg = (spawnCount > 0) and (360 / spawnCount) or 180
								local aliasBase = "FOOTHOLD_CSAR_REDINF_"..tostring(aircraftID or math.random(1000,9999)).."_"..tostring(pilotObjectID or math.random(1000,9999))
								local anySpawned = false
								for i = 1, spawnCount do
									local heading = (baseHeading + ((i - 1) * stepDeg)) % 360
									local spawnDist = minDist + ((maxDist - minDist) * math.random())
									local spawnCoord = pilotCoord:Translate(spawnDist, heading, true)
									local spawnVec2 = spawnCoord and spawnCoord.GetVec2 and spawnCoord:GetVec2() or nil
									local spawnSurface = spawnVec2 and land.getSurfaceType(spawnVec2) or nil
									local spawnOverWater = (spawnSurface == land.SurfaceType.WATER) or (spawnSurface == land.SurfaceType.SHALLOW_WATER)
									if not spawnOverWater then
										local templateName = pickTemplateName()
										if templateName and templateName ~= '' then
											local alias = aliasBase.."_"..tostring(i).."_"..tostring(math.random(1000,9999))
											local spawned = SPAWN:NewWithAlias(templateName, alias):InitCoalition(coalition.side.RED):InitValidateAndRepositionGroundUnits(true):SpawnFromPointVec3(spawnCoord)
											if spawned then
												anySpawned = true
												local spawnedGroupName = alias
												if spawned.GetName then
													local resolvedName = spawned:GetName()
													if resolvedName and resolvedName ~= '' then
														spawnedGroupName = resolvedName
													end
												end
												self.context:_appendUniqueCsarHostileGroup(hostileSpawnedGroupNames, spawnedGroupName)
											end
										end
									end
								end
								if anySpawned then
									local msgAt = timer.getTime() + 120
									if pilotData then
										pilotData.hostileEnemyMessageAt = msgAt
									else
										hostileEnemyMessageAt = msgAt
									end
								end
							end
						end
					end
				end
			end
			self.context.csarPilotByAircraft = self.context.csarPilotByAircraft or {}
			local existingPilot = aircraftID and self.context.csarPilotByAircraft[aircraftID]
			local isPlayerAircraft = aircraftID and self.context.csarPlayerAircraftByAircraft and self.context.csarPlayerAircraftByAircraft[aircraftID]
			if not pilotData and not isPlayerAircraft and existingPilot and existingPilot:isExist() then
				landedPilotOwners[pilotObjectID]=nil
				if event.initiator and event.initiator:isExist() then
					event.initiator:destroy()
				end
				return
			end

			local function isWaterPoint(point)
				if not point then return true end
				local surfaceType = land.getSurfaceType({ x = point.x, y = point.z })
				return (surfaceType == land.SurfaceType.WATER) or (surfaceType == land.SurfaceType.SHALLOW_WATER)
			end

			local function addPilotToCsarQueues(pilotObj)
				self.context:_addPilotToCsarQueues(pilotObj)
			end

			local function bindPilotDataToObject(objectID, data)
				self.context:_bindPilotDataToObject(objectID, data)
			end

			local function chooseMainPilotSpawnPoint()
				local fallbackPoint = event.initiator and event.initiator:getPoint()
				local anchorPoint = nil
				if event.place and event.place.getPoint and ((not event.place.isExist) or event.place:isExist()) then
					anchorPoint = event.place:getPoint()
				end
				anchorPoint = anchorPoint or fallbackPoint
				if not anchorPoint then return nil, nil end

				local preferredHeading = nil
				if anchorPoint and fallbackPoint then
					local dx = fallbackPoint.x - anchorPoint.x
					local dz = fallbackPoint.z - anchorPoint.z
					if (dx*dx + dz*dz) > 1 then
						preferredHeading = COORDINATE:NewFromVec3(anchorPoint):HeadingTo(COORDINATE:NewFromVec3(fallbackPoint))
					end
				end

				local baseHeading = preferredHeading or 0
				local headingCandidates = {
					baseHeading,
					(baseHeading + 45) % 360,
					(baseHeading + 315) % 360,
					(baseHeading + 90) % 360,
					(baseHeading + 270) % 360,
					(baseHeading + 135) % 360,
					(baseHeading + 225) % 360,
					(baseHeading + 180) % 360,
				}
				local anchorCoord = COORDINATE:NewFromVec3(anchorPoint)
				for _, heading in ipairs(headingCandidates) do
					local candidateCoord = anchorCoord:Translate(10, heading, true)
					local candidatePoint = candidateCoord and candidateCoord.GetVec3 and candidateCoord:GetVec3() or nil
					if candidatePoint and not isWaterPoint(candidatePoint) then
						return candidatePoint, preferredHeading
					end
				end
				return anchorPoint, preferredHeading
			end

			local function spawnDownedPilot(spawnPoint, aliasSuffix, spawnCoalition)
				local templateName = "Downed Pilot"
				local coord = spawnPoint or (event.initiator and event.initiator:getPoint())
				if not coord then return nil end
				local spawnCoord = COORDINATE:NewFromVec3(coord)
				if not spawnCoord then return nil end
				local alias = "FOOTHOLD_CSAR_"..tostring(aircraftID or math.random(1000,9999)).."_"..tostring(pilotObjectID or math.random(1000,9999))
				if aliasSuffix and aliasSuffix ~= '' then
					alias = alias.."_"..aliasSuffix
				end
				local sp = SPAWN:NewWithAlias(templateName, alias)
				if sp.InitCoalition then
					sp = sp:InitCoalition(spawnCoalition or coalitionSide)
				end
				local spawned = sp:SpawnFromPointVec3(spawnCoord)
				if not spawned then return nil end
				local unitWrapper = spawned:GetUnit(1)
				env.info('[FOOTHOLD CSAR] Spawned downed pilot '..tostring(alias or nil))
				return unitWrapper and unitWrapper:GetDCSObject() or nil	
			end

			local mainSpawnPoint, passengerHeadingBase = chooseMainPilotSpawnPoint()
			local newPilotObj = spawnDownedPilot(mainSpawnPoint)
			local pilotObj = newPilotObj or event.initiator
			local newObjectID = pilotObj and pilotObj:getObjectID()
			self.context:_bindCsarHostilesToPilot(pilotObjectID, pilotData, hostileSpawnedGroupNames)
			if newObjectID and newObjectID ~= pilotObjectID then
				self.context:_bindCsarHostilesToPilot(newObjectID, pilotData, hostileSpawnedGroupNames)
			end
			local carriedRescuedPilots = pilotData and pilotData.carriedRescuedPilots or nil
			if pilotData then
				pilotData.carriedRescuedPilots = nil
			end
			if pilotData then
				if pilotObjectID then bindPilotDataToObject(pilotObjectID, pilotData) end
				if newObjectID and newObjectID ~= pilotObjectID then
					bindPilotDataToObject(newObjectID, pilotData)
				end
				if pilotData.hostileEnemyMessageAt and pilotObj then
					local delay = pilotData.hostileEnemyMessageAt - timer.getTime()
					if delay < 0 then delay = 0 end
					local playerName = pilotData.player
					SCHEDULER:New(nil,function()
						if pilotObj and pilotObj:isExist() then
							trigger.action.outTextForCoalition(2,(playerName and playerName ~= '' and L10N:Format("CSAR_ENEMY_SURROUNDED_PLAYER", playerName) or L10N:Get("CSAR_ENEMY_SURROUNDED_PILOT")),10)
						end
					end,{},delay,0)
					pilotData.hostileEnemyMessageAt = nil
				end
			else
				if hostileEnemyMessageAt and pilotObj then
					local delay = hostileEnemyMessageAt - timer.getTime()
					if delay < 0 then delay = 0 end
					SCHEDULER:New(nil,function()
						if pilotObj and pilotObj:isExist() then
							trigger.action.outTextForCoalition(2,L10N:Get("CSAR_ENEMY_SURROUNDED_PILOT"),10)
						end
					end,{},delay,0)
					hostileEnemyMessageAt = nil
				end
			end


			if aircraftID and not pilotData then
				self.context.csarPilotByAircraft[aircraftID] = pilotObj
				processed = processed + 1
				self.context.csarPilotProcessedByAircraft[aircraftID] = processed
			end

			addPilotToCsarQueues(pilotObj)
			self.context:_startCsarHomeForPilot(pilotObj, pilotData, zoneSide, zoneName)
			if carriedRescuedPilots and #carriedRescuedPilots > 0 and pilotObj and pilotObj:isExist() then
				local mainPilotPoint = pilotObj:getPoint()
				if mainPilotPoint then
					local mainPilotCoord = COORDINATE:NewFromVec3(mainPilotPoint)
					local passengerCount = #carriedRescuedPilots
					local passengerBaseHeading = passengerHeadingBase or 0
					for i, passengerData in ipairs(carriedRescuedPilots) do
						local passengerRadius = math.min(5, 2 + i)
						local passengerHeading = (passengerBaseHeading + ((i - 1) * (360 / passengerCount))) % 360
						local passengerCoord = mainPilotCoord:Translate(passengerRadius, passengerHeading, true)
						local passengerPoint = passengerCoord and passengerCoord.GetVec3 and passengerCoord:GetVec3() or mainPilotPoint
						if isWaterPoint(passengerPoint) then
							passengerPoint = mainPilotPoint
						end
						local passengerObj = spawnDownedPilot(
							passengerPoint,
							"carried_"..tostring(i).."_"..tostring(math.random(1000,9999)),
							(passengerData and passengerData.coalition) or coalitionSide
						)
						if passengerObj then
							local passengerObjectID = passengerObj:getObjectID()
							if passengerObjectID and passengerData then
								bindPilotDataToObject(passengerObjectID, passengerData)
							end
							addPilotToCsarQueues(passengerObj)
							self.context:_startCsarHomeForPilot(passengerObj, passengerData, zoneSide, zoneName)
						end
					end
				end
			end

			if newPilotObj and event.initiator and event.initiator:isExist() then
				event.initiator:destroy()
			end
		end
    end
    world.addEventHandler(ev)
	SCHEDULER:New(nil,function(context) context:_restorePendingCsarPilots() end,{self},1,0)
	SCHEDULER:New(nil,self.update,{self},10,10)
end


function LogisticCommander:checkSuppliesStatus(groupid)
	local T = L10N:ForGroup(groupid)
	local cargo = self.carriedCargo[groupid]
	if cargo then
			local count = type(cargo) == "table" and cargo.count or 1
		if count and count > 1 then
			trigger.action.outTextForGroup(groupid, T:Format("LOGISTICS_SUPPLIES_LOADED_COUNT_CAP", count), 10)
		else
			trigger.action.outTextForGroup(groupid, T:Get("LOGISTICS_SUPPLIES_LOADED"), 10)
		end
	else
		trigger.action.outTextForGroup(groupid, T:Get("LOGISTICS_SUPPLIES_NOT_LOADED"), 10)
	end
end

MissionCommander = {}
do
    function MissionCommander:new(obj)
        obj = obj or {}
        obj.missions = {}
        obj.missionsType = {}
        obj.missionFlags = {}
		obj.autoArtyTrackedGroups = obj.autoArtyTrackedGroups or {}
		obj.strikeMenuByGroup = obj.strikeMenuByGroup or {}
		obj.intelMenuByGroup = obj.intelMenuByGroup or {}
        if obj.checkFrequency then
            obj.checkFrequency = 15
        end
        setmetatable(obj, self)
        self.__index = self
		obj:autoTrackArtyMissions()
        return obj
    end

	function MissionCommander:autoTrackArtyMissions()
		for _, zoneObj in ipairs(self.battleCommander.zones) do
			for _, gc in ipairs(zoneObj.groups or {}) do
				if gc and gc.mission == 'attack' and gc.type == 'surface' and gc.MissionType == 'ARTY' then
						local groupName = tostring(gc.name or '')
						if groupName ~= '' and not self.autoArtyTrackedGroups[groupName] then
						local originZoneName = tostring(gc.zoneCommander.zone or '')
						local targetZoneName = tostring(gc.targetzone or '')
						local reward = gc.Reward or 250
						local statName = L10N:Get("MISSION_ARTY_TITLE")

						self:trackMission({
							_autoArtyGroup = groupName,
							title = statName,
							description = L10N:Format("MISSION_ARTY_DESCRIPTION", originZoneName, targetZoneName),
							messageStart = L10N:Format("MISSION_ARTY_START", targetZoneName),
							messageEnd = L10N:Get("MISSION_ARTY_END"),
							startAction = function()
								if not missionCompleted and trigger.misc.getUserFlag(180) == 0 then
									trigger.action.outSoundForCoalition(2, "ding.ogg")
								end
								RegisterGroupTarget(groupName, reward, statName, groupName)
							end,
							endAction = function()
								if not missionCompleted and trigger.misc.getUserFlag(180) == 0 then
									trigger.action.outSoundForCoalition(2, "ding.ogg")
								end
							end,
							isActive = function()
								if not ActiveMission[groupName] then return false end
								if Group.getByName(groupName) then return true end
								ActiveMission[groupName] = nil
								return false
							end
						})

						self.autoArtyTrackedGroups[groupName] = true
					end
				end
			end
		end
	end

	function MissionCommander:decodeMessage(param, translator)
		if type(param) == "function" then
			return param(translator)
		elseif type(param) == "string" then
			return param
		end
	end

	function MissionCommander:getMissionFlagName(mission)
		if not mission then return nil end
		return mission.customFlagName or mission.flagName or mission.flag
	end

	function MissionCommander:inferStrikeFlagForMission(mission)
		if not mission or mission.customFlagName or not mission.isRunning then return mission and mission.customFlagName or nil end
		if type(mission.isActive) ~= 'function' then return nil end

		local strikeFlags = {}
		for flagName, isActive in pairs(ActiveMission or {}) do
			local meta = MissionFlagMetadata and MissionFlagMetadata[flagName]
			if isActive and meta and meta.isStrike == true then
				strikeFlags[#strikeFlags + 1] = flagName
			end
		end
		if #strikeFlags == 0 then return nil end

		local okRunning, isRunningNow = pcall(function() return mission:isActive() end)
		if not okRunning or not isRunningNow then return nil end

		for _, flagName in ipairs(strikeFlags) do
			local oldValue = ActiveMission[flagName]
			ActiveMission[flagName] = nil
			local okWithout, stillActiveWithout = pcall(function() return mission:isActive() end)
			ActiveMission[flagName] = oldValue
			if okWithout and not stillActiveWithout then
				mission.customFlagName = flagName
				return flagName
			end
		end

		return nil
	end

	function MissionCommander:isStrikeMission(mission)
		local flagName = self:getMissionFlagName(mission)
		if not flagName then
			flagName = self:inferStrikeFlagForMission(mission)
		end
		if not flagName then return false end
		local meta = MissionFlagMetadata and MissionFlagMetadata[flagName]
		return meta and meta.isStrike == true or false
	end

	function MissionCommander:getActiveStrikeMissions()
		local list = {}
		for _, mission in ipairs(self.missions) do
			if mission.isRunning and self:isStrikeMission(mission) then
				table.insert(list, mission)
			end
		end
		return list
	end

	function MissionCommander:_missionToText(mission, titleField, translator)
		local T = translator or L10N
		local rawTitle = self:decodeMessage(mission and mission[titleField or 'title'], T) or self:decodeMessage(mission and mission.title, T) or T:Get("MISSION_DEFAULT_TITLE")
		local rawDescription = self:decodeMessage(mission and mission.description, T) or T:Get("MISSION_DEFAULT_DESCRIPTION")
		return '[' .. rawTitle .. ']\n' .. rawDescription .. '\n------------------------------------------------'
	end

	function MissionCommander:_printMissionText(groupId, output, groupDuration, coalitionDuration)
		if groupId then
			trigger.action.outTextForGroup(groupId, output, groupDuration or 30)
		else
			trigger.action.outTextForCoalition(2, output, coalitionDuration or 10)
		end
	end

	function MissionCommander:printSingleMission(groupId, mission)
		local T = groupId and L10N:ForGroup(groupId) or L10N
		if not mission or not mission.isRunning then
			self:_printMissionText(groupId, T:Get("MISSION_STRIKE_EXPIRED"), 12, 8)
			return
		end
		local output = T:Get("MISSION_ACTIVE_HEADER") .. '\n------------------------------------------------\n'
		output = output .. self:_missionToText(mission, 'title', T)
		self:_printMissionText(groupId, output, 30, 10)
	end

	function MissionCommander:_buildStrikeMenuSignature(activeStrikeMissions)
		local keys = {}
		for idx, mission in ipairs(activeStrikeMissions or {}) do
			keys[#keys + 1] = self:getMissionFlagName(mission) or tostring(idx)
		end
		table.sort(keys)
		return table.concat(keys, '|')
	end

	function MissionCommander:createStrikeMissionSubMenuForGroup(groupId, parent)
		if not parent then return end
		local T = L10N:ForGroup(groupId)
		self.strikeMenuByGroup = self.strikeMenuByGroup or {}
		local state = self.strikeMenuByGroup[groupId]
		if state and state.root then
			return state.root
		end
		local root = missionCommands.addSubMenuForGroup(groupId, T:Get("MISSION_STRIKE_MENU"), parent)
		self.strikeMenuByGroup[groupId] = {
			root = root,
			items = {},
			signature = nil
		}
		return root
	end

	function MissionCommander:refreshStrikeMissionMenuForGroup(groupId, force)
		local T = L10N:ForGroup(groupId)
		self.strikeMenuByGroup = self.strikeMenuByGroup or {}
		local state = self.strikeMenuByGroup[groupId]
		if not state or not state.root then return end

		local active = self:getActiveStrikeMissions()
		local signature = self:_buildStrikeMenuSignature(active)
		if not force and state.signature == signature then
			return
		end

		if state.items then
			for _, item in ipairs(state.items) do
				missionCommands.removeItemForGroup(groupId, item)
			end
		end
		state.items = {}
		state.signature = signature

		if #active == 0 then
			local emptyItem = missionCommands.addCommandForGroup(groupId, T:Get("MISSION_STRIKE_NONE"), state.root, function()
				trigger.action.outTextForGroup(groupId, T:Get("MISSION_STRIKE_NONE_MESSAGE"), 10)
			end)
			state.items[#state.items + 1] = emptyItem
			return
		end

		local titleCount = {}
		for _, mission in ipairs(active) do
			local title = self:decodeMessage(mission.title, T) or T:Get("MISSION_STRIKE_DEFAULT_TITLE")
			titleCount[title] = (titleCount[title] or 0) + 1
		end

		for idx, mission in ipairs(active) do
			local title = self:decodeMessage(mission.title, T) or T:Get("MISSION_STRIKE_DEFAULT_TITLE")
			local label = title
			if titleCount[title] and titleCount[title] > 1 then
				local flagName = self:getMissionFlagName(mission) or tostring(idx)
				label = title .. ' [' .. flagName .. ']'
			end
			local missionRef = mission
			local item = missionCommands.addCommandForGroup(groupId, label, state.root, function()
				if not missionRef.isRunning then
					trigger.action.outTextForGroup(groupId, T:Get("MISSION_STRIKE_EXPIRED"), 12)
					self:refreshStrikeMissionMenuForGroup(groupId, true)
					return
				end
				self:printSingleMission(groupId, missionRef)
			end)
			state.items[#state.items + 1] = item
		end
	end

	function MissionCommander:refreshAllStrikeMissionMenus(force)
		self.strikeMenuByGroup = self.strikeMenuByGroup or {}
		for groupId, _ in pairs(self.strikeMenuByGroup) do
			self:refreshStrikeMissionMenuForGroup(groupId, force)
		end
	end

	function MissionCommander:_buildIntelMenuSignature(activeIntelZones)
		return table.concat(activeIntelZones or {}, "|")
	end

	function MissionCommander:createIntelMissionSubMenuForGroup(groupId, parent)
		if not parent then return end
		local T = L10N:ForGroup(groupId)
		self.intelMenuByGroup = self.intelMenuByGroup or {}
		local state = self.intelMenuByGroup[groupId]
		if state and state.root then
			if state.parent ~= parent then
				missionCommands.removeItemForGroup(groupId, state.root)
				state.root = nil
				state.items = {}
				state.signature = nil
			else
				return state.root
			end
		end
		local root = missionCommands.addSubMenuForGroup(groupId, T:Get("MENU_INTEL"), parent)
		self.intelMenuByGroup[groupId] = {
			root = root,
			items = {},
			signature = nil,
			parent = parent
		}
		return root
	end

	function MissionCommander:refreshIntelMissionMenuForGroup(groupId, force)
		local T = L10N:ForGroup(groupId)
		self.intelMenuByGroup = self.intelMenuByGroup or {}
		local state = self.intelMenuByGroup[groupId]
		if not state or not state.root then return end

		local activeIntelZones = _zoneIntelGetActiveZoneNamesForMenu(timer.getTime())
		local signature = self:_buildIntelMenuSignature(activeIntelZones)
		if not force and state.signature == signature then
			return
		end

		if state.items then
			for _, item in ipairs(state.items) do
				missionCommands.removeItemForGroup(groupId, item)
			end
		end
		state.items = {}
		state.signature = signature

		if #activeIntelZones == 0 then
			local emptyItem = missionCommands.addCommandForGroup(groupId, T:Get("INTEL_NONE_AVAILABLE_MENU"), state.root, function()
				trigger.action.outTextForGroup(groupId, T:Get("INTEL_NONE_AVAILABLE"), 10)
			end)
			state.items[#state.items + 1] = emptyItem
			return
		end

		for _, zoneName in ipairs(activeIntelZones) do
			local selectedZoneName = zoneName
			local item = missionCommands.addCommandForGroup(groupId, selectedZoneName, state.root, function()
				local report = _zoneIntelBuildCurrentReport(selectedZoneName, T)
				if report then
					trigger.action.outTextForGroup(groupId, report, 20)
				else
					trigger.action.outTextForGroup(groupId, T:Format("INTEL_NONE_AVAILABLE_FOR_ZONE", selectedZoneName), 10)
					self:refreshIntelMissionMenuForGroup(groupId, true)
				end
			end)
			state.items[#state.items + 1] = item
		end
	end

	function MissionCommander:refreshAllIntelMissionMenus(force)
		self.intelMenuByGroup = self.intelMenuByGroup or {}
		for groupId, _ in pairs(self.intelMenuByGroup) do
			self:refreshIntelMissionMenuForGroup(groupId, force)
		end
	end

	function MissionCommander:printMissions(groupId, opts)
		opts = opts or {}
		local T = groupId and L10N:ForGroup(groupId) or L10N
		local includeStrike = opts.includeStrike == true
		local output = T:Get("MISSION_ACTIVE_HEADER")
		output = output .. '\n------------------------------------------------'

		for _, v in ipairs(self.missions) do
			if v.isRunning and (includeStrike or not self:isStrikeMission(v)) then
				output = output .. '\n' .. self:_missionToText(v, 'title', T)
			end
		end

		local hasAvailableEscortMissions = false
		for _, v in ipairs(self.missions) do
			if v.isEscortMission and not v.isRunning and not v.accept and v:isActive() and not v.denied then 
				hasAvailableEscortMissions = true
				break
			end
		end

		if self.escortMissionGenerated and hasAvailableEscortMissions then
			output = output .. '\n' .. T:Get("MENU_AVAILABLE_MISSIONS")
			output = output .. '\n------------------------------------------------'
			for _, v in ipairs(self.missions) do
				if v.isEscortMission and not v.isRunning and not v.accept and v:isActive() then
					output = output .. '\n' .. self:_missionToText(v, 'MainTitle', T)
				end
			end
		end
		self:_printMissionText(groupId, output, 30, 10)
	end

	function MissionCommander:trackMission(params)

		if params.isEscortMission and params.zoneName then
			for _, existing in ipairs(self.missions) do
				if existing.isEscortMission and existing.zoneName == params.zoneName then
					return
				end
			end
		end
		params.isRunning = false
		params.accept = false
		params.notified = false
		table.insert(self.missions, params)
	end

	function MissionCommander:checkMissions(time)
		for i, v in ipairs(self.missions) do
			local isActiveNow = v:isActive()
			if v.isRunning then
				if v.missionFail and isActiveNow and v:missionFail() then
					local wasStrikeMission = self:isStrikeMission(v)
					v.isRunning = false
					table.remove(self.missions, i)
					if wasStrikeMission then
						self:refreshAllStrikeMissionMenus(true)
					end
				if v.startOver then v:startOver() end
				elseif not isActiveNow then
					local wasStrikeMission = self:isStrikeMission(v)
					if v.messageEnd then trigger.action.outTextForCoalition(self.side, self:decodeMessage(v.messageEnd), 30) end
					if v.reward then self.battleCommander:addFunds(self.side, v.reward) end
					if v.endAction then v:endAction() end
					v.isRunning = false
					if wasStrikeMission then
						self:refreshAllStrikeMissionMenus(true)
					end
					return time + 2
				end
			elseif isActiveNow and not v.isEscortMission then
				if v.canExecute and type(v.canExecute) == 'function' then
					if v:canExecute() then
						if v.messageStart then
							trigger.action.outTextForCoalition(self.side, self:decodeMessage(v.messageStart), 30) end
						if v.startAction then v:startAction() end
						v.isRunning = true
						if self:isStrikeMission(v) then
							self:refreshAllStrikeMissionMenus(true)
						end
						--return time + 4
					end
				else
					if v.messageStart then
						trigger.action.outTextForCoalition(self.side, self:decodeMessage(v.messageStart), 30) end
					if v.startAction then v:startAction() end
					v.isRunning = true
					if self:isStrikeMission(v) then
						self:refreshAllStrikeMissionMenus(true)
					end
					return time + 6
				end
			elseif v.isEscortMission and isActiveNow and not v.isRunning then
				if not v.notified then
					if v.titleBefore then
					v:titleBefore() end
					v.notified = true
				end
				if v.notified and v:returnAccepted() and not v.isRunning then
					if v.startAction then v.startAction() end
					v.isRunning = true
					return time + 4
				end
			elseif v.isEscortMission and not isActiveNow and v.notified then
				v.notified = false
			end
		end

		return time + self.checkFrequency
	end

	function MissionCommander:acceptMission(mission)
		local targetMissionGroup = mission.missionGroup
		for _, v in ipairs(self.missions) do
			if v.isEscortMission and v.missionGroup == targetMissionGroup then
				v.accept = true
				v.isRunning = true
				return
			end
		end
	end

	function MissionCommander:init()
		--missionCommands.addCommandForCoalition(self.side, 'Missions', nil, self.printMissions, self)
		timer.scheduleFunction(self.checkMissions, self, timer.getTime() + 15)
	end

	function MissionCommander:createMissionsMenuForGroup(groupId)
		env.info("DEBUG: Creating menu for groupId="..tostring(groupId))
		
		if printMissionMenus[groupId] then
			return
		end
		
		local parent = MissionsRootMenus[groupId]
		if parent then
			local T = L10N:ForGroup(groupId)
			printMissionMenus[groupId] = missionCommands.addCommandForGroup(groupId, T:Get("MENU_AVAILABLE_MISSIONS"), parent, function() self:printMissions(groupId) end)
			self:createStrikeMissionSubMenuForGroup(groupId, parent)
			self:refreshStrikeMissionMenuForGroup(groupId, true)
		else
			return
		end
	end
end

function isZoneUnderSEADMission(zoneName)
    for _, mission in ipairs(mc.missions) do
        if mission.zone == zoneName and mission.missionType == "SEAD" and mission:isActive() then
            return true
        end
    end
    return false
end

function isAnyOtherMissionActive(currentMissionZone)
    local missionData = getFirstMatchingZoneMission(currentMissionZone, function(mission)
        return IsGroupActive(mission.missionGroup)
    end)
    if missionData and IsGroupActive(missionData.missionGroup) then
        return true, missionData
    end
    return false, nil
end

function startNextMission(missionZone)
    for trackedGroupName, _ in pairs(trackedGroups) do
        if IsGroupActive(trackedGroupName) then
            local trackedGroup = Group.getByName(trackedGroupName)
            if trackedGroup then
                local groupID = trackedGroup:getID()
                missionMenus[groupID] = missionMenus[groupID] or {}

                local isActive, activeMission = isAnyOtherMissionActive(missionZone)
                if isActive then
                    local T = L10N:ForGroup(groupID)
                    local mission = activeMission
                    local activeMissionZone = activeMission.zone
                    local inProgressMenu = missionCommands.addSubMenuForGroup(groupID, T:Get("MISSION_IN_PROGRESS_CONTINUE"))
                    missionMenus[groupID].inProgressMenu = inProgressMenu

                    missionCommands.addCommandForGroup(groupID, T:Get("COMMON_YES"), inProgressMenu, function()
                        removeMissionMenuForAll(activeMissionZone, nil, true)

                        if mission.missionGroup and type(mission.missionGroup) == "string" then
							local grpObj = GROUP:FindByName(mission.missionGroup)
							if grpObj then
								grpObj:Respawn()
							end
                            timer.scheduleFunction(function()
                                local groundUnitGroup = Group.getByName(mission.missionGroup)
                                if groundUnitGroup then
                                    trigger.action.groupStopMoving(groundUnitGroup)
                                end
                            end, {}, timer.getTime() + 2)

                            monitorFlagForMission(mission, trackedGroup, groupID)
                            createControlMenuForGroup(trackedGroup, mission, groupID)
                        else
                            trigger.action.outTextForGroup(groupID, T:Get("MISSION_ESCORT_GROUP_INVALID"), 10)
                        end
                    end)

                    missionCommands.addCommandForGroup(groupID, T:Get("COMMON_NO"), inProgressMenu, function()
                        if missionMenus[groupID].inProgressMenu then
                            missionCommands.removeItemForGroup(groupID, missionMenus[groupID].inProgressMenu)
                            missionMenus[groupID].inProgressMenu = nil
                        end
                    end)

                    return
                end
            end
        end
    end
end


	if ManualHold == nil then ManualHold = false end
	function monitorFlagForMission(mission, group, groupID)
		if mission.MissionType ~= "Escort" then return end
		mission.lastFlagValue = nil
		mission.wasStopped = false
		ManualHold = false

		local missionGroup = GROUP:FindByName(mission.missionGroup)
		if not missionGroup or not missionGroup:IsAlive() then return end

		local triggerZone = ZONE_GROUP:New(mission.missionGroup .. "_Zone", missionGroup, mission.radius)
		local groupSet = SET_GROUP:New():FilterCoalitions("red"):FilterCategories('ground'):FilterAlive():FilterStart()
		
		triggerZone.OnAfterEnteredZone = function(self, From, Event, To, triggeringGroup)
			if mission.wasStopped then return end
			mission.wasStopped = true
			if missionGroup:IsAlive() then
				local txtIndex = math.random(4)
				local snd = getRandomSound("halt")
				local checkpoint = false
				local movingsound = 'Frontal.ogg'
				local ms
				if triggeringGroup then
					local dcsGroup = Group.getByName(triggeringGroup:GetName())
					if dcsGroup and dcsGroup:isExist() then
						for _, u in ipairs(dcsGroup:getUnits()) do
							if u:isExist() and u:getLife() > 0 and u:hasAttribute("Fortifications") and triggerZone:IsVec3InZone(u:getPosition().p) then
								checkpoint = true
								break
							end
						end
						local _, speed = getGroupSpeed(dcsGroup)
						ms = speed
					end
				end
				local function broadcastAndStop()
					if missionGroupIDs[mission.zone] then
						for _, data in pairs(missionGroupIDs[mission.zone]) do
							local grp = data.group
							if grp and grp:isExist() then
								local dataT = L10N:ForGroup(data.groupID)
								if ms and ms > 1 then
									local moving = dataT:Get("ESCORT_CONVOY_HOLDING_INTEL")
									trigger.action.outTextForGroup(data.groupID, moving, 30)
									trigger.action.outSoundForGroup(data.groupID, movingsound)
								else
									local txt = checkpoint and dataT:Get("ESCORT_CHECKPOINT_AHEAD") or sendRandomMessage("halt", dataT, txtIndex)
									trigger.action.outTextForGroup(data.groupID, txt, 30)
									trigger.action.outSoundForGroup(data.groupID, snd)
								end
							end
						end
					end
					if missionGroup:IsAlive() then missionGroup:RouteStop() end
				end
				
				if not ms or ms <= 1 then
					timer.scheduleFunction(function()
						if triggeringGroup then
							local dcsGroup = Group.getByName(triggeringGroup:GetName())
							if dcsGroup and dcsGroup:isExist() then
								local _, speed = getGroupSpeed(dcsGroup)
								ms = speed
							end
						end
						broadcastAndStop()
					end, {}, timer.getTime() + 15)
				else
					broadcastAndStop()
				end
			else
				for trackedGroupName,_ in pairs(trackedGroups) do
					local tracked = GROUP:FindByName(trackedGroupName)
					if not tracked or not tracked:IsAlive() then
						trackedGroups[trackedGroupName] = nil
					end
				end
			end
			
		end
		triggerZone.OnAfterZoneEmpty = function(self, From, Event, To)
			if ManualHold then 
				mission.wasStopped = false
				env.info('Manual hold is active, not resuming mission.')
				return 
			end
			if missionGroup:IsAlive() then
				local _, ms = getGroupSpeed(missionGroup:GetDCSObject() or Group.getByName(mission.missionGroup))
				local txtIndex = math.random(4)
				local snd = getRandomSound("moving")
				if missionGroupIDs[mission.zone] then
					for _, data in pairs(missionGroupIDs[mission.zone]) do
						local grp = data.group
						if grp and grp:isExist() then
							if not ms or ms <= 1 then
								local txt = sendRandomMessage("moving", L10N:ForGroup(data.groupID), txtIndex)
								trigger.action.outTextForGroup(data.groupID, txt, 30)
								trigger.action.outSoundForGroup(data.groupID, snd)
							end
						end
					end
				end
				missionGroup:RouteResume()
			else
				for trackedGroupName,_ in pairs(trackedGroups) do
					local tracked = GROUP:FindByName(trackedGroupName)
					if not tracked or not tracked:IsAlive() then
						trackedGroups[trackedGroupName] = nil
					end
				end
			end
			mission.wasStopped = false
		end
		triggerZone:SetPartlyInside()
		triggerZone:Trigger(groupSet)
	end

	function ArmEscortAutoCapture(mission)
		if not mission or mission.MissionType ~= "Escort" then return end
		if mission._autoCapSch then mission._autoCapSch:Stop() mission._autoCapSch = nil end
		local zone = ZONE:FindByName(mission.TargetZone)
		if not zone then return end
		mission._autoCapSch = SCHEDULER:New(nil, function()
			local group = Group.getByName(mission.missionGroup)
			if not group or not group:isExist() then if mission._autoCapSch then mission._autoCapSch:Stop() mission._autoCapSch = nil end return end
			local currentZone = bc.indexedZones[mission.TargetZone]
			if not currentZone then if mission._autoCapSch then mission._autoCapSch:Stop() mission._autoCapSch = nil end return end
			if currentZone.side == 2 then if mission._autoCapSch then mission._autoCapSch:Stop() mission._autoCapSch = nil end return end
			if currentZone.side == 0 and Utils.someOfGroupInZone(group, mission.TargetZone) then currentZone:capture(2) if mission._autoCapSch then mission._autoCapSch:Stop() mission._autoCapSch = nil end return end
		end, {}, 2, 5)
	end

function canStartMission(mission)
    if not mission then return false end
    local targetZone = bc.indexedZones[mission.TargetZone]
    if not targetZone or targetZone.side ~= 1 then return false end
    if not missions[mission.zone] then return false end
    return not IsGroupActive(mission.missionGroup)
end

getOrderedZoneMissions = function(zoneName)
    local zoneMissions = {}
    if not missions then
        return zoneMissions
    end

    for _, mission in pairs(missions) do
        if mission and mission.zone == zoneName then
            zoneMissions[#zoneMissions + 1] = mission
        end
    end

    local hasOrder = false
    for _, mission in ipairs(zoneMissions) do
        if mission.order ~= nil then
            hasOrder = true
            break
        end
    end

    if hasOrder then
        table.sort(zoneMissions, function(a, b)
            local aOrder = tonumber(a.order)
            local bOrder = tonumber(b.order)
            if aOrder ~= nil and bOrder ~= nil then
                if aOrder ~= bOrder then
                    return aOrder < bOrder
                end
                return false
            end
            if aOrder ~= nil then
                return true
            end
            if bOrder ~= nil then
                return false
            end
            return false
        end)
    end

    return zoneMissions
end

getFirstMatchingZoneMission = function(zoneName, predicate)
    for _, mission in ipairs(getOrderedZoneMissions(zoneName)) do
        if not predicate or predicate(mission) then
            return mission
        end
    end
    return nil
end

