	TEXACO_DEFAULT_SPEED_KT = TexacoSpeed or 286
	ArcoCurrentAltitudeFt = ARCO_DEFAULT_ALTITUDE_FT
	TexacoCurrentAltitudeFt = TEXACO_DEFAULT_ALTITUDE_FT
	ArcoCurrentSpeedKt = ARCO_DEFAULT_SPEED_KT
	TexacoCurrentSpeedKt = TEXACO_DEFAULT_SPEED_KT

-- Persisted tanker unlock + station state (saved in BattleCommander state table).
	TANKER_PERSISTENCE = TANKER_PERSISTENCE or {
	    arco = { unlocked = false, x = nil, y = nil, z = nil, heading = 45, leg = 0, zone = nil, speed = ARCO_DEFAULT_SPEED_KT },
	    texaco = { unlocked = false, x = nil, y = nil, z = nil, heading = 45, leg = 0, zone = nil, speed = TEXACO_DEFAULT_SPEED_KT },
	}
_tankerRestoreScheduled = _tankerRestoreScheduled or false

_getTankerDefaultAltitude = function(kind)
    if kind == "arco" then
        return ARCO_DEFAULT_ALTITUDE_FT
    end
    return TEXACO_DEFAULT_ALTITUDE_FT
end

_getTankerCurrentAltitude = function(kind)
    if kind == "arco" then
        ArcoCurrentAltitudeFt = tonumber(ArcoCurrentAltitudeFt) or ARCO_DEFAULT_ALTITUDE_FT
        return ArcoCurrentAltitudeFt
    end
    TexacoCurrentAltitudeFt = tonumber(TexacoCurrentAltitudeFt) or TEXACO_DEFAULT_ALTITUDE_FT
    return TexacoCurrentAltitudeFt
end

_setTankerCurrentAltitude = function(kind, altitudeFt)
    local alt = tonumber(altitudeFt)
    if not alt then return nil end
    alt = math.floor(alt + 0.5)
    if kind == "arco" then
        ArcoCurrentAltitudeFt = alt
        return ArcoCurrentAltitudeFt
    end
    TexacoCurrentAltitudeFt = alt
    return TexacoCurrentAltitudeFt
end

	_getTankerAltitudeOptions = function(kind)
	    if kind == "arco" then
	        return {16000, 17000, 18000, 19000, 20000, 21000, 22000}
	    end
	    return {14000, 15000, 16000, 17000, 18000, 19000, 20000}
	end

	_getTankerDefaultSpeed = function(kind)
	    if kind == "arco" then
	        return ARCO_DEFAULT_SPEED_KT
	    end
	    if kind == "texaco" then
	        return TEXACO_DEFAULT_SPEED_KT
	    end
	    return nil
	end

	_getTankerCurrentSpeed = function(kind)
	    if kind ~= "arco" and kind ~= "texaco" then return nil end
	    local defaultSpeed = _getTankerDefaultSpeed(kind)
	    local speed = (kind == "arco") and ArcoCurrentSpeedKt or TexacoCurrentSpeedKt
	    if type(speed) ~= "number" then
	        speed = defaultSpeed
	    end
	    if type(_getTankerState) == "function" then
	        local st = _getTankerState(kind)
	        if st then
	            if type(st.speed) == "number" then
	                speed = st.speed
	            elseif st.speed == nil then
	                st.speed = speed
	            end
	        end
	    end
	    speed = math.floor((speed or defaultSpeed or 0) + 0.5)
	    if kind == "arco" then
	        ArcoCurrentSpeedKt = speed
	        return ArcoCurrentSpeedKt
	    end
	    TexacoCurrentSpeedKt = speed
	    return TexacoCurrentSpeedKt
	end

	_setTankerCurrentSpeed = function(kind, speedKt)
	    if kind ~= "arco" and kind ~= "texaco" then return nil end
	    if type(speedKt) ~= "number" then return nil end
	    local speed = math.floor(speedKt + 0.5)
	    local st = nil
	    if type(_getTankerState) == "function" then
	        st = _getTankerState(kind)
	        if st then st.speed = speed end
	    end
	    if kind == "arco" then
	        ArcoCurrentSpeedKt = speed
	        return speed
	    end
	    TexacoCurrentSpeedKt = speed
	    return speed
	end

	_getTankerSpeedOptions = function(kind)
	    if kind == "arco" then
	        return {220, 286, 300, 320, 340}
	    end
	    if kind == "texaco" then
	        return {220, 286, 300, 320, 340}
	    end
	    return {}
	end

_formatFeetMenuLabel = function(feet)
    local n = math.floor((tonumber(feet) or 0) + 0.5)
    local s = tostring(n)
    while true do
        local formatted, k = s:gsub("^(-?%d+)(%d%d%d)", "%1,%2")
        s = formatted
        if k == 0 then break end
    end
    return s
end

	_normalizeTankerState = function(raw, defaultHeading, defaultSpeed)
	    local out = {
	        unlocked = false,
	        x = nil,
	        y = nil,
	        z = nil,
	        heading = defaultHeading,
	        leg = 0,
	        zone = nil,
	        speed = defaultSpeed,
	    }
	    if type(raw) ~= "table" then return out end
	    out.unlocked = raw.unlocked == true
	    out.x = tonumber(raw.x)
	    out.y = tonumber(raw.y)
	    out.z = tonumber(raw.z)
	    out.heading = tonumber(raw.heading) or defaultHeading
	    out.leg = tonumber(raw.leg) or 0
	    out.zone = raw.zone
	    if type(raw.speed) == "number" then
	        out.speed = math.floor(raw.speed + 0.5)
	    end
	    return out
	end
	
	_getTankerState = function(kind)
	    local key = (kind == "arco") and "arco" or "texaco"
	    local defHeading = (key == "arco") and 45 or 45
	    local defSpeed = (key == "arco") and ARCO_DEFAULT_SPEED_KT or TEXACO_DEFAULT_SPEED_KT
	    TANKER_PERSISTENCE = TANKER_PERSISTENCE or {}
	    TANKER_PERSISTENCE[key] = _normalizeTankerState(TANKER_PERSISTENCE[key], defHeading, defSpeed)
	    if key == "arco" and type(TANKER_PERSISTENCE[key].speed) == "number" then
	        ArcoCurrentSpeedKt = TANKER_PERSISTENCE[key].speed
	    elseif key == "texaco" and type(TANKER_PERSISTENCE[key].speed) == "number" then
	        TexacoCurrentSpeedKt = TANKER_PERSISTENCE[key].speed
	    end
	    return TANKER_PERSISTENCE[key]
	end

_isTankerUnlockedById = function(id)
    if id == "dynamicarco" then
        return _getTankerState("arco").unlocked == true
    elseif id == "dynamictexaco" then
        return _getTankerState("texaco").unlocked == true
    end
    return false
end

_setTankerUnlockedById = function(id)
    if id == "dynamicarco" then
        _getTankerState("arco").unlocked = true
    elseif id == "dynamictexaco" then
        _getTankerState("texaco").unlocked = true
    end
end

	_saveTankerStation = function(kind, coord, heading, leg, zone)
	    -- Read tanker speed before grabbing state to avoid stale table refs from nested _getTankerState calls.
	    local tankerSpeed = nil
	    if kind == "arco" or kind == "texaco" then
	        tankerSpeed = _getTankerCurrentSpeed(kind)
	    end
	    local st = _getTankerState(kind)
	    st.unlocked = true
	    st.heading = tonumber(heading) or st.heading or 45
	    st.leg = tonumber(leg) or 0
	    if kind == "arco" or kind == "texaco" then
	        if type(tankerSpeed) == "number" then
	            st.speed = tankerSpeed
	        end
	    end
	    if zone then st.zone = zone end

    local vec = nil
    if coord and coord.GetVec3 then
        vec = coord:GetVec3()
    elseif type(coord) == "table" and coord.x and (coord.z or coord.y) then
        vec = { x = coord.x, y = coord.y, z = coord.z or coord.y }
    end
    if vec and vec.x and vec.z then
        st.x = vec.x
        st.y = vec.y
        st.z = vec.z
    end
end

