function isArcoRepositionAllowed()
    if not ArcoGroup or not ArcoGroup:isExist() then return true end
    local u = ArcoGroup:getUnit(1)
    if not u or not u:isExist() then return true end
    local tv = u:getPoint()
    if not tv then return true end
    local occupied = false
    BlueClients:ForEachClient(function(client)
        if occupied then return end
        if client:IsAlive() then
            local pv = client:GetPointVec3()
            if math.abs(pv.y - tv.y) <= ARCO_PROX_ALT_M then
                local dx = pv.x - tv.x
                local dz = pv.z - tv.z
                if (dx*dx + dz*dz) <= (ARCO_PROX_RADIUS_M*ARCO_PROX_RADIUS_M) then
                    occupied = true
                end
            end
        end
    end)
    return not occupied
end

function isTexacoRepositionAllowed()
    if not TexacoGroup or not TexacoGroup:isExist() then return true end
    local u = TexacoGroup:getUnit(1)
    if not u or not u:isExist() then return true end
    local tv = u:getPoint()
    if not tv then return true end
    local occupied = false
    BlueClients:ForEachClient(function(client)
        if occupied then return end
        if client:IsAlive() then
            local pv = client:GetPointVec3()
            if math.abs(pv.y - tv.y) <= TEXACO_PROX_ALT_M then
                local dx = pv.x - tv.x
                local dz = pv.z - tv.z
                if (dx*dx + dz*dz) <= (TEXACO_PROX_RADIUS_M*TEXACO_PROX_RADIUS_M) then
                    occupied = true
                end
            end
        end
    end)
    return not occupied
end

function ArcoAltitudeCheckAndSet(altFt)
    if not ArcoGroup then return false end
    if not isArcoRepositionAllowed() then
        MESSAGE:New(L10N:Get("DYNAMIC_TANKER_BUSY"), 10):ToAll()
        return false
    end

    local currentAlt = tonumber(_getTankerCurrentAltitude("arco")) or _getTankerDefaultAltitude("arco")
    local targetAlt = _setTankerCurrentAltitude("arco", altFt)
    if not targetAlt then return false end
    if currentAlt == targetAlt then return false end

    local st = _getTankerState("arco")
    if not ArcoGroup:isExist() then return false end
    local controller = ArcoGroup:getController()
    if not controller then return false end
    controller:setAltitude(UTILS.FeetToMeters(targetAlt), true, "BARO")
    st.unlocked = true
    MESSAGE:New(L10N:Format("DYNAMIC_TANKER_ALTITUDE_SET", "Arco", _formatFeetMenuLabel(targetAlt)), 10):ToAll()
    return true
end

