function ArcoSpeedCheckAndSet(speedKt)
    if not ArcoGroup then return false end
    if not isArcoRepositionAllowed() then
        MESSAGE:New(L10N:Get("DYNAMIC_TANKER_BUSY"), 10):ToAll()
        return false
    end

    local currentSpeed = _getTankerCurrentSpeed("arco") or _getTankerDefaultSpeed("arco")
    if type(speedKt) ~= "number" then return false end
    local targetSpeed = math.floor(speedKt + 0.5)
    if currentSpeed == targetSpeed then return false end

    if not ArcoGroup:isExist() then return false end
    local controller = ArcoGroup:getController()
    if not controller then return false end

    local altitudeM = UTILS.FeetToMeters(_getTankerCurrentAltitude("arco"))
    local speedMps = UTILS.IasToTas(UTILS.KnotsToMps(targetSpeed), altitudeM)
    controller:setSpeed(speedMps, true)

    _setTankerCurrentSpeed("arco", targetSpeed)
    local st = _getTankerState("arco")
    st.unlocked = true
    st.speed = targetSpeed
    MESSAGE:New(L10N:Format("DYNAMIC_TANKER_SPEED_SET", "Arco", targetSpeed), 10):ToAll()
    return true
end

