function isZoneSafeForSpawn(friendlyZoneName, minDistNM)
    for _, v in ipairs(bc.zones) do
        if v.side == 1 then -- enemy zone
            local dist_m = ZONE_DISTANCES[friendlyZoneName][v.zone]
            local dist = UTILS.MetersToNM(dist_m)
            if dist and dist < minDistNM then
                --env.info("Blue zone " .. friendlyZoneName .. " is not safe: enemy zone " .. v.zone .. " is only " .. string.format("%.1f", dist) .. " NM away.")
                return false
            end
        end
    end
    return true
end

local function _useAIAttackGroundTakeoff()
    return AIAttackTakeoffFromGround == true
end

local function _getAIAttackGroundTakeoffExtraNM()
    local extra = tonumber(AIAttackTakeoffFromGroundExtraNM)
    if not extra or extra < 0 then
        return 20
    end
    return extra
end

local function _getAIAttackRequiredSpawnDistanceNM(minDistNM)
    local required = tonumber(minDistNM) or 0
    if _useAIAttackGroundTakeoff() then
        required = required + _getAIAttackGroundTakeoffExtraNM()
    end
    return required
end

local function _getDynamicSupportTemplateCopy(templateName)
	local tpl = _DATABASE.Templates.Groups[templateName]
	tpl = tpl and tpl.Template or nil
    if tpl then
        return UTILS.DeepCopy(tpl)
    end
    return FetchMETemplate(templateName)
end

local function _getDynamicSupportTemplateUnitCount(templateName)
    local tpl = _getDynamicSupportTemplateCopy(templateName)
    local units = tpl and tpl.units
    if type(units) == "table" and #units > 0 then
        return #units
    end
    return 1
end

local function _getPreferredTakeoffRunwayName(airbase)
    if not airbase or not airbase.IsAirdrome or not airbase:IsAirdrome() then
        return nil
    end

    local runway = airbase.GetActiveRunwayTakeoff and airbase:GetActiveRunwayTakeoff() or nil
    if not runway and airbase.GetActiveRunway then
        local _, takeoffRunway = airbase:GetActiveRunway()
        runway = takeoffRunway
    end
    if not runway and airbase.GetRunwayIntoWind then
        runway = airbase:GetRunwayIntoWind()
    end
    if not runway or not airbase.GetRunwayName then
        return nil
    end

    return airbase:GetRunwayName(runway)
end

local function _buildParkingDistanceCacheForAirbase(airbase, terminalType)
    if not airbase or not terminalType then
        return nil
    end

    local airbaseName = airbase.GetName and airbase:GetName() or nil
    if not airbaseName then
        return nil
    end

    ParkingDistanceCache[airbaseName] = ParkingDistanceCache[airbaseName] or {}

    local spots = airbase:GetParkingSpotsTable(terminalType) or {}
    local usable = {}
    for i = 1, #spots do
        local spot = spots[i]
        if spot and spot.TerminalID and spot.Coordinate then
            usable[#usable + 1] = spot
        end
    end

    table.sort(usable, function(a, b)
        return a.TerminalID < b.TerminalID
    end)

    local cache = {
        airbaseName = airbaseName,
        terminalType = terminalType,
        neighborOrder = {},
    }

    for i = 1, #usable do
        local anchor = usable[i]
        local ranked = {}
        for j = 1, #usable do
            local spot = usable[j]
            ranked[#ranked + 1] = {
                TerminalID = spot.TerminalID,
                distance = anchor.Coordinate:Get2DDistance(spot.Coordinate)
            }
        end
        table.sort(ranked, function(a, b)
            if a.distance == b.distance then
                return a.TerminalID < b.TerminalID
            end
            return a.distance < b.distance
        end)
        cache.neighborOrder[anchor.TerminalID] = ranked
    end

    ParkingDistanceCache[airbaseName][terminalType] = cache
    return cache
end

function BuildAirbaseParkingClusterCache(airbaseNames, terminalTypes)
    local names = {}
    local seen = {}

    if type(airbaseNames) == "table" then
        for _, airbaseName in pairs(airbaseNames) do
            if type(airbaseName) == "string" and airbaseName ~= "" and not seen[airbaseName] then
                names[#names + 1] = airbaseName
                seen[airbaseName] = true
            end
        end
    else
        for _, z in ipairs((bc and bc.zones) or zones or {}) do
            local airbaseName = z and z.airbaseName
            if type(airbaseName) == "string" and airbaseName ~= "" and not seen[airbaseName] then
                names[#names + 1] = airbaseName
                seen[airbaseName] = true
            end
        end
    end

    local types = terminalTypes
    if type(types) ~= "table" or #types == 0 then
        types = {
            AIRBASE.TerminalType.OpenMedOrBig,
            AIRBASE.TerminalType.HelicopterUsable
        }
    end

    for i = 1, #names do
        local airbase = getAirbaseByName(names[i])
        if airbase and airbase.IsAirdrome and airbase:IsAirdrome() then
            for j = 1, #types do
                _buildParkingDistanceCacheForAirbase(airbase, types[j])
            end
        end
    end

    return ParkingDistanceCache
end

_pickCachedParkingIds = function(airbase, terminalType, freeSpots, need)
    if type(freeSpots) ~= "table" or #freeSpots < need then
        return nil
    end

    local preferredRunwayName = _getPreferredTakeoffRunwayName(airbase)
    local bestIds = nil
    local bestRunwayDistance = nil
    local bestMaxDistance = nil
    local bestTotalDistance = nil
    local freeById = {}
    for i = 1, #freeSpots do
        local spot = freeSpots[i]
        if spot and spot.TerminalID then
            freeById[spot.TerminalID] = spot
        end
    end

    local cache = nil
    if airbase and terminalType then
        local airbaseName = airbase.GetName and airbase:GetName() or nil
        cache = airbaseName and ParkingDistanceCache[airbaseName] and ParkingDistanceCache[airbaseName][terminalType] or nil
        if not cache then
            cache = _buildParkingDistanceCacheForAirbase(airbase, terminalType)
        end
    end

    if cache and cache.neighborOrder then
        for terminalID, _ in pairs(freeById) do
            local ranked = cache.neighborOrder[terminalID]
            if ranked then
                local ids = {}
                local maxDistance = 0
                local totalDistance = 0
                local runwayDistance = 0
                for i = 1, #ranked do
                    local candidate = ranked[i]
                    if freeById[candidate.TerminalID] then
                        ids[#ids + 1] = candidate.TerminalID
                        totalDistance = totalDistance + candidate.distance
                        runwayDistance = runwayDistance + (freeById[candidate.TerminalID].DistToRwy or 0)
                        if candidate.distance > maxDistance then
                            maxDistance = candidate.distance
                        end
                        if #ids >= need then
                            break
                        end
                    end
                end
                if #ids >= need then
                    local isBetter = bestIds == nil
                    if not isBetter and maxDistance < bestMaxDistance then
                        isBetter = true
                    elseif not isBetter and maxDistance == bestMaxDistance and totalDistance < bestTotalDistance then
                        isBetter = true
                    elseif not isBetter and preferredRunwayName and maxDistance == bestMaxDistance and totalDistance == bestTotalDistance and runwayDistance < bestRunwayDistance then
                        isBetter = true
                    end
                    if isBetter then
                        bestIds = ids
                        bestRunwayDistance = runwayDistance
                        bestMaxDistance = maxDistance
                        bestTotalDistance = totalDistance
                    end
                end
            end
        end
    end

    if bestIds then
        return bestIds
    end

    for i = 1, #freeSpots do
        local anchor = freeSpots[i]
        local anchorCoord = anchor and anchor.Coordinate
        if anchorCoord then
            local ranked = {}
            for j = 1, #freeSpots do
                local spot = freeSpots[j]
                local spotCoord = spot and spot.Coordinate
                if spotCoord then
                    ranked[#ranked + 1] = {
                        spot = spot,
                        distance = anchorCoord:Get2DDistance(spotCoord)
                    }
                end
            end
            if #ranked >= need then
                table.sort(ranked, function(a, b)
                    if a.distance == b.distance then
                        return a.spot.TerminalID < b.spot.TerminalID
                    end
                    return a.distance < b.distance
                end)
                local ids = {}
                local maxDistance = 0
                local totalDistance = 0
                local runwayDistance = 0
                for j = 1, need do
                    ids[#ids + 1] = ranked[j].spot.TerminalID
                    totalDistance = totalDistance + ranked[j].distance
                    runwayDistance = runwayDistance + (ranked[j].spot.DistToRwy or 0)
                    if ranked[j].distance > maxDistance then
                        maxDistance = ranked[j].distance
                    end
                end
                local isBetter = bestIds == nil
                if not isBetter and maxDistance < bestMaxDistance then
                    isBetter = true
                elseif not isBetter and maxDistance == bestMaxDistance and totalDistance < bestTotalDistance then
                    isBetter = true
                elseif not isBetter and preferredRunwayName and maxDistance == bestMaxDistance and totalDistance == bestTotalDistance and runwayDistance < bestRunwayDistance then
                    isBetter = true
                end
                if isBetter then
                    bestIds = ids
                    bestRunwayDistance = runwayDistance
                    bestMaxDistance = maxDistance
                    bestTotalDistance = totalDistance
                end
            end
        end
    end

    if bestIds then
        return bestIds
    end

    table.sort(freeSpots, function(a, b) return a.TerminalID < b.TerminalID end)
    local ids = {}
    for i = 1, need do
        ids[i] = freeSpots[i].TerminalID
    end
    return ids
end

function PickCachedParkingIdsForAirbase(airbase, terminalType, freeSpots, need)
    return _pickCachedParkingIds(airbase, terminalType, freeSpots, need)
end

local function _pickFriendlySupportAirbase(originCoord, side, templateName, termType, excludedAirbases)
    if not originCoord then return nil end
    local need = math.max(_getDynamicSupportTemplateUnitCount(templateName), 1)
    local terminalType = termType or AIRBASE.TerminalType.OpenMedOrBig
    local candidates = {}
    local seen = {}
    local preferredAirbases = {}
    local preferredSeen = {}

    for _, z in ipairs(bc.zones) do
        if z.side == side and z.active and z.airbaseName and not preferredSeen[z.airbaseName] then
            local hasCapOrigin = false
            for _, gc in ipairs(z.groups or {}) do
                if gc and (gc.type == 'air' or gc.type == 'carrier_air') and gc.MissionType == 'CAP' and (gc.mission == 'patrol' or gc.mission == 'attack') then
                    hasCapOrigin = true
                    break
                end
            end
            if hasCapOrigin then
                preferredSeen[z.airbaseName] = true
                preferredAirbases[#preferredAirbases + 1] = z.airbaseName
            end
        end
    end

    local function addCandidate(list, seenMap, abName)
        if not abName or seenMap[abName] or (excludedAirbases and excludedAirbases[abName]) then return end
        local ab = getAirbaseByName(abName)
        local sideOk = ab and ((side == 1 and ab:GetCoalition() == coalition.side.RED) or (side == 2 and ab:GetCoalition() == coalition.side.BLUE))
        if sideOk and ab:IsAirdrome() then
            list[#list + 1] = {
                ab = ab,
                d = originCoord:Get2DDistance(ab:GetCoordinate())
            }
            seenMap[abName] = true
        end
    end

    local capCandidates = {}
    local capSeen = {}

    for i = 1, #preferredAirbases do
        addCandidate(capCandidates, capSeen, preferredAirbases[i])
    end

    if #capCandidates > 0 then
        candidates = capCandidates
        seen = capSeen
    else
        for _, z in ipairs(bc.zones) do
            if z.side == side and z.active then
                addCandidate(candidates, seen, z.airbaseName)
            end
        end
    end

    table.sort(candidates, function(a, b) return a.d < b.d end)

    for _, candidate in ipairs(candidates) do
        local free = candidate.ab:GetFreeParkingSpotsTable(terminalType, false) or {}
        if #free < need then
            local free2 = candidate.ab:GetFreeParkingSpotsTable(terminalType, true)
            if type(free2) == "table" and #free2 > #free then
                free = free2
            end
        end
        local ids = _pickCachedParkingIds(candidate.ab, terminalType, free, need)
        if ids then
            return candidate.ab, ids
        end
    end

    return nil
end

local function _resolveDynamicSupportSpawnGroup(groupLike)
    if not groupLike then return nil end
    local group = nil
    if type(groupLike) == "string" then
        group = GROUP:FindByName(groupLike)
    elseif groupLike.ClassName == "GROUP" then
        group = groupLike
    else
        local name = groupLike.getName and groupLike:getName() or (groupLike.GetName and groupLike:GetName()) or nil
        if not name then return nil end
        group = GROUP:FindByName(name)
    end
    if not group then return nil end

    local function dcsGroupExists(dcsGroup)
        if not dcsGroup then return false end
        if dcsGroup.isExist and not dcsGroup:isExist() then return false end
        if dcsGroup.getSize and dcsGroup:getSize() <= 0 then return false end
        return true
    end

    local dcsGroup = group.GetDCSObject and group:GetDCSObject() or nil
    if not dcsGroupExists(dcsGroup) then
        local name = group.GetName and group:GetName() or nil
        dcsGroup = name and Group.getByName(name) or nil
    end
    if not dcsGroupExists(dcsGroup) then return nil end
    return group
end

local function _getDynamicSupportOriginLabel(fallbackZoneName, homebase)
    local label = fallbackZoneName
    if not homebase then return label end

    local abName = homebase.GetName and homebase:GetName() or nil
    if not abName then return label end

    for _, z in ipairs((bc and bc.zones) or {}) do
        if z and z.airbaseName == abName and z.zone then
            return z.zone
        end
    end

    return label or abName
end

local function _attachDynamicSupportTakeoffMenuRefresh(flightGroup, airborneMessage)
    if not flightGroup or not _useAIAttackGroundTakeoff() then return end
    function flightGroup:OnAfterTakeoff(From, Event, To)
        if buildCapControlMenu then
            buildCapControlMenu()
        end
        if airborneMessage then
            trigger.action.outTextForCoalition(2, airborneMessage, 15)
        end
    end
end

local function _getDynamicSupportIngressAnchorCoord(originZoneName, forcedHomebase)
    local originZone = originZoneName and ZONE:FindByName(originZoneName) or nil
    local originCoord = originZone and originZone:GetCoordinate() or nil
    if originCoord then
        return originCoord
    end
    return forcedHomebase and forcedHomebase.GetCoordinate and forcedHomebase:GetCoordinate() or nil
end

local function _setDynamicSupportGroundIngress(mission, originZoneName, forcedHomebase, targetCoord, attackOffsetNM, missionAltitudeFeet, missionSpeedKnots)
    if not mission or not forcedHomebase or not targetCoord then return end

    local baseOffsetNM = tonumber(attackOffsetNM) or 0
    if baseOffsetNM <= 0 then return end

    local extraNM = _getAIAttackGroundTakeoffExtraNM()
    if extraNM <= 0 then return end

    local anchorCoord = _getDynamicSupportIngressAnchorCoord(originZoneName, forcedHomebase)
    if not anchorCoord then return end

    local ingressOffsetNM = baseOffsetNM + extraNM
    local headingFromTarget = targetCoord:GetAngleDegrees(targetCoord:GetDirectionVec3(anchorCoord))
    local ingressCoord = targetCoord:Translate(UTILS.NMToMeters(ingressOffsetNM), headingFromTarget, true)

    mission:SetMissionIngressCoord(ingressCoord, missionAltitudeFeet, missionSpeedKnots)
end

local function _refreshDynamicSupportMenuOnSpawn(usedGroundSpawn)
    if usedGroundSpawn then return end
    if buildCapControlMenu then
        buildCapControlMenu()
    end
end

local function _spawnDynamicSupportFromGround(templateName, spawnName, originCoord, onSpawnGroup, skill, termType)
    if not _useAIAttackGroundTakeoff() then return nil end

	local tpl = _getDynamicSupportTemplateCopy(templateName)
	if not tpl then return nil end

    local excludedAirbases = {}
    for attempt = 1, 8 do
        local homebase, spots = _pickFriendlySupportAirbase(originCoord, 2, templateName, termType, excludedAirbases)
        if not homebase or not spots then return nil end
        local homebaseName = homebase.GetName and homebase:GetName() or tostring(homebase)

        local function spawnWith(method)
	        local callbackGroupLike = nil
            local methodSpawnName = spawnName
            if attempt > 1 or method ~= "parking" then
                methodSpawnName = spawnName.."_"..tostring(attempt).."_"..tostring(method)
            end
	        local sp = SPAWN:NewFromTemplate(UTILS.DeepCopy(tpl), templateName, methodSpawnName, true)

            if skill then
                sp = sp:InitSkill(skill)
            end
            sp = sp:OnSpawnGroup(function(g)
                callbackGroupLike = g
            end)

            local spawned = nil
            if method == "parking" then
                spawned = sp:SpawnAtParkingSpot(homebase, spots, SPAWN.Takeoff.Hot)
            else
                spawned = sp:SpawnAtAirbase(homebase, SPAWN.Takeoff.Hot)
            end

            local spawnGroup = _resolveDynamicSupportSpawnGroup(callbackGroupLike or spawned)
            if not spawnGroup then
                env.info("[DynamicSupport] invalid "..tostring(method).." spawn template="..tostring(templateName).." homebase="..tostring(homebaseName))
                return nil
            end
            if onSpawnGroup then
                onSpawnGroup(spawnGroup, homebase)
            end
            return spawnGroup
        end

        local spawned = spawnWith("parking")
        if spawned then return spawned end

        spawned = spawnWith("airbase")
        if spawned then return spawned end

        excludedAirbases[homebaseName] = true
    end

    return nil
end

function findClosestBlueZoneOutside(targetZoneName,minDistNM)
    local requiredMinNM = _getAIAttackRequiredSpawnDistanceNM(minDistNM)
    if _useAIAttackGroundTakeoff() then
        requiredMinNM = requiredMinNM - (_getAIAttackGroundTakeoffExtraNM() * 0.5)
    end
    local bestZone,bestDist=nil,nil
    local altZone,altDist=nil,0
    for _,z in ipairs(bc.zones) do
        if z.side==2 and isZoneSafeForSpawn(z.zone,20) then
            local d=UTILS.MetersToNM(ZONE_DISTANCES[z.zone][targetZoneName])
            if d then
                if d>=requiredMinNM then
                    if not bestDist or d<bestDist then
                        bestZone,bestDist=z.zone,d
                    end
                elseif d>altDist then
                    altZone,altDist=z.zone,d
                end
            end
        end
    end
    if bestZone then
        return bestZone,bestDist
    else
        return altZone,altDist
    end
end
-- cap
function buildCapControlMenu()
    bc:refreshDynamicControlMenusForBlue(true)
end


function spawnCapAt(zoneName, heading, leg)
    if capActive then return end
    local zone = ZONE:FindByName(zoneName)
    if not zone then return end
    local coordVec3 = zone:GetCoordinate():GetVec3()
	local SpawnCords = zone:GetCoordinate()
	local coord = COORDINATE:NewFromVec3(coordVec3, heading)
    local function setupCap(spawnedGroupLike, forcedHomebase)
		local spawnedGroup = _resolveDynamicSupportSpawnGroup(spawnedGroupLike)
		if not spawnedGroup then return end
        capGroup = FLIGHTGROUP:New(spawnedGroup)
		capGroup:GetGroup():CommandSetUnlimitedFuel(true):SetOptionRadarUsingForContinousSearch(true):SetOptionRadioSilence(true)
		capGroup:SetOutOfAAMRTB(true):SetSpeed(600)
		local homebase = forcedHomebase or select(1, SpawnCords:GetClosestAirbase(0, 2))
		local originLabel = _getDynamicSupportOriginLabel(zoneName, forcedHomebase)
		if homebase then
			capGroup:SetHomebase(homebase)
		end
		local formation = 196610
		if leg == 0 then
			capSpeed = 330
			formation = 393217
			-- CapMissionOrbit = AUFTRAG:NewORBIT_CIRCLE_EngageTargets(coord,capAltitude,capSpeed,8,formation,50)
			CapMissionOrbit = AUFTRAG:NewORBIT_CIRCLE(coord, capAltitude, capSpeed)
			CapMissionOrbit.missionTask=ENUMS.MissionTask.CAP
			CapMissionOrbit:SetEngageDetected(40, {"Air"})
			CapMissionOrbit:SetROT(2)
			CapMissionOrbit:SetROE(2)
			CapMissionOrbit:SetFormation(196610)
			capGroup:AddMission(CapMissionOrbit)
			capGroup:MissionStart(CapMissionOrbit)
		else
			local capSpeed = 350
			-- CapMissionPatrol = AUFTRAG:NewPATROLRACETRACK_EngageTargets(coord,capAltitude,capSpeed,heading,leg,formation,50)
			CapMissionPatrol = AUFTRAG:NewORBIT(coord, capAltitude, capSpeed, heading, leg)
			CapMissionPatrol.missionTask=ENUMS.MissionTask.CAP
			CapMissionPatrol:SetEngageDetected(40, {"Air"})
			CapMissionPatrol:SetROT(2)
			CapMissionPatrol:SetROE(2)
			CapMissionPatrol:SetFormation(196610)
			capGroup:AddMission(CapMissionPatrol)
			capGroup:MissionStart(CapMissionPatrol)
		end
		_attachDynamicSupportTakeoffMenuRefresh(capGroup)

		function capGroup:OnAfterLanded(From, Event, To)
    	self:ScheduleOnce(5, function() self:Destroy() end)
		end
		function capGroup:OnAfterOutOfMissilesAA(From, Event, To)
			if capGroup then
			self:SwitchROE(2)
			trigger.action.outText(L10N:Get("DYNAMIC_SUPPORT_CAP_OUT_OF_MISSILES"), 20)
			end
		end
		
		function capGroup:OnAfterDead(From, Event, To)
			local landed = (From=="Landed") or (From=="Arrived")
			self:__Stop(1)
			capGroup  = nil
			capActive = false
			buildCapControlMenu()
			if landed then
				trigger.action.outText(L10N:Get("DYNAMIC_SUPPORT_CAP_LANDED"), 20)
			else
				trigger.action.outText(L10N:Get("DYNAMIC_SUPPORT_CAP_KILLED"), 20)
			end
		end

		local msg
		if forcedHomebase then
			msg = (leg == 0)
				and L10N:Format("DYNAMIC_SUPPORT_CAP_SCRAMBLING_ORBIT", originLabel, zoneName)
				or  L10N:Format("DYNAMIC_SUPPORT_CAP_SCRAMBLING_RACETRACK", originLabel, zoneName, heading, leg)
		else
			msg = (leg == 0)
				and L10N:Format("DYNAMIC_SUPPORT_CAP_ON_STATION_ORBIT", zoneName)
				or  L10N:Format("DYNAMIC_SUPPORT_CAP_ON_STATION_RACETRACK", zoneName, heading, leg)
		end
		MESSAGE:New(msg, 20):ToAll()

		if capParentMenu then
		missionCommands.removeItemForCoalition(2, capParentMenu)
		capParentMenu = nil
		end
    end

	local capSpawnName = capTemplate .. tostring(capSpawnIndex)
	local spawned = _spawnDynamicSupportFromGround(capTemplate, capSpawnName, SpawnCords, setupCap, nil, AIRBASE.TerminalType.OpenMedOrBig)
	local usedGroundSpawn = spawned ~= nil
	if not spawned then
		local g = Respawn.SpawnAtPoint(capTemplate, coord, heading, 2, 28000)
		if not g then return end
		timer.scheduleFunction(function(group, time)
			setupCap(group)
		end, g, timer.getTime() + 1)
	end
    capActive = true
	_refreshDynamicSupportMenuOnSpawn(usedGroundSpawn)


	capSpawnIndex = capSpawnIndex + 1
end

	function buildCapMenu()
		if capParentMenu then
			missionCommands.removeItemForCoalition(2, capParentMenu)
			capParentMenu = nil
		end
		capParentMenu = missionCommands.addSubMenuForCoalition(2, L10N:Get("DYNAMIC_REQUEST_CAP_FROM"))
		local count = 0
		local sub1
		local zoneMenu
		for _, wrap in ipairs(orderedZones(2)) do
			local v = wrap.z
			local zoneName = v.zone
			local zoneDisplayName = wrap.disp
			count = count + 1
			if count < 10 then
				zoneMenu = missionCommands.addSubMenuForCoalition(2, zoneDisplayName, capParentMenu)
			elseif count == 10 then
				sub1 = missionCommands.addSubMenuForCoalition(2, L10N:Get("MENU_MORE"), capParentMenu)
				zoneMenu = missionCommands.addSubMenuForCoalition(2, zoneDisplayName, sub1)
			elseif count % 9 == 1 then
				sub1 = missionCommands.addSubMenuForCoalition(2, L10N:Get("MENU_MORE"), sub1)
				zoneMenu = missionCommands.addSubMenuForCoalition(2, zoneDisplayName, sub1)
			else
				zoneMenu = missionCommands.addSubMenuForCoalition(2, zoneDisplayName, sub1)
			end
			for _, headingName in ipairs({ "Orbit", "Hot 360", "Hot 045", "Hot 090", "Hot 135", "Hot 180", "Hot 225", "Hot 270", "Hot 315" }) do
				if headingName == "Orbit" then
					missionCommands.addCommandForCoalition(2, localizedDynamicHeadingLabel(headingName), zoneMenu, function()
						spawnCapAt(zoneName, 045, 0)
					end)
				else
					local headingVal = capHeadings[headingName]
					local headingMenu = missionCommands.addSubMenuForCoalition(2, localizedDynamicHeadingLabel(headingName), zoneMenu)
					for _, legName in ipairs({ "10 NM Leg", "20 NM Leg", "30 NM Leg", "40 NM Leg", "50 NM Leg" }) do
						local legVal = capLegs[legName]
						missionCommands.addCommandForCoalition(2, localizedDynamicLegLabel(legName), headingMenu, function()
							spawnCapAt(zoneName, headingVal, legVal)
						end)
					end
				end
			end
		end
	end
