--Arco

local function _resolveTankerSpawnInput(input, heading, fallbackZoneLabel)
	local zoneName = nil
	local sourceCoord = nil
	if type(input) == "string" then
		local zone = ZONE:FindByName(input)
		if not zone then return nil end
		zoneName = input
		sourceCoord = zone:GetCoordinate()
	elseif input and type(input) == "table" and input.GetVec3 then
		sourceCoord = input
	elseif type(input) == "table" and input.x and (input.z or input.y) then
		sourceCoord = COORDINATE:New(input.x, input.y or 0, input.z or input.y)
	end
	if not sourceCoord then return nil end
	local spawnHeading = tonumber(heading) or 45
	local coord = COORDINATE:NewFromVec3(sourceCoord:GetVec3(), spawnHeading)
	local label = zoneName or fallbackZoneLabel or "saved position"
	return {
		coord = coord,
		spawnCoord = sourceCoord,
		zoneName = zoneName,
		label = label,
		heading = spawnHeading,
	}
end

local function ApplyProtectionCommandsToGroupController(GroupController)
	if not GroupController then return end
	GroupController:setCommand({
		id = 'SetInvisible',
		params = { value = true }
	})
	GroupController:setCommand({
		id = 'SetImmortal',
		params = { value = true }
	})
	GroupController:setCommand({
		id = 'SetUnlimitedFuel',
		params = { value = true }
	})
end

local function ActivateTankerBeacon(TankerUnit, TacanChannelNumber, TacanCallsignCode)
	if not TankerUnit then return end
	local BeaconFrequency = UTILS.TACANToFrequency(TacanChannelNumber, "Y")
	if not BeaconFrequency then return end
	local UnitController = TankerUnit:getController()
	if not UnitController then return end
	UnitController:setCommand({
		id = "ActivateBeacon",
		params = {
			type = BEACON.Type.TACAN,
			system = BEACON.System.TACAN_TANKER_Y,
			frequency = BeaconFrequency,
			unitId = TankerUnit:getID(),
			channel = TacanChannelNumber,
			modeChannel = "Y",
			AA = true,
			callsign = TacanCallsignCode,
			bearing = true,
		},
	})
end

local function BuildTankerRequestMenu(MenuTitleText, ExistingMenuHandle, SpawnRequestFunction)
	if ExistingMenuHandle then
		missionCommands.removeItemForCoalition(2, ExistingMenuHandle)
	end
	local ParentMenu = missionCommands.addSubMenuForCoalition(2, MenuTitleText)
	local ZoneCount = 0
	local PagingMenu = nil
	local HeadingNames = { "Orbit", "Hot 360", "Hot 045", "Hot 090", "Hot 135", "Hot 180", "Hot 225", "Hot 270", "Hot 315" }
	local LegNames = { "10 NM Leg", "20 NM Leg", "30 NM Leg", "40 NM Leg", "50 NM Leg" }

	for _, ZoneWrapper in ipairs(orderedZones(2)) do
		local ZoneObject = ZoneWrapper.z
		local ZoneName = ZoneObject.zone
		local ZoneDisplayName = ZoneWrapper.disp
		local ZoneMenu = nil
		ZoneCount = ZoneCount + 1
		if ZoneCount < 10 then
			ZoneMenu = missionCommands.addSubMenuForCoalition(2, ZoneDisplayName, ParentMenu)
		elseif ZoneCount == 10 then
			PagingMenu = missionCommands.addSubMenuForCoalition(2, L10N:Get("MENU_MORE"), ParentMenu)
			ZoneMenu = missionCommands.addSubMenuForCoalition(2, ZoneDisplayName, PagingMenu)
		elseif ZoneCount % 9 == 1 then
			PagingMenu = missionCommands.addSubMenuForCoalition(2, L10N:Get("MENU_MORE"), PagingMenu)
			ZoneMenu = missionCommands.addSubMenuForCoalition(2, ZoneDisplayName, PagingMenu)
		else
			ZoneMenu = missionCommands.addSubMenuForCoalition(2, ZoneDisplayName, PagingMenu)
		end

		for _, HeadingName in ipairs(HeadingNames) do
			if HeadingName == "Orbit" then
				missionCommands.addCommandForCoalition(2, localizedDynamicHeadingLabel(HeadingName), ZoneMenu, function()
					SpawnRequestFunction(ZoneName, 045, 0)
				end)
			else
				local HeadingValue = capHeadings[HeadingName]
				local HeadingMenu = missionCommands.addSubMenuForCoalition(2, localizedDynamicHeadingLabel(HeadingName), ZoneMenu)
				for _, LegName in ipairs(LegNames) do
					local LegValue = capLegs[LegName]
					missionCommands.addCommandForCoalition(2, localizedDynamicLegLabel(LegName), HeadingMenu, function()
						SpawnRequestFunction(ZoneName, HeadingValue, LegValue)
					end)
				end
			end
		end
	end

	return ParentMenu
end

function spawnArcoAt(zoneOrCoord, heading, leg, zoneLabel, fromRestore)
    if ArcoActive then return end
	_setTankerCurrentAltitude("arco", _getTankerDefaultAltitude("arco"))
	local arcoAltFt = _getTankerCurrentAltitude("arco")
	local spawn = _resolveTankerSpawnInput(zoneOrCoord, heading, zoneLabel)
	if not spawn then return end
	local spawnLeg = tonumber(leg) or 0
	if fromRestore then
		local arcoState = _getTankerState("arco")
		if arcoState and type(arcoState.speed) == "number" then
			_setTankerCurrentSpeed("arco", arcoState.speed)
		end
	else
		_setTankerCurrentSpeed("arco", _getTankerDefaultSpeed("arco"))
	end
	local g = Respawn.SpawnAtPoint('Arco', spawn.coord, spawn.heading, 2, arcoAltFt, ARCO_DEFAULT_SPEED_KT)
	if not g then return end
	local zoneToSave = spawn.zoneName or ((zoneLabel and zoneLabel ~= "saved position") and zoneLabel or nil)
	_saveTankerStation("arco", spawn.coord, spawn.heading, spawnLeg, zoneToSave)
	timer.scheduleFunction(function(group, time)
		ArcoGroup = Group.getByName(group:getName())
		if not ArcoGroup then return end
		local groupController = ArcoGroup:getController()
		ApplyProtectionCommandsToGroupController(groupController)
		local arcoUnit = ArcoGroup:getUnit(1)
		ActivateTankerBeacon(arcoUnit, 101, "ARC")
		local speed = _getTankerCurrentSpeed("arco") or _getTankerDefaultSpeed("arco") or ARCO_DEFAULT_SPEED_KT
		setArcoRacetrack(spawn.coord, spawn.heading, spawnLeg, zoneToSave, speed, true)
		startArcoProximityWatch()
		local msg
		if fromRestore then
			msg = (spawnLeg == 0)
				and L10N:Get("DYNAMIC_ARCO_STATION_ORBIT")
				or  L10N:Format("DYNAMIC_ARCO_STATION_RACETRACK", spawn.heading, tostring(spawnLeg))
		else
			msg = (spawnLeg == 0)
				and L10N:Format("DYNAMIC_ARCO_STATION_ORBIT_AT", spawn.label)
				or  L10N:Format("DYNAMIC_ARCO_STATION_RACETRACK_AT", spawn.label, spawn.heading, tostring(spawnLeg))
		end
		MESSAGE:New(msg, 20):ToAll()
		if ArcoParentMenu then
		missionCommands.removeItemForCoalition(2, ArcoParentMenu)
		ArcoParentMenu = nil
		end
	end, g, timer.getTime() + 1)
    ArcoActive = true
	buildCapControlMenu()
	ArcoSpawnIndex = ArcoSpawnIndex + 1
end

function buildArcoMenu()
	ArcoParentMenu = BuildTankerRequestMenu(L10N:Get("DYNAMIC_REQUEST_DROGUE_TANKER_FROM"), ArcoParentMenu, spawnArcoAt)
end


