local planeUnlimitedCheckInitialized = false

local function checkUnlimitedPlanesOnce(airbaseNames)
	if planeUnlimitedCheckInitialized then return end
	planeUnlimitedCheckInitialized = true
	if type(airbaseNames) ~= "table" then return end
	for _, airbaseName in ipairs(airbaseNames) do
		local storage = STORAGE:FindByName(airbaseName)
		if storage and storage.GetInventory and storage.IsUnlimited then
			local ac = storage:GetInventory()
			local samplePlane = nil
			for name, _ in pairs(ac or {}) do
				samplePlane = name
				break
			end
			if samplePlane then
				local ok, isUnlimited = pcall(storage.IsUnlimited, storage, samplePlane)
				if ok and isUnlimited then
					trigger.action.outText(L10N:Format("WAREHOUSE_UNLIMITED_AIRCRAFT_DETECTED", tostring(airbaseName)),15)
				end
			end
		end
	end
end

local function getZoneSideByAirbaseName(airbaseName)
	for _, zref in ipairs(bc:getZones() or {}) do
		local z = bc.indexedZones[zref.zone]
		if z and z.airbaseName == airbaseName then
			return z.side
		end
	end
	return nil
end

local function getColdwarAllowedPlaneListByAirbase(airbaseName)
	local zoneSide = getZoneSideByAirbaseName(airbaseName)
	if zoneSide == 2 then
		return allowedPlanes or {}
	end
	if zoneSide == 1 or zoneSide == 0 then
		return allowedPlanesRed or allowedPlanes or {}
	end
	return allowedPlanes or {}
end

local function syncColdwarPlanesInStorage(storage, planeList)
	if not storage or not storage.GetInventory then return end
	local ac = storage:GetInventory()
	for name, _ in pairs(ac or {}) do
		storage:SetItem(name, 0)
	end
	for i = 1, #(planeList or {}) do
		storage:SetItem(planeList[i], 1073741823)
	end
end

function checkWeaponsList(airbase)
	if airbase and Era ~= 'Coldwar' then
		local storage = STORAGE:FindByName(airbase)
		if storage then
			local allWeapons = WEAPONSLIST.GetAllItems()
			for _, name in ipairs(allWeapons or {}) do
				local okAmt, amt = pcall(storage.GetItemAmount, storage, name)
				if (not okAmt) or (amt == nil) or (amt == 0) or (amt >= 0 and amt < 10000000) then
					pcall(storage.SetItem, storage, name, 1073741823)
				end
			end

			for _, acName in ipairs(restockAircraft) do
				local okAmt, amt = pcall(storage.GetItemAmount, storage, acName)
				if (not okAmt) or (amt == nil) or (amt >= 0 and amt < 10000000) then
					pcall(storage.SetItem, storage, acName, 1073741823)
				end
			end
			for _, forbiddenWeapon in ipairs(ForbiddWeaponsInAllEra or {}) do
				storage:SetItem(forbiddenWeapon, 0)
			end
		end
		return
	end	
    local function isLogisticCenterAirbase(airbaseName)
        if not airbaseName then return false end
        for _, zref in ipairs(bc:getZones() or {}) do
            local z = bc.indexedZones[zref.zone]
            if z and z.airbaseName == airbaseName then
                return z.LogisticCenter == true
            end
        end
        return false
    end

    local function removeRestricted(storage, airbaseName)
        if not storage then return end
		local unlimitedDetected = false
        for _, weapon in ipairs(restrictedWeapons or {}) do
            local amt = storage:GetItemAmount(weapon)
			if amt == 1000000 then unlimitedDetected = true end
            if amt and amt > 0 then
               storage:RemoveItem(weapon, amt)
            end
        end
		if unlimitedDetected then
			trigger.action.outText(L10N:Format("WAREHOUSE_UNLIMITED_WAREHOUSE_DETECTED", tostring(airbaseName)),15)
		end
    end

	local function restockColdwarLogisticCenter(storage,airbaseName)
		if not storage then return end
		if not storage.GetInventory then return end

		local _, _, wp = storage:GetInventory()
		if WarehouseLogistics ~= true or isLogisticCenterAirbase(airbaseName) then
			for name, _ in pairs(wp or {}) do
				if not (restrictedWeaponSet and restrictedWeaponSet[name]) then
					storage:SetItem(name, 1073741823)
				end
			end
			-- Also fill any allowed items that are missing from the warehouse list.
			local allItems = (WEAPONSLIST and WEAPONSLIST.GetAllItems and WEAPONSLIST.GetAllItems()) or {}
			for i = 1, #allItems do
				local name = allItems[i]
				if not (restrictedWeaponSet and restrictedWeaponSet[name]) then
					storage:SetItem(name, 1073741823)
				end
			end
		end

		local planeList = getColdwarAllowedPlaneListByAirbase(airbaseName)
		syncColdwarPlanesInStorage(storage, planeList)
    end

    local function processColdwarAirbase(airbaseName)
        local storage = getStorageByName(airbaseName)
        if not storage then return end

        removeRestricted(storage, airbaseName)
        restockColdwarLogisticCenter(storage,airbaseName)
		for _, forbiddenWeapon in ipairs(ForbiddWeaponsInAllEra or {}) do
			storage:SetItem(forbiddenWeapon, 0)
		end
    end

    if Era == 'Coldwar' then
        if airbase then
            processColdwarAirbase(airbase)
            return
        end

        local airbaseList, seen = {}, {}

        for _, zref in ipairs(bc:getZones() or {}) do
            local z = bc.indexedZones[zref.zone]
            local abName = z and z.airbaseName
            if abName and not seen[abName] and (not abName:find("^CVN%-")) and (abName ~= "Tarawa") and (abName ~= "HMS Invincible") then
                seen[abName] = true
                airbaseList[#airbaseList + 1] = abName
            end
        end

        for _, n in ipairs({"FOB ALPHA", "CVN-72","CVN-73","Tarawa","CVN-59","CVN-74","CVN-75","HMS Invincible","Tarawa North", "Tarawa South"}) do
            if not seen[n] and IsGroupActive(n) then
                seen[n] = true
                airbaseList[#airbaseList + 1] = n
            end
        end

        checkUnlimitedPlanesOnce(airbaseList)

        for _, airbaseName in ipairs(airbaseList) do
            processColdwarAirbase(airbaseName)
        end

        return
    end

     local fillAll = (WarehouseLogistics == false)
    local airbaseList, seen = {}, {}

    for _, z in ipairs(bc:getZones() or {}) do
        local zobj = bc.indexedZones[z.zone]
        local ab = zobj and zobj.airbaseName
        if ab and not seen[ab] and (fillAll or zobj.LogisticCenter == true) then
            seen[ab] = true
            airbaseList[#airbaseList + 1] = ab
        end
    end


    local allWeapons = WEAPONSLIST.GetAllItems()
    for _, airbaseName in ipairs(airbaseList) do
        local storage = STORAGE:FindByName(airbaseName)
        if storage then

            for _, name in ipairs(allWeapons or {}) do
                local okAmt, amt = pcall(storage.GetItemAmount, storage, name)
                if (not okAmt) or (amt == nil) or (amt == 0) or (amt >= 0 and amt < 10000000) then
                    pcall(storage.SetItem, storage, name, 1073741823)
                end
            end

            for _, acName in ipairs(restockAircraft) do
                local okAmt, amt = pcall(storage.GetItemAmount, storage, acName)
                if (not okAmt) or (amt == nil) or (amt >= 0 and amt < 10000000) then
                    pcall(storage.SetItem, storage, acName, 1073741823)
                end
            end
			for _, forbiddenWeapon in ipairs(ForbiddWeaponsInAllEra or {}) do
				storage:SetItem(forbiddenWeapon, 0)
			end
        end
    end
end

timer.scheduleFunction(function()
    checkWeaponsList()
end, {}, timer.getTime() + 1)

local _wsWarehouseSyncDone = false
timer.scheduleFunction(function()
    if _wsWarehouseSyncDone then return end
    if WarehouseLogistics ~= true then return end
    if WEAPONSLIST and WEAPONSLIST.SyncFromWarehouseLogistics then
        local ok = WEAPONSLIST.SyncFromWarehouseLogistics({ addToList = true, logMissing = true, logAdded = true })
        if ok then
            _wsWarehouseSyncDone = true
            return
        end
    end
end, {}, timer.getTime() + 0.1)
